namespace AtsBackgroundBuilder
{
    public class Plugin : IExtensionApplication
    {
        private const string RaDiagBuildTag = "RA-DIAG-BUILD 2026-02-08-alt6";
        private const string LayerUsecBase = "L-USEC";
        private const string LayerUsecZero = "L-USEC-0";
        private const string LayerUsecTwenty = "L-USEC2012";
        private const string LayerUsecThirty = "L-USEC3018";
        private const double RoadAllowanceUsecWidthMeters = 30.17;
        private const double RoadAllowanceSecWidthMeters = 20.11;
        private const double SurveyedUnsurveyedThresholdMeters = 25.0;
        private const double CorrectionLineInsetMeters = (RoadAllowanceUsecWidthMeters - RoadAllowanceSecWidthMeters) * 0.5;
        private const double CorrectionLinePairGapMeters = CorrectionLineInsetMeters * 2.0;
        private const double RoadAllowanceWidthToleranceMeters = 0.10;
        private const double RoadAllowanceGapOffsetToleranceMeters = 0.35;
        private const double MinAdjustableLsdLineLengthMeters = 20.0;
        // Heavy road-allowance tracing is off by default; enable with ATSBUILD_RA_DIAG=1 when needed.
        private static readonly bool EnableRoadAllowanceDiagnostics =
            string.Equals(Environment.GetEnvironmentVariable("ATSBUILD_RA_DIAG"), "1", StringComparison.OrdinalIgnoreCase);
        // 100m DEFPOINTS buffer windows are off by default for performance testing.
        private static readonly bool EnableBufferedQuarterWindowDrawing =
            string.Equals(Environment.GetEnvironmentVariable("ATSBUILD_DRAW_100M_BUFFER"), "1", StringComparison.OrdinalIgnoreCase);
        // Export final CAD diagnostic layers (L-SEC/L-USEC/L-QSEC/L-SECTION-LSD) as GeoJSON for py viewer parity.
        private static readonly bool EnableCadGeoJsonExport =
            string.Equals(Environment.GetEnvironmentVariable("ATSBUILD_EXPORT_GEOJSON"), "1", StringComparison.OrdinalIgnoreCase);
        private static readonly string CadGeoJsonExportPath =
            Environment.GetEnvironmentVariable("ATSBUILD_EXPORT_GEOJSON_PATH") ?? string.Empty;
        private static readonly object SectionOutlineCacheLock = new object();
        private static readonly object BufferedDefpointsWindowLock = new object();
        private static readonly Dictionary<string, SectionOutline?> SectionOutlineCache = new Dictionary<string, SectionOutline?>(StringComparer.OrdinalIgnoreCase);
        private static readonly Dictionary<string, bool> FolderIndexCache = new Dictionary<string, bool>(StringComparer.OrdinalIgnoreCase);
        private static readonly HashSet<ObjectId> BufferedDefpointsWindowIds = new HashSet<ObjectId>();

        public void Initialize()
        {
        }

        public void Terminate()
        {
        }

        [CommandMethod("ATSBUILD")]
        public void AtsBuild()
        {
            var doc = Application.DocumentManager.MdiActiveDocument;
            var editor = doc.Editor;
            var database = doc.Database;

            var logger = new Logger();
            var dllFolder = Path.GetDirectoryName(Assembly.GetExecutingAssembly().Location) ?? Environment.CurrentDirectory;
            logger.Initialize(Path.Combine(dllFolder, "AtsBackgroundBuilder.log"));
            var assemblyPath = Assembly.GetExecutingAssembly().Location ?? string.Empty;
            var assemblyLocalStamp = File.Exists(assemblyPath)
                ? File.GetLastWriteTime(assemblyPath)
                : DateTime.MinValue;
            var assemblyUtcStamp = File.Exists(assemblyPath)
                ? File.GetLastWriteTimeUtc(assemblyPath)
                : DateTime.MinValue;
            logger.WriteLine($"ATSBUILD assembly: {assemblyPath} (local={assemblyLocalStamp:yyyy-MM-dd h:mm:ss tt}, utc={assemblyUtcStamp:yyyy-MM-dd HH:mm:ss})");
            var exitStage = "startup";
            void EmitExit(string reason)
            {
                var msg = $"ATSBUILD exit stage: {exitStage} ({reason})";
                editor.WriteMessage("\n" + msg);
                logger.WriteLine(msg);
            }

            var configPath = Path.Combine(dllFolder, "Config.json");
            var config = Config.Load(configPath, logger);
            config.AllowMultiQuarterDispositions = true;

            var companyLookupPath = ResolveLookupPath(config.LookupFolder, config.CompanyLookupFile, dllFolder, "CompanyLookup.xlsx");
            var purposeLookupPath = ResolveLookupPath(config.LookupFolder, config.PurposeLookupFile, dllFolder, "PurposeLookup.xlsx");

            var companyLookup = ExcelLookup.Load(companyLookupPath, logger);
            var purposeLookup = ExcelLookup.Load(purposeLookupPath, logger);

            // ------------------------------------------------------------------
            // UI input (replaces command line prompts)
            // ------------------------------------------------------------------
            AtsBuildInput? input = null;
            try
            {
                var clientNames = companyLookup.ValuesByExtra("C");
                if (clientNames.Count == 0)
                {
                    logger.WriteLine("No company rows flagged with Extra='C'; using full company list for client dropdown.");
                    clientNames = companyLookup.Values;
                }

                using (var form = new AtsBuildForm(clientNames, config))
                {
                    var dr = form.ShowDialog();
                    if (dr != System.Windows.Forms.DialogResult.OK || form.Result == null)
                    {
                        exitStage = "ui_cancelled";
                        editor.WriteMessage("\nATSBUILD cancelled.");
                        EmitExit("cancelled");
                        logger.Dispose();
                        return;
                    }

                    input = form.Result;
                }
            }
            catch (System.Exception ex)
            {
                exitStage = "ui_error";
                editor.WriteMessage($"\nATSBUILD UI error: {ex.Message}");
                logger.WriteLine("ATSBUILD UI error: " + ex);
                EmitExit("error");
                logger.Dispose();
                return;
            }

            if (input == null)
            {
                exitStage = "input_null";
                editor.WriteMessage("\nATSBUILD cancelled.");
                EmitExit("cancelled");
                logger.Dispose();
                return;
            }

            // Enforce existing behavior (multi-quarter labeling) unless you later decide to expose this in the UI.
            config.AllowMultiQuarterDispositions = true;
            config.TextHeight = input.TextHeight;
            config.MaxOverlapAttempts = input.MaxOverlapAttempts;

            if (!config.UseSectionIndex)
            {
                exitStage = "config_use_section_index_false";
                editor.WriteMessage("\nConfig.UseSectionIndex=false. This build requires the section index workflow.");
                EmitExit("error");
                logger.Dispose();
                return;
            }

            // Build the section geometry used to determine 1/4s.
            // NOTE: These entities are considered "temporary" unless ATS fabric is enabled (see cleanup at the end).
            var sectionDrawResult = DrawSectionsFromRequests(
                editor,
                database,
                input.SectionRequests,
                config,
                logger,
                input.DrawLsdSubdivisionLines);
            exitStage = "sections_built";
            var quarterPolylinesForLabelling = sectionDrawResult.LabelQuarterPolylineIds;
            if (quarterPolylinesForLabelling.Count == 0)
            {
                exitStage = "no_quarters_generated";
                editor.WriteMessage("\nNo quarter polylines generated from the section index (check your grid inputs)." );

                // Ensure we don't leave temporary section outlines behind when ATS fabric is unchecked.
                CleanupAfterBuild(database, sectionDrawResult, new List<ObjectId>(), input, logger);

                EmitExit("error");
                logger.Dispose();
                return;
            }

            if (input.IncludeP3Shapefiles)
            {
                exitStage = "p3_import";
                var p3Summary = ImportP3Shapefiles(
                    database,
                    editor,
                    logger,
                    sectionDrawResult.SectionPolylineIds);
                editor.WriteMessage($"\nP3 import: imported {p3Summary.ImportedEntities}, filtered {p3Summary.FilteredEntities}, failures {p3Summary.ImportFailures}.");
                logger.WriteLine($"P3 import summary: imported={p3Summary.ImportedEntities}, filtered={p3Summary.FilteredEntities}, failures={p3Summary.ImportFailures}");
            }

            var dispositionPolylines = new List<ObjectId>();
            ShapefileImportSummary importSummary;
            if (input.IncludeDispositionLinework || input.IncludeDispositionLabels)
            {
                exitStage = "disposition_import";
                importSummary = ShapefileImporter.ImportShapefiles(
                    database,
                    editor,
                    logger,
                    config,
                    sectionDrawResult.SectionPolylineIds,
                    dispositionPolylines);
                if (dispositionPolylines.Count == 0)
                {
                    editor.WriteMessage("\nNo disposition polylines imported from shapefiles.");
                    // Continue so ATS fabric / cleanup behavior still runs.
                }
            }
            else
            {
                importSummary = new ShapefileImportSummary();
            }

            var currentClient = input.CurrentClient;
            if (string.IsNullOrWhiteSpace(currentClient))
            {
                exitStage = "missing_current_client";
                editor.WriteMessage("\nCurrent client is required.");
                EmitExit("error");
                logger.Dispose();
                return;
            }

            var layerManager = new LayerManager(database);
            var dispositions = new List<DispositionInfo>();
            var result = new SummaryResult();
            var shouldLoadSupplementalSectionInfos = input.IncludeDispositionLabels && dispositionPolylines.Count > 0;
            var supplementalSectionInfos = shouldLoadSupplementalSectionInfos
                ? LoadSupplementalSectionSpatialInfos(input.SectionRequests, config, logger)
                : new List<SectionSpatialInfo>();

            using (var transaction = database.TransactionManager.StartTransaction())
            {
                exitStage = "processing_dispositions";
                var lsdCells = new List<LsdCellInfo>();
                var sectionInfos = new List<SectionSpatialInfo>();
                if (shouldLoadSupplementalSectionInfos)
                {
                    lsdCells = BuildSectionLsdCells(transaction, sectionDrawResult.SectionNumberByPolylineId);
                    sectionInfos = BuildSectionSpatialInfos(transaction, sectionDrawResult.SectionNumberByPolylineId);
                }
                try
                {
                    foreach (var info in supplementalSectionInfos)
                    {
                        sectionInfos.Add(info);
                        BuildLsdCellsForSection(info.SectionPolyline, info.Section, lsdCells);
                    }

                    foreach (var id in dispositionPolylines)
                    {
                        var ent = transaction.GetObject(id, OpenMode.ForRead) as Entity;
                        if (ent == null || !GeometryUtils.TryGetClosedBoundaryClone(ent, out var clone))
                        {
                            result.SkippedNotClosed++;
                            continue;
                        }

                        // Work with an in-memory clone after the transaction ends.
                        // NOTE: clone is a DBObject not in the database; keep it alive for label placement.

                        result.TotalDispositions++;
                        var od = OdHelpers.ReadObjectData(id, logger);
                        if (od == null)
                        {
                            result.SkippedNoOd++;
                            continue;
                        }

                    var dispNum = od.TryGetValue("DISP_NUM", out var dispRaw) ? dispRaw : string.Empty;
                    var company = od.TryGetValue("COMPANY", out var companyRaw) ? companyRaw : string.Empty;
                    var purpose = od.TryGetValue("PURPCD", out var purposeRaw) ? purposeRaw : string.Empty;
                    var odDimension = od.TryGetValue("DIMENSION", out var dimensionRaw) ? dimensionRaw : string.Empty;

                        var mappedCompany = MapValue(companyLookup, company, company);
                        var mappedPurpose = MapValue(purposeLookup, purpose, purpose);
                        var purposeExtra = purposeLookup.Lookup(purpose)?.Extra ?? string.Empty;

                    var dispNumFormatted = FormatDispNum(dispNum);
                    var safePoint = GeometryUtils.GetSafeInteriorPoint(clone);

                    var isSurfaceLabel = (mappedPurpose ?? string.Empty).IndexOf("(Surface)", StringComparison.OrdinalIgnoreCase) >= 0;
                    if (input.IncludeDispositionLabels && (IsWellSitePurpose(purpose) || isSurfaceLabel))
                    {
                        var normalizedPurpose = NormalizePurposeCode(purpose);
                        editor.WriteMessage($"\nWELLSITE DEBUG: DISP={dispNumFormatted} PURPCD='{purpose}' normalized='{normalizedPurpose}' mapped='{mappedPurpose}' surface={isSurfaceLabel}");
                        logger.WriteLine($"WELLSITE DEBUG: DISP={dispNumFormatted} PURPCD='{purpose}' normalized='{normalizedPurpose}' mapped='{mappedPurpose}' surface={isSurfaceLabel}");

                        var lsdSecToken = GetDominantLsdSectionToken(clone, lsdCells);
                        editor.WriteMessage($"\nWELLSITE DEBUG: primary-token='{lsdSecToken}' lsd-cells={lsdCells.Count}");
                        logger.WriteLine($"WELLSITE DEBUG: primary-token='{lsdSecToken}' lsd-cells={lsdCells.Count}");
                        if (string.IsNullOrWhiteSpace(lsdSecToken))
                        {
                            lsdSecToken = GetDominantLsdSectionTokenBySection(clone, sectionInfos);
                            editor.WriteMessage($"\nWELLSITE DEBUG: fallback-token='{lsdSecToken}' section-infos={sectionInfos.Count}");
                            logger.WriteLine($"WELLSITE DEBUG: fallback-token='{lsdSecToken}' section-infos={sectionInfos.Count}");
                            if (string.IsNullOrWhiteSpace(lsdSecToken))
                            {
                                lsdSecToken = GetPointBasedLsdSectionToken(clone, sectionInfos, out var pointDebug);
                                editor.WriteMessage($"\nWELLSITE DEBUG: point-token='{lsdSecToken}' detail={pointDebug}");
                                logger.WriteLine($"WELLSITE DEBUG: point-token='{lsdSecToken}' detail={pointDebug}");
                            }
                            if (string.IsNullOrWhiteSpace(lsdSecToken))
                            {
                                var overlapDebug = GetSectionOverlapDebugString(clone, sectionInfos);
                                editor.WriteMessage($"\nWELLSITE DEBUG: overlaps {overlapDebug}");
                                logger.WriteLine($"WELLSITE DEBUG: overlaps {overlapDebug}");
                            }
                        }
                        if (!string.IsNullOrWhiteSpace(lsdSecToken))
                        {
                            mappedPurpose = lsdSecToken + " " + mappedPurpose;
                            editor.WriteMessage($"\nWELLSITE DEBUG: final surface line='{mappedPurpose}'");
                            logger.WriteLine($"WELLSITE DEBUG: final surface line='{mappedPurpose}'");
                        }
                    }
                    else if (input.IncludeDispositionLabels && (mappedPurpose ?? string.Empty).IndexOf("(Surface)", StringComparison.OrdinalIgnoreCase) >= 0)
                    {
                        var normalizedPurpose = NormalizePurposeCode(purpose);
                        editor.WriteMessage($"\nWELLSITE DEBUG: skipped (not detected as wellsite) DISP={dispNumFormatted} PURPCD='{purpose}' normalized='{normalizedPurpose}' mapped='{mappedPurpose}'");
                        logger.WriteLine($"WELLSITE DEBUG: skipped (not detected as wellsite) DISP={dispNumFormatted} PURPCD='{purpose}' normalized='{normalizedPurpose}' mapped='{mappedPurpose}'");
                    }

                        // Default output layers; will be overridden when mapping succeeds.
                        string lineLayer = ent.Layer;
                        string textLayer = ent.Layer;

                    // Determine client/foreign layer names based on company and purpose.
                    // Purpose extra column supplies the layer suffix (e.g. ROW, PIPE, etc.).
                    string? lineLayerName = null;
                    string? textLayerName = null;
                    try
                    {
                        var purposeEntry = purposeLookup.Lookup(purpose);
                        var suffix = purposeEntry?.Extra?.Trim() ?? string.Empty;
                        if (suffix.StartsWith("-", StringComparison.InvariantCulture))
                            suffix = suffix.Substring(1);
                        if (!string.IsNullOrEmpty(suffix))
                        {
                            // OD COMPANY is often a code (lookup key), while the UI client list comes from
                            // the lookup VALUE column. Compare against the mapped company first.
                            bool isClient = string.Equals(currentClient, mappedCompany, StringComparison.InvariantCultureIgnoreCase)
                                            || string.Equals(currentClient, company, StringComparison.InvariantCultureIgnoreCase);

                            var prefix = isClient ? "C" : "F";
                            lineLayerName = $"{prefix}-{suffix}";
                            textLayerName = $"{lineLayerName}-T";
                        }
                    }
                    catch
                    {
                        // ignore lookup failures; fall back to original layer
                    }

                    if (!string.IsNullOrEmpty(lineLayerName))
                        lineLayer = lineLayerName;
                    if (!string.IsNullOrEmpty(textLayerName))
                        textLayer = textLayerName;

                    // Ensure the layer exists before assigning
                    layerManager.EnsureLayer(lineLayer);
                    var lineEntity = transaction.GetObject(id, OpenMode.ForWrite) as Entity;
                    if (lineEntity != null && lineEntity.Layer != lineLayer)
                    {
                        lineEntity.Layer = lineLayer;
                        lineEntity.ColorIndex = 256;  // ensure ByLayer colour
                    }

                    if (!input.IncludeDispositionLabels)
                    {
                        clone.Dispose();
                        continue;
                    }

                    var requiresWidth = PurposeRequiresWidth(purpose, config);
                    string labelText;

                    if (requiresWidth)
                    {
                        var info = new DispositionInfo(id, clone, string.Empty, lineLayer, textLayer, safePoint)
                        {
                            AllowLabelOutsideDisposition = config.AllowOutsideDispositionForWidthPurposes,
                            AddLeader = true,
                            RequiresWidth = true,
                            MappedCompany = mappedCompany ?? string.Empty,
                            MappedPurpose = mappedPurpose ?? string.Empty,
                            PurposeTitleCase = ToTitleCaseWords(purpose),
                            DispNumFormatted = dispNumFormatted,
                            OdDimension = odDimension ?? string.Empty
                        };
                        dispositions.Add(info);
                        continue;
                    }

                    labelText = mappedCompany + "\\P" + mappedPurpose + "\\P" + dispNumFormatted;

                    var nonWidthInfo = new DispositionInfo(id, clone, labelText, lineLayer, textLayer, safePoint)
                    {
                        AllowLabelOutsideDisposition = false,
                        AddLeader = false
                    };

                        dispositions.Add(nonWidthInfo);
                    }
                }
                finally
                {
                    DisposeLsdCells(lsdCells);
                    DisposeSectionInfos(sectionInfos);
                }
                transaction.Commit();
            }

            var quarters = new List<QuarterInfo>();
            if (input.IncludeDispositionLabels)
            {
                using (var transaction = database.TransactionManager.StartTransaction())
                {
                    if (sectionDrawResult.LabelQuarterInfos != null && sectionDrawResult.LabelQuarterInfos.Count > 0)
                    {
                        foreach (var info in sectionDrawResult.LabelQuarterInfos)
                        {
                            var polyline = transaction.GetObject(info.QuarterId, OpenMode.ForRead) as Polyline;
                            if (polyline == null || !polyline.Closed)
                            {
                                continue;
                            }

                            quarters.Add(new QuarterInfo((Polyline)polyline.Clone(), info.SectionKey, info.Quarter));
                        }
                    }
                    else
                    {
                        foreach (var id in quarterPolylinesForLabelling.Distinct())
                        {
                            var polyline = transaction.GetObject(id, OpenMode.ForRead) as Polyline;
                            if (polyline == null || !polyline.Closed)
                            {
                                continue;
                            }

                            quarters.Add(new QuarterInfo((Polyline)polyline.Clone()));
                        }
                    }
                    transaction.Commit();
                }
            }

            if (input.IncludeDispositionLabels)
            {
                exitStage = "placing_labels";
                var placer = new LabelPlacer(database, editor, layerManager, config, logger, input.UseAlignedDimensions);
                var placement = placer.PlaceLabels(quarters, dispositions, currentClient);

                result.LabelsPlaced = placement.LabelsPlaced;
                result.SkippedNoLayerMapping += placement.SkippedNoLayerMapping;
                result.OverlapForced = placement.OverlapForced;
                result.MultiQuarterProcessed = placement.MultiQuarterProcessed;
            }
            result.ImportedDispositions = importSummary.ImportedDispositions;
            result.DedupedDispositions = importSummary.DedupedDispositions;
            result.FilteredDispositions = importSummary.FilteredDispositions;
            result.ImportFailures = importSummary.ImportFailures;

            if (input.CheckPlsr)
            {
                exitStage = "plsr_check";
                if (!input.IncludeDispositionLabels)
                {
                    editor.WriteMessage("\nPLSR check skipped: Disposition labels are disabled.");
                    logger.WriteLine("PLSR check skipped: Disposition labels are disabled.");
                }
                else
                {
                    RunPlsrCheck(database, editor, logger, companyLookup, input, quarters);
                }
            }

            if (input.IncludeQuarterSectionLabels)
            {
                exitStage = "quarter_section_labels_final";
                PlaceQuarterSectionLabels(database, sectionDrawResult.LabelQuarterInfos ?? new List<QuarterLabelInfo>(), input.DrawLsdSubdivisionLines, logger);
            }

            // ------------------------------------------------------------------
            // Cleanup / output control
            // ------------------------------------------------------------------
            // Per your UI rules:
            //  - Quarter boxes used to determine 1/4s are ALWAYS removed.
            //  - If ATS fabric is unchecked, section outlines/labels created for calculation are removed.
            //  - If Dispositions (linework) is unchecked, imported disposition polylines are removed (labels remain).
            exitStage = "cleanup";
            CleanupAfterBuild(database, sectionDrawResult, dispositionPolylines, input, logger);
            if (EnableCadGeoJsonExport)
            {
                TryExportCadDiagnosticGeoJson(database, input.SectionRequests, dllFolder, logger);
            }

            exitStage = "summary";
            editor.WriteMessage("\nATSBUILD complete.");
            editor.WriteMessage("\nTotal dispositions: " + result.TotalDispositions);
            editor.WriteMessage("\nLabels placed: " + result.LabelsPlaced);
            editor.WriteMessage("\nSkipped (no OD): " + result.SkippedNoOd);
            editor.WriteMessage("\nSkipped (not closed): " + result.SkippedNotClosed);
            editor.WriteMessage("\nNo layer mapping: " + result.SkippedNoLayerMapping);
            editor.WriteMessage("\nOverlap forced: " + result.OverlapForced);
            editor.WriteMessage("\nMulti-quarter processed: " + result.MultiQuarterProcessed);
            editor.WriteMessage("\nImported dispositions: " + result.ImportedDispositions);
            editor.WriteMessage("\nFiltered out: " + result.FilteredDispositions);
            editor.WriteMessage("\nDeduped: " + result.DedupedDispositions);
            editor.WriteMessage("\nImport failures: " + result.ImportFailures);

            logger.WriteLine("ATSBUILD summary");
            logger.WriteLine("Total dispositions: " + result.TotalDispositions);
            logger.WriteLine("Labels placed: " + result.LabelsPlaced);
            logger.WriteLine("Skipped (no OD): " + result.SkippedNoOd);
            logger.WriteLine("Skipped (not closed): " + result.SkippedNotClosed);
            logger.WriteLine("No layer mapping: " + result.SkippedNoLayerMapping);
            logger.WriteLine("Overlap forced: " + result.OverlapForced);
            logger.WriteLine("Multi-quarter processed: " + result.MultiQuarterProcessed);
            logger.WriteLine("Imported dispositions: " + result.ImportedDispositions);
            logger.WriteLine("Filtered out: " + result.FilteredDispositions);
            logger.WriteLine("Deduped: " + result.DedupedDispositions);
            logger.WriteLine("Import failures: " + result.ImportFailures);
            exitStage = "completed";
            EmitExit("ok");
            logger.Dispose();
        }

        private static void CleanupAfterBuild(
            Database database,
            SectionDrawResult sectionDrawResult,
            List<ObjectId> dispositionPolylineIds,
            AtsBuildInput input,
            Logger logger)
        {
            if (database == null || sectionDrawResult == null || input == null)
                return;

            try
            {
                if (!input.IncludeAtsFabric)
                {
                    // If ATS fabric is not requested, remove all temporary section geometry.
                    EraseEntities(database, sectionDrawResult.QuarterPolylineIds, logger, "quarter boxes");
                    EraseEntities(database, sectionDrawResult.QuarterHelperEntityIds, logger, "quarter helper lines");
                    EraseEntities(database, sectionDrawResult.SectionPolylineIds, logger, "section outlines");
                    EraseEntities(database, sectionDrawResult.ContextSectionPolylineIds, logger, "context section pieces");
                    EraseEntities(database, sectionDrawResult.SectionLabelEntityIds, logger, "section labels");
                }
                else
                {
                    // Keep mapped section lines and generated linework; remove temp quarter polygons only.
                    EraseEntities(database, sectionDrawResult.QuarterPolylineIds, logger, "quarter boxes");
                }

                // If disposition linework is NOT requested, erase imported disposition polylines after labels are placed.
                if (!input.IncludeDispositionLinework)
                {
                    EraseEntities(database, dispositionPolylineIds, logger, "disposition linework");
                }
            }
            catch (System.Exception ex)
            {
                logger?.WriteLine("CleanupAfterBuild error: " + ex);
            }
        }

        private static void EraseEntities(Database database, IEnumerable<ObjectId> ids, Logger logger, string label)
        {
            if (database == null || ids == null)
                return;

            var unique = ids.Where(id => !id.IsNull).Distinct().ToList();
            if (unique.Count == 0)
                return;

            using (var tr = database.TransactionManager.StartTransaction())
            {
                int erased = 0;
                foreach (var id in unique)
                {
                    try
                    {
                        var obj = tr.GetObject(id, OpenMode.ForWrite, false);
                        if (obj == null || obj.IsErased)
                            continue;

                        obj.Erase(true);
                        erased++;
                    }
                    catch
                    {
                        // Ignore failures (object may already be erased, on locked layer, etc.)
                    }
                }

                tr.Commit();

                if (erased > 0)
                {
                    logger?.WriteLine($"Cleanup: erased {erased} {label} entities");
                }
            }
        }

        private static void TryExportCadDiagnosticGeoJson(
            Database database,
            IReadOnlyList<SectionRequest> requests,
            string dllFolder,
            Logger logger)
        {
            if (database == null)
            {
                return;
            }

            try
            {
                var exportPath = ResolveCadGeoJsonPath(database, dllFolder);
                var exportDirectory = Path.GetDirectoryName(exportPath);
                if (!string.IsNullOrWhiteSpace(exportDirectory))
                {
                    Directory.CreateDirectory(exportDirectory);
                }

                var zone = ResolveSingleRequestedZone(requests);
                var features = CollectCadDiagnosticLineFeatures(database, zone);

                using (var stream = new FileStream(exportPath, FileMode.Create, FileAccess.Write, FileShare.Read))
                using (var writer = new Utf8JsonWriter(stream, new JsonWriterOptions { Indented = true }))
                {
                    writer.WriteStartObject();
                    writer.WriteString("type", "FeatureCollection");
                    writer.WriteStartObject("properties");
                    writer.WriteString("source", "AtsBackgroundBuilder");
                    writer.WriteString("coordinate_space", "UTM83");
                    if (zone.HasValue)
                    {
                        writer.WriteNumber("zone", zone.Value);
                    }
                    writer.WriteEndObject();
                    writer.WriteStartArray("features");
                    foreach (var feature in features)
                    {
                        WriteCadDiagnosticFeature(writer, feature);
                    }
                    writer.WriteEndArray();
                    writer.WriteEndObject();
                    writer.Flush();
                }

                logger?.WriteLine($"CAD-DIAG export: wrote {features.Count} segment(s) to {exportPath}.");
            }
            catch (System.Exception ex)
            {
                logger?.WriteLine("CAD-DIAG export failed: " + ex.Message);
            }
        }

        private static string ResolveCadGeoJsonPath(Database database, string dllFolder)
        {
            if (!string.IsNullOrWhiteSpace(CadGeoJsonExportPath))
            {
                var expanded = Environment.ExpandEnvironmentVariables(CadGeoJsonExportPath.Trim().Trim('"'));
                return Path.GetFullPath(expanded);
            }

            if (!string.IsNullOrWhiteSpace(database?.Filename))
            {
                var drawingDirectory = Path.GetDirectoryName(database.Filename);
                if (!string.IsNullOrWhiteSpace(drawingDirectory))
                {
                    return Path.Combine(drawingDirectory, "cad_lines.geojson");
                }
            }

            var baseDirectory = string.IsNullOrWhiteSpace(dllFolder) ? Environment.CurrentDirectory : dllFolder;
            return Path.Combine(baseDirectory, "cad_lines.geojson");
        }

        private static int? ResolveSingleRequestedZone(IReadOnlyList<SectionRequest> requests)
        {
            if (requests == null || requests.Count == 0)
            {
                return null;
            }

            int? zone = null;
            for (var i = 0; i < requests.Count; i++)
            {
                var request = requests[i];
                var requestZone = request.Key.Zone;
                if (!zone.HasValue)
                {
                    zone = requestZone;
                    continue;
                }

                if (zone.Value != requestZone)
                {
                    return null;
                }
            }

            return zone;
        }

        private static List<CadDiagnosticLineFeature> CollectCadDiagnosticLineFeatures(Database database, int? zone)
        {
            var features = new List<CadDiagnosticLineFeature>();
            if (database == null)
            {
                return features;
            }

            using (var tr = database.TransactionManager.StartTransaction())
            {
                var blockTable = (BlockTable)tr.GetObject(database.BlockTableId, OpenMode.ForRead);
                var modelSpace = (BlockTableRecord)tr.GetObject(blockTable[BlockTableRecord.ModelSpace], OpenMode.ForRead);

                foreach (ObjectId id in modelSpace)
                {
                    var ent = tr.GetObject(id, OpenMode.ForRead, false) as Entity;
                    if (ent == null || ent.IsErased)
                    {
                        continue;
                    }

                    if (!ShouldExportCadDiagnosticLayer(ent.Layer))
                    {
                        continue;
                    }

                    if (ent is Line line)
                    {
                        AddCadDiagnosticSegment(features, line.StartPoint, line.EndPoint, ent, zone);
                        continue;
                    }

                    if (ent is Polyline polyline)
                    {
                        var vertexCount = polyline.NumberOfVertices;
                        if (vertexCount < 2)
                        {
                            continue;
                        }

                        for (var i = 0; i < vertexCount; i++)
                        {
                            var next = i + 1;
                            if (next >= vertexCount)
                            {
                                if (!polyline.Closed)
                                {
                                    break;
                                }

                                next = 0;
                            }

                            AddCadDiagnosticSegment(features, polyline.GetPoint3dAt(i), polyline.GetPoint3dAt(next), ent, zone);
                        }

                        continue;
                    }

                    if (ent is Polyline2d polyline2d)
                    {
                        var vertices = new List<Point3d>();
                        foreach (ObjectId vertexId in polyline2d)
                        {
                            var vertex = tr.GetObject(vertexId, OpenMode.ForRead, false) as Vertex2d;
                            if (vertex != null)
                            {
                                vertices.Add(vertex.Position);
                            }
                        }

                        AddPolylineSegments(features, vertices, polyline2d.Closed, ent, zone);
                        continue;
                    }

                    if (ent is Polyline3d polyline3d)
                    {
                        var vertices = new List<Point3d>();
                        foreach (ObjectId vertexId in polyline3d)
                        {
                            var vertex = tr.GetObject(vertexId, OpenMode.ForRead, false) as PolylineVertex3d;
                            if (vertex != null)
                            {
                                vertices.Add(vertex.Position);
                            }
                        }

                        AddPolylineSegments(features, vertices, polyline3d.Closed, ent, zone);
                    }
                }

                tr.Commit();
            }

            return features;
        }

        private static void AddPolylineSegments(
            List<CadDiagnosticLineFeature> features,
            List<Point3d> vertices,
            bool closed,
            Entity ent,
            int? zone)
        {
            if (features == null || vertices == null || ent == null || vertices.Count < 2)
            {
                return;
            }

            var segmentCount = closed ? vertices.Count : vertices.Count - 1;
            for (var i = 0; i < segmentCount; i++)
            {
                var next = i + 1;
                if (next >= vertices.Count)
                {
                    next = 0;
                }

                AddCadDiagnosticSegment(features, vertices[i], vertices[next], ent, zone);
            }
        }

        private static void AddCadDiagnosticSegment(
            List<CadDiagnosticLineFeature> features,
            Point3d start,
            Point3d end,
            Entity ent,
            int? zone)
        {
            if (features == null || ent == null)
            {
                return;
            }

            if (start.DistanceTo(end) <= 1e-9)
            {
                return;
            }

            var layer = NormalizeCadDiagnosticLayerName(ent.Layer);
            features.Add(new CadDiagnosticLineFeature(
                start,
                end,
                layer,
                ent.GetType().Name,
                ent.Handle.ToString(),
                ent.ColorIndex,
                zone));
        }

        private static bool ShouldExportCadDiagnosticLayer(string layer)
        {
            var normalized = NormalizeCadDiagnosticLayerName(layer);
            return
                string.Equals(normalized, "L-SEC", StringComparison.OrdinalIgnoreCase) ||
                string.Equals(normalized, LayerUsecBase, StringComparison.OrdinalIgnoreCase) ||
                string.Equals(normalized, LayerUsecZero, StringComparison.OrdinalIgnoreCase) ||
                string.Equals(normalized, LayerUsecTwenty, StringComparison.OrdinalIgnoreCase) ||
                string.Equals(normalized, LayerUsecThirty, StringComparison.OrdinalIgnoreCase) ||
                string.Equals(normalized, "L-QSEC", StringComparison.OrdinalIgnoreCase) ||
                string.Equals(normalized, "L-SECTION-LSD", StringComparison.OrdinalIgnoreCase) ||
                string.Equals(normalized, "L-QSEC-BOX", StringComparison.OrdinalIgnoreCase);
        }

        private static string NormalizeCadDiagnosticLayerName(string layer)
        {
            return string.IsNullOrWhiteSpace(layer) ? string.Empty : layer.Trim().ToUpperInvariant();
        }

        private static void WriteCadDiagnosticFeature(Utf8JsonWriter writer, CadDiagnosticLineFeature feature)
        {
            writer.WriteStartObject();
            writer.WriteString("type", "Feature");

            writer.WriteStartObject("properties");
            writer.WriteString("layer", feature.Layer);
            writer.WriteString("entity_type", feature.EntityType);
            writer.WriteString("handle", feature.Handle);
            writer.WriteNumber("color_index", feature.ColorIndex);
            if (feature.Zone.HasValue)
            {
                writer.WriteNumber("zone", feature.Zone.Value);
            }
            writer.WriteEndObject();

            writer.WriteStartObject("geometry");
            writer.WriteString("type", "LineString");
            writer.WriteStartArray("coordinates");
            writer.WriteStartArray();
            writer.WriteNumberValue(feature.Start.X);
            writer.WriteNumberValue(feature.Start.Y);
            writer.WriteEndArray();
            writer.WriteStartArray();
            writer.WriteNumberValue(feature.End.X);
            writer.WriteNumberValue(feature.End.Y);
            writer.WriteEndArray();
            writer.WriteEndArray();
            writer.WriteEndObject();

            writer.WriteEndObject();
        }

        private sealed class CadDiagnosticLineFeature
        {
            public CadDiagnosticLineFeature(
                Point3d start,
                Point3d end,
                string layer,
                string entityType,
                string handle,
                int colorIndex,
                int? zone)
            {
                Start = start;
                End = end;
                Layer = layer ?? string.Empty;
                EntityType = entityType ?? string.Empty;
                Handle = handle ?? string.Empty;
                ColorIndex = colorIndex;
                Zone = zone;
            }

            public Point3d Start { get; }
            public Point3d End { get; }
            public string Layer { get; }
            public string EntityType { get; }
            public string Handle { get; }
            public int ColorIndex { get; }
            public int? Zone { get; }
        }

        private static SectionDrawResult TryPromptAndBuildSections(Editor editor, Database database, Config config, Logger logger)
        {
            if (config.UseSectionIndex)
            {
                var requests = PromptForSectionRequests(editor);
                if (requests.Count > 0)
                {
                    var result = DrawSectionsFromRequests(editor, database, requests, config, logger, false);
                    if (result.QuarterPolylineIds.Count == 0)
                    {
                        var searchFolders = BuildSectionIndexSearchFolders(config);
                        var zones = new HashSet<int>();
                        foreach (var request in requests)
                        {
                            zones.Add(request.Key.Zone);
                        }

                        var zoneList = string.Join(", ", zones);
                        editor.WriteMessage(
                            $"\nNo section outlines found in index. " +
                            $"Verify the section index files for zone(s) {zoneList} exist in {string.Join("; ", searchFolders)} " +
                            "(Master_Sections.index_Z<zone>.jsonl/.csv or Master_Sections.index.jsonl/.csv). " +
                            "See AtsBackgroundBuilder.log for details.");
                    }

                    return result;
                }
            }

            editor.WriteMessage("\nSection input required.");
            return new SectionDrawResult(
                new List<ObjectId>(),
                new List<QuarterLabelInfo>(),
                new List<ObjectId>(),
                new List<ObjectId>(),
                new List<ObjectId>(),
                new List<ObjectId>(),
                new List<ObjectId>(),
                new Dictionary<ObjectId, int>(),
                false);
        }

        private static List<SectionRequest> PromptForSectionRequests(Editor editor)
        {
            var requests = new List<SectionRequest>();
            var zone = PromptForInt(editor, "Enter zone", 11, 1, 60);

            var addAnother = true;
            while (addAnother)
            {
                var quarter = PromptForQuarter(editor);
                if (quarter == QuarterSelection.None)
                {
                    break;
                }

                if (!TryPromptString(editor, "Enter section", out var section) ||
                    !TryPromptString(editor, "Enter township", out var township) ||
                    !TryPromptString(editor, "Enter range", out var range) ||
                    !TryPromptString(editor, "Enter meridian", out var meridian))
                {
                    break;
                }

                requests.Add(new SectionRequest(quarter, new SectionKey(zone, section, township, range, meridian)));

                var moreOptions = new PromptKeywordOptions("Add another section?")
                {
                    AllowNone = true
                };
                moreOptions.Keywords.Add("Yes");
                moreOptions.Keywords.Add("No");
                moreOptions.Keywords.Default = "No";

                var moreResult = editor.GetKeywords(moreOptions);
                addAnother = moreResult.Status == PromptStatus.OK &&
                             string.Equals(moreResult.StringResult, "Yes", StringComparison.OrdinalIgnoreCase);
            }

            return requests;
        }

        private static string PromptForClient(Editor editor, ExcelLookup lookup)
        {
            var values = lookup.Values;
            if (values.Count > 0 && values.Count <= 20)
            {
                var options = new PromptKeywordOptions("Select current client")
                {
                    AllowNone = false
                };

                foreach (var value in values)
                {
                    options.Keywords.Add(value);
                }

                var result = editor.GetKeywords(options);
                if (result.Status == PromptStatus.OK)
                {
                    return result.StringResult;
                }
            }

            if (values.Count > 0)
            {
                editor.WriteMessage("\nAvailable clients: " + string.Join(", ", values));
            }

            var prompt = new PromptStringOptions("Enter current client name: ")
            {
                AllowSpaces = true
            };
            var input = editor.GetString(prompt);
            return input.Status == PromptStatus.OK ? input.StringResult : string.Empty;
        }

        private static double PromptForDouble(Editor editor, string message, double defaultValue, double min, double max)
        {
            var options = new PromptDoubleOptions(message + " [" + defaultValue + "]: ")
            {
                DefaultValue = defaultValue,
                AllowNone = true
            };

            var result = editor.GetDouble(options);
            if (result.Status != PromptStatus.OK)
            {
                return defaultValue;
            }

            var value = result.Value;
            if (value < min || value > max)
            {
                editor.WriteMessage($"\nValue out of range. Using nearest allowed value ({min} - {max}).");
                return Math.Min(Math.Max(value, min), max);
            }

            return value;
        }

        private static int PromptForInt(Editor editor, string message, int defaultValue, int min, int max)
        {
            var options = new PromptIntegerOptions(message + " [" + defaultValue + "]: ")
            {
                DefaultValue = defaultValue,
                AllowNone = true,
                LowerLimit = min,
                UpperLimit = max
            };

            var result = editor.GetInteger(options);
            return result.Status == PromptStatus.OK ? result.Value : defaultValue;
        }

        private static string MapValue(ExcelLookup lookup, string key, string fallback)
        {
            var entry = lookup.Lookup(key);
            return string.IsNullOrWhiteSpace(entry?.Value) ? fallback : entry.Value!;
        }

        private static string FormatDispNum(string? dispNum)
        {
            var regex = new Regex("^([A-Z]{3})(\\d+)");
            var match = regex.Match(dispNum ?? string.Empty);
            if (!match.Success)
            {
                return dispNum ?? string.Empty;
            }

            return match.Groups[1].Value + " " + match.Groups[2].Value;
        }

        private static string ResolveLookupPath(string lookupFolder, string configuredFileName, string dllFolder, string defaultFileName)
        {
            // If the configured name is an absolute path, use it directly.
            if (!string.IsNullOrWhiteSpace(configuredFileName) && Path.IsPathRooted(configuredFileName) && File.Exists(configuredFileName))
                return configuredFileName;

            var fileName = string.IsNullOrWhiteSpace(configuredFileName) ? defaultFileName : configuredFileName;

            var candidates = new List<string>();

            if (!string.IsNullOrWhiteSpace(lookupFolder))
                candidates.Add(Path.Combine(lookupFolder, fileName));

            if (!string.IsNullOrWhiteSpace(dllFolder))
                candidates.Add(Path.Combine(dllFolder, fileName));

            // Fall back to current working directory if needed
            candidates.Add(Path.Combine(Environment.CurrentDirectory, fileName));

            foreach (var p in candidates)
            {
                try
                {
                    if (File.Exists(p))
                        return p;
                }
                catch
                {
                    // ignore
                }
            }

            // If nothing exists, return the first candidate so the logger prints a useful "not found" path.
            return candidates.FirstOrDefault() ?? Path.Combine(dllFolder ?? "", fileName);
        }

        private static bool PurposeRequiresWidth(string purpose, Config config)
        {
            if (string.IsNullOrWhiteSpace(purpose))
                return false;

            var norm = NormalizePurposeCode(purpose);
            var list = config.WidthRequiredPurposeCodes ?? Array.Empty<string>();

            foreach (var item in list)
            {
                if (NormalizePurposeCode(item) == norm)
                    return true;
            }

            return false;
        }

        private static string NormalizePurposeCode(string value)
        {
            if (string.IsNullOrWhiteSpace(value))
                return string.Empty;

            // Trim, uppercase, and collapse all whitespace to single spaces
            var s = value.Trim().ToUpperInvariant();
            var chars = new List<char>(s.Length);
            bool prevSpace = false;

            foreach (var ch in s)
            {
                if (char.IsWhiteSpace(ch))
                {
                    if (!prevSpace)
                    {
                        chars.Add(' ');
                        prevSpace = true;
                    }
                }
                else
                {
                    chars.Add(ch);
                    prevSpace = false;
                }
            }

            return new string(chars.ToArray());
        }

        private static string ToTitleCaseWords(string value)
        {
            if (string.IsNullOrWhiteSpace(value))
                return string.Empty;

            // TitleCase, then common-word cleanup ("and" stays lower-case)
            var lower = NormalizePurposeCode(value).ToLowerInvariant();
            var title = CultureInfo.InvariantCulture.TextInfo.ToTitleCase(lower);

            title = title.Replace(" And ", " and ");
            title = title.Replace(" Of ", " of ");
            title = title.Replace(" The ", " the ");
            return title;
        }

        private static bool IsWellSitePurpose(string purpose)
        {
            var normalized = NormalizePurposeCode(purpose);
            return string.Equals(normalized, "WELL SITE", StringComparison.OrdinalIgnoreCase)
                   || string.Equals(normalized, "WELLSITE", StringComparison.OrdinalIgnoreCase);
        }

        private static int ParseSectionNumber(string section)
        {
            if (string.IsNullOrWhiteSpace(section))
            {
                return 0;
            }

            var match = Regex.Match(section, "\\d+");
            if (!match.Success)
            {
                return 0;
            }

            return int.TryParse(match.Value, NumberStyles.Integer, CultureInfo.InvariantCulture, out var value)
                ? value
                : 0;
        }

        private static bool TryGetAtsSectionGridPosition(int section, out int row, out int col)
        {
            row = -1;
            col = -1;
            if (section < 1 || section > 36)
            {
                return false;
            }

            // ATS/DLS section grid (6x6 snake pattern, north at top).
            // Alberta numbering starts at the southeast corner:
            // 6  5  4  3  2  1
            // 7  8  9 10 11 12
            // 18 17 16 15 14 13
            // 19 20 21 22 23 24
            // 30 29 28 27 26 25
            // 31 32 33 34 35 36
            var rows = new[]
            {
                new[] { 31, 32, 33, 34, 35, 36 },
                new[] { 30, 29, 28, 27, 26, 25 },
                new[] { 19, 20, 21, 22, 23, 24 },
                new[] { 18, 17, 16, 15, 14, 13 },
                new[] { 7, 8, 9, 10, 11, 12 },
                new[] { 6, 5, 4, 3, 2, 1 }
            };

            for (var r = 0; r < rows.Length; r++)
            {
                for (var c = 0; c < rows[r].Length; c++)
                {
                    if (rows[r][c] == section)
                    {
                        row = r;
                        col = c;
                        return true;
                    }
                }
            }

            return false;
        }

        private static List<LsdCellInfo> BuildSectionLsdCells(Transaction transaction, Dictionary<ObjectId, int> sectionNumberById)
        {
            var cells = new List<LsdCellInfo>();
            if (sectionNumberById == null || sectionNumberById.Count == 0)
            {
                return cells;
            }

            foreach (var pair in sectionNumberById)
            {
                if (pair.Key.IsNull || pair.Key.IsErased)
                {
                    continue;
                }

                var section = transaction.GetObject(pair.Key, OpenMode.ForRead) as Polyline;
                if (section == null || !section.Closed || section.NumberOfVertices < 3)
                {
                    continue;
                }

                BuildLsdCellsForSection(section, pair.Value, cells);
            }

            return cells;
        }

        private static void BuildLsdCellsForSection(Polyline section, int sectionNumber, List<LsdCellInfo> destination)
        {
            var outline = GetPolylinePoints(section);
            if (outline.Count < 3)
            {
                return;
            }

            QuarterAnchors anchors;
            if (!TryGetQuarterAnchors(section, out anchors))
            {
                anchors = GetFallbackAnchors(section);
            }

            var eastUnit = GetUnitVector(anchors.Left, anchors.Right, new Vector2d(1, 0));
            var northUnit = GetUnitVector(anchors.Bottom, anchors.Top, new Vector2d(0, 1));

            if (!TryGetQuarterCorner(section, eastUnit, northUnit, QuarterCorner.NorthWest, out var nw) ||
                !TryGetQuarterCorner(section, eastUnit, northUnit, QuarterCorner.NorthEast, out var ne) ||
                !TryGetQuarterCorner(section, eastUnit, northUnit, QuarterCorner.SouthWest, out var sw) ||
                !TryGetQuarterCorner(section, eastUnit, northUnit, QuarterCorner.SouthEast, out var se))
            {
                var ext = section.GeometricExtents;
                sw = new Point2d(ext.MinPoint.X, ext.MinPoint.Y);
                se = new Point2d(ext.MaxPoint.X, ext.MinPoint.Y);
                nw = new Point2d(ext.MinPoint.X, ext.MaxPoint.Y);
                ne = new Point2d(ext.MaxPoint.X, ext.MaxPoint.Y);
            }

            for (var row = 0; row < 4; row++)
            {
                for (var col = 0; col < 4; col++)
                {
                    var u0 = col / 4.0;
                    var u1 = (col + 1) / 4.0;
                    var t0 = row / 4.0;
                    var t1 = (row + 1) / 4.0;

                    var sample = BilinearPoint(sw, se, nw, ne, 0.5 * (u0 + u1), 0.5 * (t0 + t1));
                    var points = new List<Point2d>(outline);

                    var leftSouth = BilinearPoint(sw, se, nw, ne, u0, 0.0);
                    var leftNorth = BilinearPoint(sw, se, nw, ne, u0, 1.0);
                    var rightSouth = BilinearPoint(sw, se, nw, ne, u1, 0.0);
                    var rightNorth = BilinearPoint(sw, se, nw, ne, u1, 1.0);
                    var bottomWest = BilinearPoint(sw, se, nw, ne, 0.0, t0);
                    var bottomEast = BilinearPoint(sw, se, nw, ne, 1.0, t0);
                    var topWest = BilinearPoint(sw, se, nw, ne, 0.0, t1);
                    var topEast = BilinearPoint(sw, se, nw, ne, 1.0, t1);

                    var keepLeft = GetSideSign(leftSouth, leftNorth, sample);
                    var keepRight = GetSideSign(rightSouth, rightNorth, sample);
                    var keepBottom = GetSideSign(bottomWest, bottomEast, sample);
                    var keepTop = GetSideSign(topWest, topEast, sample);

                    if (keepLeft == 0 || keepRight == 0 || keepBottom == 0 || keepTop == 0)
                    {
                        continue;
                    }

                    points = ClipPolygon(points, leftSouth, leftNorth, keepLeft);
                    points = ClipPolygon(points, rightSouth, rightNorth, keepRight);
                    points = ClipPolygon(points, bottomWest, bottomEast, keepBottom);
                    points = ClipPolygon(points, topWest, topEast, keepTop);

                    var cell = BuildPolylineFromPoints(points);
                    if (cell == null)
                    {
                        continue;
                    }

                    var lsd = GetLsdNumber(row, col);
                    destination.Add(new LsdCellInfo(cell, lsd, sectionNumber));
                }
            }
        }

        private static int GetLsdNumber(int rowFromSouth, int colFromWest)
        {
            if ((rowFromSouth % 2) == 0)
            {
                return (rowFromSouth * 4) + (4 - colFromWest);
            }

            return (rowFromSouth * 4) + (colFromWest + 1);
        }

        private static Point2d BilinearPoint(Point2d sw, Point2d se, Point2d nw, Point2d ne, double u, double t)
        {
            var south = sw + ((se - sw) * u);
            var north = nw + ((ne - nw) * u);
            return south + ((north - south) * t);
        }

        private static string GetDominantLsdSectionToken(Polyline disposition, List<LsdCellInfo> lsdCells)
        {
            if (disposition == null || lsdCells == null || lsdCells.Count == 0)
            {
                return string.Empty;
            }

            double bestArea = 0.0;
            int bestLsd = 0;
            int bestSection = 0;

            Extents3d dispExtents;
            try
            {
                dispExtents = disposition.GeometricExtents;
            }
            catch
            {
                return string.Empty;
            }

            foreach (var cell in lsdCells)
            {
                if (cell.Cell == null)
                {
                    continue;
                }

                try
                {
                    if (!GeometryUtils.ExtentsIntersect(dispExtents, cell.Cell.GeometricExtents))
                    {
                        continue;
                    }
                }
                catch
                {
                    // ignore extents failures and try geometric intersection directly
                }

                var overlapArea = GetIntersectionArea(disposition, cell.Cell);
                if (overlapArea > bestArea)
                {
                    bestArea = overlapArea;
                    bestLsd = cell.Lsd;
                    bestSection = cell.Section;
                }
            }

            return bestArea > 1e-6 && bestLsd > 0 && bestSection > 0
                ? $"{bestLsd}-{bestSection}"
                : string.Empty;
        }

        private static List<SectionSpatialInfo> BuildSectionSpatialInfos(Transaction transaction, Dictionary<ObjectId, int> sectionNumberById)
        {
            var infos = new List<SectionSpatialInfo>();
            if (sectionNumberById == null || sectionNumberById.Count == 0)
            {
                return infos;
            }

            foreach (var pair in sectionNumberById)
            {
                if (pair.Key.IsNull || pair.Key.IsErased)
                {
                    continue;
                }

                var section = transaction.GetObject(pair.Key, OpenMode.ForRead) as Polyline;
                if (section == null || !section.Closed || section.NumberOfVertices < 3)
                {
                    continue;
                }

                if (TryCreateSectionSpatialInfo(section, pair.Value, out var info))
                {
                    infos.Add(info);
                }
            }

            return infos;
        }

        private static List<SectionSpatialInfo> LoadSupplementalSectionSpatialInfos(
            IReadOnlyList<SectionRequest> requests,
            Config config,
            Logger logger)
        {
            var infos = new List<SectionSpatialInfo>();
            if (requests == null || requests.Count == 0)
            {
                return infos;
            }

            var searchFolders = BuildSectionIndexSearchFolders(config);
            var townshipKeys = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
            var sectionKeys = new HashSet<string>(StringComparer.OrdinalIgnoreCase);

            foreach (var request in requests)
            {
                var key = request.Key;
                var townshipKey = $"{key.Zone}|{NormalizeNumberToken(key.Meridian)}|{NormalizeNumberToken(key.Range)}|{NormalizeNumberToken(key.Township)}";
                if (!townshipKeys.Add(townshipKey))
                {
                    continue;
                }

                for (var section = 1; section <= 36; section++)
                {
                    var sectionKey = new SectionKey(
                        key.Zone,
                        section.ToString(CultureInfo.InvariantCulture),
                        key.Township,
                        key.Range,
                        key.Meridian);
                    var keyId = BuildSectionKeyId(sectionKey);
                    if (!sectionKeys.Add(keyId))
                    {
                        continue;
                    }

                    if (!TryLoadSectionOutline(searchFolders, sectionKey, logger, out var outline))
                    {
                        continue;
                    }

                    if (TryCreateSectionSpatialInfo(outline, section, out var info))
                    {
                        infos.Add(info);
                    }
                }
            }

            if (infos.Count > 0)
            {
                logger.WriteLine($"Loaded {infos.Count} supplemental section outlines for wellsite section matching.");
            }

            return infos;
        }

        private static bool TryCreateSectionSpatialInfo(
            SectionOutline outline,
            int sectionNumber,
            [NotNullWhen(true)] out SectionSpatialInfo? info)
        {
            info = null;
            if (outline == null || outline.Vertices == null || outline.Vertices.Count < 3)
            {
                return false;
            }

            var section = new Polyline(outline.Vertices.Count)
            {
                Closed = outline.Closed
            };
            for (var i = 0; i < outline.Vertices.Count; i++)
            {
                section.AddVertexAt(i, outline.Vertices[i], 0, 0, 0);
            }

            try
            {
                return TryCreateSectionSpatialInfo(section, sectionNumber, out info);
            }
            finally
            {
                section.Dispose();
            }
        }

        private static bool TryCreateSectionSpatialInfo(
            Polyline section,
            int sectionNumber,
            [NotNullWhen(true)] out SectionSpatialInfo? info)
        {
            info = null;
            var clone = section.Clone() as Polyline;
            if (clone == null)
            {
                return false;
            }

            try
            {
                QuarterAnchors anchors;
                if (!TryGetQuarterAnchors(clone, out anchors))
                {
                    anchors = GetFallbackAnchors(clone);
                }

                var eastUnit = GetUnitVector(anchors.Left, anchors.Right, new Vector2d(1, 0));
                var northUnit = GetUnitVector(anchors.Bottom, anchors.Top, new Vector2d(0, 1));

                if (!TryGetQuarterCorner(clone, eastUnit, northUnit, QuarterCorner.SouthWest, out var sw) ||
                    !TryGetQuarterCorner(clone, eastUnit, northUnit, QuarterCorner.SouthEast, out var se) ||
                    !TryGetQuarterCorner(clone, eastUnit, northUnit, QuarterCorner.NorthWest, out var nw))
                {
                    var ext = clone.GeometricExtents;
                    sw = new Point2d(ext.MinPoint.X, ext.MinPoint.Y);
                    se = new Point2d(ext.MaxPoint.X, ext.MinPoint.Y);
                    nw = new Point2d(ext.MinPoint.X, ext.MaxPoint.Y);
                }

                var width = Math.Abs((se - sw).DotProduct(eastUnit));
                var height = Math.Abs((nw - sw).DotProduct(northUnit));
                if (width <= 1e-6 || height <= 1e-6)
                {
                    clone.Dispose();
                    return false;
                }

                info = new SectionSpatialInfo(clone, sectionNumber, sw, eastUnit, northUnit, width, height);
                return true;
            }
            catch
            {
                clone.Dispose();
                return false;
            }
        }

        private static string GetDominantLsdSectionTokenBySection(Polyline disposition, List<SectionSpatialInfo> sections)
        {
            if (disposition == null || sections == null || sections.Count == 0)
            {
                return string.Empty;
            }

            SectionSpatialInfo? best = null;
            double bestArea = 0.0;

            foreach (var section in sections)
            {
                var area = GetIntersectionArea(disposition, section.SectionPolyline);
                if (area > bestArea)
                {
                    bestArea = area;
                    best = section;
                }
            }

            if (best == null || bestArea <= 1e-6)
            {
                return string.Empty;
            }

            if (!TryGetRepresentativePointInSection(disposition, best.SectionPolyline, out var point))
            {
                return string.Empty;
            }

            var rowCol = GetLsdRowCol(point, best);
            if (rowCol == null)
            {
                return string.Empty;
            }

            var lsd = GetLsdNumber(rowCol.Value.row, rowCol.Value.col);
            return (lsd > 0 && best.Section > 0) ? $"{lsd}-{best.Section}" : string.Empty;
        }

        private static bool TryGetRepresentativePointInSection(Polyline disposition, Polyline section, out Point2d point)
        {
            point = default;
            if (disposition == null || section == null)
            {
                return false;
            }

            if (GeometryUtils.TryIntersectPolylines(disposition, section, out var pieces) && pieces.Count > 0)
            {
                Polyline? best = null;
                double bestArea = 0.0;
                foreach (var p in pieces)
                {
                    double area = 0.0;
                    try { area = Math.Abs(p.Area); } catch { }
                    if (area > bestArea)
                    {
                        best?.Dispose();
                        best = p;
                        bestArea = area;
                    }
                    else
                    {
                        p.Dispose();
                    }
                }

                if (best != null)
                {
                    try
                    {
                        point = GeometryUtils.GetSafeInteriorPoint(best);
                        return true;
                    }
                    finally
                    {
                        best.Dispose();
                    }
                }
            }

            return false;
        }

        private static (int row, int col)? GetLsdRowCol(Point2d point, SectionSpatialInfo section)
        {
            var v = point - section.SouthWest;
            var u = v.DotProduct(section.EastUnit) / section.Width;
            var t = v.DotProduct(section.NorthUnit) / section.Height;

            if (double.IsNaN(u) || double.IsInfinity(u) || double.IsNaN(t) || double.IsInfinity(t))
            {
                return null;
            }

            u = Math.Max(0.0, Math.Min(0.999999, u));
            t = Math.Max(0.0, Math.Min(0.999999, t));

            var col = (int)Math.Floor(u * 4.0);
            var row = (int)Math.Floor(t * 4.0);

            if (col < 0 || col > 3 || row < 0 || row > 3)
            {
                return null;
            }

            return (row, col);
        }

        private static string GetSectionOverlapDebugString(Polyline disposition, List<SectionSpatialInfo> sections)
        {
            if (disposition == null || sections == null || sections.Count == 0)
            {
                return "(no section infos)";
            }

            var rows = new List<(int section, double area)>();
            foreach (var section in sections)
            {
                var area = GetIntersectionArea(disposition, section.SectionPolyline);
                if (area > 1e-6)
                {
                    rows.Add((section.Section, area));
                }
            }

            if (rows.Count == 0)
            {
                return "(no overlaps > 0)";
            }

            rows.Sort((a, b) => b.area.CompareTo(a.area));
            var top = rows.Take(3).Select(r => $"SEC{r.section}={r.area:0.###}");
            return string.Join(", ", top);
        }

        private static string GetPointBasedLsdSectionToken(Polyline disposition, List<SectionSpatialInfo> sections, out string debug)
        {
            debug = "no-sections";
            if (disposition == null || sections == null || sections.Count == 0)
            {
                return string.Empty;
            }

            var samplePoints = new List<Point2d>();
            try
            {
                samplePoints.Add(GeometryUtils.GetSafeInteriorPoint(disposition));
            }
            catch
            {
                // ignore
            }

            for (var i = 0; i < disposition.NumberOfVertices; i++)
            {
                samplePoints.Add(disposition.GetPoint2dAt(i));
            }

            if (samplePoints.Count == 0)
            {
                debug = "no-samples";
                return string.Empty;
            }

            SectionSpatialInfo? bestSection = null;
            int bestHits = -1;
            Point2d bestPoint = default;

            foreach (var section in sections)
            {
                int hits = 0;
                Point2d firstHit = default;
                bool hasFirst = false;

                foreach (var p in samplePoints)
                {
                    if (GeometryUtils.IsPointInsidePolyline(section.SectionPolyline, p))
                    {
                        hits++;
                        if (!hasFirst)
                        {
                            firstHit = p;
                            hasFirst = true;
                        }
                    }
                }

                if (hits > bestHits)
                {
                    bestHits = hits;
                    bestSection = section;
                    bestPoint = hasFirst ? firstHit : samplePoints[0];
                }
            }

            if (bestSection == null || bestHits <= 0)
            {
                debug = "no-section-hit";
                return string.Empty;
            }

            var rowCol = GetLsdRowCol(bestPoint, bestSection);
            if (rowCol == null)
            {
                debug = $"section={bestSection.Section} hits={bestHits} rowcol=none";
                return string.Empty;
            }

            var lsd = GetLsdNumber(rowCol.Value.row, rowCol.Value.col);
            debug = $"section={bestSection.Section} hits={bestHits} point=({bestPoint.X:0.###},{bestPoint.Y:0.###}) row={rowCol.Value.row} col={rowCol.Value.col} lsd={lsd}";
            return (lsd > 0 && bestSection.Section > 0) ? $"{lsd}-{bestSection.Section}" : string.Empty;
        }

        private static double GetIntersectionArea(Polyline a, Polyline b)
        {
            if (a == null || b == null)
            {
                return 0.0;
            }

            if (!GeometryUtils.TryIntersectPolylines(a, b, out var pieces) || pieces == null || pieces.Count == 0)
            {
                return 0.0;
            }

            double area = 0.0;
            foreach (var piece in pieces)
            {
                try
                {
                    area += Math.Abs(piece.Area);
                }
                catch
                {
                    // ignore individual piece area failures
                }
                finally
                {
                    piece.Dispose();
                }
            }

            return area;
        }

        private static void DisposeLsdCells(List<LsdCellInfo> cells)
        {
            if (cells == null)
            {
                return;
            }

            foreach (var cell in cells)
            {
                try
                {
                    cell.Cell?.Dispose();
                }
                catch
                {
                    // ignore cleanup failures
                }
            }
        }

        private static void DisposeSectionInfos(List<SectionSpatialInfo> infos)
        {
            if (infos == null)
            {
                return;
            }

            foreach (var info in infos)
            {
                try
                {
                    info.SectionPolyline?.Dispose();
                }
                catch
                {
                    // ignore cleanup failures
                }
            }
        }

        private static IEnumerable<Polyline> GenerateQuarters(Polyline section)
        {
            var extents = section.GeometricExtents;
            var minX = extents.MinPoint.X;
            var minY = extents.MinPoint.Y;
            var maxX = extents.MaxPoint.X;
            var maxY = extents.MaxPoint.Y;
            var midX = (minX + maxX) / 2.0;
            var midY = (minY + maxY) / 2.0;

            yield return CreateRectangle(minX, minY, midX, midY);
            yield return CreateRectangle(midX, minY, maxX, midY);
            yield return CreateRectangle(minX, midY, midX, maxY);
            yield return CreateRectangle(midX, midY, maxX, maxY);
        }

        private static Polyline CreateRectangle(double minX, double minY, double maxX, double maxY)
        {
            var polyline = new Polyline(4)
            {
                Closed = true
            };

            polyline.AddVertexAt(0, new Point2d(minX, minY), 0, 0, 0);
            polyline.AddVertexAt(1, new Point2d(maxX, minY), 0, 0, 0);
            polyline.AddVertexAt(2, new Point2d(maxX, maxY), 0, 0, 0);
            polyline.AddVertexAt(3, new Point2d(minX, maxY), 0, 0, 0);

            return polyline;
        }

        private static SectionDrawResult DrawSectionsFromRequests(
            Editor editor,
            Database database,
            List<SectionRequest> requests,
            Config config,
            Logger logger,
            bool drawLsds)
        {
            var timer = Stopwatch.StartNew();
            if (logger == null)
            {
                throw new ArgumentNullException(nameof(logger));
            }
            // We always draw the full section outline (ATS fabric on) but may label only specific quarters.
            var labelQuarterIds = new HashSet<ObjectId>();
            var labelQuarterInfos = new List<QuarterLabelInfo>();
            var lsdQuarterInfos = new List<QuarterLabelInfo>();
            var lsdQuarterInfoIds = new HashSet<ObjectId>();
            var allQuarterIds = new HashSet<ObjectId>();
            var quarterHelperIds = new HashSet<ObjectId>();
            var sectionLabelIds = new HashSet<ObjectId>();
            var sectionIds = new HashSet<ObjectId>();
            var contextSectionIds = new HashSet<ObjectId>();
            var contextRuleSectionInfos = new List<QuarterLabelInfo>();
            var contextSectionOutlineHelperIds = new List<ObjectId>();
            var sectionNumberById = new Dictionary<ObjectId, int>();
            var createdSections = new Dictionary<string, SectionBuildResult>(StringComparer.OrdinalIgnoreCase);
            var createdSectionQuarterSecTypes = new Dictionary<string, Dictionary<QuarterSelection, string>>(StringComparer.OrdinalIgnoreCase);
            var searchFolders = BuildSectionIndexSearchFolders(config);
            var inferredSecTypes = InferSectionTypes(requests, searchFolders, logger);
            var inferredQuarterSecTypes = InferQuarterSectionTypes(requests, searchFolders, logger);
            logger.WriteLine($"TIMING DrawSectionsFromRequests: inference completed in {timer.ElapsedMilliseconds} ms");

            foreach (var request in requests)
            {
                var keyId = BuildSectionKeyId(request.Key);
                var resolvedSecType = ResolveSectionType(request.Key, request.SecType, inferredSecTypes);
                Dictionary<QuarterSelection, string>? resolvedQuarterSecTypes = null;
                if (!createdSections.TryGetValue(keyId, out var buildResult))
                {
                    if (!TryLoadSectionOutline(searchFolders, request.Key, logger, out var outline))
                    {
                        continue;
                    }

                    resolvedQuarterSecTypes = ResolveQuarterSectionTypes(request.Key, resolvedSecType, inferredQuarterSecTypes);
                    buildResult = DrawSectionFromIndex(editor, database, outline, request.Key, drawLsds, resolvedSecType, resolvedQuarterSecTypes);
                    createdSections[keyId] = buildResult;
                    createdSectionQuarterSecTypes[keyId] = resolvedQuarterSecTypes;
                    sectionIds.Add(buildResult.SectionPolylineId);
                    sectionNumberById[buildResult.SectionPolylineId] = ParseSectionNumber(request.Key.Section);
                }
                else if (!createdSectionQuarterSecTypes.TryGetValue(keyId, out resolvedQuarterSecTypes))
                {
                    resolvedQuarterSecTypes = ResolveQuarterSectionTypes(request.Key, resolvedSecType, inferredQuarterSecTypes);
                    createdSectionQuarterSecTypes[keyId] = resolvedQuarterSecTypes;
                }

                if (resolvedQuarterSecTypes == null)
                {
                    resolvedQuarterSecTypes = ResolveQuarterSectionTypes(request.Key, resolvedSecType, inferredQuarterSecTypes);
                    createdSectionQuarterSecTypes[keyId] = resolvedQuarterSecTypes;
                }

                // Track all quarter geometry we created (always removed during cleanup).
                foreach (var quarterId in buildResult.QuarterPolylineIds.Values)
                    allQuarterIds.Add(quarterId);
                foreach (var pair in buildResult.QuarterPolylineIds)
                {
                    if (!lsdQuarterInfoIds.Add(pair.Value))
                    {
                        continue;
                    }

                    var quarterSecType = ResolveQuarterSecTypeForQuarter(resolvedQuarterSecTypes, pair.Key, resolvedSecType);
                    lsdQuarterInfos.Add(new QuarterLabelInfo(pair.Value, request.Key, pair.Key, quarterSecType, buildResult.SectionPolylineId));
                }

                foreach (var helperId in buildResult.QuarterHelperEntityIds)
                    quarterHelperIds.Add(helperId);

                if (!buildResult.SectionLabelEntityId.IsNull)
                    sectionLabelIds.Add(buildResult.SectionLabelEntityId);

                // Track the quarters that should actually be labelled.
                foreach (var quarter in ExpandQuarterSelections(request.Quarter))
                {
                    if (buildResult.QuarterPolylineIds.TryGetValue(quarter, out var qid))
                    {
                        if (labelQuarterIds.Add(qid))
                        {
                            var quarterSecType = ResolveQuarterSecTypeForQuarter(resolvedQuarterSecTypes, quarter, resolvedSecType);
                            labelQuarterInfos.Add(new QuarterLabelInfo(qid, request.Key, quarter, quarterSecType, buildResult.SectionPolylineId));
                        }
                    }
                }
            }

            logger.WriteLine($"TIMING DrawSectionsFromRequests: requested sections drawn in {timer.ElapsedMilliseconds} ms");

            var requestedScopeIds = new HashSet<ObjectId>(sectionIds.Where(id => !id.IsNull));
            if (requestedScopeIds.Count == 0)
            {
                foreach (var qid in labelQuarterIds)
                {
                    if (!qid.IsNull)
                    {
                        requestedScopeIds.Add(qid);
                    }
                }
            }

            foreach (var id in DrawAdjoiningSectionsForContext(
                database,
                searchFolders,
                requests,
                requestedScopeIds,
                inferredSecTypes,
                inferredQuarterSecTypes,
                logger,
                contextRuleSectionInfos,
                contextSectionOutlineHelperIds))
            {
                contextSectionIds.Add(id);
            }

            foreach (var id in contextSectionOutlineHelperIds)
            {
                if (!id.IsNull)
                {
                    allQuarterIds.Add(id);
                }
            }

            var ruleScopeIds = new HashSet<ObjectId>(requestedScopeIds);
            foreach (var contextOutlineId in contextSectionOutlineHelperIds)
            {
                if (!contextOutlineId.IsNull)
                {
                    ruleScopeIds.Add(contextOutlineId);
                }
            }

            CleanupContextSectionOverlaps(database, contextSectionIds, logger);
            logger.WriteLine("Cleanup: deferred context 100m trim until final geometry stage.");
            logger.WriteLine($"TIMING DrawSectionsFromRequests: context sections staged in {timer.ElapsedMilliseconds} ms");

            var generatedRoadAllowanceIds = new HashSet<ObjectId>();
            var activeSectionKeyIds = new HashSet<string>(
                requests.Select(r => BuildSectionKeyId(r.Key)),
                StringComparer.OrdinalIgnoreCase);
            foreach (var contextInfo in contextRuleSectionInfos)
            {
                if (contextInfo == null)
                {
                    continue;
                }

                activeSectionKeyIds.Add(BuildSectionKeyId(contextInfo.SectionKey));
            }

            foreach (var id in DrawRoadAllowanceGapOffsetLines(
                database,
                searchFolders,
                requests,
                ruleScopeIds,
                inferredSecTypes,
                inferredQuarterSecTypes,
                logger,
                activeSectionKeyIds))
            {
                quarterHelperIds.Add(id);
                generatedRoadAllowanceIds.Add(id);
            }

            // Canonical simplified road-allowance mode:
            // - never move existing lines
            // - only add 20.11 connector extensions to satisfy orthogonal endpoint rules
            // - keep 30.17 as generated (no endpoint extension pass)
            logger.WriteLine("Cleanup: canonical RA mode enabled; legacy RA extension/move passes are skipped.");
            CleanupGeneratedRoadAllowanceOverlaps(database, generatedRoadAllowanceIds, logger);
            var sectionNumberByPolylineIdForUsec = new Dictionary<ObjectId, int>(sectionNumberById);
            foreach (var sectionInfo in contextRuleSectionInfos)
            {
                if (sectionInfo == null || sectionInfo.SectionPolylineId.IsNull)
                {
                    continue;
                }

                var sectionNumber = ParseSectionNumber(sectionInfo.SectionKey.Section);
                sectionNumberByPolylineIdForUsec[sectionInfo.SectionPolylineId] = sectionNumber;
            }

            NormalizeUsecLayersToThreeBands(
                database,
                ruleScopeIds,
                sectionNumberByPolylineIdForUsec,
                generatedRoadAllowanceIds,
                logger);
            var quarterInfosForRoadAllowanceRules = labelQuarterInfos
                .Concat(contextRuleSectionInfos)
                .Where(info => info != null)
                .ToList();
            ConnectUsecSeSouthTwentyTwelveLinesToEastOriginalBoundary(
                database,
                searchFolders,
                quarterInfosForRoadAllowanceRules,
                generatedRoadAllowanceIds,
                logger);
            CleanupDuplicateBlindLineSegments(database, ruleScopeIds, logger);
            logger.WriteLine("Cleanup: context 100m trim deferred to final stage; context snap/stitch/seam-heal passes skipped in canonical RA mode.");
            NormalizeGeneratedRoadAllowanceLayers(database, generatedRoadAllowanceIds, logger);
            NormalizeShortRoadAllowanceLayersByNeighborhood(database, ruleScopeIds, generatedRoadAllowanceIds, logger);
            NormalizeHorizontalSecRoadAllowanceLayers(database, ruleScopeIds, generatedRoadAllowanceIds, logger);
            NormalizeBottomTownshipBoundaryLayers(database, ruleScopeIds, generatedRoadAllowanceIds, logger);
            NormalizeThirtyEighteenCorridorLayers(database, ruleScopeIds, logger);
            // TODO: unresolved WIP - R/A layer mix/match still occurs on corridors perpendicular
            // to township/range switch boundaries. Keep disabled range-edge relayer until deterministic fix.
            CleanupDuplicateBlindLineSegments(database, ruleScopeIds, logger);
            logger.WriteLine("Cleanup: legacy SW/NW/simple-west/stop-rule passes skipped in canonical RA mode; SE east-boundary bridge pass enabled.");
            NormalizeBlindLineLayersBySecConnections(database, ruleScopeIds, logger);
            NormalizeUsecLayersToThreeBands(
                database,
                ruleScopeIds,
                sectionNumberByPolylineIdForUsec,
                generatedRoadAllowanceIds,
                logger);
            NormalizeUsecCollinearComponentLayerConsistency(
                database,
                ruleScopeIds,
                sectionNumberByPolylineIdForUsec,
                logger);
            NormalizeWestRoadAllowanceBandsForKnownSections(
                database,
                ruleScopeIds,
                sectionNumberByPolylineIdForUsec,
                logger);
            NormalizeUsecLayersBySectionEdgeOffsets(
                database,
                ruleScopeIds,
                sectionNumberByPolylineIdForUsec,
                logger);
            logger.WriteLine("Cleanup: context endpoint snap/stitch disabled (context is build-adjoining + 100m trim only).");
            TrimContextSectionsToBufferedWindows(database, contextSectionIds, requestedScopeIds, logger);
            if (generatedRoadAllowanceIds.Count > 0)
            {
                // "Build first, trim last": generated RA lines are now trimmed in the final stage
                // so surrounding-context behavior matches regular section construction.
                TrimContextSectionsToBufferedWindows(database, generatedRoadAllowanceIds.ToHashSet(), requestedScopeIds, logger);
            }
            // Keep final endpoint correction narrow and deterministic:
            // enforce only explicit 0/20 dangling-to-3018 cleanup after final trim.
            ConnectDanglingUsecZeroTwentyEndpoints(database, requestedScopeIds, logger);
            // Final deterministic relayer + reconnect pass after endpoint moves keeps
            // 0/20/30 assignment and cross-intersection continuity consistent on partial builds.
            NormalizeUsecLayersBySectionEdgeOffsets(
                database,
                ruleScopeIds,
                sectionNumberByPolylineIdForUsec,
                logger);
            ConnectDanglingUsecZeroTwentyEndpoints(database, requestedScopeIds, logger);
            RebuildLsdLabelsAtFinalIntersections(database, lsdQuarterInfos, logger);
            logger.WriteLine($"TIMING DrawSectionsFromRequests: road allowances processed in {timer.ElapsedMilliseconds} ms");

            if (EnableBufferedQuarterWindowDrawing)
            {
                DrawBufferedQuarterWindowsOnDefpoints(database, requestedScopeIds, 100.0, logger);
            }
            else
            {
                logger.WriteLine("DEFPOINTS 100m buffer drawing skipped (ATSBUILD_DRAW_100M_BUFFER != 1).");
            }
            logger.WriteLine($"TIMING DrawSectionsFromRequests: total {timer.ElapsedMilliseconds} ms");

            return new SectionDrawResult(
                labelQuarterIds.ToList(),
                labelQuarterInfos,
                allQuarterIds.ToList(),
                quarterHelperIds.ToList(),
                sectionIds.ToList(),
                contextSectionIds.ToList(),
                sectionLabelIds.ToList(),
                sectionNumberById,
                true);
        }

        private static List<ObjectId> DrawAdjoiningSectionsForContext(
            Database database,
            IReadOnlyList<string> searchFolders,
            IReadOnlyList<SectionRequest> requests,
            IEnumerable<ObjectId> requestedQuarterIds,
            IReadOnlyDictionary<string, string> inferredSecTypes,
            IReadOnlyDictionary<string, string> inferredQuarterSecTypes,
            Logger logger,
            List<QuarterLabelInfo>? contextRuleSectionInfos = null,
            List<ObjectId>? contextSectionOutlineHelperIds = null)
        {
            var drawnIds = new List<ObjectId>();
            if (database == null || searchFolders == null || requests == null || requestedQuarterIds == null)
            {
                return drawnIds;
            }

            var rawClipWindows = BuildBufferedQuarterWindows(database, requestedQuarterIds, 100.0);
            var clipWindows = MergeOverlappingClipWindows(rawClipWindows);
            if (clipWindows.Count == 0)
            {
                return drawnIds;
            }

            bool IntersectsAnyClipWindow(Extents3d extents)
            {
                for (var wi = 0; wi < clipWindows.Count; wi++)
                {
                    if (GeometryUtils.ExtentsIntersect(extents, clipWindows[wi]))
                    {
                        return true;
                    }
                }

                return false;
            }

            string BuildGridKey(int zone, string meridian, int globalX, int globalY)
            {
                return string.Format(
                    CultureInfo.InvariantCulture,
                    "{0}|{1}|{2}|{3}",
                    zone,
                    NormalizeNumberToken(meridian),
                    globalX,
                    globalY);
            }

            var requestedGridKeys = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
            foreach (var request in requests)
            {
                if (request == null ||
                    !TryParsePositiveToken(request.Key.Range, out var rangeNum) ||
                    !TryParsePositiveToken(request.Key.Township, out var townshipNum))
                {
                    continue;
                }

                var sectionNumber = ParseSectionNumber(request.Key.Section);
                if (!TryGetAtsSectionGridPosition(sectionNumber, out var row, out var col))
                {
                    continue;
                }

                var globalX = (-rangeNum * 6) + col;
                var globalY = (townshipNum * 6) + (5 - row);
                requestedGridKeys.Add(BuildGridKey(request.Key.Zone, request.Key.Meridian, globalX, globalY));
            }

            var requestedSectionKeys = new HashSet<string>(
                requests.Select(r => BuildSectionKeyId(r.Key)),
                StringComparer.OrdinalIgnoreCase);

            var townshipKeys = BuildContextTownshipKeys(requests).ToList();

            var processedSections = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
            using (var tr = database.TransactionManager.StartTransaction())
            {
                var blockTable = (BlockTable)tr.GetObject(database.BlockTableId, OpenMode.ForRead);
                var modelSpace = (BlockTableRecord)tr.GetObject(blockTable[BlockTableRecord.ModelSpace], OpenMode.ForWrite);
                EnsureLayer(database, tr, "L-QSEC");
                EnsureLayer(database, tr, "L-QSEC-BOX");
                SetLayerVisibility(database, tr, "L-QSEC-BOX", isOff: true, isPlottable: false);
                foreach (var townshipKey in townshipKeys)
                {
                    if (!TryParseTownshipKey(townshipKey, out var zone, out var meridian, out var range, out var township))
                    {
                        continue;
                    }

                    for (var section = 1; section <= 36; section++)
                    {
                        var key = new SectionKey(zone, section.ToString(CultureInfo.InvariantCulture), township, range, meridian);
                        var keyId = BuildSectionKeyId(key);
                        if (requestedSectionKeys.Contains(keyId) || !processedSections.Add(keyId))
                        {
                            continue;
                        }

                        if (!TryLoadSectionOutline(searchFolders, key, logger, out var outline))
                        {
                            continue;
                        }

                        using (var sectionPolyline = new Polyline(outline.Vertices.Count))
                        {
                            sectionPolyline.Closed = outline.Closed;
                            for (var i = 0; i < outline.Vertices.Count; i++)
                            {
                                sectionPolyline.AddVertexAt(i, outline.Vertices[i], 0, 0, 0);
                            }

                            if (!IntersectsAnyClipWindow(sectionPolyline.GeometricExtents))
                            {
                                continue;
                            }

                            if (requestedGridKeys.Count > 0 &&
                                TryParsePositiveToken(range, out var rangeNum) &&
                                TryParsePositiveToken(township, out var townshipNum) &&
                                TryGetAtsSectionGridPosition(section, out var row, out var col))
                            {
                                var globalX = (-rangeNum * 6) + col;
                                var globalY = (townshipNum * 6) + (5 - row);
                                var adjoiningRequested = false;
                                for (var dx = -1; dx <= 1 && !adjoiningRequested; dx++)
                                {
                                    for (var dy = -1; dy <= 1; dy++)
                                    {
                                        if (dx == 0 && dy == 0)
                                        {
                                            continue;
                                        }

                                        if (!requestedGridKeys.Contains(BuildGridKey(zone, meridian, globalX + dx, globalY + dy)))
                                        {
                                            continue;
                                        }

                                        adjoiningRequested = true;
                                        break;
                                    }
                                }

                                if (!adjoiningRequested)
                                {
                                    continue;
                                }
                            }

                            if (!TryGetQuarterAnchors(sectionPolyline, out var anchors))
                            {
                                anchors = GetFallbackAnchors(sectionPolyline);
                            }

                            var eastUnit = GetUnitVector(anchors.Left, anchors.Right, new Vector2d(1, 0));
                            var northUnit = GetUnitVector(anchors.Bottom, anchors.Top, new Vector2d(0, 1));
                            if (!TryGetQuarterCorner(sectionPolyline, eastUnit, northUnit, QuarterCorner.NorthWest, out var nw) ||
                                !TryGetQuarterCorner(sectionPolyline, eastUnit, northUnit, QuarterCorner.NorthEast, out var ne) ||
                                !TryGetQuarterCorner(sectionPolyline, eastUnit, northUnit, QuarterCorner.SouthWest, out var sw) ||
                                !TryGetQuarterCorner(sectionPolyline, eastUnit, northUnit, QuarterCorner.SouthEast, out var se))
                            {
                                continue;
                            }

                            var secType = ResolveSectionType(key, "AUTO", inferredSecTypes);
                            var quarterSecTypes = ResolveQuarterSectionTypes(key, secType, inferredQuarterSecTypes);
                            EnsureSecTypeLayers(database, tr, secType, quarterSecTypes);

                            var helperSection = (Polyline)sectionPolyline.Clone();
                            helperSection.Layer = "L-QSEC-BOX";
                            helperSection.ColorIndex = 256;
                            var helperSectionId = modelSpace.AppendEntity(helperSection);
                            tr.AddNewlyCreatedDBObject(helperSection, true);
                            contextSectionOutlineHelperIds?.Add(helperSectionId);
                            contextRuleSectionInfos?.Add(new QuarterLabelInfo(
                                helperSectionId,
                                key,
                                QuarterSelection.SouthEast,
                                secType,
                                helperSectionId));

                            foreach (var id in DrawSectionBoundaryQuarterSegmentPolylines(
                                modelSpace,
                                tr,
                                nw,
                                ne,
                                sw,
                                se,
                                secType,
                                quarterSecTypes,
                                clipToWindow: null,
                                anchors.Top,
                                anchors.Right,
                                anchors.Bottom,
                                anchors.Left))
                            {
                                drawnIds.Add(id);
                            }

                            foreach (var id in DrawClippedQuarterDividerLinesForContext(
                                modelSpace,
                                tr,
                                anchors.Top,
                                anchors.Bottom,
                                anchors.Left,
                                anchors.Right,
                                Array.Empty<Extents3d>()))
                            {
                                drawnIds.Add(id);
                            }
                        }
                    }
                }

                tr.Commit();
            }

            if (drawnIds.Count > 0)
            {
                logger?.WriteLine($"Context sections drawn: {drawnIds.Count} piece(s) before final 100m trim.");
            }

            return drawnIds;
        }

        private static List<ObjectId> DrawClippedQuarterDividerLinesForContext(
            BlockTableRecord modelSpace,
            Transaction transaction,
            Point2d top,
            Point2d bottom,
            Point2d left,
            Point2d right,
            IReadOnlyList<Extents3d> clipWindows)
        {
            var ids = new List<ObjectId>();
            if (modelSpace == null || transaction == null)
            {
                return ids;
            }

            var segments = new[]
            {
                (A: top, B: bottom),
                (A: left, B: right)
            };

            var dedupe = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
            foreach (var seg in segments)
            {
                if (clipWindows == null || clipWindows.Count == 0)
                {
                    if (!TryClipSegmentToWindow(seg.A, seg.B, (Extents3d?)null, out var a, out var b))
                    {
                        continue;
                    }

                    var line = new Line(new Point3d(a.X, a.Y, 0.0), new Point3d(b.X, b.Y, 0.0))
                    {
                        Layer = "L-QSEC",
                        ColorIndex = 256
                    };
                    var id = modelSpace.AppendEntity(line);
                    transaction.AddNewlyCreatedDBObject(line, true);
                    ids.Add(id);
                    continue;
                }

                foreach (var win in clipWindows)
                {
                    if (!TryClipSegmentToWindow(seg.A, seg.B, win, out var a, out var b))
                    {
                        continue;
                    }

                    var p0 = a;
                    var p1 = b;
                    if (p1.X < p0.X || (Math.Abs(p1.X - p0.X) <= 1e-9 && p1.Y < p0.Y))
                    {
                        var tmp = p0;
                        p0 = p1;
                        p1 = tmp;
                    }

                    var key = string.Format(
                        CultureInfo.InvariantCulture,
                        "{0:0.###},{1:0.###},{2:0.###},{3:0.###}",
                        p0.X, p0.Y, p1.X, p1.Y);
                    if (!dedupe.Add(key))
                    {
                        continue;
                    }

                    var line = new Line(new Point3d(a.X, a.Y, 0.0), new Point3d(b.X, b.Y, 0.0))
                    {
                        Layer = "L-QSEC",
                        ColorIndex = 256
                    };
                    var id = modelSpace.AppendEntity(line);
                    transaction.AddNewlyCreatedDBObject(line, true);
                    ids.Add(id);
                }
            }

            return ids;
        }

        private static bool TryGetBufferedQuarterWindow(
            Database database,
            IEnumerable<ObjectId> quarterIds,
            double buffer,
            out Extents3d window)
        {
            window = default;
            var windows = BuildBufferedQuarterWindows(database, quarterIds, buffer);
            if (windows.Count == 0)
            {
                return false;
            }

            window = UnionExtents3d(windows);
            return true;
        }

        private static List<Extents3d> BuildBufferedQuarterWindows(
            Database database,
            IEnumerable<ObjectId> quarterIds,
            double buffer)
        {
            var windows = new List<Extents3d>();
            if (database == null || quarterIds == null)
            {
                return windows;
            }

            using (var tr = database.TransactionManager.StartTransaction())
            {
                foreach (var id in quarterIds.Distinct())
                {
                    if (id.IsNull || id.IsErased)
                    {
                        continue;
                    }

                    if (!(tr.GetObject(id, OpenMode.ForRead, false) is Polyline poly))
                    {
                        continue;
                    }

                    try
                    {
                        var ext = poly.GeometricExtents;
                        windows.Add(new Extents3d(
                            new Point3d(ext.MinPoint.X - buffer, ext.MinPoint.Y - buffer, 0.0),
                            new Point3d(ext.MaxPoint.X + buffer, ext.MaxPoint.Y + buffer, 0.0)));
                    }
                    catch
                    {
                    }
                }

                tr.Commit();
            }

            return windows;
        }

        private static Extents3d UnionExtents3d(IReadOnlyList<Extents3d> windows)
        {
            var union = windows[0];
            for (var i = 1; i < windows.Count; i++)
            {
                union.AddExtents(windows[i]);
            }

            return union;
        }

        private static bool DoExtentsOverlapOrTouch(Extents3d a, Extents3d b, double tolerance)
        {
            return a.MinPoint.X <= (b.MaxPoint.X + tolerance) &&
                   a.MaxPoint.X >= (b.MinPoint.X - tolerance) &&
                   a.MinPoint.Y <= (b.MaxPoint.Y + tolerance) &&
                   a.MaxPoint.Y >= (b.MinPoint.Y - tolerance);
        }

        private static List<Extents3d> MergeOverlappingClipWindows(IReadOnlyList<Extents3d> windows)
        {
            var result = new List<Extents3d>();
            if (windows == null || windows.Count == 0)
            {
                return result;
            }

            const double toleranceMeters = 0.01;

            static bool ContainsExtents(Extents3d outer, Extents3d inner, double tolerance)
            {
                return outer.MinPoint.X <= (inner.MinPoint.X + tolerance) &&
                       outer.MinPoint.Y <= (inner.MinPoint.Y + tolerance) &&
                       outer.MaxPoint.X >= (inner.MaxPoint.X - tolerance) &&
                       outer.MaxPoint.Y >= (inner.MaxPoint.Y - tolerance);
            }

            static bool ExtentsNearEqual(Extents3d a, Extents3d b, double tolerance)
            {
                return Math.Abs(a.MinPoint.X - b.MinPoint.X) <= tolerance &&
                       Math.Abs(a.MinPoint.Y - b.MinPoint.Y) <= tolerance &&
                       Math.Abs(a.MaxPoint.X - b.MaxPoint.X) <= tolerance &&
                       Math.Abs(a.MaxPoint.Y - b.MaxPoint.Y) <= tolerance;
            }

            foreach (var window in windows)
            {
                var skip = false;
                for (var i = result.Count - 1; i >= 0; i--)
                {
                    if (ContainsExtents(result[i], window, toleranceMeters) ||
                        ExtentsNearEqual(result[i], window, toleranceMeters))
                    {
                        skip = true;
                        break;
                    }

                    if (ContainsExtents(window, result[i], toleranceMeters))
                    {
                        result.RemoveAt(i);
                    }
                }

                if (!skip)
                {
                    result.Add(window);
                }
            }

            return result;
        }

        private static List<ObjectId> DrawRoadAllowanceGapOffsetLines(
            Database database,
            IReadOnlyList<string> searchFolders,
            IReadOnlyList<SectionRequest> requests,
            IEnumerable<ObjectId> requestedQuarterIds,
            IReadOnlyDictionary<string, string> inferredSecTypes,
            IReadOnlyDictionary<string, string> inferredQuarterSecTypes,
            Logger logger,
            IReadOnlyCollection<string>? activeSectionKeyIds = null)
        {
            var ids = new List<ObjectId>();
            if (database == null || searchFolders == null || requests == null || requestedQuarterIds == null)
            {
                return ids;
            }

            var rawClipWindows = BuildBufferedQuarterWindows(database, requestedQuarterIds, 100.0);
            var clipWindows = MergeOverlappingClipWindows(rawClipWindows);
            if (clipWindows.Count == 0)
            {
                return ids;
            }
            if (EnableRoadAllowanceDiagnostics)
            {
                logger?.WriteLine(RaDiagBuildTag);
                logger?.WriteLine($"RA-DIAG clip windows: raw={rawClipWindows.Count}, merged={clipWindows.Count}");
            }

            var selectedSectionKeyIds = activeSectionKeyIds != null && activeSectionKeyIds.Count > 0
                ? new HashSet<string>(activeSectionKeyIds.Where(k => !string.IsNullOrWhiteSpace(k)), StringComparer.OrdinalIgnoreCase)
                : new HashSet<string>(
                    requests.Select(r => BuildSectionKeyId(r.Key)),
                    StringComparer.OrdinalIgnoreCase);

            var contextTownshipKeys = BuildContextTownshipKeys(requests);
            var secTypeLookup = inferredSecTypes ??
                new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
            var quarterTypeLookup = inferredQuarterSecTypes ??
                new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);

            static string ResolveEdgeSecTypeForRoadAllowance(
                string primary,
                string secondary,
                string fallback,
                bool allowSectionFallbackOnMixed)
            {
                var p = NormalizeSecType(primary);
                var s = NormalizeSecType(secondary);
                if (string.Equals(p, s, StringComparison.OrdinalIgnoreCase))
                {
                    return p;
                }

                if (!allowSectionFallbackOnMixed)
                {
                    return "L-USEC";
                }

                return NormalizeSecType(fallback);
            }

            bool TryGetAtsSectionGridPosition(int section, out int row, out int col)
            {
                row = -1;
                col = -1;
                if (section < 1 || section > 36)
                {
                    return false;
                }

                // ATS/DLS section grid (6x6 snake pattern, north at top).
                // Alberta numbering starts at the southeast corner:
                // 6  5  4  3  2  1
                // 7  8  9 10 11 12
                // 18 17 16 15 14 13
                // 19 20 21 22 23 24
                // 30 29 28 27 26 25
                // 31 32 33 34 35 36
                var rows = new[]
                {
                    new[] { 31, 32, 33, 34, 35, 36 },
                    new[] { 30, 29, 28, 27, 26, 25 },
                    new[] { 19, 20, 21, 22, 23, 24 },
                    new[] { 18, 17, 16, 15, 14, 13 },
                    new[] { 7, 8, 9, 10, 11, 12 },
                    new[] { 6, 5, 4, 3, 2, 1 }
                };

                for (var r = 0; r < rows.Length; r++)
                {
                    for (var c = 0; c < rows[r].Length; c++)
                    {
                        if (rows[r][c] == section)
                        {
                            row = r;
                            col = c;
                            return true;
                        }
                    }
                }

                return false;
            }

            var offsetSpecs = new List<(Point2d A, Point2d B, string Tag, string Layer)>();
            var diagCandidates = 0;
            var diagEligible = 0;
            var diagMatched30 = 0;
            var diagMatched20 = 0;
            var geoms = new List<(
                string KeyId,
                string Label,
                Point2d SW,
                Point2d SE,
                Point2d NW,
                Point2d NE,
                Point2d LeftMid,
                Point2d RightMid,
                Point2d TopMid,
                Point2d BottomMid,
                Point2d Center,
                int Zone,
                string Meridian,
                int GlobalX,
                int GlobalY,
                string SouthEdgeLayer,
                string EastEdgeLayer,
                string NorthEdgeLayer,
                string WestEdgeLayer,
                string SwQuarterLayer,
                string SeQuarterLayer,
                string NeQuarterLayer,
                string NwQuarterLayer,
                bool IntersectsClipWindow)>();
            foreach (var townshipKey in contextTownshipKeys)
            {
                if (!TryParseTownshipKey(townshipKey, out var zone, out var meridian, out var range, out var township))
                {
                    continue;
                }

                for (var section = 1; section <= 36; section++)
                {
                    var sectionKey = new SectionKey(zone, section.ToString(CultureInfo.InvariantCulture), township, range, meridian);
                    if (!TryLoadSectionOutline(searchFolders, sectionKey, logger!, out var outline))
                    {
                        continue;
                    }

                    using (var poly = new Polyline(outline.Vertices.Count))
                    {
                        poly.Closed = outline.Closed;
                        for (var vi = 0; vi < outline.Vertices.Count; vi++)
                        {
                            poly.AddVertexAt(vi, outline.Vertices[vi], 0, 0, 0);
                        }

                        if (!TryGetQuarterAnchors(poly, out var anchors))
                        {
                            anchors = GetFallbackAnchors(poly);
                        }

                        var eastUnit = GetUnitVector(anchors.Left, anchors.Right, new Vector2d(1, 0));
                        var northUnit = GetUnitVector(anchors.Bottom, anchors.Top, new Vector2d(0, 1));
                        if (!TryGetQuarterCorner(poly, eastUnit, northUnit, QuarterCorner.SouthWest, out var sw) ||
                            !TryGetQuarterCorner(poly, eastUnit, northUnit, QuarterCorner.SouthEast, out var se) ||
                            !TryGetQuarterCorner(poly, eastUnit, northUnit, QuarterCorner.NorthWest, out var nw) ||
                            !TryGetQuarterCorner(poly, eastUnit, northUnit, QuarterCorner.NorthEast, out var ne))
                        {
                            continue;
                        }

                        var center = new Point2d(
                            0.25 * (sw.X + se.X + nw.X + ne.X),
                            0.25 * (sw.Y + se.Y + nw.Y + ne.Y));
                        var rangeNum = 0;
                        var townshipNum = 0;
                        var hasRange = TryParsePositiveToken(range, out rangeNum);
                        var hasTownship = TryParsePositiveToken(township, out townshipNum);
                        var hasGrid = TryGetAtsSectionGridPosition(section, out var row, out var col);
                        // In ATS, range numbers increase westward, so invert range axis for adjacency math.
                        var globalX = (hasRange && hasGrid) ? ((-rangeNum * 6) + col) : int.MinValue;
                        // Township numbers increase northward; with row[0] at north, invert row to keep
                        // immediate north/south neighbors one grid step apart across township boundaries.
                        var globalY = (hasTownship && hasGrid) ? ((townshipNum * 6) + (5 - row)) : int.MinValue;
                        var resolvedSecType = ResolveSectionType(sectionKey, "AUTO", secTypeLookup);
                        var resolvedQuarterSecTypes = ResolveQuarterSectionTypes(sectionKey, resolvedSecType, quarterTypeLookup);
                        var swType = ResolveQuarterSecTypeForQuarter(resolvedQuarterSecTypes, QuarterSelection.SouthWest, resolvedSecType);
                        var seType = ResolveQuarterSecTypeForQuarter(resolvedQuarterSecTypes, QuarterSelection.SouthEast, resolvedSecType);
                        var neType = ResolveQuarterSecTypeForQuarter(resolvedQuarterSecTypes, QuarterSelection.NorthEast, resolvedSecType);
                        var nwType = ResolveQuarterSecTypeForQuarter(resolvedQuarterSecTypes, QuarterSelection.NorthWest, resolvedSecType);
                        var southEdgeType = ResolveEdgeSecTypeForRoadAllowance(swType, seType, resolvedSecType, allowSectionFallbackOnMixed: true);
                        var eastEdgeType = ResolveEdgeSecTypeForRoadAllowance(seType, neType, resolvedSecType, allowSectionFallbackOnMixed: false);
                        var northEdgeType = ResolveEdgeSecTypeForRoadAllowance(nwType, neType, resolvedSecType, allowSectionFallbackOnMixed: true);
                        var westEdgeType = ResolveEdgeSecTypeForRoadAllowance(swType, nwType, resolvedSecType, allowSectionFallbackOnMixed: false);
                        var ext = poly.GeometricExtents;
                        var intersectsClipWindow = false;
                        for (var wi = 0; wi < clipWindows.Count; wi++)
                        {
                            if (!GeometryUtils.ExtentsIntersect(ext, clipWindows[wi]))
                            {
                                continue;
                            }

                            intersectsClipWindow = true;
                            break;
                        }

                        geoms.Add((
                            BuildSectionKeyId(sectionKey),
                            BuildSectionDescriptor(sectionKey),
                            sw, se, nw, ne,
                            anchors.Left, anchors.Right, anchors.Top, anchors.Bottom,
                            center,
                            zone,
                            NormalizeNumberToken(meridian),
                            globalX,
                            globalY,
                            southEdgeType,
                            eastEdgeType,
                            northEdgeType,
                            westEdgeType,
                            swType,
                            seType,
                            neType,
                            nwType,
                            intersectsClipWindow));
                    }
                }
            }

            if (geoms.Count == 0)
            {
                return ids;
            }

            var localKeyIds = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
            var selectedGeoms = geoms
                .Where(g => selectedSectionKeyIds.Contains(g.KeyId))
                .ToList();
            if (selectedGeoms.Count > 0)
            {
                foreach (var g in geoms)
                {
                    foreach (var s in selectedGeoms)
                    {
                        if (g.Zone != s.Zone ||
                            !string.Equals(g.Meridian, s.Meridian, StringComparison.OrdinalIgnoreCase))
                        {
                            continue;
                        }

                        var dx = g.Center.X - s.Center.X;
                        var dy = g.Center.Y - s.Center.Y;
                        var centerDistance = Math.Sqrt((dx * dx) + (dy * dy));
                        var spanG = Math.Max((g.SE - g.SW).Length, (g.NW - g.SW).Length);
                        var spanS = Math.Max((s.SE - s.SW).Length, (s.NW - s.SW).Length);
                        var neighborThreshold = Math.Max(spanG, spanS) * 1.8;
                        if (centerDistance <= neighborThreshold)
                        {
                            localKeyIds.Add(g.KeyId);
                            break;
                        }
                    }
                }
            }

            var clipWindowKeyIds = new HashSet<string>(
                geoms
                    .Where(g => g.IntersectsClipWindow)
                    .Select(g => g.KeyId),
                StringComparer.OrdinalIgnoreCase);

            var selectedOrLocalKeyIds = new HashSet<string>(selectedSectionKeyIds, StringComparer.OrdinalIgnoreCase);
            // When caller provides explicit active section keys (requested + adjoining built set),
            // keep RA generation strictly in that set for deterministic parity.
            if (activeSectionKeyIds == null || activeSectionKeyIds.Count == 0)
            {
                if (localKeyIds.Count > 0)
                {
                    selectedOrLocalKeyIds.UnionWith(localKeyIds);
                }

                selectedOrLocalKeyIds.UnionWith(clipWindowKeyIds);
            }
            if (EnableRoadAllowanceDiagnostics)
            {
                logger?.WriteLine($"RA-DIAG selection: requested={selectedSectionKeyIds.Count}, local={localKeyIds.Count}, clipWindow={clipWindowKeyIds.Count}, active={selectedOrLocalKeyIds.Count}");
            }

            var seenSpecs = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
            void AddSpec(Point2d s, Point2d e, string tag, string keyA, string keyB, bool verticalMode, string sourceLayer)
            {
                diagEligible++;
                var p0 = s;
                var p1 = e;
                if (p1.X < p0.X || (Math.Abs(p1.X - p0.X) < 1e-9 && p1.Y < p0.Y))
                {
                    var tmp = p0;
                    p0 = p1;
                    p1 = tmp;
                }

                var first = string.Compare(keyA, keyB, StringComparison.OrdinalIgnoreCase) <= 0 ? keyA : keyB;
                var second = string.Equals(first, keyA, StringComparison.OrdinalIgnoreCase) ? keyB : keyA;
                var dedupeKey = string.Format(
                    CultureInfo.InvariantCulture,
                    "{0}|{1}|{2}|{3:0.###}|{4:0.###}|{5:0.###}|{6:0.###}",
                    first,
                    second,
                    verticalMode ? "V" : "H",
                    p0.X, p0.Y, p1.X, p1.Y);
                if (!seenSpecs.Add(dedupeKey))
                    return;

                offsetSpecs.Add((s, e, tag, NormalizeSecType(sourceLayer)));
                if (EnableRoadAllowanceDiagnostics)
                    logger?.WriteLine($"RA-DIAG ADD {tag}: layer={NormalizeSecType(sourceLayer)} A=({s.X:0.###},{s.Y:0.###}) B=({e.X:0.###},{e.Y:0.###})");
            }

            void TryAddFromPair(
                string baseKey,
                string baseLabel,
                Point2d baseStart,
                Point2d baseMid,
                Point2d baseEnd,
                string baseLayerP1,
                string baseLayerP2,
                string otherKey,
                string otherLabel,
                Point2d otherStart,
                Point2d otherMid,
                Point2d otherEnd,
                string otherLayerP1,
                string otherLayerP2,
                bool verticalMode)
            {
                double? gapP1 = null;
                double? gapP2 = null;

                void TryAddQuarterOffsetSegment(
                    Point2d b0,
                    Point2d b1,
                    Point2d o0,
                    Point2d o1,
                    string part,
                    string sourceLayer,
                    out double? gapOut)
                {
                    gapOut = null;
                    var baseDir = b1 - b0;
                    var otherDir = o1 - o0;
                    var baseLen = baseDir.Length;
                    var otherLen = otherDir.Length;
                    if (baseLen <= 1e-6 || otherLen <= 1e-6)
                    {
                        return;
                    }

                    var baseU = baseDir / baseLen;
                    var otherU = otherDir / otherLen;
                    if (Math.Abs(baseU.DotProduct(otherU)) < 0.99)
                    {
                        return;
                    }

                    if (baseU.DotProduct(otherU) < 0.0)
                    {
                        var tmp = o0;
                        o0 = o1;
                        o1 = tmp;
                        otherDir = o1 - o0;
                        otherLen = otherDir.Length;
                        if (otherLen <= 1e-6)
                        {
                            return;
                        }
                    }

                    var tBase0 = 0.0;
                    var tBase1 = baseLen;
                    var tOther0 = (o0 - b0).DotProduct(baseU);
                    var tOther1 = (o1 - b0).DotProduct(baseU);
                    var overlapMin = Math.Max(Math.Min(tBase0, tBase1), Math.Min(tOther0, tOther1));
                    var overlapMax = Math.Min(Math.Max(tBase0, tBase1), Math.Max(tOther0, tOther1));
                    var rawOverlapMin = overlapMin;
                    var rawOverlapMax = overlapMax;
                    const double endpointSnapToleranceMeters = 1.0;
                    if (overlapMin > 0.0 && overlapMin < endpointSnapToleranceMeters)
                    {
                        overlapMin = 0.0;
                    }

                    if (overlapMax < baseLen && (baseLen - overlapMax) < endpointSnapToleranceMeters)
                    {
                        overlapMax = baseLen;
                    }

                    var overlapLength = overlapMax - overlapMin;
                    var minEdgeLength = Math.Min(baseLen, otherLen);
                    if (overlapLength < Math.Max(100.0, minEdgeLength * 0.75))
                    {
                        return;
                    }

                    if (EnableRoadAllowanceDiagnostics)
                    {
                        logger?.WriteLine(
                            $"RA-DIAG overlap {(verticalMode ? "V" : "H")} {baseLabel}/{otherLabel} {part}: " +
                            $"baseLen={baseLen:0.###}, raw=[{rawOverlapMin:0.###},{rawOverlapMax:0.###}], " +
                            $"snapped=[{overlapMin:0.###},{overlapMax:0.###}], overlap={overlapLength:0.###}");
                    }

                    var clippedBaseStart = b0 + (baseU * overlapMin);
                    var clippedBaseEnd = b0 + (baseU * overlapMax);
                    var otherLen2 = otherDir.DotProduct(otherDir);
                    if (otherLen2 <= 1e-9)
                    {
                        return;
                    }

                    var sample = b0 + (baseU * (overlapMin + (0.5 * (overlapMax - overlapMin))));
                    var proj = (sample - o0).DotProduct(otherDir) / otherLen2;
                    proj = Math.Max(0.0, Math.Min(1.0, proj));
                    var otherSample = o0 + (otherDir * proj);

                    var normal = new Vector2d(-baseU.Y, baseU.X);
                    if ((otherSample - sample).DotProduct(normal) < 0.0)
                    {
                        normal = -normal;
                    }

                    var gap = Math.Abs((otherSample - sample).DotProduct(normal));
                    gapOut = gap;
                    diagCandidates++;
                    if (Math.Abs(gap - RoadAllowanceUsecWidthMeters) <= 0.50) diagMatched30++;
                    if (Math.Abs(gap - RoadAllowanceSecWidthMeters) <= 0.50) diagMatched20++;

                    if (Math.Abs(gap - RoadAllowanceSecWidthMeters) <= RoadAllowanceWidthToleranceMeters)
                    {
                        return;
                    }

                    if (Math.Abs(gap - RoadAllowanceUsecWidthMeters) > RoadAllowanceGapOffsetToleranceMeters)
                    {
                        return;
                    }

                    var offsetStart = clippedBaseStart + (normal * RoadAllowanceSecWidthMeters);
                    var offsetEnd = clippedBaseEnd + (normal * RoadAllowanceSecWidthMeters);
                    var tag = $"{(verticalMode ? "V" : "H")} {baseLabel}/{otherLabel} {part} gap={gap:0.###}";
                    AddSpec(offsetStart, offsetEnd, tag, baseKey, otherKey, verticalMode, sourceLayer);
                }

                // Per-half layer attribution avoids one quarter forcing the sibling quarter.
                TryAddQuarterOffsetSegment(baseStart, baseMid, otherStart, otherMid, "P1", baseLayerP1, out gapP1);
                TryAddQuarterOffsetSegment(baseMid, baseEnd, otherMid, otherEnd, "P2", baseLayerP2, out gapP2);

                if (EnableRoadAllowanceDiagnostics)
                {
                    logger?.WriteLine(
                        $"RA-DIAG {(verticalMode ? "V" : "H")} pair {baseLabel}/{otherLabel}: " +
                        $"gapP1={(gapP1.HasValue ? gapP1.Value.ToString("0.###", CultureInfo.InvariantCulture) : "n/a")} " +
                        $"gapP2={(gapP2.HasValue ? gapP2.Value.ToString("0.###", CultureInfo.InvariantCulture) : "n/a")} " +
                        $"layersP1={NormalizeSecType(baseLayerP1)}/{NormalizeSecType(otherLayerP1)} " +
                        $"layersP2={NormalizeSecType(baseLayerP2)}/{NormalizeSecType(otherLayerP2)}");
                }
            }

            string BuildGridKey(int zone, string meridian, int globalX, int globalY)
            {
                return string.Format(
                    CultureInfo.InvariantCulture,
                    "{0}|{1}|{2}|{3}",
                    zone,
                    meridian ?? string.Empty,
                    globalX,
                    globalY);
            }

            var geomIndexByGrid = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
            for (var i = 0; i < geoms.Count; i++)
            {
                var g = geoms[i];
                if (g.GlobalX == int.MinValue || g.GlobalY == int.MinValue)
                {
                    continue;
                }

                var key = BuildGridKey(g.Zone, g.Meridian, g.GlobalX, g.GlobalY);
                if (!geomIndexByGrid.ContainsKey(key))
                {
                    geomIndexByGrid[key] = i;
                }
            }

            bool TryGetNeighborIndex(int zone, string meridian, int globalX, int globalY, int dx, int dy, out int index)
            {
                var key = BuildGridKey(zone, meridian, globalX + dx, globalY + dy);
                return geomIndexByGrid.TryGetValue(key, out index);
            }

            bool IsNeighborPairEligible(
                (string KeyId, string Label, Point2d SW, Point2d SE, Point2d NW, Point2d NE, Point2d LeftMid, Point2d RightMid, Point2d TopMid, Point2d BottomMid, Point2d Center, int Zone, string Meridian, int GlobalX, int GlobalY, string SouthEdgeLayer, string EastEdgeLayer, string NorthEdgeLayer, string WestEdgeLayer, string SwQuarterLayer, string SeQuarterLayer, string NeQuarterLayer, string NwQuarterLayer, bool IntersectsClipWindow) a,
                (string KeyId, string Label, Point2d SW, Point2d SE, Point2d NW, Point2d NE, Point2d LeftMid, Point2d RightMid, Point2d TopMid, Point2d BottomMid, Point2d Center, int Zone, string Meridian, int GlobalX, int GlobalY, string SouthEdgeLayer, string EastEdgeLayer, string NorthEdgeLayer, string WestEdgeLayer, string SwQuarterLayer, string SeQuarterLayer, string NeQuarterLayer, string NwQuarterLayer, bool IntersectsClipWindow) b)
            {
                if (!selectedOrLocalKeyIds.Contains(a.KeyId) &&
                    !selectedOrLocalKeyIds.Contains(b.KeyId))
                {
                    return false;
                }

                var centerDx = b.Center.X - a.Center.X;
                var centerDy = b.Center.Y - a.Center.Y;
                var centerDistance = Math.Sqrt((centerDx * centerDx) + (centerDy * centerDy));
                var spanA = Math.Max((a.SE - a.SW).Length, (a.NW - a.SW).Length);
                var spanB = Math.Max((b.SE - b.SW).Length, (b.NW - b.SW).Length);
                return centerDistance <= (Math.Max(spanA, spanB) * 1.8);
            }

            for (var i = 0; i < geoms.Count; i++)
            {
                var a = geoms[i];
                if (a.GlobalX == int.MinValue || a.GlobalY == int.MinValue)
                {
                    continue;
                }

                // Immediate east/west neighbor (grid +1 X) only.
                if (TryGetNeighborIndex(a.Zone, a.Meridian, a.GlobalX, a.GlobalY, 1, 0, out var eastNeighborIndex))
                {
                    var b = geoms[eastNeighborIndex];
                    if (IsNeighborPairEligible(a, b))
                    {
                        var aIsWest = a.Center.X <= b.Center.X;
                        var west = aIsWest ? a : b;
                        var east = aIsWest ? b : a;
                        TryAddFromPair(
                            west.KeyId, west.Label, west.SE, west.RightMid, west.NE,
                            west.SeQuarterLayer,
                            west.NeQuarterLayer,
                            east.KeyId, east.Label, east.SW, east.LeftMid, east.NW,
                            east.SwQuarterLayer,
                            east.NwQuarterLayer,
                            verticalMode: true);
                    }
                }

                // Immediate north/south neighbor (grid +1 Y) only.
                if (TryGetNeighborIndex(a.Zone, a.Meridian, a.GlobalX, a.GlobalY, 0, 1, out var northNeighborIndex))
                {
                    var b = geoms[northNeighborIndex];
                    if (IsNeighborPairEligible(a, b))
                    {
                        var aIsSouth = a.Center.Y <= b.Center.Y;
                        var south = aIsSouth ? a : b;
                        var north = aIsSouth ? b : a;
                        TryAddFromPair(
                            south.KeyId, south.Label, south.NW, south.TopMid, south.NE,
                            south.NwQuarterLayer,
                            south.NeQuarterLayer,
                            north.KeyId, north.Label, north.SW, north.BottomMid, north.SE,
                            north.SwQuarterLayer,
                            north.SeQuarterLayer,
                            verticalMode: false);
                    }
                }
            }

            if (EnableRoadAllowanceDiagnostics)
            {
                logger?.WriteLine($"RA-DIAG summary: candidates={diagCandidates}, eligible={diagEligible}, near30.17={diagMatched30}, near20.11={diagMatched20}, addPreClip={offsetSpecs.Count}");
            }

            if (offsetSpecs.Count == 0)
            {
                return ids;
            }

            using (var tr = database.TransactionManager.StartTransaction())
            {
                var blockTable = (BlockTable)tr.GetObject(database.BlockTableId, OpenMode.ForRead);
                var modelSpace = (BlockTableRecord)tr.GetObject(blockTable[BlockTableRecord.ModelSpace], OpenMode.ForWrite);
                var drawnSegmentKeys = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
                var clippedSegments = new List<(Point2d A, Point2d B, string Tag, string Layer)>();

                foreach (var seg in offsetSpecs)
                {
                    var intersectsWindow = false;
                    foreach (var clipWindow in clipWindows)
                    {
                        if (!TryClipSegmentToWindow(seg.A, seg.B, clipWindow, out _, out _))
                        {
                            continue;
                        }

                        intersectsWindow = true;
                        break;
                    }

                    if (!intersectsWindow)
                    {
                        if (EnableRoadAllowanceDiagnostics)
                        {
                            logger?.WriteLine($"RA-DIAG CLIP-OUT {seg.Tag}");
                        }

                        continue;
                    }

                    var p0 = seg.A;
                    var p1 = seg.B;
                    if (p1.X < p0.X || (Math.Abs(p1.X - p0.X) <= 1e-9 && p1.Y < p0.Y))
                    {
                        var tmp = p0;
                        p0 = p1;
                        p1 = tmp;
                    }

                    var key = string.Format(
                        CultureInfo.InvariantCulture,
                        "{0:0.###},{1:0.###},{2:0.###},{3:0.###}|{4}",
                        p0.X, p0.Y, p1.X, p1.Y,
                        NormalizeSecType(seg.Layer));
                    if (!drawnSegmentKeys.Add(key))
                    {
                        continue;
                    }

                    clippedSegments.Add((seg.A, seg.B, seg.Tag, seg.Layer));
                    if (EnableRoadAllowanceDiagnostics)
                    {
                        logger?.WriteLine($"RA-DIAG DRAW {seg.Tag}: layer={seg.Layer} A=({seg.A.X:0.###},{seg.A.Y:0.###}) B=({seg.B.X:0.###},{seg.B.Y:0.###})");
                    }
                }

                var mergedSegments = MergeCollinearRoadAllowanceSegments(clippedSegments);
                var alignedSegments = AlignRoadAllowanceSegmentEndpointsToSectionBoundaries(
                    tr,
                    modelSpace,
                    clipWindows,
                    mergedSegments,
                    logger);
                if (EnableRoadAllowanceDiagnostics)
                {
                    logger?.WriteLine($"RA-DIAG merge: raw={clippedSegments.Count}, merged={mergedSegments.Count}, aligned={alignedSegments.Count}");
                }

                var layersToEnsure = alignedSegments
                    .Select(s => NormalizeSecType(s.Layer))
                    .Distinct(StringComparer.OrdinalIgnoreCase)
                    .ToList();
                if (layersToEnsure.Count == 0)
                {
                    layersToEnsure.Add("L-USEC");
                }

                foreach (var layer in layersToEnsure)
                {
                    EnsureLayer(database, tr, layer);
                }

                foreach (var seg in alignedSegments)
                {
                    var poly = new Polyline(2)
                    {
                        Layer = NormalizeSecType(seg.Layer),
                        ColorIndex = 256
                    };
                    poly.AddVertexAt(0, seg.A, 0, 0, 0);
                    poly.AddVertexAt(1, seg.B, 0, 0, 0);
                    var id = modelSpace.AppendEntity(poly);
                    tr.AddNewlyCreatedDBObject(poly, true);
                    ids.Add(id);
                }

                tr.Commit();
            }

            logger?.WriteLine($"Road allowance offset lines drawn: {ids.Count}");
            return ids;
        }

        private static List<(Point2d A, Point2d B, string Tag, string Layer)> AlignRoadAllowanceSegmentEndpointsToSectionBoundaries(
            Transaction transaction,
            BlockTableRecord modelSpace,
            IReadOnlyList<Extents3d> clipWindows,
            List<(Point2d A, Point2d B, string Tag, string Layer)> segments,
            Logger? logger)
        {
            if (transaction == null || modelSpace == null || segments == null || segments.Count == 0)
            {
                return segments ?? new List<(Point2d A, Point2d B, string Tag, string Layer)>();
            }

            bool IsPointInAnyWindow(Point2d point)
            {
                if (clipWindows == null || clipWindows.Count == 0)
                {
                    return true;
                }

                for (var i = 0; i < clipWindows.Count; i++)
                {
                    var w = clipWindows[i];
                    if (point.X >= w.MinPoint.X && point.X <= w.MaxPoint.X &&
                        point.Y >= w.MinPoint.Y && point.Y <= w.MaxPoint.Y)
                    {
                        return true;
                    }
                }

                return false;
            }

            bool DoesSegmentIntersectAnyWindow(Point2d a, Point2d b)
            {
                if (clipWindows == null || clipWindows.Count == 0)
                {
                    return true;
                }

                if (IsPointInAnyWindow(a) || IsPointInAnyWindow(b))
                {
                    return true;
                }

                for (var i = 0; i < clipWindows.Count; i++)
                {
                    if (TryClipSegmentToWindow(a, b, clipWindows[i], out _, out _))
                    {
                        return true;
                    }
                }

                return false;
            }

            bool TryReadOpenSegment(Entity ent, out Point2d a, out Point2d b)
            {
                a = default;
                b = default;
                if (ent == null)
                {
                    return false;
                }

                if (ent is Polyline pl)
                {
                    if (pl.Closed || pl.NumberOfVertices < 2)
                    {
                        return false;
                    }

                    a = pl.GetPoint2dAt(0);
                    b = pl.GetPoint2dAt(pl.NumberOfVertices - 1);
                    if (a.GetDistanceTo(b) <= 1e-4)
                    {
                        return false;
                    }

                    if (pl.NumberOfVertices > 2)
                    {
                        const double collinearTol = 0.35;
                        for (var vi = 1; vi < pl.NumberOfVertices - 1; vi++)
                        {
                            var p = pl.GetPoint2dAt(vi);
                            if (DistancePointToInfiniteLine(p, a, b) > collinearTol)
                            {
                                return false;
                            }
                        }
                    }

                    return true;
                }

                if (ent is Line ln)
                {
                    a = new Point2d(ln.StartPoint.X, ln.StartPoint.Y);
                    b = new Point2d(ln.EndPoint.X, ln.EndPoint.Y);
                    return a.GetDistanceTo(b) > 1e-4;
                }

                return false;
            }

            var boundarySegments = new List<(Point2d A, Point2d B)>();
            foreach (ObjectId id in modelSpace)
            {
                if (!(transaction.GetObject(id, OpenMode.ForRead, false) is Entity ent) || ent.IsErased)
                {
                    continue;
                }

                if (!string.Equals(ent.Layer, "L-SEC", StringComparison.OrdinalIgnoreCase) &&
                    !string.Equals(ent.Layer, "L-USEC", StringComparison.OrdinalIgnoreCase))
                {
                    continue;
                }

                if (!TryReadOpenSegment(ent, out var a, out var b))
                {
                    continue;
                }

                if (!DoesSegmentIntersectAnyWindow(a, b))
                {
                    continue;
                }

                boundarySegments.Add((a, b));
            }

            if (boundarySegments.Count == 0)
            {
                return segments;
            }

            bool TryClampSegmentEndsToBoundaryIntersections(
                Point2d start,
                Point2d end,
                out Point2d clampedStart,
                out Point2d clampedEnd,
                out double startShift,
                out double endShift)
            {
                clampedStart = start;
                clampedEnd = end;
                startShift = 0.0;
                endShift = 0.0;

                var axis = end - start;
                var length = axis.Length;
                if (length <= 1e-6)
                {
                    return false;
                }

                var axisUnit = axis / length;
                var center = Midpoint(start, end);
                var tMin = -0.5 * length;
                var tMax = 0.5 * length;
                const double minT = 1e-3;
                const double maxShrinkMeters = 8.0;
                const double maxExtendMeters = 0.75;
                double? bestNeg = null;
                double? bestPos = null;

                foreach (var candidate in boundarySegments)
                {
                    if (!TryIntersectInfiniteLineWithSegment(center, axisUnit, candidate.A, candidate.B, out var t))
                    {
                        continue;
                    }

                    if (t < -minT)
                    {
                        if (!bestNeg.HasValue || t > bestNeg.Value)
                        {
                            bestNeg = t;
                        }
                    }
                    else if (t > minT)
                    {
                        if (!bestPos.HasValue || t < bestPos.Value)
                        {
                            bestPos = t;
                        }
                    }
                }

                var newMin = tMin;
                var newMax = tMax;
                var changed = false;

                if (bestNeg.HasValue)
                {
                    var delta = bestNeg.Value - tMin;
                    var canAdjust = delta >= 0.0
                        ? delta <= maxShrinkMeters
                        : (-delta) <= maxExtendMeters;
                    if (canAdjust)
                    {
                        newMin = bestNeg.Value;
                        startShift = Math.Abs(delta);
                        changed = true;
                    }
                }

                if (bestPos.HasValue)
                {
                    var delta = bestPos.Value - tMax;
                    var canAdjust = delta <= 0.0
                        ? (-delta) <= maxShrinkMeters
                        : delta <= maxExtendMeters;
                    if (canAdjust)
                    {
                        newMax = bestPos.Value;
                        endShift = Math.Abs(delta);
                        changed = true;
                    }
                }

                if (!changed || (newMax - newMin) <= minT)
                {
                    return false;
                }

                clampedStart = center + (axisUnit * newMin);
                clampedEnd = center + (axisUnit * newMax);
                return clampedStart.GetDistanceTo(clampedEnd) > 1e-4;
            }

            var result = new List<(Point2d A, Point2d B, string Tag, string Layer)>(segments.Count);
            foreach (var seg in segments)
            {
                var a = seg.A;
                var b = seg.B;
                var clamped = TryClampSegmentEndsToBoundaryIntersections(
                    seg.A,
                    seg.B,
                    out var aClamp,
                    out var bClamp,
                    out var aShift,
                    out var bShift);
                if (clamped)
                {
                    a = aClamp;
                    b = bClamp;
                }

                if (a.GetDistanceTo(b) <= 1e-4)
                {
                    result.Add(seg);
                    continue;
                }

                if (EnableRoadAllowanceDiagnostics && clamped)
                {
                    logger?.WriteLine(
                        $"RA-DIAG END-CLAMP {seg.Tag}: " +
                        $"Ashift={aShift:0.###} Bshift={bShift:0.###} " +
                        $"A=({a.X:0.###},{a.Y:0.###}) B=({b.X:0.###},{b.Y:0.###})");
                }

                result.Add((a, b, seg.Tag, seg.Layer));
            }

            return result;
        }

        private static List<(Point2d A, Point2d B, string Tag, string Layer)> MergeCollinearRoadAllowanceSegments(List<(Point2d A, Point2d B, string Tag, string Layer)> input)
        {
            var merged = input == null
                ? new List<(Point2d A, Point2d B, string Tag, string Layer)>()
                : new List<(Point2d A, Point2d B, string Tag, string Layer)>(input);
            if (merged.Count <= 1)
            {
                return merged;
            }

            bool changed;
            do
            {
                changed = false;
                for (var i = 0; i < merged.Count; i++)
                {
                    for (var j = i + 1; j < merged.Count; j++)
                    {
                        // Keep merges scoped to the same originating RA pair/part.
                        // Cross-tag merges can chain 20.11 segments across sections.
                        if (!string.Equals(merged[i].Tag, merged[j].Tag, StringComparison.OrdinalIgnoreCase))
                        {
                            continue;
                        }

                        if (!string.Equals(merged[i].Layer, merged[j].Layer, StringComparison.OrdinalIgnoreCase))
                        {
                            continue;
                        }

                        if (!TryMergeCollinearSegments(merged[i].A, merged[i].B, merged[j].A, merged[j].B, out var outA, out var outB))
                        {
                            continue;
                        }

                        merged[i] = (outA, outB, merged[i].Tag, merged[i].Layer);
                        merged.RemoveAt(j);
                        changed = true;
                        break;
                    }

                    if (changed)
                    {
                        break;
                    }
                }
            } while (changed);

            return merged;
        }

        private static bool TryMergeCollinearSegments(Point2d a0, Point2d a1, Point2d b0, Point2d b1, out Point2d mergedA, out Point2d mergedB)
        {
            mergedA = a0;
            mergedB = a1;

            const double angleTol = 0.0015;
            const double distanceTol = 0.20;
            const double gapTol = 0.75;

            var ua = a1 - a0;
            var ub = b1 - b0;
            var la = ua.Length;
            var lb = ub.Length;
            if (la <= 1e-6 || lb <= 1e-6)
            {
                return false;
            }

            var cross = Math.Abs((ua.X * ub.Y) - (ua.Y * ub.X)) / (la * lb);
            if (cross > angleTol)
            {
                return false;
            }

            if (DistancePointToInfiniteLine(b0, a0, a1) > distanceTol ||
                DistancePointToInfiniteLine(b1, a0, a1) > distanceTol)
            {
                return false;
            }

            var axis = ua / la;
            var tA0 = 0.0;
            var tA1 = la;
            var tB0 = (b0 - a0).DotProduct(axis);
            var tB1 = (b1 - a0).DotProduct(axis);

            var aMin = Math.Min(tA0, tA1);
            var aMax = Math.Max(tA0, tA1);
            var bMin = Math.Min(tB0, tB1);
            var bMax = Math.Max(tB0, tB1);

            if (Math.Min(aMax, bMax) < (Math.Max(aMin, bMin) - gapTol))
            {
                return false;
            }

            var tMin = Math.Min(aMin, bMin);
            var tMax = Math.Max(aMax, bMax);
            mergedA = a0 + (axis * tMin);
            mergedB = a0 + (axis * tMax);
            return mergedA.GetDistanceTo(mergedB) > 1e-4;
        }

        private static void CleanupContextSectionOverlaps(Database database, IReadOnlyCollection<ObjectId> contextSectionIds, Logger? logger)
        {
            if (database == null || contextSectionIds == null || contextSectionIds.Count == 0)
            {
                return;
            }

            var contextSet = new HashSet<ObjectId>(contextSectionIds);
            var contextSegments = new List<(ObjectId Id, Point2d A, Point2d B, double Length)>();
            var otherSegments = new List<(ObjectId Id, Point2d A, Point2d B, double Length)>();
            using (var tr = database.TransactionManager.StartTransaction())
            {
                var bt = (BlockTable)tr.GetObject(database.BlockTableId, OpenMode.ForRead);
                var ms = (BlockTableRecord)tr.GetObject(bt[BlockTableRecord.ModelSpace], OpenMode.ForRead);
                foreach (ObjectId id in ms)
                {
                    if (!(tr.GetObject(id, OpenMode.ForRead, false) is Polyline pl))
                    {
                        continue;
                    }

                    if (!string.Equals(pl.Layer, "L-SEC", StringComparison.OrdinalIgnoreCase) &&
                        !string.Equals(pl.Layer, "L-USEC", StringComparison.OrdinalIgnoreCase))
                    {
                        continue;
                    }

                    if (pl.Closed || pl.NumberOfVertices != 2)
                    {
                        continue;
                    }

                    var a = pl.GetPoint2dAt(0);
                    var b = pl.GetPoint2dAt(1);
                    var len = a.GetDistanceTo(b);
                    if (len <= 1e-4)
                    {
                        continue;
                    }

                    if (contextSet.Contains(id))
                    {
                        contextSegments.Add((id, a, b, len));
                    }
                    else
                    {
                        otherSegments.Add((id, a, b, len));
                    }
                }

                var toErase = new HashSet<ObjectId>();
                // Remove context segments that duplicate/overlap any existing section linework.
                foreach (var c in contextSegments)
                {
                    foreach (var o in otherSegments)
                    {
                        if (!AreSegmentsDuplicateOrCollinearOverlap(c.A, c.B, o.A, o.B))
                        {
                            continue;
                        }

                        toErase.Add(c.Id);
                        break;
                    }
                }

                // De-dupe within context fragments themselves: keep longer one.
                for (var i = 0; i < contextSegments.Count; i++)
                {
                    var s1 = contextSegments[i];
                    if (toErase.Contains(s1.Id))
                    {
                        continue;
                    }

                    for (var j = i + 1; j < contextSegments.Count; j++)
                    {
                        var s2 = contextSegments[j];
                        if (toErase.Contains(s2.Id))
                        {
                            continue;
                        }

                        if (!AreSegmentsDuplicateOrCollinearOverlap(s1.A, s1.B, s2.A, s2.B))
                        {
                            continue;
                        }

                        var eraseId = s1.Length < s2.Length ? s1.Id : s2.Id;
                        if (Math.Abs(s1.Length - s2.Length) <= 0.01)
                        {
                            eraseId = s1.Id.Handle.Value > s2.Id.Handle.Value ? s1.Id : s2.Id;
                        }

                        toErase.Add(eraseId);
                    }
                }

                var erased = 0;
                foreach (var id in toErase)
                {
                    if (!(tr.GetObject(id, OpenMode.ForWrite, false) is Entity ent) || ent.IsErased)
                    {
                        continue;
                    }

                    ent.Erase();
                    erased++;
                }

                tr.Commit();
                if (erased > 0)
                {
                    logger?.WriteLine($"Cleanup: erased {erased} overlapping context L-SEC/L-USEC segment(s).");
                }
            }
        }

        private static void CleanupGeneratedRoadAllowanceOverlaps(Database database, IReadOnlyCollection<ObjectId> generatedRoadAllowanceIds, Logger? logger)
        {
            if (database == null || generatedRoadAllowanceIds == null || generatedRoadAllowanceIds.Count == 0)
            {
                return;
            }

            var generatedSet = new HashSet<ObjectId>(generatedRoadAllowanceIds);
            var generatedSegments = new List<(ObjectId Id, Point2d A, Point2d B, double Length)>();
            var existingSegments = new List<(ObjectId Id, Point2d A, Point2d B, string Layer, double Length)>();

            using (var tr = database.TransactionManager.StartTransaction())
            {
                bool TryReadOpenSegment(Entity ent, out Point2d a, out Point2d b)
                {
                    a = default;
                    b = default;
                    if (ent == null)
                    {
                        return false;
                    }

                    if (ent is Polyline pl)
                    {
                        if (pl.Closed || pl.NumberOfVertices != 2)
                        {
                            return false;
                        }

                        a = pl.GetPoint2dAt(0);
                        b = pl.GetPoint2dAt(1);
                        return a.GetDistanceTo(b) > 1e-4;
                    }

                    if (ent is Line ln)
                    {
                        a = new Point2d(ln.StartPoint.X, ln.StartPoint.Y);
                        b = new Point2d(ln.EndPoint.X, ln.EndPoint.Y);
                        return a.GetDistanceTo(b) > 1e-4;
                    }

                    return false;
                }

                var bt = (BlockTable)tr.GetObject(database.BlockTableId, OpenMode.ForRead);
                var ms = (BlockTableRecord)tr.GetObject(bt[BlockTableRecord.ModelSpace], OpenMode.ForRead);
                foreach (ObjectId id in ms)
                {
                    if (!(tr.GetObject(id, OpenMode.ForRead, false) is Entity ent))
                    {
                        continue;
                    }

                    if (!string.Equals(ent.Layer, "L-SEC", StringComparison.OrdinalIgnoreCase) &&
                        !IsUsecLayer(ent.Layer))
                    {
                        continue;
                    }

                    if (!TryReadOpenSegment(ent, out var a, out var b))
                    {
                        continue;
                    }

                    if (generatedSet.Contains(id))
                    {
                        generatedSegments.Add((id, a, b, a.GetDistanceTo(b)));
                    }
                    else
                    {
                        existingSegments.Add((id, a, b, ent.Layer ?? string.Empty, a.GetDistanceTo(b)));
                    }
                }

                const double containTol = 0.40;
                const double lengthDeltaTol = 0.35;
                bool IsSegmentContained(Point2d innerA, Point2d innerB, Point2d outerA, Point2d outerB)
                {
                    return DistancePointToSegment(innerA, outerA, outerB) <= containTol &&
                           DistancePointToSegment(innerB, outerA, outerB) <= containTol;
                }

                var toEraseGenerated = new HashSet<ObjectId>();
                foreach (var g in generatedSegments)
                {
                    if (toEraseGenerated.Contains(g.Id))
                    {
                        continue;
                    }

                    foreach (var e in existingSegments)
                    {
                        if (!AreSegmentsDuplicateOrCollinearOverlap(g.A, g.B, e.A, e.B))
                        {
                            continue;
                        }

                        var existingInsideGenerated = IsSegmentContained(e.A, e.B, g.A, g.B);
                        var generatedInsideExisting = IsSegmentContained(g.A, g.B, e.A, e.B);
                        if (existingInsideGenerated && (g.Length - e.Length) > lengthDeltaTol)
                        {
                            // Preserve existing section/context fabric; trim/cleanup generated instead.
                            toEraseGenerated.Add(g.Id);
                            break;
                        }

                        if (generatedInsideExisting && (e.Length - g.Length) > lengthDeltaTol)
                        {
                            // Existing full-length boundary already present; drop redundant generated.
                            toEraseGenerated.Add(g.Id);
                            break;
                        }

                        // Near-equal overlap:
                        // keep existing fabric (L-SEC and L-USEC families) as authoritative.
                        toEraseGenerated.Add(g.Id);
                        break;
                    }
                }

                var erasedGenerated = 0;
                foreach (var id in toEraseGenerated)
                {
                    if (!(tr.GetObject(id, OpenMode.ForWrite, false) is Entity ent) || ent.IsErased)
                    {
                        continue;
                    }

                    ent.Erase();
                    erasedGenerated++;
                }

                tr.Commit();
                if (erasedGenerated > 0)
                {
                    logger?.WriteLine(
                        $"Cleanup: overlap resolve erased {erasedGenerated} generated RA segment(s) (existing boundaries preserved).");
                }
            }
        }

        private static void TrimContextSectionsToBufferedWindows(
            Database database,
            ICollection<ObjectId> contextSectionIds,
            IEnumerable<ObjectId> requestedQuarterIds,
            Logger? logger)
        {
            if (database == null || contextSectionIds == null || contextSectionIds.Count == 0 || requestedQuarterIds == null)
            {
                return;
            }

            var clipWindows = MergeOverlappingClipWindows(BuildBufferedQuarterWindows(database, requestedQuarterIds, 100.0));
            if (clipWindows.Count == 0)
            {
                return;
            }

            using (var tr = database.TransactionManager.StartTransaction())
            {
                var bt = (BlockTable)tr.GetObject(database.BlockTableId, OpenMode.ForRead);

                bool TryReadOpenSegment(Entity ent, out Point2d a, out Point2d b)
                {
                    a = default;
                    b = default;
                    if (ent == null)
                    {
                        return false;
                    }

                    if (ent is Line ln)
                    {
                        a = new Point2d(ln.StartPoint.X, ln.StartPoint.Y);
                        b = new Point2d(ln.EndPoint.X, ln.EndPoint.Y);
                        return a.GetDistanceTo(b) > 1e-4;
                    }

                    if (ent is Polyline pl)
                    {
                        if (pl.Closed || pl.NumberOfVertices != 2)
                        {
                            return false;
                        }

                        a = pl.GetPoint2dAt(0);
                        b = pl.GetPoint2dAt(1);
                        return a.GetDistanceTo(b) > 1e-4;
                    }

                    return false;
                }

                bool TryWriteOpenSegment(Entity ent, Point2d a, Point2d b)
                {
                    if (ent is Line ln)
                    {
                        ln.StartPoint = new Point3d(a.X, a.Y, ln.StartPoint.Z);
                        ln.EndPoint = new Point3d(b.X, b.Y, ln.EndPoint.Z);
                        return true;
                    }

                    if (ent is Polyline pl && !pl.Closed && pl.NumberOfVertices == 2)
                    {
                        pl.SetPointAt(0, a);
                        pl.SetPointAt(1, b);
                        return true;
                    }

                    return false;
                }

                var trimmed = 0;
                var erased = 0;
                const double endpointMoveTol = 0.05;
                foreach (var id in contextSectionIds.Where(x => !x.IsNull).Distinct().ToList())
                {
                    if (id.IsNull || id.IsErased)
                    {
                        if (!contextSectionIds.IsReadOnly)
                        {
                            contextSectionIds.Remove(id);
                        }
                        continue;
                    }

                    Entity? ent = null;
                    try
                    {
                        ent = tr.GetObject(id, OpenMode.ForWrite, false) as Entity;
                    }
                    catch (Autodesk.AutoCAD.Runtime.Exception)
                    {
                        if (!contextSectionIds.IsReadOnly)
                        {
                            contextSectionIds.Remove(id);
                        }
                        continue;
                    }

                    if (ent == null || ent.IsErased)
                    {
                        if (!contextSectionIds.IsReadOnly)
                        {
                            contextSectionIds.Remove(id);
                        }
                        continue;
                    }

                    if (!TryReadOpenSegment(ent, out var a, out var b))
                    {
                        continue;
                    }

                    var clipped = new List<(Point2d A, Point2d B)>();
                    var dedupe = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
                    for (var wi = 0; wi < clipWindows.Count; wi++)
                    {
                        if (!TryClipSegmentToWindow(a, b, clipWindows[wi], out var c0, out var c1))
                        {
                            continue;
                        }

                        var p0 = c0;
                        var p1 = c1;
                        if (p1.X < p0.X || (Math.Abs(p1.X - p0.X) <= 1e-9 && p1.Y < p0.Y))
                        {
                            var tmp = p0;
                            p0 = p1;
                            p1 = tmp;
                        }

                        var key = string.Format(
                            CultureInfo.InvariantCulture,
                            "{0:0.###}|{1:0.###}|{2:0.###}|{3:0.###}",
                            p0.X, p0.Y, p1.X, p1.Y);
                        if (!dedupe.Add(key))
                        {
                            continue;
                        }

                        clipped.Add((c0, c1));
                    }

                    bool merged;
                    do
                    {
                        merged = false;
                        for (var i = 0; i < clipped.Count; i++)
                        {
                            for (var j = i + 1; j < clipped.Count; j++)
                            {
                                if (!TryMergeCollinearSegments(clipped[i].A, clipped[i].B, clipped[j].A, clipped[j].B, out var mA, out var mB))
                                {
                                    continue;
                                }

                                clipped[i] = (mA, mB);
                                clipped.RemoveAt(j);
                                merged = true;
                                break;
                            }

                            if (merged)
                            {
                                break;
                            }
                        }
                    } while (merged);

                    if (clipped.Count == 0)
                    {
                        ent.Erase();
                        if (!contextSectionIds.IsReadOnly)
                        {
                            contextSectionIds.Remove(id);
                        }
                        erased++;
                        continue;
                    }

                    var primary = clipped
                        .OrderByDescending(s => s.A.GetDistanceTo(s.B))
                        .First();
                    var changed = primary.A.GetDistanceTo(a) > endpointMoveTol ||
                                  primary.B.GetDistanceTo(b) > endpointMoveTol;
                    if (changed && TryWriteOpenSegment(ent, primary.A, primary.B))
                    {
                        trimmed++;
                    }
                }

                tr.Commit();
                if (trimmed > 0 || erased > 0)
                {
                    logger?.WriteLine($"Cleanup: final 100m trim adjusted {trimmed} context segment(s), erased {erased} outside segment(s).");
                }
            }
        }

        private static void ConnectDanglingUsecZeroTwentyEndpoints(
            Database database,
            IEnumerable<ObjectId> requestedQuarterIds,
            Logger? logger)
        {
            if (database == null || requestedQuarterIds == null)
            {
                return;
            }

            var clipWindows = MergeOverlappingClipWindows(BuildBufferedQuarterWindows(database, requestedQuarterIds, 100.0));
            if (clipWindows.Count == 0)
            {
                return;
            }

            bool IsPointInAnyWindow(Point2d p)
            {
                for (var i = 0; i < clipWindows.Count; i++)
                {
                    var w = clipWindows[i];
                    if (p.X >= w.MinPoint.X && p.X <= w.MaxPoint.X &&
                        p.Y >= w.MinPoint.Y && p.Y <= w.MaxPoint.Y)
                    {
                        return true;
                    }
                }

                return false;
            }

            bool IsPointOnAnyWindowBoundary(Point2d p, double tol)
            {
                for (var i = 0; i < clipWindows.Count; i++)
                {
                    var w = clipWindows[i];
                    var withinX = p.X >= (w.MinPoint.X - tol) && p.X <= (w.MaxPoint.X + tol);
                    var withinY = p.Y >= (w.MinPoint.Y - tol) && p.Y <= (w.MaxPoint.Y + tol);
                    if (!withinX || !withinY)
                    {
                        continue;
                    }

                    var onLeft = Math.Abs(p.X - w.MinPoint.X) <= tol;
                    var onRight = Math.Abs(p.X - w.MaxPoint.X) <= tol;
                    var onBottom = Math.Abs(p.Y - w.MinPoint.Y) <= tol;
                    var onTop = Math.Abs(p.Y - w.MaxPoint.Y) <= tol;
                    if (onLeft || onRight || onBottom || onTop)
                    {
                        return true;
                    }
                }

                return false;
            }

            bool DoesSegmentIntersectAnyWindow(Point2d a, Point2d b)
            {
                if (IsPointInAnyWindow(a) || IsPointInAnyWindow(b))
                {
                    return true;
                }

                for (var i = 0; i < clipWindows.Count; i++)
                {
                    if (TryClipSegmentToWindow(a, b, clipWindows[i], out _, out _))
                    {
                        return true;
                    }
                }

                return false;
            }

            bool TryReadOpenSegment(Entity ent, out Point2d a, out Point2d b)
            {
                a = default;
                b = default;
                if (ent == null)
                {
                    return false;
                }

                if (ent is Line ln)
                {
                    a = new Point2d(ln.StartPoint.X, ln.StartPoint.Y);
                    b = new Point2d(ln.EndPoint.X, ln.EndPoint.Y);
                    return a.GetDistanceTo(b) > 1e-4;
                }

                if (ent is Polyline pl)
                {
                    if (pl.Closed || pl.NumberOfVertices != 2)
                    {
                        return false;
                    }

                    a = pl.GetPoint2dAt(0);
                    b = pl.GetPoint2dAt(1);
                    return a.GetDistanceTo(b) > 1e-4;
                }

                return false;
            }

            bool TryMoveEndpoint(Entity writable, bool moveStart, Point2d target, double moveTol)
            {
                if (writable is Line ln)
                {
                    var old = moveStart
                        ? new Point2d(ln.StartPoint.X, ln.StartPoint.Y)
                        : new Point2d(ln.EndPoint.X, ln.EndPoint.Y);
                    if (old.GetDistanceTo(target) <= moveTol)
                    {
                        return false;
                    }

                    if (moveStart)
                    {
                        ln.StartPoint = new Point3d(target.X, target.Y, ln.StartPoint.Z);
                    }
                    else
                    {
                        ln.EndPoint = new Point3d(target.X, target.Y, ln.EndPoint.Z);
                    }

                    return true;
                }

                if (writable is Polyline pl && !pl.Closed && pl.NumberOfVertices == 2)
                {
                    var index = moveStart ? 0 : 1;
                    var old = pl.GetPoint2dAt(index);
                    if (old.GetDistanceTo(target) <= moveTol)
                    {
                        return false;
                    }

                    pl.SetPointAt(index, target);
                    return true;
                }

                return false;
            }

            bool TryIntersectInfiniteLines(Point2d a0, Point2d a1, Point2d b0, Point2d b1, out Point2d intersection)
            {
                intersection = default;
                var da = a1 - a0;
                var db = b1 - b0;
                var denom = Cross2d(da, db);
                if (Math.Abs(denom) <= 1e-9)
                {
                    return false;
                }

                var diff = b0 - a0;
                var t = Cross2d(diff, db) / denom;
                intersection = a0 + (da * t);
                return true;
            }

            bool IsHorizontalLike(Point2d a, Point2d b)
            {
                var d = b - a;
                return Math.Abs(d.X) >= Math.Abs(d.Y);
            }

            bool IsVerticalLike(Point2d a, Point2d b)
            {
                var d = b - a;
                return Math.Abs(d.Y) > Math.Abs(d.X);
            }

            bool IsUsecZeroOrTwentyLayer(string layer)
            {
                return string.Equals(layer, LayerUsecZero, StringComparison.OrdinalIgnoreCase) ||
                       string.Equals(layer, LayerUsecTwenty, StringComparison.OrdinalIgnoreCase);
            }

            bool IsRoadLayer(string layer)
            {
                return string.Equals(layer, "L-SEC", StringComparison.OrdinalIgnoreCase) ||
                       string.Equals(layer, LayerUsecBase, StringComparison.OrdinalIgnoreCase) ||
                       string.Equals(layer, LayerUsecZero, StringComparison.OrdinalIgnoreCase) ||
                       string.Equals(layer, LayerUsecTwenty, StringComparison.OrdinalIgnoreCase) ||
                       string.Equals(layer, LayerUsecThirty, StringComparison.OrdinalIgnoreCase);
            }

            using (var tr = database.TransactionManager.StartTransaction())
            {
                var allRoadSegments = new List<(ObjectId Id, Point2d A, Point2d B, string Layer)>();
                var trackedSegments = new List<(ObjectId Id, Point2d A, Point2d B, bool Horizontal, bool Vertical, bool MovableSource, bool IsBaseUsecTarget, string Layer)>();

                var bt = (BlockTable)tr.GetObject(database.BlockTableId, OpenMode.ForRead);
                var ms = (BlockTableRecord)tr.GetObject(bt[BlockTableRecord.ModelSpace], OpenMode.ForRead);
                foreach (ObjectId id in ms)
                {
                    if (!(tr.GetObject(id, OpenMode.ForRead, false) is Entity ent) || ent.IsErased)
                    {
                        continue;
                    }

                    if (!TryReadOpenSegment(ent, out var a, out var b))
                    {
                        continue;
                    }

                    if (!DoesSegmentIntersectAnyWindow(a, b))
                    {
                        continue;
                    }

                    var layer = ent.Layer ?? string.Empty;
                    if (IsRoadLayer(layer))
                    {
                        allRoadSegments.Add((id, a, b, layer));
                    }

                    var isMovableSource = IsUsecZeroOrTwentyLayer(layer);
                    var isBaseUsecTarget =
                        string.Equals(layer, LayerUsecBase, StringComparison.OrdinalIgnoreCase) ||
                        string.Equals(layer, "L-USEC", StringComparison.OrdinalIgnoreCase);
                    // Square-closure mode for interior boundaries:
                    // only 0/20 lines are movable and valid targets (0->0, 20->20).
                    var isConnectTarget = isMovableSource;
                    if (!isConnectTarget)
                    {
                        continue;
                    }

                    var horizontal = IsHorizontalLike(a, b);
                    var vertical = IsVerticalLike(a, b);
                    if (!horizontal && !vertical)
                    {
                        continue;
                    }

                    trackedSegments.Add((id, a, b, horizontal, vertical, isMovableSource, isBaseUsecTarget, layer));
                }

                if (trackedSegments.Count == 0)
                {
                    tr.Commit();
                    return;
                }

                const double endpointHitTol = 0.35;
                const double endpointMoveTol = 0.05;
                const double endpointSnapTol = 1.0;
                const double minExtend = 0.05;
                const double maxExtend = 45.0;
                const double targetOnSegmentTol = 0.65;
                const double targetOnSegmentTolRelaxed = 1.50;
                const double apparentEndpointGapTol = 24.0;
                const double outerBoundaryTol = 0.40;
                var scannedEndpoints = 0;
                var skippedOnOuterBoundary = 0;
                var alreadyConnected = 0;
                var noThirtyContext = 0;
                var noTarget = 0;
                var moved = 0;
                var sideRejected = 0;
                var sideRuleFallbackUsed = 0;
                var baseTargetFallbackUsed = 0;
                var apparentFallbackUsed = 0;

                bool IsUsecThirtyLayerName(string layer)
                {
                    return string.Equals(layer, LayerUsecThirty, StringComparison.OrdinalIgnoreCase);
                }

                bool TryGetNearestThirtyAxis(bool wantVertical, Point2d referencePoint, out double axis)
                {
                    axis = 0.0;
                    var found = false;
                    var bestDistance = double.MaxValue;
                    const double axisRangeTol = 4.0;
                    for (var i = 0; i < allRoadSegments.Count; i++)
                    {
                        var seg = allRoadSegments[i];
                        if (!IsUsecThirtyLayerName(seg.Layer))
                        {
                            continue;
                        }

                        var horizontal = IsHorizontalLike(seg.A, seg.B);
                        var vertical = IsVerticalLike(seg.A, seg.B);
                        if (wantVertical && !vertical)
                        {
                            continue;
                        }

                        if (!wantVertical && !horizontal)
                        {
                            continue;
                        }

                        if (wantVertical)
                        {
                            var minY = Math.Min(seg.A.Y, seg.B.Y) - axisRangeTol;
                            var maxY = Math.Max(seg.A.Y, seg.B.Y) + axisRangeTol;
                            if (referencePoint.Y < minY || referencePoint.Y > maxY)
                            {
                                continue;
                            }

                            var d = Math.Abs(referencePoint.X - (0.5 * (seg.A.X + seg.B.X)));
                            if (d >= bestDistance)
                            {
                                continue;
                            }

                            bestDistance = d;
                            axis = 0.5 * (seg.A.X + seg.B.X);
                            found = true;
                            continue;
                        }

                        var minX = Math.Min(seg.A.X, seg.B.X) - axisRangeTol;
                        var maxX = Math.Max(seg.A.X, seg.B.X) + axisRangeTol;
                        if (referencePoint.X < minX || referencePoint.X > maxX)
                        {
                            continue;
                        }

                        var dY = Math.Abs(referencePoint.Y - (0.5 * (seg.A.Y + seg.B.Y)));
                        if (dY >= bestDistance)
                        {
                            continue;
                        }

                        bestDistance = dY;
                        axis = 0.5 * (seg.A.Y + seg.B.Y);
                        found = true;
                    }

                    return found;
                }

                int SignWithTol(double value, double tol)
                {
                    if (value > tol)
                    {
                        return 1;
                    }

                    if (value < -tol)
                    {
                        return -1;
                    }

                    return 0;
                }

                bool IsSameSideOfRoadAllowance(
                    (ObjectId Id, Point2d A, Point2d B, bool Horizontal, bool Vertical, bool MovableSource, bool IsBaseUsecTarget, string Layer) source,
                    Point2d sourcePoint,
                    Point2d sourceOtherPoint,
                    Point2d targetPoint)
                {
                    const double sideTol = 0.25;
                    if (source.Vertical)
                    {
                        if (!TryGetNearestThirtyAxis(wantVertical: false, sourcePoint, out var axisY))
                        {
                            return true;
                        }

                        var sourceSign = SignWithTol(sourcePoint.Y - axisY, sideTol);
                        if (sourceSign == 0)
                        {
                            sourceSign = SignWithTol(sourceOtherPoint.Y - axisY, sideTol);
                        }

                        var targetSign = SignWithTol(targetPoint.Y - axisY, sideTol);
                        if (sourceSign == 0 || targetSign == 0)
                        {
                            return true;
                        }

                        return sourceSign == targetSign;
                    }

                    if (source.Horizontal)
                    {
                        if (!TryGetNearestThirtyAxis(wantVertical: true, sourcePoint, out var axisX))
                        {
                            return true;
                        }

                        var sourceSign = SignWithTol(sourcePoint.X - axisX, sideTol);
                        if (sourceSign == 0)
                        {
                            sourceSign = SignWithTol(sourceOtherPoint.X - axisX, sideTol);
                        }

                        var targetSign = SignWithTol(targetPoint.X - axisX, sideTol);
                        if (sourceSign == 0 || targetSign == 0)
                        {
                            return true;
                        }

                        return sourceSign == targetSign;
                    }

                    return false;
                }

                (bool TouchesSameBand, bool TouchesUsecThirty) GetEndpointTouchState(
                    Point2d endpoint,
                    ObjectId sourceId,
                    string sourceLayer)
                {
                    var touchesSameBand = false;
                    var touchesUsecThirty = false;
                    for (var i = 0; i < allRoadSegments.Count; i++)
                    {
                        var seg = allRoadSegments[i];
                        if (seg.Id == sourceId)
                        {
                            continue;
                        }

                        if (DistancePointToSegment(endpoint, seg.A, seg.B) <= endpointHitTol)
                        {
                            if (string.Equals(seg.Layer, sourceLayer, StringComparison.OrdinalIgnoreCase))
                            {
                                touchesSameBand = true;
                            }
                            else if (IsUsecThirtyLayerName(seg.Layer))
                            {
                                touchesUsecThirty = true;
                            }
                        }
                    }

                    return (touchesSameBand, touchesUsecThirty);
                }

                void UpdateTrackedSegment(ObjectId id, Point2d a, Point2d b)
                {
                    var horizontal = IsHorizontalLike(a, b);
                    var vertical = IsVerticalLike(a, b);
                    for (var i = 0; i < trackedSegments.Count; i++)
                    {
                        if (trackedSegments[i].Id != id)
                        {
                            continue;
                        }

                        trackedSegments[i] = (id, a, b, horizontal, vertical, trackedSegments[i].MovableSource, trackedSegments[i].IsBaseUsecTarget, trackedSegments[i].Layer);
                        break;
                    }

                    for (var i = 0; i < allRoadSegments.Count; i++)
                    {
                        if (allRoadSegments[i].Id != id)
                        {
                            continue;
                        }

                        allRoadSegments[i] = (id, a, b, allRoadSegments[i].Layer);
                        break;
                    }
                }

                for (var si = 0; si < trackedSegments.Count; si++)
                {
                    var source = trackedSegments[si];
                    if (!source.MovableSource)
                    {
                        continue;
                    }

                    if (!source.Horizontal && !source.Vertical)
                    {
                        continue;
                    }

                    // Square-closure mode: allow both orientations so 0 and 20.11/20.12
                    // can close full corners in partial builds.

                    for (var endpointIndex = 0; endpointIndex <= 1; endpointIndex++)
                    {
                        scannedEndpoints++;
                        var endpoint = endpointIndex == 0 ? source.A : source.B;
                        var other = endpointIndex == 0 ? source.B : source.A;

                        if (IsPointOnAnyWindowBoundary(endpoint, outerBoundaryTol))
                        {
                            skippedOnOuterBoundary++;
                            continue;
                        }

                        var touchState = GetEndpointTouchState(endpoint, source.Id, source.Layer);
                        if (touchState.TouchesSameBand)
                        {
                            alreadyConnected++;
                            continue;
                        }
                        if (!touchState.TouchesUsecThirty)
                        {
                            // Allow dangling 0/20 endpoints to connect even without explicit 30.18 touch.
                            // This keeps partial township builds consistent with full-township intersections.
                            noThirtyContext++;
                        }

                        var outward = endpoint - other;
                        var outwardLen = outward.Length;
                        if (outwardLen <= 1e-6)
                        {
                            continue;
                        }

                        var outwardUnit = outward / outwardLen;
                        var found = false;
                        var bestScore = double.MaxValue;
                        var bestTarget = endpoint;

                        bool TrySelectBestTarget(
                            bool enforceSideRule,
                            bool allowBaseUsecTarget,
                            double targetTol,
                            bool allowApparent,
                            out int rejectedBySideThisPass)
                        {
                            rejectedBySideThisPass = 0;
                            var localFound = false;
                            var localBestScore = double.MaxValue;
                            var localBestTarget = endpoint;
                            for (var ti = 0; ti < trackedSegments.Count; ti++)
                            {
                                var target = trackedSegments[ti];
                                if (target.Id == source.Id)
                                {
                                    continue;
                                }

                                if (!allowBaseUsecTarget && target.IsBaseUsecTarget)
                                {
                                    continue;
                                }

                                var orthogonal =
                                    (source.Horizontal && target.Vertical) ||
                                    (source.Vertical && target.Horizontal);
                                if (!orthogonal)
                                {
                                    continue;
                                }

                                if (!TryIntersectInfiniteLines(source.A, source.B, target.A, target.B, out var intersection))
                                {
                                    continue;
                                }

                                if (!IsPointInAnyWindow(intersection))
                                {
                                    continue;
                                }

                                if (enforceSideRule &&
                                    !IsSameSideOfRoadAllowance(source, endpoint, other, intersection))
                                {
                                    rejectedBySideThisPass++;
                                    continue;
                                }

                                var along = (intersection - endpoint).DotProduct(outwardUnit);
                                if (along <= minExtend || along > maxExtend)
                                {
                                    continue;
                                }

                                if (!string.Equals(source.Layer, target.Layer, StringComparison.OrdinalIgnoreCase))
                                {
                                    continue;
                                }

                                var targetDistance = DistancePointToSegment(intersection, target.A, target.B);
                                var endpointGap = Math.Min(
                                    intersection.GetDistanceTo(target.A),
                                    intersection.GetDistanceTo(target.B));
                                var isApparent =
                                    targetDistance > targetTol &&
                                    allowApparent &&
                                    endpointGap <= apparentEndpointGapTol;

                                if (targetDistance > targetTol && !isApparent)
                                {
                                    continue;
                                }

                                var score = along + (4.0 * targetDistance);
                                if (isApparent)
                                {
                                    // Prefer true on-segment targets, but allow short open-T/perpendicular
                                    // pairs to resolve by apparent intersection when both are 0/20.
                                    score += (8.0 * endpointGap) + 20.0;
                                }

                                if (score >= localBestScore)
                                {
                                    continue;
                                }

                                localFound = true;
                                localBestScore = score;
                                localBestTarget = intersection;
                            }

                            if (localFound)
                            {
                                found = true;
                                bestScore = localBestScore;
                                bestTarget = localBestTarget;
                            }

                            return localFound;
                        }

                        if (!TrySelectBestTarget(
                                enforceSideRule: true,
                                allowBaseUsecTarget: false,
                                targetTol: targetOnSegmentTol,
                                allowApparent: false,
                                out var rejectedBySide))
                        {
                            sideRejected += rejectedBySide;
                            // Fallback: if side-of-road inference is ambiguous for this endpoint,
                            // still connect to the nearest valid orthogonal 0/20 target.
                            if (TrySelectBestTarget(
                                enforceSideRule: false,
                                allowBaseUsecTarget: false,
                                targetTol: targetOnSegmentTol,
                                allowApparent: false,
                                out _))
                            {
                                sideRuleFallbackUsed++;
                            }
                            else if (TrySelectBestTarget(
                                enforceSideRule: false,
                                allowBaseUsecTarget: false,
                                targetTol: targetOnSegmentTolRelaxed,
                                allowApparent: true,
                                out _))
                            {
                                sideRuleFallbackUsed++;
                                apparentFallbackUsed++;
                            }
                            else if (TrySelectBestTarget(
                                enforceSideRule: false,
                                allowBaseUsecTarget: true,
                                targetTol: targetOnSegmentTolRelaxed,
                                allowApparent: false,
                                out _))
                            {
                                sideRuleFallbackUsed++;
                                baseTargetFallbackUsed++;
                            }
                        }
                        else
                        {
                            sideRejected += rejectedBySide;
                        }

                        if (!found)
                        {
                            noTarget++;
                            continue;
                        }

                        if (!(tr.GetObject(source.Id, OpenMode.ForWrite, false) is Entity writable) || writable.IsErased)
                        {
                            continue;
                        }

                        if (!TryReadOpenSegment(writable, out var curA, out var curB))
                        {
                            continue;
                        }

                        var d0 = curA.GetDistanceTo(endpoint);
                        var d1 = curB.GetDistanceTo(endpoint);
                        if (d0 > endpointSnapTol && d1 > endpointSnapTol)
                        {
                            continue;
                        }

                        var moveStart = d0 <= d1;
                        var sourceEndpoint = moveStart ? curA : curB;
                        var moveDistance = sourceEndpoint.GetDistanceTo(bestTarget);
                        if (moveDistance <= endpointMoveTol || moveDistance > maxExtend)
                        {
                            continue;
                        }

                        if (!TryMoveEndpoint(writable, moveStart, bestTarget, endpointMoveTol))
                        {
                            continue;
                        }

                        if (!TryReadOpenSegment(writable, out var newA, out var newB))
                        {
                            continue;
                        }

                        moved++;
                        UpdateTrackedSegment(source.Id, newA, newB);
                        source = trackedSegments[si];
                    }
                }

                tr.Commit();
                if (moved > 0 || noTarget > 0)
                {
                    logger?.WriteLine(
                        $"Cleanup: 0/20 dangling endpoint connect scanned={scannedEndpoints}, outerSkipped={skippedOnOuterBoundary}, alreadyConnected={alreadyConnected}, no3018Context={noThirtyContext}, sideRejected={sideRejected}, sideFallbackUsed={sideRuleFallbackUsed}, apparentFallbackUsed={apparentFallbackUsed}, baseFallbackUsed={baseTargetFallbackUsed}, moved={moved}, noTarget={noTarget}.");
                }
            }
        }

        private static void CleanupDuplicateBlindLineSegments(
            Database database,
            IEnumerable<ObjectId> requestedQuarterIds,
            Logger? logger)
        {
            if (database == null || requestedQuarterIds == null)
            {
                return;
            }

            var clipWindows = BuildBufferedQuarterWindows(database, requestedQuarterIds, 100.0);
            if (clipWindows.Count == 0)
            {
                return;
            }

            bool IsPointInAnyWindow(Point2d p)
            {
                for (var i = 0; i < clipWindows.Count; i++)
                {
                    var w = clipWindows[i];
                    if (p.X >= w.MinPoint.X && p.X <= w.MaxPoint.X &&
                        p.Y >= w.MinPoint.Y && p.Y <= w.MaxPoint.Y)
                    {
                        return true;
                    }
                }

                return false;
            }

            bool DoesSegmentIntersectAnyWindow(Point2d a, Point2d b)
            {
                if (IsPointInAnyWindow(a) || IsPointInAnyWindow(b))
                {
                    return true;
                }

                for (var i = 0; i < clipWindows.Count; i++)
                {
                    if (TryClipSegmentToWindow(a, b, clipWindows[i], out _, out _))
                    {
                        return true;
                    }
                }

                return false;
            }

            bool TryReadOpenSegment(Entity ent, out Point2d a, out Point2d b)
            {
                a = default;
                b = default;
                if (ent == null)
                {
                    return false;
                }

                if (ent is Line ln)
                {
                    a = new Point2d(ln.StartPoint.X, ln.StartPoint.Y);
                    b = new Point2d(ln.EndPoint.X, ln.EndPoint.Y);
                    return a.GetDistanceTo(b) > 1e-4;
                }

                if (ent is Polyline pl)
                {
                    if (pl.Closed || pl.NumberOfVertices < 2)
                    {
                        return false;
                    }

                    a = pl.GetPoint2dAt(0);
                    b = pl.GetPoint2dAt(pl.NumberOfVertices - 1);
                    if (a.GetDistanceTo(b) <= 1e-4)
                    {
                        return false;
                    }

                    if (pl.NumberOfVertices > 2)
                    {
                        const double collinearTol = 0.35;
                        for (var vi = 1; vi < pl.NumberOfVertices - 1; vi++)
                        {
                            var p = pl.GetPoint2dAt(vi);
                            if (DistancePointToInfiniteLine(p, a, b) > collinearTol)
                            {
                                return false;
                            }
                        }
                    }

                    return true;
                }

                return false;
            }

            bool IsHorizontalLike(Point2d a, Point2d b)
            {
                var d = b - a;
                return Math.Abs(d.X) >= Math.Abs(d.Y);
            }

            bool IsVerticalLike(Point2d a, Point2d b)
            {
                var d = b - a;
                return Math.Abs(d.Y) > Math.Abs(d.X);
            }

            using (var tr = database.TransactionManager.StartTransaction())
            {
                var candidates = new List<(ObjectId Id, string Layer, Point2d A, Point2d B, Point2d Mid, double Len)>();
                var bt = (BlockTable)tr.GetObject(database.BlockTableId, OpenMode.ForRead);
                var ms = (BlockTableRecord)tr.GetObject(bt[BlockTableRecord.ModelSpace], OpenMode.ForRead);
                foreach (ObjectId id in ms)
                {
                    Entity? ent = null;
                    try
                    {
                        ent = tr.GetObject(id, OpenMode.ForRead, false) as Entity;
                    }
                    catch (Autodesk.AutoCAD.Runtime.Exception)
                    {
                        continue;
                    }

                    if (ent == null || ent.IsErased)
                    {
                        continue;
                    }

                    var isUsec = IsUsecLayer(ent.Layer ?? string.Empty);
                    var isSec = string.Equals(ent.Layer, "L-SEC", StringComparison.OrdinalIgnoreCase);
                    if (!isUsec && !isSec)
                    {
                        continue;
                    }

                    if (!TryReadOpenSegment(ent, out var a, out var b))
                    {
                        continue;
                    }

                    if (!DoesSegmentIntersectAnyWindow(a, b))
                    {
                        continue;
                    }

                    var len = a.GetDistanceTo(b);
                    if (len < 2.0 || len > 2000.0)
                    {
                        continue;
                    }

                    if (!IsHorizontalLike(a, b) && !IsVerticalLike(a, b))
                    {
                        continue;
                    }

                    candidates.Add((id, ent.Layer, a, b, Midpoint(a, b), len));
                }

                if (candidates.Count < 2)
                {
                    tr.Commit();
                    return;
                }

                const double endpointTol = 0.75;
                const double midpointTol = 0.60;
                const double lengthTol = 0.60;
                const double minBlindLen = 8.0;
                const double maxBlindLen = 2000.0;
                const double containTol = 0.60;

                bool IsSegmentContained(Point2d innerA, Point2d innerB, Point2d outerA, Point2d outerB)
                {
                    return DistancePointToSegment(innerA, outerA, outerB) <= containTol &&
                           DistancePointToSegment(innerB, outerA, outerB) <= containTol;
                }

                var toErase = new HashSet<ObjectId>();
                for (var i = 0; i < candidates.Count; i++)
                {
                    var a = candidates[i];
                    if (toErase.Contains(a.Id))
                    {
                        continue;
                    }

                    if (a.Len < minBlindLen || a.Len > maxBlindLen)
                    {
                        continue;
                    }

                    for (var j = i + 1; j < candidates.Count; j++)
                    {
                        var b = candidates[j];
                        if (toErase.Contains(b.Id))
                        {
                            continue;
                        }

                        if (b.Len < minBlindLen || b.Len > maxBlindLen)
                        {
                            continue;
                        }

                        var nearDuplicate = AreSegmentEndpointsNear(a.A, a.B, b.A, b.B, endpointTol);
                        if (!nearDuplicate)
                        {
                            var collinearOverlap = AreSegmentsDuplicateOrCollinearOverlap(a.A, a.B, b.A, b.B);
                            if (!collinearOverlap)
                            {
                                continue;
                            }

                            var similarShape =
                                Math.Abs(a.Len - b.Len) <= lengthTol &&
                                a.Mid.GetDistanceTo(b.Mid) <= midpointTol;
                            var contained =
                                IsSegmentContained(a.A, a.B, b.A, b.B) ||
                                IsSegmentContained(b.A, b.B, a.A, a.B);
                            if (!similarShape && !contained)
                            {
                                continue;
                            }
                        }

                        var eraseId = a.Id.Handle.Value > b.Id.Handle.Value ? a.Id : b.Id;
                        var aUsec = string.Equals(a.Layer, "L-USEC", StringComparison.OrdinalIgnoreCase);
                        var bUsec = string.Equals(b.Layer, "L-USEC", StringComparison.OrdinalIgnoreCase);
                        if (aUsec != bUsec)
                        {
                            // Prefer keeping L-USEC when duplicates were emitted on mixed layers.
                            eraseId = aUsec ? b.Id : a.Id;
                        }

                        toErase.Add(eraseId);
                    }
                }

                var erased = 0;
                foreach (var id in toErase)
                {
                    if (!(tr.GetObject(id, OpenMode.ForWrite, false) is Entity ent) || ent.IsErased)
                    {
                        continue;
                    }

                    ent.Erase();
                    erased++;
                }

                tr.Commit();
                if (erased > 0)
                {
                    logger?.WriteLine($"Cleanup: erased {erased} duplicate blind-line segment(s) on adjoining sections.");
                }
            }
        }

        private static void NormalizeGeneratedRoadAllowanceLayers(
            Database database,
            IReadOnlyCollection<ObjectId> generatedRoadAllowanceIds,
            Logger? logger)
        {
            if (database == null || generatedRoadAllowanceIds == null || generatedRoadAllowanceIds.Count == 0)
            {
                return;
            }

            using (var tr = database.TransactionManager.StartTransaction())
            {
                bool TryReadOpenSegment(Entity ent, out Point2d a, out Point2d b)
                {
                    a = default;
                    b = default;
                    if (ent == null)
                    {
                        return false;
                    }

                    if (ent is Line ln)
                    {
                        a = new Point2d(ln.StartPoint.X, ln.StartPoint.Y);
                        b = new Point2d(ln.EndPoint.X, ln.EndPoint.Y);
                        return a.GetDistanceTo(b) > 1e-4;
                    }

                    if (ent is Polyline pl)
                    {
                        if (pl.Closed || pl.NumberOfVertices != 2)
                        {
                            return false;
                        }

                        a = pl.GetPoint2dAt(0);
                        b = pl.GetPoint2dAt(1);
                        return a.GetDistanceTo(b) > 1e-4;
                    }

                    return false;
                }

                bool IsHorizontalLike(Point2d a, Point2d b)
                {
                    var d = b - a;
                    return Math.Abs(d.X) >= Math.Abs(d.Y);
                }

                bool IsVerticalLike(Point2d a, Point2d b)
                {
                    var d = b - a;
                    return Math.Abs(d.Y) > Math.Abs(d.X);
                }
                const double lengthMin = 4.0;

                var generatedSet = new HashSet<ObjectId>(generatedRoadAllowanceIds.Where(id => !id.IsNull));
                var generatedSegments = new List<(ObjectId Id, Point2d A, Point2d B, bool Horizontal, bool Vertical, double Length)>();
                var bt = (BlockTable)tr.GetObject(database.BlockTableId, OpenMode.ForRead);
                var ms = (BlockTableRecord)tr.GetObject(bt[BlockTableRecord.ModelSpace], OpenMode.ForRead);
                foreach (ObjectId id in ms)
                {
                    if (!(tr.GetObject(id, OpenMode.ForRead, false) is Entity ent) || ent.IsErased)
                    {
                        continue;
                    }

                    if (!TryReadOpenSegment(ent, out var a, out var b))
                    {
                        continue;
                    }

                    var len = a.GetDistanceTo(b);
                    if (len < lengthMin)
                    {
                        continue;
                    }

                    var horizontal = IsHorizontalLike(a, b);
                    var vertical = IsVerticalLike(a, b);
                    if (!horizontal && !vertical)
                    {
                        continue;
                    }

                    if (generatedSet.Contains(id))
                    {
                        generatedSegments.Add((id, a, b, horizontal, vertical, len));
                    }
                }

                if (generatedSegments.Count == 0)
                {
                    tr.Commit();
                    return;
                }

                var normalizedGenerated = 0;
                for (var i = 0; i < generatedSegments.Count; i++)
                {
                    var seg = generatedSegments[i];
                    if (!(tr.GetObject(seg.Id, OpenMode.ForWrite, false) is Entity writable) || writable.IsErased)
                    {
                        continue;
                    }

                    if (IsUsecLayer(writable.Layer) ||
                        string.Equals(writable.Layer, "L-SEC", StringComparison.OrdinalIgnoreCase))
                    {
                        continue;
                    }

                    writable.Layer = LayerUsecBase;
                    writable.ColorIndex = 256;
                    normalizedGenerated++;
                }

                tr.Commit();
                if (normalizedGenerated > 0)
                {
                    logger?.WriteLine($"Cleanup: normalized {normalizedGenerated} generated RA segment(s) with invalid layer to L-USEC base [candidates={generatedSegments.Count}].");
                }
            }
        }

        private static void SnapContextEndpointsAfterTrim(
            Database database,
            IReadOnlyCollection<ObjectId> contextSectionIds,
            IEnumerable<ObjectId> requestedQuarterIds,
            Logger? logger)
        {
            if (database == null || contextSectionIds == null || contextSectionIds.Count == 0 || requestedQuarterIds == null)
            {
                return;
            }

            var clipWindows = BuildBufferedQuarterWindows(database, requestedQuarterIds, 102.0);
            if (clipWindows.Count == 0)
            {
                return;
            }

            bool IsPointInAnyWindow(Point2d p)
            {
                for (var i = 0; i < clipWindows.Count; i++)
                {
                    var w = clipWindows[i];
                    if (p.X >= w.MinPoint.X && p.X <= w.MaxPoint.X &&
                        p.Y >= w.MinPoint.Y && p.Y <= w.MaxPoint.Y)
                    {
                        return true;
                    }
                }

                return false;
            }

            bool DoesSegmentIntersectAnyWindow(Point2d a, Point2d b)
            {
                if (IsPointInAnyWindow(a) || IsPointInAnyWindow(b))
                {
                    return true;
                }

                for (var i = 0; i < clipWindows.Count; i++)
                {
                    if (TryClipSegmentToWindow(a, b, clipWindows[i], out _, out _))
                    {
                        return true;
                    }
                }

                return false;
            }

            using (var tr = database.TransactionManager.StartTransaction())
            {
                bool TryReadOpenSegment(Entity ent, out Point2d a, out Point2d b)
                {
                    a = default;
                    b = default;
                    if (ent == null)
                    {
                        return false;
                    }

                    if (ent is Line ln)
                    {
                        a = new Point2d(ln.StartPoint.X, ln.StartPoint.Y);
                        b = new Point2d(ln.EndPoint.X, ln.EndPoint.Y);
                        return a.GetDistanceTo(b) > 1e-4;
                    }

                    if (ent is Polyline pl)
                    {
                        if (pl.Closed || pl.NumberOfVertices != 2)
                        {
                            return false;
                        }

                        a = pl.GetPoint2dAt(0);
                        b = pl.GetPoint2dAt(1);
                        return a.GetDistanceTo(b) > 1e-4;
                    }

                    return false;
                }

                bool TryWriteOpenSegment(Entity ent, Point2d a, Point2d b)
                {
                    if (a.GetDistanceTo(b) <= 1e-4)
                    {
                        return false;
                    }

                    if (ent is Line ln)
                    {
                        ln.StartPoint = new Point3d(a.X, a.Y, ln.StartPoint.Z);
                        ln.EndPoint = new Point3d(b.X, b.Y, ln.EndPoint.Z);
                        return true;
                    }

                    if (ent is Polyline pl && !pl.Closed && pl.NumberOfVertices == 2)
                    {
                        pl.SetPointAt(0, a);
                        pl.SetPointAt(1, b);
                        return true;
                    }

                    return false;
                }

                bool IsHorizontalLike(Point2d a, Point2d b)
                {
                    var d = b - a;
                    return Math.Abs(d.X) >= Math.Abs(d.Y);
                }

                bool IsVerticalLike(Point2d a, Point2d b)
                {
                    var d = b - a;
                    return Math.Abs(d.Y) > Math.Abs(d.X);
                }

                var contextSet = new HashSet<ObjectId>(contextSectionIds.Where(id => !id.IsNull));
                var endpointAnchors = new List<(ObjectId Id, string Layer, bool IsContext, Point2d P)>();
                var allSegments = new List<(ObjectId Id, string Layer, bool IsContext, Point2d A, Point2d B, bool Horizontal, bool Vertical)>();
                var bt = (BlockTable)tr.GetObject(database.BlockTableId, OpenMode.ForRead);
                var ms = (BlockTableRecord)tr.GetObject(bt[BlockTableRecord.ModelSpace], OpenMode.ForRead);
                foreach (ObjectId id in ms)
                {
                    Entity? ent = null;
                    try
                    {
                        ent = tr.GetObject(id, OpenMode.ForRead, false) as Entity;
                    }
                    catch (Autodesk.AutoCAD.Runtime.Exception)
                    {
                        continue;
                    }

                    if (ent == null || ent.IsErased)
                    {
                        continue;
                    }

                    if (!string.Equals(ent.Layer, "L-SEC", StringComparison.OrdinalIgnoreCase) &&
                        !IsUsecLayer(ent.Layer))
                    {
                        continue;
                    }

                    if (!TryReadOpenSegment(ent, out var a, out var b))
                    {
                        continue;
                    }

                    if (!DoesSegmentIntersectAnyWindow(a, b))
                    {
                        continue;
                    }

                    var isContext = contextSet.Contains(id);
                    var layerName = ent.Layer ?? string.Empty;
                    endpointAnchors.Add((id, layerName, isContext, a));
                    endpointAnchors.Add((id, layerName, isContext, b));
                    allSegments.Add((id, layerName, isContext, a, b, IsHorizontalLike(a, b), IsVerticalLike(a, b)));
                }

                if (endpointAnchors.Count == 0)
                {
                    tr.Commit();
                    return;
                }

                const double endpointSnapTol = 1.20;
                const double segmentSnapTol = 0.60;
                const double moveTol = 0.02;
                const double axisTol = 1.20;
                var adjusted = 0;
                foreach (var id in contextSet.ToList())
                {
                    Entity? ent = null;
                    try
                    {
                        ent = tr.GetObject(id, OpenMode.ForWrite, false) as Entity;
                    }
                    catch (Autodesk.AutoCAD.Runtime.Exception)
                    {
                        continue;
                    }

                    if (ent == null || ent.IsErased)
                    {
                        continue;
                    }

                    if (!TryReadOpenSegment(ent, out var p0, out var p1))
                    {
                        continue;
                    }

                    var currentLayer = ent.Layer ?? string.Empty;
                    var thisIsHorizontal = IsHorizontalLike(p0, p1);
                    var thisIsVertical = IsVerticalLike(p0, p1);

                    bool TrySnapEndpoint(Point2d endpoint, Point2d oppositeEndpoint, out Point2d snapped)
                    {
                        snapped = endpoint;
                        var found = false;
                        var bestDist = double.MaxValue;
                        var bestTargetIsContext = true;
                        var ownerDirVec = oppositeEndpoint - endpoint;
                        var ownerDirLen = ownerDirVec.Length;
                        if (ownerDirLen <= 1e-6)
                        {
                            return false;
                        }

                        var ownerDir = ownerDirVec / ownerDirLen;
                        for (var i = 0; i < endpointAnchors.Count; i++)
                        {
                            var anchor = endpointAnchors[i];
                            if (anchor.Id == id)
                            {
                                continue;
                            }

                            if (!string.Equals(anchor.Layer, currentLayer, StringComparison.OrdinalIgnoreCase))
                            {
                                continue;
                            }

                            if (thisIsHorizontal && Math.Abs(anchor.P.Y - endpoint.Y) > axisTol)
                            {
                                continue;
                            }

                            if (thisIsVertical && Math.Abs(anchor.P.X - endpoint.X) > axisTol)
                            {
                                continue;
                            }

                            var candidate = anchor.P;
                            if (thisIsHorizontal)
                            {
                                candidate = new Point2d(anchor.P.X, endpoint.Y);
                            }
                            else if (thisIsVertical)
                            {
                                candidate = new Point2d(endpoint.X, anchor.P.Y);
                            }

                            var d = endpoint.GetDistanceTo(candidate);
                            if (d > endpointSnapTol)
                            {
                                continue;
                            }

                            var prefer = !anchor.IsContext;
                            var better = !found;
                            if (!better)
                            {
                                if (prefer && bestTargetIsContext)
                                {
                                    better = true;
                                }
                                else if (prefer == !bestTargetIsContext && d < (bestDist - 1e-9))
                                {
                                    better = true;
                                }
                            }

                            if (!better)
                            {
                                continue;
                            }

                            found = true;
                            bestDist = d;
                            bestTargetIsContext = anchor.IsContext;
                            snapped = candidate;
                        }

                        // Also allow endpoint to snap onto nearby segment span
                        // (axis-constrained) to eliminate tiny overlaps/gaps where anchor
                        // endpoints are not the closest geometry.
                        for (var i = 0; i < allSegments.Count; i++)
                        {
                            var seg = allSegments[i];
                            if (seg.Id == id)
                            {
                                continue;
                            }

                            if (!string.Equals(seg.Layer, currentLayer, StringComparison.OrdinalIgnoreCase))
                            {
                                continue;
                            }

                            if (thisIsHorizontal && !seg.Horizontal)
                            {
                                continue;
                            }

                            if (thisIsVertical && !seg.Vertical)
                            {
                                continue;
                            }

                            Point2d candidate;
                            if (thisIsHorizontal)
                            {
                                var yLine = 0.5 * (seg.A.Y + seg.B.Y);
                                if (Math.Abs(yLine - endpoint.Y) > axisTol)
                                {
                                    continue;
                                }

                                var minX = Math.Min(seg.A.X, seg.B.X);
                                var maxX = Math.Max(seg.A.X, seg.B.X);
                                var x = Math.Max(minX, Math.Min(maxX, endpoint.X));
                                candidate = new Point2d(x, endpoint.Y);
                            }
                            else if (thisIsVertical)
                            {
                                var xLine = 0.5 * (seg.A.X + seg.B.X);
                                if (Math.Abs(xLine - endpoint.X) > axisTol)
                                {
                                    continue;
                                }

                                var minY = Math.Min(seg.A.Y, seg.B.Y);
                                var maxY = Math.Max(seg.A.Y, seg.B.Y);
                                var y = Math.Max(minY, Math.Min(maxY, endpoint.Y));
                                candidate = new Point2d(endpoint.X, y);
                            }
                            else
                            {
                                continue;
                            }

                            var d = endpoint.GetDistanceTo(candidate);
                            if (d > segmentSnapTol)
                            {
                                continue;
                            }

                            var prefer = !seg.IsContext;
                            var better = !found;
                            if (!better)
                            {
                                if (prefer && bestTargetIsContext)
                                {
                                    better = true;
                                }
                                else if (prefer == !bestTargetIsContext && d < (bestDist - 1e-9))
                                {
                                    better = true;
                                }
                            }

                            if (!better)
                            {
                                continue;
                            }

                            found = true;
                            bestDist = d;
                            bestTargetIsContext = seg.IsContext;
                            snapped = candidate;
                        }

                        // Orientation-based fallback for rotated local geometry where
                        // world X/Y axis checks are not sufficient.
                        const double collinearDotMin = 0.995;
                        const double perpendicularDotMax = 0.10;
                        const double collinearOffsetTol = 0.85;

                        for (var i = 0; i < endpointAnchors.Count; i++)
                        {
                            var anchor = endpointAnchors[i];
                            if (anchor.Id == id)
                            {
                                continue;
                            }

                            if (!string.Equals(anchor.Layer, currentLayer, StringComparison.OrdinalIgnoreCase))
                            {
                                continue;
                            }

                            var t = (anchor.P - endpoint).DotProduct(ownerDir);
                            var candidate = endpoint + (ownerDir * t);
                            var d = endpoint.GetDistanceTo(candidate);
                            if (d > endpointSnapTol)
                            {
                                continue;
                            }

                            var lateral = candidate.GetDistanceTo(anchor.P);
                            if (lateral > collinearOffsetTol)
                            {
                                continue;
                            }

                            var prefer = !anchor.IsContext;
                            var better = !found;
                            if (!better)
                            {
                                if (prefer && bestTargetIsContext)
                                {
                                    better = true;
                                }
                                else if (prefer == !bestTargetIsContext && d < (bestDist - 1e-9))
                                {
                                    better = true;
                                }
                            }

                            if (!better)
                            {
                                continue;
                            }

                            found = true;
                            bestDist = d;
                            bestTargetIsContext = anchor.IsContext;
                            snapped = candidate;
                        }

                        for (var i = 0; i < allSegments.Count; i++)
                        {
                            var seg = allSegments[i];
                            if (seg.Id == id)
                            {
                                continue;
                            }

                            if (!string.Equals(seg.Layer, currentLayer, StringComparison.OrdinalIgnoreCase))
                            {
                                continue;
                            }

                            var otherVec = seg.B - seg.A;
                            var otherLen = otherVec.Length;
                            if (otherLen <= 1e-6)
                            {
                                continue;
                            }

                            var otherDir = otherVec / otherLen;
                            var cosAbs = Math.Abs(ownerDir.DotProduct(otherDir));
                            Point2d candidate;
                            double d;
                            if (cosAbs >= collinearDotMin)
                            {
                                var cA = endpoint + (ownerDir * ((seg.A - endpoint).DotProduct(ownerDir)));
                                var cB = endpoint + (ownerDir * ((seg.B - endpoint).DotProduct(ownerDir)));
                                var dA = endpoint.GetDistanceTo(cA);
                                var dB = endpoint.GetDistanceTo(cB);
                                candidate = dA <= dB ? cA : cB;
                                d = dA <= dB ? dA : dB;
                                var raw = dA <= dB ? seg.A : seg.B;
                                if (candidate.GetDistanceTo(raw) > collinearOffsetTol || d > endpointSnapTol)
                                {
                                    continue;
                                }
                            }
                            else if (cosAbs <= perpendicularDotMax)
                            {
                                if (!TryIntersectInfiniteLineWithSegment(endpoint, ownerDir, seg.A, seg.B, out var tCross))
                                {
                                    continue;
                                }

                                candidate = endpoint + (ownerDir * tCross);
                                d = Math.Abs(tCross);
                                if (d > segmentSnapTol)
                                {
                                    continue;
                                }
                            }
                            else
                            {
                                continue;
                            }

                            var prefer = !seg.IsContext;
                            var better = !found;
                            if (!better)
                            {
                                if (prefer && bestTargetIsContext)
                                {
                                    better = true;
                                }
                                else if (prefer == !bestTargetIsContext && d < (bestDist - 1e-9))
                                {
                                    better = true;
                                }
                            }

                            if (!better)
                            {
                                continue;
                            }

                            found = true;
                            bestDist = d;
                            bestTargetIsContext = seg.IsContext;
                            snapped = candidate;
                        }

                        return found;
                    }

                    var new0 = p0;
                    var new1 = p1;
                    TrySnapEndpoint(p0, p1, out new0);
                    TrySnapEndpoint(p1, p0, out new1);

                    if (new0.GetDistanceTo(p0) <= moveTol && new1.GetDistanceTo(p1) <= moveTol)
                    {
                        continue;
                    }

                    if (TryWriteOpenSegment(ent, new0, new1))
                    {
                        adjusted++;
                    }
                }

                tr.Commit();
                if (adjusted > 0)
                {
                    logger?.WriteLine($"Cleanup: snapped {adjusted} context segment endpoint(s) after 100m trim.");
                }
            }
        }

        private static void HealBufferedBoundaryEndpointSeams(
            Database database,
            IEnumerable<ObjectId> requestedQuarterIds,
            Logger? logger)
        {
            if (database == null || requestedQuarterIds == null)
            {
                return;
            }

            var clipWindows = BuildBufferedQuarterWindows(database, requestedQuarterIds, 102.0);
            if (clipWindows.Count == 0)
            {
                return;
            }

            bool IsPointInAnyWindow(Point2d p)
            {
                for (var i = 0; i < clipWindows.Count; i++)
                {
                    var w = clipWindows[i];
                    if (p.X >= w.MinPoint.X && p.X <= w.MaxPoint.X &&
                        p.Y >= w.MinPoint.Y && p.Y <= w.MaxPoint.Y)
                    {
                        return true;
                    }
                }

                return false;
            }

            bool DoesSegmentIntersectAnyWindow(Point2d a, Point2d b)
            {
                if (IsPointInAnyWindow(a) || IsPointInAnyWindow(b))
                {
                    return true;
                }

                for (var i = 0; i < clipWindows.Count; i++)
                {
                    if (TryClipSegmentToWindow(a, b, clipWindows[i], out _, out _))
                    {
                        return true;
                    }
                }

                return false;
            }

            using (var tr = database.TransactionManager.StartTransaction())
            {
                bool TryReadOpenSegment(Entity ent, out Point2d a, out Point2d b)
                {
                    a = default;
                    b = default;
                    if (ent == null)
                    {
                        return false;
                    }

                    if (ent is Line ln)
                    {
                        a = new Point2d(ln.StartPoint.X, ln.StartPoint.Y);
                        b = new Point2d(ln.EndPoint.X, ln.EndPoint.Y);
                        return a.GetDistanceTo(b) > 1e-4;
                    }

                    if (ent is Polyline pl)
                    {
                        if (pl.Closed || pl.NumberOfVertices != 2)
                        {
                            return false;
                        }

                        a = pl.GetPoint2dAt(0);
                        b = pl.GetPoint2dAt(1);
                        return a.GetDistanceTo(b) > 1e-4;
                    }

                    return false;
                }

                bool TryWriteOpenSegment(Entity ent, Point2d a, Point2d b)
                {
                    if (a.GetDistanceTo(b) <= 1e-4)
                    {
                        return false;
                    }

                    if (ent is Line ln)
                    {
                        ln.StartPoint = new Point3d(a.X, a.Y, ln.StartPoint.Z);
                        ln.EndPoint = new Point3d(b.X, b.Y, ln.EndPoint.Z);
                        return true;
                    }

                    if (ent is Polyline pl && !pl.Closed && pl.NumberOfVertices == 2)
                    {
                        pl.SetPointAt(0, a);
                        pl.SetPointAt(1, b);
                        return true;
                    }

                    return false;
                }

                bool IsHorizontalLike(Point2d a, Point2d b)
                {
                    var d = b - a;
                    return Math.Abs(d.X) >= Math.Abs(d.Y);
                }

                bool IsVerticalLike(Point2d a, Point2d b)
                {
                    var d = b - a;
                    return Math.Abs(d.Y) > Math.Abs(d.X);
                }

                var segments = new List<(ObjectId Id, string Layer, Point2d A, Point2d B, bool Horizontal, bool Vertical)>();
                var bt = (BlockTable)tr.GetObject(database.BlockTableId, OpenMode.ForRead);
                var ms = (BlockTableRecord)tr.GetObject(bt[BlockTableRecord.ModelSpace], OpenMode.ForRead);
                foreach (ObjectId id in ms)
                {
                    Entity? ent = null;
                    try
                    {
                        ent = tr.GetObject(id, OpenMode.ForRead, false) as Entity;
                    }
                    catch (Autodesk.AutoCAD.Runtime.Exception)
                    {
                        continue;
                    }

                    if (ent == null || ent.IsErased)
                    {
                        continue;
                    }

                    if (!string.Equals(ent.Layer, "L-SEC", StringComparison.OrdinalIgnoreCase) &&
                        !IsUsecLayer(ent.Layer))
                    {
                        continue;
                    }

                    if (!TryReadOpenSegment(ent, out var a, out var b))
                    {
                        continue;
                    }

                    if (!DoesSegmentIntersectAnyWindow(a, b))
                    {
                        continue;
                    }

                    var horizontal = IsHorizontalLike(a, b);
                    var vertical = IsVerticalLike(a, b);
                    if (!horizontal && !vertical)
                    {
                        continue;
                    }

                    segments.Add((id, ent.Layer ?? string.Empty, a, b, horizontal, vertical));
                }

                if (segments.Count == 0)
                {
                    tr.Commit();
                    return;
                }

                const double endpointSnapTol = 1.60;
                const double crossSnapTol = 1.60;
                const double axisTol = 1.50;
                const double moveTol = 0.01;
                var adjusted = 0;
                for (var si = 0; si < segments.Count; si++)
                {
                    var seg = segments[si];
                    Entity? ent = null;
                    try
                    {
                        ent = tr.GetObject(seg.Id, OpenMode.ForWrite, false) as Entity;
                    }
                    catch (Autodesk.AutoCAD.Runtime.Exception)
                    {
                        continue;
                    }

                    if (ent == null || ent.IsErased)
                    {
                        continue;
                    }

                    if (!TryReadOpenSegment(ent, out var p0, out var p1))
                    {
                        continue;
                    }

                    var isHorizontal = IsHorizontalLike(p0, p1);
                    var isVertical = IsVerticalLike(p0, p1);
                    if (!isHorizontal && !isVertical)
                    {
                        continue;
                    }

                    bool TrySnapEndpoint(Point2d endpoint, Point2d oppositeEndpoint, out Point2d snapped)
                    {
                        snapped = endpoint;
                        var found = false;
                        var bestDistance = double.MaxValue;
                        var bestSameLayer = false;
                        var ownerDirVec = oppositeEndpoint - endpoint;
                        var ownerDirLen = ownerDirVec.Length;
                        if (ownerDirLen <= 1e-6)
                        {
                            return false;
                        }

                        var ownerDir = ownerDirVec / ownerDirLen;

                        // 1) Axis-constrained endpoint-to-endpoint snap (closes small collinear gaps).
                        for (var oi = 0; oi < segments.Count; oi++)
                        {
                            if (oi == si)
                            {
                                continue;
                            }

                            var other = segments[oi];
                            if (isHorizontal && !other.Horizontal)
                            {
                                continue;
                            }

                            if (isVertical && !other.Vertical)
                            {
                                continue;
                            }

                            var sameLayer = string.Equals(seg.Layer, other.Layer, StringComparison.OrdinalIgnoreCase);
                            if (!sameLayer)
                            {
                                continue;
                            }
                            if (isHorizontal)
                            {
                                var otherY = 0.5 * (other.A.Y + other.B.Y);
                                if (Math.Abs(otherY - endpoint.Y) > axisTol)
                                {
                                    continue;
                                }

                                var c1 = new Point2d(other.A.X, endpoint.Y);
                                var c2 = new Point2d(other.B.X, endpoint.Y);
                                var d1 = endpoint.GetDistanceTo(c1);
                                var d2 = endpoint.GetDistanceTo(c2);
                                var candidate = d1 <= d2 ? c1 : c2;
                                var d = d1 <= d2 ? d1 : d2;
                                if (d > endpointSnapTol)
                                {
                                    continue;
                                }

                                if (!found ||
                                    (sameLayer && !bestSameLayer) ||
                                    (sameLayer == bestSameLayer && d < (bestDistance - 1e-9)))
                                {
                                    found = true;
                                    bestDistance = d;
                                    bestSameLayer = sameLayer;
                                    snapped = candidate;
                                }
                            }
                            else if (isVertical)
                            {
                                var otherX = 0.5 * (other.A.X + other.B.X);
                                if (Math.Abs(otherX - endpoint.X) > axisTol)
                                {
                                    continue;
                                }

                                var c1 = new Point2d(endpoint.X, other.A.Y);
                                var c2 = new Point2d(endpoint.X, other.B.Y);
                                var d1 = endpoint.GetDistanceTo(c1);
                                var d2 = endpoint.GetDistanceTo(c2);
                                var candidate = d1 <= d2 ? c1 : c2;
                                var d = d1 <= d2 ? d1 : d2;
                                if (d > endpointSnapTol)
                                {
                                    continue;
                                }

                                if (!found ||
                                    (sameLayer && !bestSameLayer) ||
                                    (sameLayer == bestSameLayer && d < (bestDistance - 1e-9)))
                                {
                                    found = true;
                                    bestDistance = d;
                                    bestSameLayer = sameLayer;
                                    snapped = candidate;
                                }
                            }
                        }

                        // 2) Endpoint-to-perpendicular-segment snap (clips tiny overhangs/under-runs at crosses).
                        for (var oi = 0; oi < segments.Count; oi++)
                        {
                            if (oi == si)
                            {
                                continue;
                            }

                            var other = segments[oi];
                            var sameLayer = string.Equals(seg.Layer, other.Layer, StringComparison.OrdinalIgnoreCase);
                            if (!sameLayer)
                            {
                                continue;
                            }
                            if (isHorizontal)
                            {
                                if (!other.Vertical)
                                {
                                    continue;
                                }

                                var xLine = 0.5 * (other.A.X + other.B.X);
                                var d = Math.Abs(xLine - endpoint.X);
                                if (d > crossSnapTol)
                                {
                                    continue;
                                }

                                var minY = Math.Min(other.A.Y, other.B.Y) - axisTol;
                                var maxY = Math.Max(other.A.Y, other.B.Y) + axisTol;
                                if (endpoint.Y < minY || endpoint.Y > maxY)
                                {
                                    continue;
                                }

                                var candidate = new Point2d(xLine, endpoint.Y);
                                if (!found ||
                                    (sameLayer && !bestSameLayer) ||
                                    (sameLayer == bestSameLayer && d < (bestDistance - 1e-9)))
                                {
                                    found = true;
                                    bestDistance = d;
                                    bestSameLayer = sameLayer;
                                    snapped = candidate;
                                }
                            }
                            else if (isVertical)
                            {
                                if (!other.Horizontal)
                                {
                                    continue;
                                }

                                var yLine = 0.5 * (other.A.Y + other.B.Y);
                                var d = Math.Abs(yLine - endpoint.Y);
                                if (d > crossSnapTol)
                                {
                                    continue;
                                }

                                var minX = Math.Min(other.A.X, other.B.X) - axisTol;
                                var maxX = Math.Max(other.A.X, other.B.X) + axisTol;
                                if (endpoint.X < minX || endpoint.X > maxX)
                                {
                                    continue;
                                }

                                var candidate = new Point2d(endpoint.X, yLine);
                                if (!found ||
                                    (sameLayer && !bestSameLayer) ||
                                    (sameLayer == bestSameLayer && d < (bestDistance - 1e-9)))
                                {
                                    found = true;
                                    bestDistance = d;
                                    bestSameLayer = sameLayer;
                                    snapped = candidate;
                                }
                            }
                        }

                        // 3) Orientation-based fallback (independent of world X/Y):
                        //    - collinear endpoint snap
                        //    - perpendicular segment intersection snap
                        const double collinearDotMin = 0.995;
                        const double perpendicularDotMax = 0.10;
                        const double collinearOffsetTol = 0.85;
                        for (var oi = 0; oi < segments.Count; oi++)
                        {
                            if (oi == si)
                            {
                                continue;
                            }

                            var other = segments[oi];
                            var sameLayer = string.Equals(seg.Layer, other.Layer, StringComparison.OrdinalIgnoreCase);
                            if (!sameLayer)
                            {
                                continue;
                            }
                            var otherVec = other.B - other.A;
                            var otherLen = otherVec.Length;
                            if (otherLen <= 1e-6)
                            {
                                continue;
                            }

                            var otherDir = otherVec / otherLen;
                            var cosAbs = Math.Abs(ownerDir.DotProduct(otherDir));

                            if (cosAbs >= collinearDotMin)
                            {
                                var colCandidates = new[] { other.A, other.B };
                                for (var ci = 0; ci < colCandidates.Length; ci++)
                                {
                                    var c = colCandidates[ci];
                                    var lateral = DistancePointToInfiniteLine(c, endpoint, endpoint + ownerDir);
                                    if (lateral > collinearOffsetTol)
                                    {
                                        continue;
                                    }

                                    var t = (c - endpoint).DotProduct(ownerDir);
                                    var d = Math.Abs(t);
                                    if (d > endpointSnapTol)
                                    {
                                        continue;
                                    }

                                    var candidate = endpoint + (ownerDir * t);
                                    if (!found ||
                                        (sameLayer && !bestSameLayer) ||
                                        (sameLayer == bestSameLayer && d < (bestDistance - 1e-9)))
                                    {
                                        found = true;
                                        bestDistance = d;
                                        bestSameLayer = sameLayer;
                                        snapped = candidate;
                                    }
                                }
                            }

                            if (cosAbs <= perpendicularDotMax)
                            {
                                if (!TryIntersectInfiniteLineWithSegment(endpoint, ownerDir, other.A, other.B, out var t))
                                {
                                    continue;
                                }

                                var d = Math.Abs(t);
                                if (d > crossSnapTol)
                                {
                                    continue;
                                }

                                var candidate = endpoint + (ownerDir * t);
                                if (!found ||
                                    (sameLayer && !bestSameLayer) ||
                                    (sameLayer == bestSameLayer && d < (bestDistance - 1e-9)))
                                {
                                    found = true;
                                    bestDistance = d;
                                    bestSameLayer = sameLayer;
                                    snapped = candidate;
                                }
                            }
                        }

                        return found;
                    }

                    var new0 = p0;
                    var new1 = p1;
                    TrySnapEndpoint(p0, p1, out new0);
                    TrySnapEndpoint(p1, p0, out new1);

                    if (new0.GetDistanceTo(p0) <= moveTol && new1.GetDistanceTo(p1) <= moveTol)
                    {
                        continue;
                    }

                    if (!TryWriteOpenSegment(ent, new0, new1))
                    {
                        continue;
                    }

                    adjusted++;
                    segments[si] = (seg.Id, seg.Layer, new0, new1, IsHorizontalLike(new0, new1), IsVerticalLike(new0, new1));
                }

                tr.Commit();
                logger?.WriteLine($"Cleanup: seam-healed {adjusted} L-SEC/L-USEC segment(s) near buffered boundary endpoints.");
            }
        }

        private static void CloseTinyRoadAllowanceCornerGaps(
            Database database,
            IEnumerable<ObjectId> requestedQuarterIds,
            IReadOnlyCollection<ObjectId>? generatedRoadAllowanceIds,
            Logger? logger)
        {
            if (database == null || requestedQuarterIds == null)
            {
                return;
            }

            var clipWindows = BuildBufferedQuarterWindows(database, requestedQuarterIds, 102.0);
            if (clipWindows.Count == 0)
            {
                return;
            }

            var generatedSet = generatedRoadAllowanceIds != null && generatedRoadAllowanceIds.Count > 0
                ? new HashSet<ObjectId>(generatedRoadAllowanceIds)
                : new HashSet<ObjectId>();

            bool IsPointInAnyWindow(Point2d p)
            {
                for (var i = 0; i < clipWindows.Count; i++)
                {
                    var w = clipWindows[i];
                    if (p.X >= w.MinPoint.X && p.X <= w.MaxPoint.X &&
                        p.Y >= w.MinPoint.Y && p.Y <= w.MaxPoint.Y)
                    {
                        return true;
                    }
                }

                return false;
            }

            bool DoesSegmentIntersectAnyWindow(Point2d a, Point2d b)
            {
                if (IsPointInAnyWindow(a) || IsPointInAnyWindow(b))
                {
                    return true;
                }

                for (var i = 0; i < clipWindows.Count; i++)
                {
                    if (TryClipSegmentToWindow(a, b, clipWindows[i], out _, out _))
                    {
                        return true;
                    }
                }

                return false;
            }

            using (var tr = database.TransactionManager.StartTransaction())
            {
                bool TryReadOpenSegment(Entity ent, out Point2d a, out Point2d b)
                {
                    a = default;
                    b = default;
                    if (ent == null)
                    {
                        return false;
                    }

                    if (ent is Line ln)
                    {
                        a = new Point2d(ln.StartPoint.X, ln.StartPoint.Y);
                        b = new Point2d(ln.EndPoint.X, ln.EndPoint.Y);
                        return a.GetDistanceTo(b) > 1e-4;
                    }

                    if (ent is Polyline pl)
                    {
                        if (pl.Closed || pl.NumberOfVertices < 2)
                        {
                            return false;
                        }

                        a = pl.GetPoint2dAt(0);
                        b = pl.GetPoint2dAt(pl.NumberOfVertices - 1);
                        if (a.GetDistanceTo(b) <= 1e-4)
                        {
                            return false;
                        }

                        // Accept multi-vertex open polylines only when effectively collinear.
                        if (pl.NumberOfVertices > 2)
                        {
                            const double collinearTol = 0.35;
                            for (var vi = 1; vi < pl.NumberOfVertices - 1; vi++)
                            {
                                var p = pl.GetPoint2dAt(vi);
                                if (DistancePointToInfiniteLine(p, a, b) > collinearTol)
                                {
                                    return false;
                                }
                            }
                        }

                        return a.GetDistanceTo(b) > 1e-4;
                    }

                    return false;
                }

                bool IsHorizontalLike(Point2d a, Point2d b)
                {
                    var d = b - a;
                    return Math.Abs(d.X) >= Math.Abs(d.Y);
                }

                bool IsVerticalLike(Point2d a, Point2d b)
                {
                    var d = b - a;
                    return Math.Abs(d.Y) > Math.Abs(d.X);
                }

                bool TryIntersectInfiniteLines(Point2d a0, Point2d a1, Point2d b0, Point2d b1, out Point2d intersection)
                {
                    intersection = default;
                    var da = a1 - a0;
                    var db = b1 - b0;
                    var denom = Cross2d(da, db);
                    if (Math.Abs(denom) <= 1e-9)
                    {
                        return false;
                    }

                    var diff = b0 - a0;
                    var t = Cross2d(diff, db) / denom;
                    intersection = a0 + (da * t);
                    return true;
                }

                bool TryMoveEndpointByIndex(Entity writable, int endpointIndex, Point2d target, double moveTol)
                {
                    if (endpointIndex != 0 && endpointIndex != 1)
                    {
                        return false;
                    }

                    if (writable is Line ln)
                    {
                        var old = endpointIndex == 0
                            ? new Point2d(ln.StartPoint.X, ln.StartPoint.Y)
                            : new Point2d(ln.EndPoint.X, ln.EndPoint.Y);
                        if (old.GetDistanceTo(target) <= moveTol)
                        {
                            return false;
                        }

                        if (endpointIndex == 0)
                        {
                            ln.StartPoint = new Point3d(target.X, target.Y, ln.StartPoint.Z);
                        }
                        else
                        {
                            ln.EndPoint = new Point3d(target.X, target.Y, ln.EndPoint.Z);
                        }

                        return true;
                    }

                    if (writable is Polyline pl && !pl.Closed && pl.NumberOfVertices == 2)
                    {
                        var old = pl.GetPoint2dAt(endpointIndex);
                        if (old.GetDistanceTo(target) <= moveTol)
                        {
                            return false;
                        }

                        pl.SetPointAt(endpointIndex, target);
                        return true;
                    }

                    return false;
                }

                var segments = new List<(ObjectId Id, string Layer, Point2d A, Point2d B, bool Horizontal, bool Vertical, bool Generated)>();
                var bt = (BlockTable)tr.GetObject(database.BlockTableId, OpenMode.ForRead);
                var ms = (BlockTableRecord)tr.GetObject(bt[BlockTableRecord.ModelSpace], OpenMode.ForRead);
                foreach (ObjectId id in ms)
                {
                    if (!(tr.GetObject(id, OpenMode.ForRead, false) is Entity ent) || ent.IsErased)
                    {
                        continue;
                    }

                    if (!string.Equals(ent.Layer, "L-SEC", StringComparison.OrdinalIgnoreCase) &&
                        !string.Equals(ent.Layer, "L-USEC", StringComparison.OrdinalIgnoreCase))
                    {
                        continue;
                    }

                    if (!TryReadOpenSegment(ent, out var a, out var b))
                    {
                        continue;
                    }

                    if (!DoesSegmentIntersectAnyWindow(a, b))
                    {
                        continue;
                    }

                    var horizontal = IsHorizontalLike(a, b);
                    var vertical = IsVerticalLike(a, b);
                    if (!horizontal && !vertical)
                    {
                        continue;
                    }

                    segments.Add((id, ent.Layer ?? string.Empty, a, b, horizontal, vertical, generatedSet.Contains(id)));
                }

                if (segments.Count < 2)
                {
                    tr.Commit();
                    return;
                }

                var adjusted = 0;
                const double tinyGap = 1.25;
                const double usecTwentyTwelveGap = 1.25;
                const double usecExtendedMinMajorGap = 2.00;
                const double moveTol = 0.01;
                var movedEndpoints = new HashSet<string>(StringComparer.OrdinalIgnoreCase);

                string EndpointKey(int segIndex, int endpointIndex)
                {
                    return string.Format(
                        CultureInfo.InvariantCulture,
                        "{0}:{1}",
                        segIndex,
                        endpointIndex);
                }

                double AxisOverlap(
                    (ObjectId Id, string Layer, Point2d A, Point2d B, bool Horizontal, bool Vertical, bool Generated) a,
                    (ObjectId Id, string Layer, Point2d A, Point2d B, bool Horizontal, bool Vertical, bool Generated) b)
                {
                    if (a.Horizontal && b.Horizontal)
                    {
                        var aMin = Math.Min(a.A.X, a.B.X);
                        var aMax = Math.Max(a.A.X, a.B.X);
                        var bMin = Math.Min(b.A.X, b.B.X);
                        var bMax = Math.Max(b.A.X, b.B.X);
                        return Math.Min(aMax, bMax) - Math.Max(aMin, bMin);
                    }

                    if (a.Vertical && b.Vertical)
                    {
                        var aMin = Math.Min(a.A.Y, a.B.Y);
                        var aMax = Math.Max(a.A.Y, a.B.Y);
                        var bMin = Math.Min(b.A.Y, b.B.Y);
                        var bMax = Math.Max(b.A.Y, b.B.Y);
                        return Math.Min(aMax, bMax) - Math.Max(aMin, bMin);
                    }

                    return 0.0;
                }

                bool HasCompanionAtOffset(
                    int segIndex,
                    double expectedOffset,
                    double tol,
                    double minOverlap,
                    bool requireSameLayer,
                    bool? requireCompanionGenerated = null)
                {
                    if (segIndex < 0 || segIndex >= segments.Count)
                    {
                        return false;
                    }

                    var s = segments[segIndex];
                    if (!s.Horizontal && !s.Vertical)
                    {
                        return false;
                    }

                    var sCoord = s.Horizontal
                        ? (0.5 * (s.A.Y + s.B.Y))
                        : (0.5 * (s.A.X + s.B.X));
                    for (var oi = 0; oi < segments.Count; oi++)
                    {
                        if (oi == segIndex)
                        {
                            continue;
                        }

                        var o = segments[oi];
                        if (s.Horizontal != o.Horizontal || s.Vertical != o.Vertical)
                        {
                            continue;
                        }

                        if (requireSameLayer &&
                            !string.Equals(s.Layer, o.Layer, StringComparison.OrdinalIgnoreCase))
                        {
                            continue;
                        }

                        if (requireCompanionGenerated.HasValue && o.Generated != requireCompanionGenerated.Value)
                        {
                            continue;
                        }

                        if (AxisOverlap(s, o) < minOverlap)
                        {
                            continue;
                        }

                        var oCoord = o.Horizontal
                            ? (0.5 * (o.A.Y + o.B.Y))
                            : (0.5 * (o.A.X + o.B.X));
                        var offset = Math.Abs(oCoord - sCoord);
                        if (Math.Abs(offset - expectedOffset) <= tol)
                        {
                            return true;
                        }
                    }

                    return false;
                }

                var usecInnerTwentyTwelveStrict = new bool[segments.Count];
                var usecInnerTwentyTwelveLoose = new bool[segments.Count];
                var strictInnerCount = 0;
                for (var i = 0; i < segments.Count; i++)
                {
                    var s = segments[i];
                    if (!string.Equals(s.Layer, "L-USEC", StringComparison.OrdinalIgnoreCase))
                    {
                        continue;
                    }

                    // Inner 20.11-in-30.17 indicator.
                    // Loose: previous geometry-only heuristic.
                    // Strict: requires a non-generated 20.11 companion so inner 20.11 is chosen
                    // over outer 30.17 when both are nearby.
                    var hasTenCompanion = HasCompanionAtOffset(i, 10.06, 1.75, 10.0, requireSameLayer: true);
                    var hasTwentyCompanion = HasCompanionAtOffset(i, 20.11, 2.50, 10.0, requireSameLayer: false);
                    var looseInner = hasTenCompanion && hasTwentyCompanion;
                    usecInnerTwentyTwelveLoose[i] = looseInner;

                    var strictInner = false;
                    if (looseInner && generatedSet.Count > 0)
                    {
                        var hasTwentyNonGeneratedCompanion = HasCompanionAtOffset(
                            i,
                            20.11,
                            2.50,
                            10.0,
                            requireSameLayer: false,
                            requireCompanionGenerated: false);
                        strictInner = hasTwentyNonGeneratedCompanion;
                    }

                    usecInnerTwentyTwelveStrict[i] = strictInner;
                    if (strictInner)
                    {
                        strictInnerCount++;
                    }
                }

                var usecInnerTwentyTwelve = strictInnerCount > 0
                    ? usecInnerTwentyTwelveStrict
                    : usecInnerTwentyTwelveLoose;

                for (var hi = 0; hi < segments.Count; hi++)
                {
                    var hSeg = segments[hi];
                    if (!hSeg.Horizontal)
                    {
                        continue;
                    }

                    for (var hEnd = 0; hEnd <= 1; hEnd++)
                    {
                        var hKey = EndpointKey(hi, hEnd);
                        if (movedEndpoints.Contains(hKey))
                        {
                            continue;
                        }

                        var hPoint = hEnd == 0 ? hSeg.A : hSeg.B;
                        var hInnerTwentyTwelve = usecInnerTwentyTwelve[hi];
                        var bestFound = false;
                        var bestScore = double.MaxValue;
                        var bestVi = -1;
                        var bestVEnd = -1;
                        var bestTarget = default(Point2d);
                        for (var vi = 0; vi < segments.Count; vi++)
                        {
                            if (vi == hi)
                            {
                                continue;
                            }

                            var vSeg = segments[vi];
                            if (!vSeg.Vertical)
                            {
                                continue;
                            }

                            // Allow joins when at least one corridor leg is generated.
                            // We still only move generated endpoints below.
                            if (!hSeg.Generated && !vSeg.Generated)
                            {
                                continue;
                            }

                            for (var vEnd = 0; vEnd <= 1; vEnd++)
                            {
                                var vKey = EndpointKey(vi, vEnd);
                                if (movedEndpoints.Contains(vKey))
                                {
                                    continue;
                                }

                                var vPoint = vEnd == 0 ? vSeg.A : vSeg.B;
                                var vInnerTwentyTwelve = usecInnerTwentyTwelve[vi];
                                // Keep this pass to tiny generated corner closes only.
                                // Larger 20.11/30.17 corridor joins are handled by dedicated passes.
                                var allowExtendedUsecJoin = false;

                                if (!TryIntersectInfiniteLines(hSeg.A, hSeg.B, vSeg.A, vSeg.B, out var target))
                                {
                                    continue;
                                }
                                var dH = hPoint.GetDistanceTo(target);
                                var dV = vPoint.GetDistanceTo(target);
                                var endpointGapLimit = allowExtendedUsecJoin ? usecTwentyTwelveGap : tinyGap;
                                if (dH > endpointGapLimit || dV > endpointGapLimit)
                                {
                                    continue;
                                }

                                var majorGap = Math.Max(dH, dV);
                                if (allowExtendedUsecJoin && majorGap <= usecExtendedMinMajorGap)
                                {
                                    // Prevent tiny snaps from stealing the endpoint needed for the 20.11 corner join.
                                    continue;
                                }

                                var sameLayer = string.Equals(hSeg.Layer, vSeg.Layer, StringComparison.OrdinalIgnoreCase);
                                var score =
                                    dH +
                                    dV -
                                    (sameLayer ? 0.05 : 0.0) -
                                    (allowExtendedUsecJoin ? 0.10 : 0.0) +
                                    (allowExtendedUsecJoin ? (0.15 * Math.Abs(majorGap - 10.06)) : 0.0);
                                if (!bestFound || score < (bestScore - 1e-9))
                                {
                                    bestFound = true;
                                    bestScore = score;
                                    bestVi = vi;
                                    bestVEnd = vEnd;
                                    bestTarget = target;
                                }
                            }
                        }

                        if (!bestFound || bestVi < 0 || bestVEnd < 0)
                        {
                            continue;
                        }

                        var hWritable = tr.GetObject(hSeg.Id, OpenMode.ForWrite, false) as Entity;
                        var vSegBest = segments[bestVi];
                        var vWritable = tr.GetObject(vSegBest.Id, OpenMode.ForWrite, false) as Entity;
                        if (hWritable == null || hWritable.IsErased || vWritable == null || vWritable.IsErased)
                        {
                            continue;
                        }

                        // Keep baseline section grid stable:
                        // this corner-gap pass should only pull generated RA geometry,
                        // never non-generated SEC/USEC endpoints.
                        var allowMoveH = hSeg.Generated;
                        var allowMoveV = vSegBest.Generated;
                        if (!allowMoveH && !allowMoveV)
                        {
                            continue;
                        }

                        var movedH = allowMoveH && TryMoveEndpointByIndex(hWritable, hEnd, bestTarget, moveTol);
                        var movedV = allowMoveV && TryMoveEndpointByIndex(vWritable, bestVEnd, bestTarget, moveTol);
                        if (!movedH && !movedV)
                        {
                            continue;
                        }

                        adjusted++;
                        movedEndpoints.Add(hKey);
                        movedEndpoints.Add(EndpointKey(bestVi, bestVEnd));

                        if (TryReadOpenSegment(hWritable, out var newHA, out var newHB))
                        {
                            segments[hi] = (hSeg.Id, hSeg.Layer, newHA, newHB, IsHorizontalLike(newHA, newHB), IsVerticalLike(newHA, newHB), hSeg.Generated);
                        }

                        if (TryReadOpenSegment(vWritable, out var newVA, out var newVB))
                        {
                            segments[bestVi] = (vSegBest.Id, vSegBest.Layer, newVA, newVB, IsHorizontalLike(newVA, newVB), IsVerticalLike(newVA, newVB), vSegBest.Generated);
                        }
                    }
                }

                tr.Commit();
                if (adjusted > 0)
                {
                    logger?.WriteLine($"Cleanup: corner-gap-closed {adjusted} orthogonal endpoint gap(s) on L-SEC/L-USEC.");
                }
            }
        }

        private static void EnforceSecToUsecTwentyTwelveEndpointRule(
            Database database,
            IEnumerable<ObjectId> requestedQuarterIds,
            Logger? logger)
        {
            var disableLegacyRule = true;
            if (disableLegacyRule)
            {
                logger?.WriteLine("Cleanup: EnforceSecToUsecTwentyTwelveEndpointRule disabled by canonical RA endpoint constraints.");
                return;
            }

            if (database == null || requestedQuarterIds == null)
            {
                return;
            }

            var clipWindows = BuildBufferedQuarterWindows(database, requestedQuarterIds, 102.0);
            if (clipWindows.Count == 0)
            {
                return;
            }

            bool IsPointInAnyWindow(Point2d p)
            {
                for (var i = 0; i < clipWindows.Count; i++)
                {
                    var w = clipWindows[i];
                    if (p.X >= w.MinPoint.X && p.X <= w.MaxPoint.X &&
                        p.Y >= w.MinPoint.Y && p.Y <= w.MaxPoint.Y)
                    {
                        return true;
                    }
                }

                return false;
            }

            bool DoesSegmentIntersectAnyWindow(Point2d a, Point2d b)
            {
                if (IsPointInAnyWindow(a) || IsPointInAnyWindow(b))
                {
                    return true;
                }

                for (var i = 0; i < clipWindows.Count; i++)
                {
                    if (TryClipSegmentToWindow(a, b, clipWindows[i], out _, out _))
                    {
                        return true;
                    }
                }

                return false;
            }

            using (var tr = database.TransactionManager.StartTransaction())
            {
                bool TryReadOpenSegment(Entity ent, out Point2d a, out Point2d b)
                {
                    a = default;
                    b = default;
                    if (ent == null)
                    {
                        return false;
                    }

                    if (ent is Line ln)
                    {
                        a = new Point2d(ln.StartPoint.X, ln.StartPoint.Y);
                        b = new Point2d(ln.EndPoint.X, ln.EndPoint.Y);
                        return a.GetDistanceTo(b) > 1e-4;
                    }

                    if (ent is Polyline pl)
                    {
                        if (pl.Closed || pl.NumberOfVertices != 2)
                        {
                            return false;
                        }

                        a = pl.GetPoint2dAt(0);
                        b = pl.GetPoint2dAt(1);
                        return a.GetDistanceTo(b) > 1e-4;
                    }

                    return false;
                }

                bool IsHorizontalLike(Point2d a, Point2d b)
                {
                    var d = b - a;
                    return Math.Abs(d.X) >= Math.Abs(d.Y);
                }

                bool IsVerticalLike(Point2d a, Point2d b)
                {
                    var d = b - a;
                    return Math.Abs(d.Y) > Math.Abs(d.X);
                }

                bool TryMoveEndpointByIndex(Entity writable, int endpointIndex, Point2d target, double moveTol)
                {
                    if (endpointIndex != 0 && endpointIndex != 1)
                    {
                        return false;
                    }

                    if (writable is Line ln)
                    {
                        var old = endpointIndex == 0
                            ? new Point2d(ln.StartPoint.X, ln.StartPoint.Y)
                            : new Point2d(ln.EndPoint.X, ln.EndPoint.Y);
                        if (old.GetDistanceTo(target) <= moveTol)
                        {
                            return false;
                        }

                        if (endpointIndex == 0)
                        {
                            ln.StartPoint = new Point3d(target.X, target.Y, ln.StartPoint.Z);
                        }
                        else
                        {
                            ln.EndPoint = new Point3d(target.X, target.Y, ln.EndPoint.Z);
                        }

                        return true;
                    }

                    if (writable is Polyline pl && !pl.Closed && pl.NumberOfVertices == 2)
                    {
                        var old = pl.GetPoint2dAt(endpointIndex);
                        if (old.GetDistanceTo(target) <= moveTol)
                        {
                            return false;
                        }

                        pl.SetPointAt(endpointIndex, target);
                        return true;
                    }

                    return false;
                }

                void CollectUsecSegments(Entity ent, List<(Point2d A, Point2d B)> destination)
                {
                    if (ent is Line ln)
                    {
                        var a = new Point2d(ln.StartPoint.X, ln.StartPoint.Y);
                        var b = new Point2d(ln.EndPoint.X, ln.EndPoint.Y);
                        if (a.GetDistanceTo(b) > 1e-4 && DoesSegmentIntersectAnyWindow(a, b))
                        {
                            destination.Add((a, b));
                        }

                        return;
                    }

                    if (!(ent is Polyline pl) || pl.Closed || pl.NumberOfVertices < 2)
                    {
                        return;
                    }

                    for (var vi = 0; vi < pl.NumberOfVertices - 1; vi++)
                    {
                        var a = pl.GetPoint2dAt(vi);
                        var b = pl.GetPoint2dAt(vi + 1);
                        if (a.GetDistanceTo(b) <= 1e-4)
                        {
                            continue;
                        }

                        if (!DoesSegmentIntersectAnyWindow(a, b))
                        {
                            continue;
                        }

                        destination.Add((a, b));
                    }
                }

                bool TryIntersectRayWithUsec(
                    Point2d rayOrigin,
                    Vector2d rayDirUnit,
                    Point2d segA,
                    Point2d segB,
                    out double t,
                    out Point2d target)
                {
                    t = 0.0;
                    target = rayOrigin;

                    if (TryIntersectInfiniteLineWithSegment(rayOrigin, rayDirUnit, segA, segB, out var tOnRay))
                    {
                        if (tOnRay > 1e-6)
                        {
                            t = tOnRay;
                            target = rayOrigin + (rayDirUnit * tOnRay);
                            return true;
                        }
                    }

                    var db = segB - segA;
                    if (db.Length <= 1e-6)
                    {
                        return false;
                    }

                    var denom = Cross2d(rayDirUnit, db);
                    if (Math.Abs(denom) <= 1e-9)
                    {
                        return false;
                    }

                    var diff = segA - rayOrigin;
                    var tInfinite = Cross2d(diff, db) / denom;
                    if (tInfinite <= 1e-6)
                    {
                        return false;
                    }

                    var p = rayOrigin + (rayDirUnit * tInfinite);
                    const double usecLineGapTol = 1.5;
                    if (DistancePointToSegment(p, segA, segB) > usecLineGapTol)
                    {
                        return false;
                    }

                    t = tInfinite;
                    target = p;
                    return true;
                }

                Point2d ClosestPointOnSegment(Point2d p, Point2d a, Point2d b)
                {
                    var ab = b - a;
                    var len2 = ab.DotProduct(ab);
                    if (len2 <= 1e-12)
                    {
                        return a;
                    }

                    var t = (p - a).DotProduct(ab) / len2;
                    t = Math.Max(0.0, Math.Min(1.0, t));
                    return a + (ab * t);
                }

                var secSegments = new List<(ObjectId Id, Point2d A, Point2d B, bool Horizontal, bool Vertical)>();
                var usecSegments = new List<(Point2d A, Point2d B)>();
                var lsdSegments = new List<(ObjectId Id, Point2d A, Point2d B)>();

                var bt = (BlockTable)tr.GetObject(database.BlockTableId, OpenMode.ForRead);
                var ms = (BlockTableRecord)tr.GetObject(bt[BlockTableRecord.ModelSpace], OpenMode.ForRead);
                foreach (ObjectId id in ms)
                {
                    if (!(tr.GetObject(id, OpenMode.ForRead, false) is Entity ent) || ent.IsErased)
                    {
                        continue;
                    }

                    if (string.Equals(ent.Layer, "L-USEC", StringComparison.OrdinalIgnoreCase))
                    {
                        CollectUsecSegments(ent, usecSegments);
                        continue;
                    }

                    if (!TryReadOpenSegment(ent, out var a, out var b))
                    {
                        continue;
                    }

                    if (!DoesSegmentIntersectAnyWindow(a, b))
                    {
                        continue;
                    }

                    if (string.Equals(ent.Layer, "L-SEC", StringComparison.OrdinalIgnoreCase))
                    {
                        var horizontal = IsHorizontalLike(a, b);
                        var vertical = IsVerticalLike(a, b);
                        if (!horizontal && !vertical)
                        {
                            continue;
                        }

                        secSegments.Add((id, a, b, horizontal, vertical));
                        continue;
                    }

                    if (string.Equals(ent.Layer, "L-SECTION-LSD", StringComparison.OrdinalIgnoreCase) &&
                        IsAdjustableLsdLineSegment(a, b))
                    {
                        lsdSegments.Add((id, a, b));
                    }
                }

                if (secSegments.Count == 0 || usecSegments.Count == 0)
                {
                    tr.Commit();
                    return;
                }

                const double touchTol = 0.30;
                const double inwardCompanionTarget = CorrectionLinePairGapMeters;
                const double inwardCompanionAltTarget = 20.11;
                const double inwardCompanionMin = 5.0;
                const double inwardCompanionMax = 26.5;
                const double inwardApproxPerpTol = 4.5;
                const double inwardApproxPointTol = 10.0;
                const double inwardInfiniteScoreTol = 4.0;
                const double inwardProjectedPerpTol = 12.0;
                const double inwardProjectedGapTol = 20.0;
                const double endpointMoveTol = 0.05;
                const double lsdAnchorTol = 0.40;
                const double lsdMaxMove = 15.0;

                var scannedEndpoints = 0;
                var touchingUsecEndpoints = 0;
                var candidateEndpoints = 0;
                var adjusted = 0;
                var endpointMoves = new List<(Point2d Old, Point2d New)>();
                double ScoreToExpected(double t)
                {
                    return Math.Min(
                        Math.Abs(t - inwardCompanionTarget),
                        Math.Abs(t - inwardCompanionAltTarget));
                }

                for (var si = 0; si < secSegments.Count; si++)
                {
                    var sec = secSegments[si];
                    if (!sec.Horizontal)
                    {
                        continue;
                    }

                    if (!(tr.GetObject(sec.Id, OpenMode.ForWrite, false) is Entity writableSec) || writableSec.IsErased)
                    {
                        continue;
                    }

                    if (!TryReadOpenSegment(writableSec, out var p0, out var p1))
                    {
                        continue;
                    }

                    for (var endpointIndex = 0; endpointIndex <= 1; endpointIndex++)
                    {
                        scannedEndpoints++;

                        var endpoint = endpointIndex == 0 ? p0 : p1;
                        var other = endpointIndex == 0 ? p1 : p0;
                        var inward = other - endpoint;
                        var inwardLen = inward.Length;
                        if (inwardLen <= 1e-6)
                        {
                            continue;
                        }

                        var inwardDir = inward / inwardLen;

                        var touchesUsec = false;
                        for (var ui = 0; ui < usecSegments.Count; ui++)
                        {
                            var u = usecSegments[ui];
                            if (DistancePointToSegment(endpoint, u.A, u.B) <= touchTol)
                            {
                                touchesUsec = true;
                                break;
                            }
                        }

                        if (!touchesUsec)
                        {
                            continue;
                        }

                        touchingUsecEndpoints++;

                        var expectedPoint = endpoint + (inwardDir * inwardCompanionTarget);
                        var rayRef = endpoint + inwardDir;
                        double? bestExactT = null;
                        var bestExactTarget = endpoint;
                        var bestExactScore = double.MaxValue;
                        double? bestApproxT = null;
                        var bestApproxTarget = endpoint;
                        var bestApproxScore = double.MaxValue;
                        for (var ui = 0; ui < usecSegments.Count; ui++)
                        {
                            var u = usecSegments[ui];
                            if (DistancePointToSegment(endpoint, u.A, u.B) <= touchTol)
                            {
                                continue;
                            }

                            if (!TryIntersectRayWithUsec(endpoint, inwardDir, u.A, u.B, out var t, out var target))
                            {
                                continue;
                            }

                            if (t < inwardCompanionMin || t > inwardCompanionMax)
                            {
                                continue;
                            }

                            var score = ScoreToExpected(t);
                            if (!bestExactT.HasValue ||
                                score < (bestExactScore - 1e-9) ||
                                (Math.Abs(score - bestExactScore) <= 1e-9 && t < bestExactT.Value))
                            {
                                bestExactT = t;
                                bestExactTarget = target;
                                bestExactScore = score;
                            }

                            // Fallback for split/slightly-misaligned township-change geometry:
                            // snap near the expected inward 10.06 point even when exact segment
                            // intersection is not robust.
                            var approxPoint = ClosestPointOnSegment(expectedPoint, u.A, u.B);
                            var approxT = (approxPoint - endpoint).DotProduct(inwardDir);
                            if (approxT < inwardCompanionMin || approxT > inwardCompanionMax)
                            {
                                continue;
                            }

                            var perp = DistancePointToInfiniteLine(approxPoint, endpoint, rayRef);
                            if (perp > inwardApproxPerpTol)
                            {
                                continue;
                            }

                            var gap = approxPoint.GetDistanceTo(expectedPoint);
                            if (gap > inwardApproxPointTol)
                            {
                                continue;
                            }

                            var approxScore = ScoreToExpected(approxT) + (0.25 * perp) + (0.05 * gap);
                            if (!bestApproxT.HasValue ||
                                approxScore < (bestApproxScore - 1e-9) ||
                                (Math.Abs(approxScore - bestApproxScore) <= 1e-9 && approxT < bestApproxT.Value))
                            {
                                bestApproxT = approxT;
                                bestApproxTarget = approxPoint;
                                bestApproxScore = approxScore;
                            }
                        }

                        double? bestInfiniteT = null;
                        var bestInfiniteTarget = endpoint;
                        var bestInfiniteScore = double.MaxValue;
                        if (!bestExactT.HasValue && !bestApproxT.HasValue)
                        {
                            for (var ui = 0; ui < usecSegments.Count; ui++)
                            {
                                var u = usecSegments[ui];
                                if (DistancePointToSegment(endpoint, u.A, u.B) <= touchTol)
                                {
                                    continue;
                                }

                                var segDir = u.B - u.A;
                                var denom = Cross2d(inwardDir, segDir);
                                if (Math.Abs(denom) <= 1e-9)
                                {
                                    continue;
                                }

                                var diff = u.A - endpoint;
                                var tInfinite = Cross2d(diff, segDir) / denom;
                                if (tInfinite < inwardCompanionMin || tInfinite > inwardCompanionMax)
                                {
                                    continue;
                                }

                                var score = ScoreToExpected(tInfinite);
                                if (score > inwardInfiniteScoreTol)
                                {
                                    continue;
                                }

                                if (!bestInfiniteT.HasValue ||
                                    score < (bestInfiniteScore - 1e-9) ||
                                    (Math.Abs(score - bestInfiniteScore) <= 1e-9 && tInfinite < bestInfiniteT.Value))
                                {
                                    bestInfiniteT = tInfinite;
                                    bestInfiniteTarget = endpoint + (inwardDir * tInfinite);
                                    bestInfiniteScore = score;
                                }
                            }
                        }

                        double? bestProjectedT = null;
                        var bestProjectedTarget = endpoint;
                        var bestProjectedScore = double.MaxValue;
                        if (!bestExactT.HasValue && !bestApproxT.HasValue && !bestInfiniteT.HasValue)
                        {
                            var expectedTargets = new[] { inwardCompanionTarget, inwardCompanionAltTarget };
                            for (var dirIndex = 0; dirIndex < 2; dirIndex++)
                            {
                                var dir = dirIndex == 0 ? inwardDir : -inwardDir;
                                var rayRefProj = endpoint + dir;
                                for (var ti = 0; ti < expectedTargets.Length; ti++)
                                {
                                    var expectedDistance = expectedTargets[ti];
                                    var expectedProjPoint = endpoint + (dir * expectedDistance);
                                    for (var ui = 0; ui < usecSegments.Count; ui++)
                                    {
                                        var u = usecSegments[ui];
                                        if (DistancePointToSegment(endpoint, u.A, u.B) <= touchTol)
                                        {
                                            continue;
                                        }

                                        var projected = ClosestPointOnSegment(expectedProjPoint, u.A, u.B);
                                        var tProjected = (projected - endpoint).DotProduct(dir);
                                        if (tProjected < inwardCompanionMin || tProjected > inwardCompanionMax)
                                        {
                                            continue;
                                        }

                                        var perp = DistancePointToInfiniteLine(projected, endpoint, rayRefProj);
                                        if (perp > inwardProjectedPerpTol)
                                        {
                                            continue;
                                        }

                                        var gap = projected.GetDistanceTo(expectedProjPoint);
                                        if (gap > inwardProjectedGapTol)
                                        {
                                            continue;
                                        }

                                        var score = Math.Abs(tProjected - expectedDistance) + (0.20 * perp) + (0.08 * gap);
                                        if (!bestProjectedT.HasValue ||
                                            score < (bestProjectedScore - 1e-9) ||
                                            (Math.Abs(score - bestProjectedScore) <= 1e-9 && tProjected < bestProjectedT.Value))
                                        {
                                            bestProjectedT = tProjected;
                                            bestProjectedTarget = projected;
                                            bestProjectedScore = score;
                                        }
                                    }
                                }
                            }
                        }

                        var bestT = bestExactT ?? bestApproxT ?? bestInfiniteT ?? bestProjectedT;
                        var bestTarget =
                            bestExactT.HasValue ? bestExactTarget :
                            (bestApproxT.HasValue
                                ? bestApproxTarget
                                : (bestInfiniteT.HasValue ? bestInfiniteTarget : bestProjectedTarget));
                        if (!bestT.HasValue)
                        {
                            continue;
                        }

                        candidateEndpoints++;
                        if (!TryMoveEndpointByIndex(writableSec, endpointIndex, bestTarget, endpointMoveTol))
                        {
                            continue;
                        }

                        adjusted++;
                        endpointMoves.Add((endpoint, bestTarget));
                        if (endpointIndex == 0)
                        {
                            p0 = bestTarget;
                        }
                        else
                        {
                            p1 = bestTarget;
                        }
                    }
                }

                var lsdAdjusted = 0;
                if (endpointMoves.Count > 0 && lsdSegments.Count > 0)
                {
                    for (var li = 0; li < lsdSegments.Count; li++)
                    {
                        var lsd = lsdSegments[li];
                        if (!(tr.GetObject(lsd.Id, OpenMode.ForWrite, false) is Entity writableLsd) || writableLsd.IsErased)
                        {
                            continue;
                        }

                        if (!TryReadOpenSegment(writableLsd, out var l0, out var l1))
                        {
                            continue;
                        }

                        var targets = new Point2d[] { l0, l1 };
                        var movedIndex0 = false;
                        var movedIndex1 = false;
                        for (var endpointIndex = 0; endpointIndex <= 1; endpointIndex++)
                        {
                            var endpoint = endpointIndex == 0 ? l0 : l1;
                            var found = false;
                            var bestOldDistance = double.MaxValue;
                            var bestTarget = endpoint;
                            for (var mi = 0; mi < endpointMoves.Count; mi++)
                            {
                                var move = endpointMoves[mi];
                                var oldDistance = endpoint.GetDistanceTo(move.Old);
                                if (oldDistance > lsdAnchorTol)
                                {
                                    continue;
                                }

                                var moveDistance = endpoint.GetDistanceTo(move.New);
                                if (moveDistance <= endpointMoveTol || moveDistance > lsdMaxMove)
                                {
                                    continue;
                                }

                                if (oldDistance < bestOldDistance)
                                {
                                    found = true;
                                    bestOldDistance = oldDistance;
                                    bestTarget = move.New;
                                }
                            }

                            if (!found)
                            {
                                continue;
                            }

                            targets[endpointIndex] = bestTarget;
                            if (endpointIndex == 0)
                            {
                                movedIndex0 = true;
                            }
                            else
                            {
                                movedIndex1 = true;
                            }
                        }

                        if (!movedIndex0 && !movedIndex1)
                        {
                            continue;
                        }

                        if (writableLsd is Line lsdLine)
                        {
                            if (movedIndex0)
                            {
                                lsdLine.StartPoint = new Point3d(targets[0].X, targets[0].Y, lsdLine.StartPoint.Z);
                                lsdAdjusted++;
                            }

                            if (movedIndex1)
                            {
                                lsdLine.EndPoint = new Point3d(targets[1].X, targets[1].Y, lsdLine.EndPoint.Z);
                                lsdAdjusted++;
                            }
                        }
                        else if (writableLsd is Polyline lsdPoly && !lsdPoly.Closed && lsdPoly.NumberOfVertices == 2)
                        {
                            if (movedIndex0)
                            {
                                lsdPoly.SetPointAt(0, targets[0]);
                                lsdAdjusted++;
                            }

                            if (movedIndex1)
                            {
                                lsdPoly.SetPointAt(1, targets[1]);
                                lsdAdjusted++;
                            }
                        }
                    }
                }

                tr.Commit();
                logger?.WriteLine(
                    $"Cleanup: enforced L-SEC->L-USEC 20.11 endpoint rule adjusted={adjusted}, scanned={scannedEndpoints}, touchingUsec={touchingUsecEndpoints}, withInwardCompanion={candidateEndpoints}.");
                if (lsdAdjusted > 0)
                {
                    logger?.WriteLine($"Cleanup: adjusted {lsdAdjusted} L-SECTION-LSD endpoint(s) to follow enforced 20.11 endpoint moves.");
                }
            }
        }

        private static void ApplySimpleWestEndUsecExtensionRule(
            Database database,
            IEnumerable<ObjectId> requestedQuarterIds,
            IReadOnlyCollection<ObjectId>? generatedRoadAllowanceIds,
            Logger? logger)
        {
            var disableLegacyRule = true;
            if (disableLegacyRule)
            {
                logger?.WriteLine("Cleanup: simple west-end L-SEC->L-USEC rule disabled by canonical RA endpoint constraints.");
                return;
            }

            if (database == null || requestedQuarterIds == null)
            {
                return;
            }

            var clipWindows = BuildBufferedQuarterWindows(database, requestedQuarterIds, 102.0);
            if (clipWindows.Count == 0)
            {
                return;
            }

            var generatedSet = generatedRoadAllowanceIds != null && generatedRoadAllowanceIds.Count > 0
                ? new HashSet<ObjectId>(generatedRoadAllowanceIds.Where(id => !id.IsNull))
                : new HashSet<ObjectId>();
            if (generatedSet.Count == 0)
            {
                logger?.WriteLine("Cleanup: simple west-end rule skipped (no generated RA ids).");
                return;
            }

            bool IsPointInAnyWindow(Point2d p)
            {
                for (var i = 0; i < clipWindows.Count; i++)
                {
                    var w = clipWindows[i];
                    if (p.X >= w.MinPoint.X && p.X <= w.MaxPoint.X &&
                        p.Y >= w.MinPoint.Y && p.Y <= w.MaxPoint.Y)
                    {
                        return true;
                    }
                }

                return false;
            }

            bool DoesSegmentIntersectAnyWindow(Point2d a, Point2d b)
            {
                if (IsPointInAnyWindow(a) || IsPointInAnyWindow(b))
                {
                    return true;
                }

                for (var i = 0; i < clipWindows.Count; i++)
                {
                    if (TryClipSegmentToWindow(a, b, clipWindows[i], out _, out _))
                    {
                        return true;
                    }
                }

                return false;
            }

            using (var tr = database.TransactionManager.StartTransaction())
            {
                bool TryReadOpenSegment(Entity ent, out Point2d a, out Point2d b)
                {
                    a = default;
                    b = default;
                    if (ent == null)
                    {
                        return false;
                    }

                    if (ent is Line ln)
                    {
                        a = new Point2d(ln.StartPoint.X, ln.StartPoint.Y);
                        b = new Point2d(ln.EndPoint.X, ln.EndPoint.Y);
                        return a.GetDistanceTo(b) > 1e-4;
                    }

                    if (ent is Polyline pl)
                    {
                        if (pl.Closed || pl.NumberOfVertices < 2)
                        {
                            return false;
                        }

                        a = pl.GetPoint2dAt(0);
                        b = pl.GetPoint2dAt(pl.NumberOfVertices - 1);
                        if (a.GetDistanceTo(b) <= 1e-4)
                        {
                            return false;
                        }

                        if (pl.NumberOfVertices > 2)
                        {
                            const double collinearTol = 0.35;
                            for (var vi = 1; vi < pl.NumberOfVertices - 1; vi++)
                            {
                                var p = pl.GetPoint2dAt(vi);
                                if (DistancePointToInfiniteLine(p, a, b) > collinearTol)
                                {
                                    return false;
                                }
                            }
                        }

                        return true;
                    }

                    return false;
                }

                bool IsHorizontalLike(Point2d a, Point2d b)
                {
                    var d = b - a;
                    return Math.Abs(d.X) >= Math.Abs(d.Y);
                }

                bool IsVerticalLike(Point2d a, Point2d b)
                {
                    var d = b - a;
                    return Math.Abs(d.Y) > Math.Abs(d.X);
                }

                bool TryMoveEndpointByIndex(Entity writable, int endpointIndex, Point2d target, double moveTol)
                {
                    if (endpointIndex != 0 && endpointIndex != 1)
                    {
                        return false;
                    }

                    if (writable is Line ln)
                    {
                        var old = endpointIndex == 0
                            ? new Point2d(ln.StartPoint.X, ln.StartPoint.Y)
                            : new Point2d(ln.EndPoint.X, ln.EndPoint.Y);
                        if (old.GetDistanceTo(target) <= moveTol)
                        {
                            return false;
                        }

                        if (endpointIndex == 0)
                        {
                            ln.StartPoint = new Point3d(target.X, target.Y, ln.StartPoint.Z);
                        }
                        else
                        {
                            ln.EndPoint = new Point3d(target.X, target.Y, ln.EndPoint.Z);
                        }

                        return true;
                    }

                    if (writable is Polyline pl && !pl.Closed && pl.NumberOfVertices >= 2)
                    {
                        var idx = endpointIndex == 0 ? 0 : pl.NumberOfVertices - 1;
                        var old = pl.GetPoint2dAt(idx);
                        if (old.GetDistanceTo(target) <= moveTol)
                        {
                            return false;
                        }

                        pl.SetPointAt(idx, target);
                        return true;
                    }

                    return false;
                }

                void CollectVerticalRoadSegments(Entity ent, List<(Point2d A, Point2d B)> destination)
                {
                    if (ent is Line ln)
                    {
                        var a = new Point2d(ln.StartPoint.X, ln.StartPoint.Y);
                        var b = new Point2d(ln.EndPoint.X, ln.EndPoint.Y);
                        if (a.GetDistanceTo(b) > 1e-4 &&
                            IsVerticalLike(a, b) &&
                            DoesSegmentIntersectAnyWindow(a, b))
                        {
                            destination.Add((a, b));
                        }

                        return;
                    }

                    if (!(ent is Polyline pl) || pl.Closed || pl.NumberOfVertices < 2)
                    {
                        return;
                    }

                    for (var vi = 0; vi < pl.NumberOfVertices - 1; vi++)
                    {
                        var a = pl.GetPoint2dAt(vi);
                        var b = pl.GetPoint2dAt(vi + 1);
                        if (a.GetDistanceTo(b) <= 1e-4)
                        {
                            continue;
                        }

                        if (!IsVerticalLike(a, b) || !DoesSegmentIntersectAnyWindow(a, b))
                        {
                            continue;
                        }

                        destination.Add((a, b));
                    }
                }

                var verticalUsec = new List<(Point2d A, Point2d B)>();
                var verticalRoadBoundaries = new List<(Point2d A, Point2d B)>();
                var secHorizontalIds = new List<ObjectId>();
                var lsdVerticalIds = new List<ObjectId>();

                var bt = (BlockTable)tr.GetObject(database.BlockTableId, OpenMode.ForRead);
                var ms = (BlockTableRecord)tr.GetObject(bt[BlockTableRecord.ModelSpace], OpenMode.ForRead);
                foreach (ObjectId id in ms)
                {
                    if (!(tr.GetObject(id, OpenMode.ForRead, false) is Entity ent) || ent.IsErased)
                    {
                        continue;
                    }

                    var isUsec = string.Equals(ent.Layer, "L-USEC", StringComparison.OrdinalIgnoreCase);
                    var isSec = string.Equals(ent.Layer, "L-SEC", StringComparison.OrdinalIgnoreCase);
                    var isLsd = string.Equals(ent.Layer, "L-SECTION-LSD", StringComparison.OrdinalIgnoreCase);
                    var isGenerated = generatedSet.Contains(id);
                    if (!isUsec && !isSec && !isLsd)
                    {
                        continue;
                    }

                    if (isUsec)
                    {
                        if (isGenerated)
                        {
                            CollectVerticalRoadSegments(ent, verticalUsec);
                        }

                        CollectVerticalRoadSegments(ent, verticalRoadBoundaries);
                        continue;
                    }

                    if (isSec)
                    {
                        CollectVerticalRoadSegments(ent, verticalRoadBoundaries);
                    }

                    if (!TryReadOpenSegment(ent, out var a, out var b))
                    {
                        continue;
                    }

                    if (!DoesSegmentIntersectAnyWindow(a, b))
                    {
                        continue;
                    }

                    var horizontal = IsHorizontalLike(a, b);
                    var vertical = IsVerticalLike(a, b);
                    if (isSec && horizontal && isGenerated)
                    {
                        secHorizontalIds.Add(id);
                    }
                    else if (isLsd && vertical && IsAdjustableLsdLineSegment(a, b))
                    {
                        lsdVerticalIds.Add(id);
                    }
                }

                if (verticalUsec.Count == 0 || secHorizontalIds.Count == 0)
                {
                    tr.Commit();
                    logger?.WriteLine(
                        $"Cleanup: simple west-end rule skipped (verticalUsec={verticalUsec.Count}, secHoriz={secHorizontalIds.Count}).");
                    return;
                }

                const double touchTol = 0.35;
                const double minStep = 0.10;
                const double maxStep = 120.0;
                const double endpointMoveTol = 0.05;
                const double usecProjectionTol = 1.5;
                const double usecApparentYTol = 6.0;
                const double tenOhSixStep = CorrectionLinePairGapMeters;
                const double tenOhSixTol = 2.8;
                const double thirtyEighteenStep = RoadAllowanceUsecWidthMeters;
                const double twentyTwelveStep = 20.11;
                const double corridorStepTol = 4.5;
                const double lsdMidpointXTol = 1.50;
                const double lsdMidpointYTol = 2.0;
                const double lsdMaxMove = 80.0;

                bool IsTouchingUsec(Point2d p)
                {
                    for (var i = 0; i < verticalUsec.Count; i++)
                    {
                        var seg = verticalUsec[i];
                        if (DistancePointToSegment(p, seg.A, seg.B) <= touchTol)
                        {
                            return true;
                        }
                    }

                    return false;
                }

                bool TryFindApparentTenOhSixTarget(
                    Point2d endpoint,
                    Vector2d outwardDir,
                    out Point2d target,
                    out double bestT)
                {
                    target = endpoint;
                    bestT = double.MaxValue;
                    if (Math.Abs(outwardDir.X) <= 1e-6)
                    {
                        return false;
                    }

                    var found = false;
                    var bestScore = double.MaxValue;
                    for (var i = 0; i < verticalUsec.Count; i++)
                    {
                        var seg = verticalUsec[i];
                        if (DistancePointToSegment(endpoint, seg.A, seg.B) <= touchTol)
                        {
                            continue;
                        }

                        var minY = Math.Min(seg.A.Y, seg.B.Y);
                        var maxY = Math.Max(seg.A.Y, seg.B.Y);
                        var yGap = 0.0;
                        if (endpoint.Y < minY)
                        {
                            yGap = minY - endpoint.Y;
                        }
                        else if (endpoint.Y > maxY)
                        {
                            yGap = endpoint.Y - maxY;
                        }

                        if (yGap > usecApparentYTol)
                        {
                            continue;
                        }

                        var axisX = 0.5 * (seg.A.X + seg.B.X);
                        var t = (axisX - endpoint.X) / outwardDir.X;
                        if (t < minStep || t > maxStep)
                        {
                            continue;
                        }

                        var score = Math.Abs(t - tenOhSixStep);
                        if (score > tenOhSixTol)
                        {
                            continue;
                        }

                        if (!found ||
                            score < (bestScore - 1e-9) ||
                            (Math.Abs(score - bestScore) <= 1e-9 && t < bestT))
                        {
                            found = true;
                            bestScore = score;
                            bestT = t;
                            target = endpoint + (outwardDir * t);
                        }
                    }

                    return found;
                }

                bool HasBlockingVerticalRoad(
                    Point2d endpoint,
                    Vector2d outwardDir,
                    double targetT)
                {
                    if (targetT <= (minStep + 0.20) || verticalRoadBoundaries.Count == 0)
                    {
                        return false;
                    }

                    var maxBlockT = targetT - 0.20;
                    for (var i = 0; i < verticalRoadBoundaries.Count; i++)
                    {
                        var seg = verticalRoadBoundaries[i];
                        if (DistancePointToSegment(endpoint, seg.A, seg.B) <= touchTol)
                        {
                            continue;
                        }

                        var hasIntersection = TryIntersectInfiniteLineWithSegment(endpoint, outwardDir, seg.A, seg.B, out var t);
                        if (!hasIntersection)
                        {
                            if (Math.Abs(outwardDir.X) <= 1e-6)
                            {
                                continue;
                            }

                            var axisX = 0.5 * (seg.A.X + seg.B.X);
                            t = (axisX - endpoint.X) / outwardDir.X;
                        }

                        if (t < minStep || t > maxBlockT)
                        {
                            continue;
                        }

                        var candidate = endpoint + (outwardDir * t);
                        if (DistancePointToSegment(candidate, seg.A, seg.B) > usecProjectionTol)
                        {
                            continue;
                        }

                        return true;
                    }

                    return false;
                }

                bool TryFindNextUsecTarget(
                    Point2d endpoint,
                    Vector2d outwardDir,
                    out Point2d target,
                    out double bestT,
                    out bool promotedPastThirty)
                {
                    target = endpoint;
                    bestT = double.MaxValue;
                    promotedPastThirty = false;
                    if (outwardDir.Length <= 1e-6)
                    {
                        return false;
                    }

                    var candidates = new List<(double T, Point2d Target)>();
                    for (var i = 0; i < verticalUsec.Count; i++)
                    {
                        var seg = verticalUsec[i];
                        if (DistancePointToSegment(endpoint, seg.A, seg.B) <= touchTol)
                        {
                            continue;
                        }

                        var hasIntersection = TryIntersectInfiniteLineWithSegment(endpoint, outwardDir, seg.A, seg.B, out var t);
                        if (!hasIntersection)
                        {
                            if (Math.Abs(outwardDir.X) <= 1e-6)
                            {
                                continue;
                            }

                            var axisX = 0.5 * (seg.A.X + seg.B.X);
                            t = (axisX - endpoint.X) / outwardDir.X;
                        }

                        if (t < minStep || t > maxStep)
                        {
                            continue;
                        }

                        var candidate = endpoint + (outwardDir * t);
                        if (DistancePointToSegment(candidate, seg.A, seg.B) > usecProjectionTol)
                        {
                            continue;
                        }

                        candidates.Add((t, candidate));
                    }

                    if (candidates.Count == 0)
                    {
                        if (TryFindApparentTenOhSixTarget(endpoint, outwardDir, out target, out bestT))
                        {
                            if (HasBlockingVerticalRoad(endpoint, outwardDir, bestT))
                            {
                                return false;
                            }

                            return true;
                        }

                        return false;
                    }

                    candidates.Sort((l, r) => l.T.CompareTo(r.T));

                    // Prefer the inward middle-line hit (~10.06 from a 30.17 boundary) when present.
                    var selectedIndex = -1;
                    var bestTenOhSixScore = double.MaxValue;
                    for (var i = 0; i < candidates.Count; i++)
                    {
                        var score = Math.Abs(candidates[i].T - tenOhSixStep);
                        if (score > tenOhSixTol)
                        {
                            continue;
                        }

                        if (selectedIndex < 0 ||
                            score < (bestTenOhSixScore - 1e-9) ||
                            (Math.Abs(score - bestTenOhSixScore) <= 1e-9 && candidates[i].T < candidates[selectedIndex].T))
                        {
                            selectedIndex = i;
                            bestTenOhSixScore = score;
                        }
                    }

                    if (selectedIndex >= 0)
                    {
                        var selected = candidates[selectedIndex];
                        if (HasBlockingVerticalRoad(endpoint, outwardDir, selected.T))
                        {
                            return false;
                        }

                        target = selected.Target;
                        bestT = selected.T;
                        return true;
                    }

                    if (TryFindApparentTenOhSixTarget(endpoint, outwardDir, out target, out bestT))
                    {
                        if (HasBlockingVerticalRoad(endpoint, outwardDir, bestT))
                        {
                            return false;
                        }

                        return true;
                    }

                    // Strict guard: avoid west-end overshoot by only accepting 10.06-style targets.
                    return false;
                }

                var scanned = 0;
                var touching = 0;
                var candidateHits = 0;
                var promotedPastThirty = 0;
                var secAdjusted = 0;
                var secMoveInfos = new List<(Point2d OldWest, Point2d FixedEast, Point2d NewWest, Point2d OldMid, Point2d NewMid)>();
                for (var i = 0; i < secHorizontalIds.Count; i++)
                {
                    var id = secHorizontalIds[i];
                    if (!(tr.GetObject(id, OpenMode.ForWrite, false) is Entity writableSec) || writableSec.IsErased)
                    {
                        continue;
                    }

                    if (!TryReadOpenSegment(writableSec, out var p0, out var p1) || !IsHorizontalLike(p0, p1))
                    {
                        continue;
                    }

                    var westIndex = p0.X <= p1.X ? 0 : 1;
                    var west = westIndex == 0 ? p0 : p1;
                    var east = westIndex == 0 ? p1 : p0;
                    scanned++;
                    if (!IsTouchingUsec(west))
                    {
                        continue;
                    }

                    touching++;
                    var outward = west - east;
                    if (outward.Length <= 1e-6)
                    {
                        continue;
                    }

                    var outwardDir = outward / outward.Length;
                    if (!TryFindNextUsecTarget(west, outwardDir, out var target, out _, out var usedTwentyBeyondThirty))
                    {
                        continue;
                    }

                    candidateHits++;
                    if (usedTwentyBeyondThirty)
                    {
                        promotedPastThirty++;
                    }

                    if (!TryMoveEndpointByIndex(writableSec, westIndex, target, endpointMoveTol))
                    {
                        continue;
                    }

                    secAdjusted++;
                    var oldMid = Midpoint(west, east);
                    var newMid = Midpoint(target, east);
                    secMoveInfos.Add((west, east, target, oldMid, newMid));
                }

                var lsdAdjusted = 0;
                if (secMoveInfos.Count > 0 && lsdVerticalIds.Count > 0)
                {
                    for (var i = 0; i < lsdVerticalIds.Count; i++)
                    {
                        var id = lsdVerticalIds[i];
                        if (!(tr.GetObject(id, OpenMode.ForWrite, false) is Entity writableLsd) || writableLsd.IsErased)
                        {
                            continue;
                        }

                        if (!TryReadOpenSegment(writableLsd, out var p0, out var p1) || !IsVerticalLike(p0, p1))
                        {
                            continue;
                        }

                        var southIndex = p0.Y <= p1.Y ? 0 : 1;
                        var south = southIndex == 0 ? p0 : p1;
                        var bestFound = false;
                        var bestXDelta = double.MaxValue;
                        var bestMove = double.MaxValue;
                        var bestTarget = south;
                        for (var mi = 0; mi < secMoveInfos.Count; mi++)
                        {
                            var move = secMoveInfos[mi];
                            var xDelta = Math.Abs(south.X - move.OldMid.X);
                            if (xDelta > lsdMidpointXTol)
                            {
                                continue;
                            }

                            if (Math.Abs(south.Y - move.OldMid.Y) > lsdMidpointYTol)
                            {
                                continue;
                            }

                            var moveLen = south.GetDistanceTo(move.NewMid);
                            if (moveLen <= endpointMoveTol || moveLen > lsdMaxMove)
                            {
                                continue;
                            }

                            if (!bestFound ||
                                xDelta < (bestXDelta - 1e-9) ||
                                (Math.Abs(xDelta - bestXDelta) <= 1e-9 && moveLen < bestMove))
                            {
                                bestFound = true;
                                bestXDelta = xDelta;
                                bestMove = moveLen;
                                bestTarget = move.NewMid;
                            }
                        }

                        if (!bestFound)
                        {
                            continue;
                        }
 
                        if (TryMoveEndpointByIndex(writableLsd, southIndex, bestTarget, endpointMoveTol))
                        {
                            lsdAdjusted++;
                        }
                    }
                }

                tr.Commit();
                logger?.WriteLine(
                    $"Cleanup: simple west-end L-SEC->next L-USEC rule scanned={scanned}, touchingUsec={touching}, candidateHits={candidateHits}, promotedPastThirty={promotedPastThirty}, secAdjusted={secAdjusted}, lsdAdjusted={lsdAdjusted}.");
            }
        }

        private static void EnforceTwentyTwelveStopRules(
            Database database,
            IReadOnlyList<QuarterLabelInfo> requestedQuarterInfos,
            Logger? logger)
        {
            if (database == null || requestedQuarterInfos == null || requestedQuarterInfos.Count == 0)
            {
                return;
            }

            var requestedQuarterIds = requestedQuarterInfos
                .Where(info => info != null && !info.QuarterId.IsNull && !info.QuarterId.IsErased)
                .Select(info => info.QuarterId)
                .Distinct()
                .ToList();
            if (requestedQuarterIds.Count == 0)
            {
                return;
            }

            var clipWindows = BuildBufferedQuarterWindows(database, requestedQuarterIds, 102.0);
            if (clipWindows.Count == 0)
            {
                return;
            }

            bool IsPointInAnyWindow(Point2d p)
            {
                for (var i = 0; i < clipWindows.Count; i++)
                {
                    var w = clipWindows[i];
                    if (p.X >= w.MinPoint.X && p.X <= w.MaxPoint.X &&
                        p.Y >= w.MinPoint.Y && p.Y <= w.MaxPoint.Y)
                    {
                        return true;
                    }
                }

                return false;
            }

            bool DoesSegmentIntersectAnyWindow(Point2d a, Point2d b)
            {
                if (IsPointInAnyWindow(a) || IsPointInAnyWindow(b))
                {
                    return true;
                }

                for (var i = 0; i < clipWindows.Count; i++)
                {
                    if (TryClipSegmentToWindow(a, b, clipWindows[i], out _, out _))
                    {
                        return true;
                    }
                }

                return false;
            }

            using (var tr = database.TransactionManager.StartTransaction())
            {
                bool TryReadOpenSegment(Entity ent, out Point2d a, out Point2d b)
                {
                    a = default;
                    b = default;
                    if (ent == null)
                    {
                        return false;
                    }

                    if (ent is Line ln)
                    {
                        a = new Point2d(ln.StartPoint.X, ln.StartPoint.Y);
                        b = new Point2d(ln.EndPoint.X, ln.EndPoint.Y);
                        return a.GetDistanceTo(b) > 1e-4;
                    }

                    if (ent is Polyline pl)
                    {
                        if (pl.Closed || pl.NumberOfVertices < 2)
                        {
                            return false;
                        }

                        a = pl.GetPoint2dAt(0);
                        b = pl.GetPoint2dAt(pl.NumberOfVertices - 1);
                        if (a.GetDistanceTo(b) <= 1e-4)
                        {
                            return false;
                        }

                        if (pl.NumberOfVertices > 2)
                        {
                            const double collinearTol = 0.35;
                            for (var vi = 1; vi < pl.NumberOfVertices - 1; vi++)
                            {
                                var p = pl.GetPoint2dAt(vi);
                                if (DistancePointToInfiniteLine(p, a, b) > collinearTol)
                                {
                                    return false;
                                }
                            }
                        }

                        return true;
                    }

                    return false;
                }

                bool IsHorizontalLike(Point2d a, Point2d b)
                {
                    var d = b - a;
                    return Math.Abs(d.X) >= Math.Abs(d.Y);
                }

                bool IsVerticalLike(Point2d a, Point2d b)
                {
                    var d = b - a;
                    return Math.Abs(d.Y) > Math.Abs(d.X);
                }

                bool TryMoveEndpointByIndex(Entity writable, int endpointIndex, Point2d target, double moveTol)
                {
                    if (endpointIndex != 0 && endpointIndex != 1)
                    {
                        return false;
                    }

                    if (writable is Line ln)
                    {
                        var old = endpointIndex == 0
                            ? new Point2d(ln.StartPoint.X, ln.StartPoint.Y)
                            : new Point2d(ln.EndPoint.X, ln.EndPoint.Y);
                        if (old.GetDistanceTo(target) <= moveTol)
                        {
                            return false;
                        }

                        if (endpointIndex == 0)
                        {
                            ln.StartPoint = new Point3d(target.X, target.Y, ln.StartPoint.Z);
                        }
                        else
                        {
                            ln.EndPoint = new Point3d(target.X, target.Y, ln.EndPoint.Z);
                        }

                        return true;
                    }

                    if (writable is Polyline pl && !pl.Closed && pl.NumberOfVertices >= 2)
                    {
                        var idx = endpointIndex == 0 ? 0 : pl.NumberOfVertices - 1;
                        var old = pl.GetPoint2dAt(idx);
                        if (old.GetDistanceTo(target) <= moveTol)
                        {
                            return false;
                        }

                        pl.SetPointAt(idx, target);
                        return true;
                    }

                    return false;
                }

                bool IsPointInWindow(Point2d p, Extents3d window)
                {
                    return p.X >= window.MinPoint.X &&
                           p.X <= window.MaxPoint.X &&
                           p.Y >= window.MinPoint.Y &&
                           p.Y <= window.MaxPoint.Y;
                }

                const double sectionTagBuffer = 102.0;
                var quarterContextById = new Dictionary<ObjectId, QuarterLabelInfo>();
                for (var qi = 0; qi < requestedQuarterInfos.Count; qi++)
                {
                    var info = requestedQuarterInfos[qi];
                    if (info == null || info.QuarterId.IsNull || info.QuarterId.IsErased)
                    {
                        continue;
                    }

                    if (!quarterContextById.ContainsKey(info.QuarterId))
                    {
                        quarterContextById.Add(info.QuarterId, info);
                    }
                }

                var quarterContexts = new List<(ObjectId QuarterId, Extents3d Window, Point2d Center, string SectionQuarterKeyId, string SectionQuarterLabel)>();
                foreach (var pair in quarterContextById)
                {
                    if (!(tr.GetObject(pair.Key, OpenMode.ForRead, false) is Polyline quarter) || quarter.IsErased)
                    {
                        continue;
                    }

                    try
                    {
                        var ext = quarter.GeometricExtents;
                        var window = new Extents3d(
                            new Point3d(ext.MinPoint.X - sectionTagBuffer, ext.MinPoint.Y - sectionTagBuffer, 0.0),
                            new Point3d(ext.MaxPoint.X + sectionTagBuffer, ext.MaxPoint.Y + sectionTagBuffer, 0.0));
                        var center = new Point2d(
                            0.5 * (ext.MinPoint.X + ext.MaxPoint.X),
                            0.5 * (ext.MinPoint.Y + ext.MaxPoint.Y));
                        var sectionQuarterKeyId = BuildSectionQuarterKeyId(pair.Value.SectionKey, pair.Value.Quarter);
                        var sectionDescriptor = BuildSectionDescriptor(pair.Value.SectionKey);
                        var quarterToken = QuarterSelectionToToken(pair.Value.Quarter);
                        var sectionQuarterLabel = string.IsNullOrWhiteSpace(quarterToken)
                            ? sectionDescriptor
                            : $"{sectionDescriptor} {quarterToken}";
                        quarterContexts.Add((pair.Key, window, center, sectionQuarterKeyId, sectionQuarterLabel));
                    }
                    catch
                    {
                    }
                }

                (string SectionQuarterKeyId, string SectionQuarterLabel) ResolveSectionQuarter(Point2d point)
                {
                    if (quarterContexts.Count == 0)
                    {
                        return (string.Empty, "(unknown)");
                    }

                    var insideIndex = -1;
                    var insideDistance = double.MaxValue;
                    var nearestIndex = -1;
                    var nearestDistance = double.MaxValue;
                    for (var i = 0; i < quarterContexts.Count; i++)
                    {
                        var ctx = quarterContexts[i];
                        var distance = point.GetDistanceTo(ctx.Center);
                        if (IsPointInWindow(point, ctx.Window) && distance < insideDistance)
                        {
                            insideDistance = distance;
                            insideIndex = i;
                        }

                        if (distance < nearestDistance)
                        {
                            nearestDistance = distance;
                            nearestIndex = i;
                        }
                    }

                    var chosenIndex = insideIndex >= 0 ? insideIndex : nearestIndex;
                    if (chosenIndex < 0 || chosenIndex >= quarterContexts.Count)
                    {
                        return (string.Empty, "(unknown)");
                    }

                    var chosen = quarterContexts[chosenIndex];
                    return (chosen.SectionQuarterKeyId, chosen.SectionQuarterLabel);
                }

                var unresolvedBySectionQuarter = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
                var unresolvedSectionLabelByKey = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
                var unresolvedSamples = new List<string>();
                void RecordUnresolved(
                    ObjectId entityId,
                    string layer,
                    Point2d endpoint,
                    bool lineIsVertical,
                    Vector2d inwardDir,
                    string reason)
                {
                    var sectionInfo = ResolveSectionQuarter(endpoint);
                    var sectionKey = string.IsNullOrWhiteSpace(sectionInfo.SectionQuarterKeyId)
                        ? "UNKNOWN"
                        : sectionInfo.SectionQuarterKeyId;
                    var sectionLabel = string.IsNullOrWhiteSpace(sectionInfo.SectionQuarterLabel)
                        ? "(unknown)"
                        : sectionInfo.SectionQuarterLabel;

                    if (unresolvedBySectionQuarter.TryGetValue(sectionKey, out var count))
                    {
                        unresolvedBySectionQuarter[sectionKey] = count + 1;
                    }
                    else
                    {
                        unresolvedBySectionQuarter[sectionKey] = 1;
                    }

                    if (!unresolvedSectionLabelByKey.ContainsKey(sectionKey))
                    {
                        unresolvedSectionLabelByKey.Add(sectionKey, sectionLabel);
                    }

                    if (unresolvedSamples.Count < 16)
                    {
                        unresolvedSamples.Add(
                            string.Format(
                                CultureInfo.InvariantCulture,
                                "sec={0} id={1} layer={2} p=({3:F2},{4:F2}) orient={5} inward=({6:F4},{7:F4}) reason={8}",
                                sectionLabel,
                                entityId,
                                layer,
                                endpoint.X,
                                endpoint.Y,
                                lineIsVertical ? "V" : "H",
                                inwardDir.X,
                                inwardDir.Y,
                                reason));
                    }
                }

                var roadSegments = new List<(ObjectId Id, string Layer, Point2d A, Point2d B, bool Horizontal, bool Vertical, double Axis, double MajorMin, double MajorMax, Vector2d Unit, Point2d Mid)>();
                var targetSegments = new List<(ObjectId Id, bool IsLsd, bool IsQsec)>();

                var bt = (BlockTable)tr.GetObject(database.BlockTableId, OpenMode.ForRead);
                var ms = (BlockTableRecord)tr.GetObject(bt[BlockTableRecord.ModelSpace], OpenMode.ForRead);
                foreach (ObjectId id in ms)
                {
                    if (!(tr.GetObject(id, OpenMode.ForRead, false) is Entity ent) || ent.IsErased)
                    {
                        continue;
                    }

                    var layer = ent.Layer ?? string.Empty;
                    var isRoadLayer =
                        string.Equals(layer, "L-SEC", StringComparison.OrdinalIgnoreCase) ||
                        string.Equals(layer, "L-USEC", StringComparison.OrdinalIgnoreCase);
                    var isLsdLayer = string.Equals(layer, "L-SECTION-LSD", StringComparison.OrdinalIgnoreCase);
                    var isQsecLayer = string.Equals(layer, "L-QSEC", StringComparison.OrdinalIgnoreCase);
                    if (!isRoadLayer && !isLsdLayer && !isQsecLayer)
                    {
                        continue;
                    }

                    if (!TryReadOpenSegment(ent, out var a, out var b))
                    {
                        continue;
                    }

                    if (!DoesSegmentIntersectAnyWindow(a, b))
                    {
                        continue;
                    }

                    var horizontal = IsHorizontalLike(a, b);
                    var vertical = IsVerticalLike(a, b);
                    if (!horizontal && !vertical)
                    {
                        continue;
                    }

                    if (isRoadLayer)
                    {
                        var axis = horizontal
                            ? 0.5 * (a.Y + b.Y)
                            : 0.5 * (a.X + b.X);
                        var majorMin = horizontal
                            ? Math.Min(a.X, b.X)
                            : Math.Min(a.Y, b.Y);
                        var majorMax = horizontal
                            ? Math.Max(a.X, b.X)
                            : Math.Max(a.Y, b.Y);
                        var dir = b - a;
                        var dirLen = dir.Length;
                        if (dirLen <= 1e-6)
                        {
                            continue;
                        }

                        var unit = dir / dirLen;
                        var mid = Midpoint(a, b);
                        roadSegments.Add((id, layer, a, b, horizontal, vertical, axis, majorMin, majorMax, unit, mid));
                        continue;
                    }

                    if (isLsdLayer && !IsAdjustableLsdLineSegment(a, b))
                    {
                        continue;
                    }

                    if (isQsecLayer)
                    {
                        var len = a.GetDistanceTo(b);
                        if (len < 8.0 || len > 2000.0)
                        {
                            continue;
                        }
                    }

                    targetSegments.Add((id, isLsdLayer, isQsecLayer));
                }

                if (roadSegments.Count == 0 || targetSegments.Count == 0)
                {
                    tr.Commit();
                    logger?.WriteLine(
                        $"Cleanup: 20.11 stop rules skipped (roads={roadSegments.Count}, targets={targetSegments.Count}).");
                    return;
                }

                const double twentyTwelveGap = 20.11;
                const double thirtyEighteenGap = RoadAllowanceUsecWidthMeters;
                const double tenOhSixGap = CorrectionLinePairGapMeters;
                const double twentyGapTol = 1.10;
                const double thirtyGapTol = 1.60;
                const double tenOhSixTol = 2.40;
                const double companionMinOverlap = 4.0;
                const double fallbackMinOverlap = 2.0;
                var hasTwentyCompanion = new bool[roadSegments.Count];
                var hasThirtyCompanion = new bool[roadSegments.Count];
                for (var i = 0; i < roadSegments.Count; i++)
                {
                    var a = roadSegments[i];
                    for (var j = i + 1; j < roadSegments.Count; j++)
                    {
                        var b = roadSegments[j];
                        if ((a.Horizontal != b.Horizontal) || (a.Vertical != b.Vertical))
                        {
                            continue;
                        }

                        var overlap = Math.Min(a.MajorMax, b.MajorMax) - Math.Max(a.MajorMin, b.MajorMin);
                        if (overlap < companionMinOverlap)
                        {
                            continue;
                        }

                        var gap = Math.Abs(a.Axis - b.Axis);
                        if (Math.Abs(gap - twentyTwelveGap) <= twentyGapTol)
                        {
                            hasTwentyCompanion[i] = true;
                            hasTwentyCompanion[j] = true;
                        }

                        if (Math.Abs(gap - thirtyEighteenGap) <= thirtyGapTol)
                        {
                            hasThirtyCompanion[i] = true;
                            hasThirtyCompanion[j] = true;
                        }
                    }
                }

                var twentyRoadIndices = new List<int>();
                for (var i = 0; i < roadSegments.Count; i++)
                {
                    if (hasTwentyCompanion[i])
                    {
                        twentyRoadIndices.Add(i);
                    }
                }

                const double endpointTouchTol = 0.35;
                const double endpointMoveTol = 0.05;
                const double minInwardStep = 0.05;
                const double maxInwardSearch = 28.0;
                const double inwardLengthSlack = 0.90;
                const double axisFallbackMajorTol = 22.0;
                const double lsdMidpointAxisTol = 2.0;
                const double lsdMaxMove = 24.0;
                const double qsecMaxMove = 24.0;
                const double localTwentyGapTol = 1.90;
                const double localTwentyGapTolRelaxed = 2.80;
                const double localTenOhSixGapTol = 2.80;
                const double localPairMinOverlap = 0.75;

                var thirtyOnlyRoadIndices = new List<int>();
                for (var i = 0; i < roadSegments.Count; i++)
                {
                    if (hasThirtyCompanion[i] && !hasTwentyCompanion[i])
                    {
                        thirtyOnlyRoadIndices.Add(i);
                    }
                }

                List<int> GetTouchedRoadIndices(Point2d endpoint)
                {
                    var touchedIndices = new List<int>();
                    for (var ri = 0; ri < roadSegments.Count; ri++)
                    {
                        var road = roadSegments[ri];
                        if (DistancePointToSegment(endpoint, road.A, road.B) <= endpointTouchTol)
                        {
                            touchedIndices.Add(ri);
                        }
                    }

                    return touchedIndices;
                }

                bool TryFindNearestInwardTarget(
                    Point2d endpoint,
                    Vector2d inwardDir,
                    bool lineIsVertical,
                    double maxT,
                    IEnumerable<int> candidateIndices,
                    out Point2d target,
                    out int targetRoadIndex,
                    out double bestT)
                {
                    target = endpoint;
                    targetRoadIndex = -1;
                    bestT = double.MaxValue;
                    var found = false;
                    foreach (var ri in candidateIndices)
                    {
                        if (ri < 0 || ri >= roadSegments.Count)
                        {
                            continue;
                        }

                        var road = roadSegments[ri];
                        if (lineIsVertical && !road.Horizontal)
                        {
                            continue;
                        }

                        if (!lineIsVertical && !road.Vertical)
                        {
                            continue;
                        }

                        if (!TryIntersectInfiniteLineWithSegment(endpoint, inwardDir, road.A, road.B, out var t))
                        {
                            if (lineIsVertical)
                            {
                                if (Math.Abs(inwardDir.Y) <= 1e-9)
                                {
                                    continue;
                                }

                                t = (road.Axis - endpoint.Y) / inwardDir.Y;
                                if (t < minInwardStep || t > maxT)
                                {
                                    continue;
                                }

                                var xAtT = endpoint.X + (inwardDir.X * t);
                                var majorGap = 0.0;
                                if (xAtT < road.MajorMin)
                                {
                                    majorGap = road.MajorMin - xAtT;
                                }
                                else if (xAtT > road.MajorMax)
                                {
                                    majorGap = xAtT - road.MajorMax;
                                }

                                if (majorGap > axisFallbackMajorTol)
                                {
                                    continue;
                                }
                            }
                            else
                            {
                                if (Math.Abs(inwardDir.X) <= 1e-9)
                                {
                                    continue;
                                }

                                t = (road.Axis - endpoint.X) / inwardDir.X;
                                if (t < minInwardStep || t > maxT)
                                {
                                    continue;
                                }

                                var yAtT = endpoint.Y + (inwardDir.Y * t);
                                var majorGap = 0.0;
                                if (yAtT < road.MajorMin)
                                {
                                    majorGap = road.MajorMin - yAtT;
                                }
                                else if (yAtT > road.MajorMax)
                                {
                                    majorGap = yAtT - road.MajorMax;
                                }

                                if (majorGap > axisFallbackMajorTol)
                                {
                                    continue;
                                }
                            }
                        }

                        if (t < minInwardStep || t > maxT)
                        {
                            continue;
                        }

                        if (!found || t < (bestT - 1e-9))
                        {
                            found = true;
                            bestT = t;
                            targetRoadIndex = ri;
                            target = endpoint + (inwardDir * t);
                        }
                    }

                    return found;
                }

                bool TryFindSectionLocalTwentyProjection(
                    Point2d endpoint,
                    Vector2d inwardDir,
                    bool lineIsVertical,
                    IReadOnlyList<int> touchedThirtyOnly,
                    out Point2d target,
                    out int outerRoadIndex,
                    out int twentyRoadIndex,
                    out bool usedClampedExtent)
                {
                    target = endpoint;
                    outerRoadIndex = -1;
                    twentyRoadIndex = -1;
                    usedClampedExtent = false;

                    var outerCandidates = touchedThirtyOnly != null && touchedThirtyOnly.Count > 0
                        ? touchedThirtyOnly
                        : thirtyOnlyRoadIndices;
                    if (outerCandidates == null || outerCandidates.Count == 0)
                    {
                        return false;
                    }

                    bool TryFindLocalPass(
                        bool requireSameLayer,
                        double minOverlap,
                        double gapTol,
                        out Point2d passTarget,
                        out int passOuterRoadIndex,
                        out int passTwentyRoadIndex,
                        out bool passUsedClampedExtent)
                    {
                        passTarget = endpoint;
                        passOuterRoadIndex = -1;
                        passTwentyRoadIndex = -1;
                        passUsedClampedExtent = false;

                        var found = false;
                        var bestScore = double.MaxValue;
                        for (var oi = 0; oi < outerCandidates.Count; oi++)
                        {
                            var outerIndex = outerCandidates[oi];
                            if (outerIndex < 0 || outerIndex >= roadSegments.Count)
                            {
                                continue;
                            }

                            var outer = roadSegments[outerIndex];
                            if (lineIsVertical && !outer.Horizontal)
                            {
                                continue;
                            }

                            if (!lineIsVertical && !outer.Vertical)
                            {
                                continue;
                            }

                            for (var ri = 0; ri < roadSegments.Count; ri++)
                            {
                                if (ri == outerIndex)
                                {
                                    continue;
                                }

                                var inner = roadSegments[ri];
                                if ((inner.Horizontal != outer.Horizontal) || (inner.Vertical != outer.Vertical))
                                {
                                    continue;
                                }

                                var sameLayer = string.Equals(inner.Layer, outer.Layer, StringComparison.OrdinalIgnoreCase);
                                if (requireSameLayer && !sameLayer)
                                {
                                    continue;
                                }

                                var overlap = Math.Min(outer.MajorMax, inner.MajorMax) - Math.Max(outer.MajorMin, inner.MajorMin);
                                if (overlap < minOverlap)
                                {
                                    continue;
                                }

                                var gap = Math.Abs(inner.Axis - outer.Axis);
                                var gapDeltaTwenty = Math.Abs(gap - twentyTwelveGap);
                                var gapDeltaTenOhSix = Math.Abs(gap - tenOhSixGap);
                                if (gapDeltaTwenty > gapTol && gapDeltaTenOhSix > localTenOhSixGapTol)
                                {
                                    continue;
                                }
                                var gapDelta = Math.Min(gapDeltaTwenty, gapDeltaTenOhSix);

                                var blended = outer.Unit + inner.Unit;
                                var blendedLen = blended.Length;
                                var along = blendedLen > 1e-6 ? (blended / blendedLen) : outer.Unit;
                                if (along.Length <= 1e-6)
                                {
                                    continue;
                                }

                                var normal = new Vector2d(-along.Y, along.X);
                                if (normal.DotProduct(inwardDir) < 0.0)
                                {
                                    normal = -normal;
                                }

                                var normalOffset = (inner.Mid - endpoint).DotProduct(normal);
                                if (normalOffset < minInwardStep || normalOffset > maxInwardSearch)
                                {
                                    continue;
                                }
                                var normalOffsetDeltaTwenty = Math.Abs(normalOffset - twentyTwelveGap);
                                var normalOffsetDeltaTenOhSix = Math.Abs(normalOffset - tenOhSixGap);
                                var normalOffsetDelta = Math.Min(normalOffsetDeltaTwenty, normalOffsetDeltaTenOhSix);
                                if (normalOffsetDelta > Math.Max(gapTol, localTenOhSixGapTol))
                                {
                                    continue;
                                }

                                var uA = (inner.A - endpoint).DotProduct(along);
                                var uB = (inner.B - endpoint).DotProduct(along);
                                var uMin = Math.Min(uA, uB);
                                var uMax = Math.Max(uA, uB);

                                var projectedU = 0.0;
                                var clampUsed = false;
                                if (projectedU < uMin)
                                {
                                    projectedU = uMin;
                                    clampUsed = true;
                                }
                                else if (projectedU > uMax)
                                {
                                    projectedU = uMax;
                                    clampUsed = true;
                                }

                                var majorGap = clampUsed ? Math.Abs(projectedU) : 0.0;
                                if (majorGap > axisFallbackMajorTol)
                                {
                                    continue;
                                }

                                var candidateTarget = endpoint + (along * projectedU) + (normal * normalOffset);
                                var score =
                                    DistancePointToSegment(endpoint, outer.A, outer.B) +
                                    normalOffsetDelta +
                                    (0.15 * majorGap) +
                                    (0.10 * gapDelta) +
                                    (sameLayer ? 0.0 : 0.20) +
                                    (overlap < localPairMinOverlap ? 0.12 : 0.0);
                                if (!found || score < (bestScore - 1e-9))
                                {
                                    found = true;
                                    bestScore = score;
                                    passTarget = candidateTarget;
                                    passOuterRoadIndex = outerIndex;
                                    passTwentyRoadIndex = ri;
                                    passUsedClampedExtent = clampUsed;
                                }
                            }
                        }

                        return found;
                    }

                    if (TryFindLocalPass(
                            requireSameLayer: true,
                            minOverlap: localPairMinOverlap,
                            gapTol: localTwentyGapTol,
                            out var strictTarget,
                            out var strictOuter,
                            out var strictTwenty,
                            out var strictClamp))
                    {
                        target = strictTarget;
                        outerRoadIndex = strictOuter;
                        twentyRoadIndex = strictTwenty;
                        usedClampedExtent = strictClamp;
                        return true;
                    }

                    if (TryFindLocalPass(
                            requireSameLayer: false,
                            minOverlap: 0.0,
                            gapTol: localTwentyGapTolRelaxed,
                            out var relaxedTarget,
                            out var relaxedOuter,
                            out var relaxedTwenty,
                            out var relaxedClamp))
                    {
                        target = relaxedTarget;
                        outerRoadIndex = relaxedOuter;
                        twentyRoadIndex = relaxedTwenty;
                        usedClampedExtent = relaxedClamp;
                        return true;
                    }

                    return false;
                }

                var scannedEndpoints = 0;
                var touchedRoadEndpoints = 0;
                var touchedThirtyOnlyEndpoints = 0;
                var noTwentyTarget = 0;
                var lsdUnresolvedBeforeHardStop = 0;
                var adjustedLsd = 0;
                var adjustedQsec = 0;
                var midpointMoves = 0;
                var fallbackMoves = 0;
                var fallbackReverseMoves = 0;
                var localBasisMoves = 0;
                var localBasisClampMoves = 0;
                var localBasisReverseMoves = 0;
                for (var ti = 0; ti < targetSegments.Count; ti++)
                {
                    var targetMeta = targetSegments[ti];
                    if (!(tr.GetObject(targetMeta.Id, OpenMode.ForWrite, false) is Entity writable) || writable.IsErased)
                    {
                        continue;
                    }

                    if (!TryReadOpenSegment(writable, out var p0, out var p1))
                    {
                        continue;
                    }

                    var targetLayer = writable.Layer ?? string.Empty;
                    var lineIsHorizontal = IsHorizontalLike(p0, p1);
                    var lineIsVertical = IsVerticalLike(p0, p1);
                    if (!lineIsHorizontal && !lineIsVertical)
                    {
                        continue;
                    }

                    for (var endpointIndex = 0; endpointIndex <= 1; endpointIndex++)
                    {
                        scannedEndpoints++;
                        var endpoint = endpointIndex == 0 ? p0 : p1;
                        var other = endpointIndex == 0 ? p1 : p0;
                        var inward = other - endpoint;
                        var inwardLen = inward.Length;
                        if (inwardLen <= 1e-6)
                        {
                            continue;
                        }

                        var inwardDir = inward / inwardLen;
                        var touchedIndices = GetTouchedRoadIndices(endpoint);

                        if (touchedIndices.Count == 0)
                        {
                            continue;
                        }

                        touchedRoadEndpoints++;
                        var onTwenty = touchedIndices.Any(ri => hasTwentyCompanion[ri]);
                        if (onTwenty)
                        {
                            continue;
                        }

                        var touchedThirtyOnly = touchedIndices
                            .Where(ri => hasThirtyCompanion[ri] && !hasTwentyCompanion[ri])
                            .ToList();
                        if (touchedThirtyOnly.Count == 0)
                        {
                            continue;
                        }

                        touchedThirtyOnlyEndpoints++;
                        var maxT = Math.Min(maxInwardSearch, inwardLen + inwardLengthSlack);
                        var hasTarget = TryFindNearestInwardTarget(
                            endpoint,
                            inwardDir,
                            lineIsVertical,
                            maxT,
                            twentyRoadIndices,
                            out var bestTarget,
                            out var bestRoadIndex,
                            out _);
                        var usedFallback = false;
                        var usedFallbackReverse = false;
                        var usedLocalBasis = false;
                        var usedLocalClamp = false;
                        var usedLocalReverse = false;
                        if (!hasTarget)
                        {
                            var fallbackCandidates = new HashSet<int>();
                            for (var oi = 0; oi < touchedThirtyOnly.Count; oi++)
                            {
                                var outerIndex = touchedThirtyOnly[oi];
                                var outer = roadSegments[outerIndex];
                                for (var ri = 0; ri < roadSegments.Count; ri++)
                                {
                                    if (ri == outerIndex)
                                    {
                                        continue;
                                    }

                                    var road = roadSegments[ri];
                                    if ((road.Horizontal != outer.Horizontal) || (road.Vertical != outer.Vertical))
                                    {
                                        continue;
                                    }

                                    if (!string.Equals(road.Layer, outer.Layer, StringComparison.OrdinalIgnoreCase))
                                    {
                                        continue;
                                    }

                                    var overlap = Math.Min(outer.MajorMax, road.MajorMax) - Math.Max(outer.MajorMin, road.MajorMin);
                                    if (overlap < fallbackMinOverlap)
                                    {
                                        continue;
                                    }

                                    var gap = Math.Abs(road.Axis - outer.Axis);
                                    if (Math.Abs(gap - tenOhSixGap) > tenOhSixTol &&
                                        Math.Abs(gap - twentyTwelveGap) > twentyGapTol)
                                    {
                                        continue;
                                    }

                                    fallbackCandidates.Add(ri);
                                }
                            }

                            if (fallbackCandidates.Count > 0)
                            {
                                hasTarget = TryFindNearestInwardTarget(
                                    endpoint,
                                    inwardDir,
                                    lineIsVertical,
                                    maxT,
                                    fallbackCandidates,
                                    out bestTarget,
                                    out bestRoadIndex,
                                    out _);
                                if (!hasTarget)
                                {
                                    hasTarget = TryFindNearestInwardTarget(
                                        endpoint,
                                        -inwardDir,
                                        lineIsVertical,
                                        maxT,
                                        fallbackCandidates,
                                        out bestTarget,
                                        out bestRoadIndex,
                                        out _);
                                    usedFallbackReverse = hasTarget;
                                }

                                usedFallback = hasTarget;
                            }
                        }

                        if (!hasTarget && targetMeta.IsLsd)
                        {
                            hasTarget = TryFindSectionLocalTwentyProjection(
                                endpoint,
                                inwardDir,
                                lineIsVertical,
                                touchedThirtyOnly,
                                out bestTarget,
                                out _,
                                out bestRoadIndex,
                                out usedLocalClamp);
                            if (!hasTarget)
                            {
                                hasTarget = TryFindSectionLocalTwentyProjection(
                                    endpoint,
                                    -inwardDir,
                                    lineIsVertical,
                                    touchedThirtyOnly,
                                    out bestTarget,
                                    out _,
                                    out bestRoadIndex,
                                    out usedLocalClamp);
                                usedLocalReverse = hasTarget;
                            }

                            usedLocalBasis = hasTarget;
                        }

                        if (!hasTarget || bestRoadIndex < 0)
                        {
                            if (targetMeta.IsLsd)
                            {
                                lsdUnresolvedBeforeHardStop++;
                            }
                            else
                            {
                                noTwentyTarget++;
                                RecordUnresolved(
                                    targetMeta.Id,
                                    targetLayer,
                                    endpoint,
                                    lineIsVertical,
                                    inwardDir,
                                    "no-20.11-target");
                            }

                            continue;
                        }

                        var moveTarget = bestTarget;
                        var usedMidpoint = false;
                        if (targetMeta.IsLsd && !usedLocalBasis)
                        {
                            var road = roadSegments[bestRoadIndex];
                            var mid = Midpoint(road.A, road.B);
                            if (lineIsVertical)
                            {
                                if (Math.Abs(mid.X - endpoint.X) <= lsdMidpointAxisTol)
                                {
                                    moveTarget = mid;
                                    usedMidpoint = true;
                                }
                            }
                            else if (lineIsHorizontal)
                            {
                                if (Math.Abs(mid.Y - endpoint.Y) <= lsdMidpointAxisTol)
                                {
                                    moveTarget = mid;
                                    usedMidpoint = true;
                                }
                            }
                        }

                        var moveLen = endpoint.GetDistanceTo(moveTarget);
                        var moveCap = targetMeta.IsLsd ? lsdMaxMove : qsecMaxMove;
                        if (moveLen <= endpointMoveTol || moveLen > moveCap)
                        {
                            continue;
                        }

                        if (!TryMoveEndpointByIndex(writable, endpointIndex, moveTarget, endpointMoveTol))
                        {
                            continue;
                        }

                        if (targetMeta.IsLsd)
                        {
                            adjustedLsd++;
                        }
                        else if (targetMeta.IsQsec)
                        {
                            adjustedQsec++;
                        }

                        if (usedMidpoint)
                        {
                            midpointMoves++;
                        }

                        if (usedFallback)
                        {
                            fallbackMoves++;
                            if (usedFallbackReverse)
                            {
                                fallbackReverseMoves++;
                            }
                        }

                        if (usedLocalBasis)
                        {
                            localBasisMoves++;
                            if (usedLocalClamp)
                            {
                                localBasisClampMoves++;
                            }

                            if (usedLocalReverse)
                            {
                                localBasisReverseMoves++;
                            }
                        }

                        if (endpointIndex == 0)
                        {
                            p0 = moveTarget;
                        }
                        else
                        {
                            p1 = moveTarget;
                        }
                    }
                }

                var hardStopScanned = 0;
                var hardStopAdjusted = 0;
                var hardStopClampMoves = 0;
                var hardStopReverseMoves = 0;
                var hardStopUnresolved = 0;
                for (var ti = 0; ti < targetSegments.Count; ti++)
                {
                    var targetMeta = targetSegments[ti];
                    if (!targetMeta.IsLsd)
                    {
                        continue;
                    }

                    if (!(tr.GetObject(targetMeta.Id, OpenMode.ForWrite, false) is Entity writable) || writable.IsErased)
                    {
                        continue;
                    }

                    if (!TryReadOpenSegment(writable, out var p0, out var p1))
                    {
                        continue;
                    }

                    var targetLayer = writable.Layer ?? string.Empty;
                    var lineIsHorizontal = IsHorizontalLike(p0, p1);
                    var lineIsVertical = IsVerticalLike(p0, p1);
                    if (!lineIsHorizontal && !lineIsVertical)
                    {
                        continue;
                    }

                    for (var endpointIndex = 0; endpointIndex <= 1; endpointIndex++)
                    {
                        var endpoint = endpointIndex == 0 ? p0 : p1;
                        var other = endpointIndex == 0 ? p1 : p0;
                        var touchedIndices = GetTouchedRoadIndices(endpoint);
                        if (touchedIndices.Count == 0)
                        {
                            continue;
                        }

                        if (touchedIndices.Any(ri => hasTwentyCompanion[ri]))
                        {
                            continue;
                        }

                        var touchedThirtyOnly = touchedIndices
                            .Where(ri => hasThirtyCompanion[ri] && !hasTwentyCompanion[ri])
                            .ToList();
                        if (touchedThirtyOnly.Count == 0)
                        {
                            continue;
                        }

                        hardStopScanned++;
                        var inward = other - endpoint;
                        var inwardLen = inward.Length;
                        if (inwardLen <= 1e-6)
                        {
                            hardStopUnresolved++;
                            noTwentyTarget++;
                            RecordUnresolved(
                                targetMeta.Id,
                                targetLayer,
                                endpoint,
                                lineIsVertical,
                                new Vector2d(0.0, 0.0),
                                "hard-stop-zero-inward");
                            continue;
                        }

                        var inwardDir = inward / inwardLen;
                        var hardStopUsedReverse = false;
                        if (!TryFindSectionLocalTwentyProjection(
                                endpoint,
                                inwardDir,
                                lineIsVertical,
                                touchedThirtyOnly,
                                out var hardStopTarget,
                                out _,
                                out _,
                                out var hardStopClamp))
                        {
                            if (!TryFindSectionLocalTwentyProjection(
                                    endpoint,
                                    -inwardDir,
                                    lineIsVertical,
                                    touchedThirtyOnly,
                                    out hardStopTarget,
                                    out _,
                                    out _,
                                    out hardStopClamp))
                            {
                                hardStopUnresolved++;
                                noTwentyTarget++;
                                RecordUnresolved(
                                    targetMeta.Id,
                                    targetLayer,
                                    endpoint,
                                    lineIsVertical,
                                    inwardDir,
                                    "hard-stop-no-local-axis");
                                continue;
                            }

                            hardStopUsedReverse = true;
                        }

                        var moveLen = endpoint.GetDistanceTo(hardStopTarget);
                        if (moveLen <= endpointMoveTol || moveLen > lsdMaxMove)
                        {
                            hardStopUnresolved++;
                            noTwentyTarget++;
                            RecordUnresolved(
                                targetMeta.Id,
                                targetLayer,
                                endpoint,
                                lineIsVertical,
                                inwardDir,
                                "hard-stop-move-out-of-range");
                            continue;
                        }

                        if (!TryMoveEndpointByIndex(writable, endpointIndex, hardStopTarget, endpointMoveTol))
                        {
                            hardStopUnresolved++;
                            noTwentyTarget++;
                            RecordUnresolved(
                                targetMeta.Id,
                                targetLayer,
                                endpoint,
                                lineIsVertical,
                                inwardDir,
                                "hard-stop-move-failed");
                            continue;
                        }

                        hardStopAdjusted++;
                        adjustedLsd++;
                        if (hardStopClamp)
                        {
                            hardStopClampMoves++;
                        }
                        if (hardStopUsedReverse)
                        {
                            hardStopReverseMoves++;
                        }

                        if (endpointIndex == 0)
                        {
                            p0 = hardStopTarget;
                        }
                        else
                        {
                            p1 = hardStopTarget;
                        }
                    }
                }

                tr.Commit();
                logger?.WriteLine(
                    $"Cleanup: enforced 20.11 stop rules scanned={scannedEndpoints}, touchedRoad={touchedRoadEndpoints}, touched30Only={touchedThirtyOnlyEndpoints}, adjustedLsd={adjustedLsd}, adjustedQsec={adjustedQsec}, midpointMoves={midpointMoves}, fallbackMoves={fallbackMoves}, fallbackReverseMoves={fallbackReverseMoves}, localBasisMoves={localBasisMoves}, localClampMoves={localBasisClampMoves}, localReverseMoves={localBasisReverseMoves}, preHardStopLsdUnresolved={lsdUnresolvedBeforeHardStop}, hardStopScanned={hardStopScanned}, hardStopAdjusted={hardStopAdjusted}, hardStopClampMoves={hardStopClampMoves}, hardStopReverseMoves={hardStopReverseMoves}, hardStopUnresolved={hardStopUnresolved}, unresolved={noTwentyTarget}.");
                if (noTwentyTarget > 0)
                {
                    logger?.WriteLine(
                        $"RULE-WARN: {noTwentyTarget} endpoint(s) touched 30.17 boundary but no valid inward 20.11 target was found after hard-stop.");
                    if (unresolvedSamples.Count > 0)
                    {
                        logger?.WriteLine("RULE-WARN samples: " + string.Join(" | ", unresolvedSamples));
                    }

                    if (unresolvedBySectionQuarter.Count > 0)
                    {
                        var sectionRows = unresolvedBySectionQuarter
                            .OrderByDescending(pair => pair.Value)
                            .ThenBy(pair => pair.Key, StringComparer.OrdinalIgnoreCase)
                            .Select(pair =>
                            {
                                var sectionLabel = unresolvedSectionLabelByKey.TryGetValue(pair.Key, out var label)
                                    ? label
                                    : pair.Key;
                                return $"{sectionLabel} ({pair.Key})={pair.Value}";
                            })
                            .ToList();
                        logger?.WriteLine("RULE-WARN unresolved by section-quarter: " + string.Join(" | ", sectionRows));
                    }
                }
            }
        }

        private static void ForceInwardTenOhSixFromOuterUsec(
            Database database,
            IEnumerable<ObjectId> requestedQuarterIds,
            IReadOnlyCollection<ObjectId> generatedRoadAllowanceIds,
            Logger? logger)
        {
            if (database == null || requestedQuarterIds == null || generatedRoadAllowanceIds == null || generatedRoadAllowanceIds.Count == 0)
            {
                return;
            }

            var clipWindows = BuildBufferedQuarterWindows(database, requestedQuarterIds, 102.0);
            if (clipWindows.Count == 0)
            {
                return;
            }

            bool IsPointInAnyWindow(Point2d p)
            {
                for (var i = 0; i < clipWindows.Count; i++)
                {
                    var w = clipWindows[i];
                    if (p.X >= w.MinPoint.X && p.X <= w.MaxPoint.X &&
                        p.Y >= w.MinPoint.Y && p.Y <= w.MaxPoint.Y)
                    {
                        return true;
                    }
                }

                return false;
            }

            bool DoesSegmentIntersectAnyWindow(Point2d a, Point2d b)
            {
                if (IsPointInAnyWindow(a) || IsPointInAnyWindow(b))
                {
                    return true;
                }

                for (var i = 0; i < clipWindows.Count; i++)
                {
                    if (TryClipSegmentToWindow(a, b, clipWindows[i], out _, out _))
                    {
                        return true;
                    }
                }

                return false;
            }

            using (var tr = database.TransactionManager.StartTransaction())
            {
                bool TryReadOpenSegment(Entity ent, out Point2d a, out Point2d b)
                {
                    a = default;
                    b = default;
                    if (ent == null)
                    {
                        return false;
                    }

                    if (ent is Line ln)
                    {
                        a = new Point2d(ln.StartPoint.X, ln.StartPoint.Y);
                        b = new Point2d(ln.EndPoint.X, ln.EndPoint.Y);
                        return a.GetDistanceTo(b) > 1e-4;
                    }

                    if (ent is Polyline pl)
                    {
                        if (pl.Closed || pl.NumberOfVertices < 2)
                        {
                            return false;
                        }

                        a = pl.GetPoint2dAt(0);
                        b = pl.GetPoint2dAt(pl.NumberOfVertices - 1);
                        if (a.GetDistanceTo(b) <= 1e-4)
                        {
                            return false;
                        }

                        if (pl.NumberOfVertices > 2)
                        {
                            const double collinearTol = 0.35;
                            for (var vi = 1; vi < pl.NumberOfVertices - 1; vi++)
                            {
                                var p = pl.GetPoint2dAt(vi);
                                if (DistancePointToInfiniteLine(p, a, b) > collinearTol)
                                {
                                    return false;
                                }
                            }
                        }

                        return true;
                    }

                    return false;
                }

                bool IsHorizontalLike(Point2d a, Point2d b)
                {
                    var d = b - a;
                    return Math.Abs(d.X) >= Math.Abs(d.Y);
                }

                bool IsVerticalLike(Point2d a, Point2d b)
                {
                    var d = b - a;
                    return Math.Abs(d.Y) > Math.Abs(d.X);
                }

                bool TryMoveEndpointByIndex(Entity writable, int endpointIndex, Point2d target, double moveTol)
                {
                    if (endpointIndex != 0 && endpointIndex != 1)
                    {
                        return false;
                    }

                    if (writable is Line ln)
                    {
                        var old = endpointIndex == 0
                            ? new Point2d(ln.StartPoint.X, ln.StartPoint.Y)
                            : new Point2d(ln.EndPoint.X, ln.EndPoint.Y);
                        if (old.GetDistanceTo(target) <= moveTol)
                        {
                            return false;
                        }

                        if (endpointIndex == 0)
                        {
                            ln.StartPoint = new Point3d(target.X, target.Y, ln.StartPoint.Z);
                        }
                        else
                        {
                            ln.EndPoint = new Point3d(target.X, target.Y, ln.EndPoint.Z);
                        }

                        return true;
                    }

                    if (writable is Polyline pl && !pl.Closed && pl.NumberOfVertices >= 2)
                    {
                        var idx = endpointIndex == 0 ? 0 : pl.NumberOfVertices - 1;
                        var old = pl.GetPoint2dAt(idx);
                        if (old.GetDistanceTo(target) <= moveTol)
                        {
                            return false;
                        }

                        pl.SetPointAt(idx, target);
                        return true;
                    }

                    return false;
                }

                var generatedSet = new HashSet<ObjectId>(generatedRoadAllowanceIds.Where(id => !id.IsNull));
                var verticalRoads = new List<(Point2d A, Point2d B, bool Generated)>();
                var horizontalRoads = new List<(Point2d A, Point2d B, bool Generated)>();
                var secMovables = new List<ObjectId>();
                var lsdHorizontalMovables = new List<ObjectId>();
                var lsdVerticalMovables = new List<ObjectId>();

                var bt = (BlockTable)tr.GetObject(database.BlockTableId, OpenMode.ForRead);
                var ms = (BlockTableRecord)tr.GetObject(bt[BlockTableRecord.ModelSpace], OpenMode.ForRead);
                foreach (ObjectId id in ms)
                {
                    if (!(tr.GetObject(id, OpenMode.ForRead, false) is Entity ent) || ent.IsErased)
                    {
                        continue;
                    }

                    var isUsec = string.Equals(ent.Layer, "L-USEC", StringComparison.OrdinalIgnoreCase);
                    var isSec = string.Equals(ent.Layer, "L-SEC", StringComparison.OrdinalIgnoreCase);
                    var isLsd = string.Equals(ent.Layer, "L-SECTION-LSD", StringComparison.OrdinalIgnoreCase);
                    if (!isUsec && !isSec && !isLsd)
                    {
                        continue;
                    }

                    if (!TryReadOpenSegment(ent, out var a, out var b))
                    {
                        continue;
                    }

                    if (!DoesSegmentIntersectAnyWindow(a, b))
                    {
                        continue;
                    }

                    var horizontal = IsHorizontalLike(a, b);
                    var vertical = IsVerticalLike(a, b);
                    if ((isUsec || isSec) && vertical)
                    {
                        verticalRoads.Add((a, b, generatedSet.Contains(id)));
                    }

                    if ((isUsec || isSec) && horizontal)
                    {
                        horizontalRoads.Add((a, b, generatedSet.Contains(id)));
                    }

                    if (isSec && horizontal)
                    {
                        secMovables.Add(id);
                    }
                    else if (isLsd && IsAdjustableLsdLineSegment(a, b))
                    {
                        if (horizontal)
                        {
                            lsdHorizontalMovables.Add(id);
                        }
                        else if (vertical)
                        {
                            lsdVerticalMovables.Add(id);
                        }
                    }
                }

                if (verticalRoads.Count == 0 &&
                    horizontalRoads.Count == 0 &&
                    secMovables.Count == 0 &&
                    lsdHorizontalMovables.Count == 0 &&
                    lsdVerticalMovables.Count == 0)
                {
                    tr.Commit();
                    logger?.WriteLine(
                        $"Cleanup: forced inward 10.06 skipped (verticalRoads={verticalRoads.Count}, horizontalRoads={horizontalRoads.Count}, secMovables={secMovables.Count}, lsdH={lsdHorizontalMovables.Count}, lsdV={lsdVerticalMovables.Count}).");
                    return;
                }

                const double touchTol = 0.35;
                const double outerCompanionTarget = RoadAllowanceUsecWidthMeters;
                const double outerCompanionTol = 3.0;
                const double targetCompanionTarget = 20.11;
                const double targetCompanionTol = 2.70;
                const double companionMinOverlap = 10.0;
                const double stepTargetPrimary = CorrectionLinePairGapMeters;
                const double stepTargetSecondary = 20.11;
                const double stepMin = 0.10;
                const double stepMax = 45.0;
                const double endpointMoveTol = 0.05;
                const double lsdMaxMove = 16.50;
                var scanned = 0;
                var touchingOuter = 0;
                var touchingOuterThirtyEighteen = 0;
                var candidates = 0;
                var adjusted = 0;
                var lsdAdjusted = 0;
                var outerCompanionCache = new Dictionary<int, bool>();
                var targetCompanionCache = new Dictionary<int, bool>();
                var outerHorizontalCompanionCache = new Dictionary<int, bool>();
                var targetHorizontalCompanionCache = new Dictionary<int, bool>();

                double AxisX((Point2d A, Point2d B, bool Generated) seg)
                {
                    return 0.5 * (seg.A.X + seg.B.X);
                }

                double OverlapY((Point2d A, Point2d B, bool Generated) a, (Point2d A, Point2d B, bool Generated) b)
                {
                    var aMin = Math.Min(a.A.Y, a.B.Y);
                    var aMax = Math.Max(a.A.Y, a.B.Y);
                    var bMin = Math.Min(b.A.Y, b.B.Y);
                    var bMax = Math.Max(b.A.Y, b.B.Y);
                    return Math.Min(aMax, bMax) - Math.Max(aMin, bMin);
                }

                bool ComputeHasCompanionAtOffset(
                    int index,
                    double expectedOffset,
                    double tol,
                    Dictionary<int, bool> cache)
                {
                    if (cache.TryGetValue(index, out var cached))
                    {
                        return cached;
                    }

                    if (index < 0 || index >= verticalRoads.Count)
                    {
                        cache[index] = false;
                        return false;
                    }

                    var s = verticalRoads[index];
                    var sAxis = AxisX(s);
                    var found = false;
                    for (var oi = 0; oi < verticalRoads.Count; oi++)
                    {
                        if (oi == index)
                        {
                            continue;
                        }

                        var o = verticalRoads[oi];
                        if (OverlapY(s, o) < companionMinOverlap)
                        {
                            continue;
                        }

                        var offset = Math.Abs(AxisX(o) - sAxis);
                        if (Math.Abs(offset - expectedOffset) <= tol)
                        {
                            found = true;
                            break;
                        }
                    }

                    cache[index] = found;
                    return found;
                }

                bool HasOuterCompanion(int index)
                {
                    return ComputeHasCompanionAtOffset(
                        index,
                        outerCompanionTarget,
                        outerCompanionTol,
                        outerCompanionCache);
                }

                bool HasTargetCompanion(int index)
                {
                    return ComputeHasCompanionAtOffset(
                        index,
                        targetCompanionTarget,
                        targetCompanionTol,
                        targetCompanionCache);
                }

                double AxisY((Point2d A, Point2d B, bool Generated) seg)
                {
                    return 0.5 * (seg.A.Y + seg.B.Y);
                }

                double OverlapX((Point2d A, Point2d B, bool Generated) a, (Point2d A, Point2d B, bool Generated) b)
                {
                    var aMin = Math.Min(a.A.X, a.B.X);
                    var aMax = Math.Max(a.A.X, a.B.X);
                    var bMin = Math.Min(b.A.X, b.B.X);
                    var bMax = Math.Max(b.A.X, b.B.X);
                    return Math.Min(aMax, bMax) - Math.Max(aMin, bMin);
                }

                bool ComputeHorizontalHasCompanionAtOffset(
                    int index,
                    double expectedOffset,
                    double tol,
                    Dictionary<int, bool> cache)
                {
                    if (cache.TryGetValue(index, out var cached))
                    {
                        return cached;
                    }

                    if (index < 0 || index >= horizontalRoads.Count)
                    {
                        cache[index] = false;
                        return false;
                    }

                    var s = horizontalRoads[index];
                    var sAxis = AxisY(s);
                    var found = false;
                    for (var oi = 0; oi < horizontalRoads.Count; oi++)
                    {
                        if (oi == index)
                        {
                            continue;
                        }

                        var o = horizontalRoads[oi];
                        if (OverlapX(s, o) < companionMinOverlap)
                        {
                            continue;
                        }

                        var offset = Math.Abs(AxisY(o) - sAxis);
                        if (Math.Abs(offset - expectedOffset) <= tol)
                        {
                            found = true;
                            break;
                        }
                    }

                    cache[index] = found;
                    return found;
                }

                bool HasOuterHorizontalCompanion(int index)
                {
                    return ComputeHorizontalHasCompanionAtOffset(
                        index,
                        outerCompanionTarget,
                        outerCompanionTol,
                        outerHorizontalCompanionCache);
                }

                bool HasTargetHorizontalCompanion(int index)
                {
                    return ComputeHorizontalHasCompanionAtOffset(
                        index,
                        targetCompanionTarget,
                        targetCompanionTol,
                        targetHorizontalCompanionCache);
                }

                bool TryFindBestTarget(
                    Point2d endpoint,
                    Vector2d inwardDir,
                    out Point2d bestTarget,
                    out double bestScore,
                    out double bestT,
                    out bool endpointTouchedOuter,
                    out bool endpointTouchedOuterThirtyEighteen)
                {
                    bestTarget = endpoint;
                    bestScore = double.MaxValue;
                    bestT = double.MaxValue;
                    endpointTouchedOuter = false;
                    endpointTouchedOuterThirtyEighteen = false;
                    var found = false;

                    for (var oi = 0; oi < verticalRoads.Count; oi++)
                    {
                        var outer = verticalRoads[oi];
                        if (DistancePointToSegment(endpoint, outer.A, outer.B) > touchTol)
                        {
                            continue;
                        }

                        endpointTouchedOuter = true;
                        if (!HasOuterCompanion(oi))
                        {
                            continue;
                        }

                        endpointTouchedOuterThirtyEighteen = true;
                        if (Math.Abs(inwardDir.X) <= 1e-3)
                        {
                            continue;
                        }

                        var outerAxisX = AxisX(outer);
                        var inwardSign = Math.Sign(inwardDir.X);
                        for (var pass = 0; pass <= 1; pass++)
                        {
                            for (var ti = 0; ti < verticalRoads.Count; ti++)
                            {
                                if (ti == oi)
                                {
                                    continue;
                                }

                                var targetHasTwentyCompanion = HasTargetCompanion(ti);
                                var targetHasThirtyCompanion = HasOuterCompanion(ti);
                                if (pass == 0 && !targetHasTwentyCompanion)
                                {
                                    continue;
                                }

                                if (pass == 1)
                                {
                                    if (targetHasTwentyCompanion)
                                    {
                                        continue;
                                    }

                                    if (targetHasThirtyCompanion)
                                    {
                                        continue;
                                    }
                                }

                                var targetSeg = verticalRoads[ti];
                                var targetAxisX = AxisX(targetSeg);
                                var t = (targetAxisX - outerAxisX) * inwardSign;
                                if (t < stepMin || t > stepMax)
                                {
                                    continue;
                                }

                                var score =
                                    (pass * 1000.0) +
                                    0.65 * Math.Min(
                                        Math.Abs(t - stepTargetPrimary),
                                        Math.Abs(t - stepTargetSecondary)) +
                                    0.35 * t;
                                if (targetHasTwentyCompanion)
                                {
                                    score -= 0.08;
                                }

                                if (targetSeg.Generated)
                                {
                                    score -= 0.03;
                                }

                                if (!found ||
                                    score < (bestScore - 1e-9) ||
                                    (Math.Abs(score - bestScore) <= 1e-9 && t < bestT))
                                {
                                    found = true;
                                    bestScore = score;
                                    bestT = t;
                                    bestTarget = new Point2d(targetAxisX, endpoint.Y);
                                }
                            }
                        }
                    }

                    return found;
                }

                bool TryFindBestVerticalLsdTarget(
                    Point2d southEndpoint,
                    Point2d northEndpoint,
                    out Point2d bestTarget)
                {
                    bestTarget = southEndpoint;
                    if (horizontalRoads.Count == 0)
                    {
                        return false;
                    }

                    var dirY = northEndpoint.Y - southEndpoint.Y;
                    if (Math.Abs(dirY) <= 1e-6)
                    {
                        return false;
                    }

                    var inwardSign = Math.Sign(dirY);
                    var found = false;
                    var bestScore = double.MaxValue;
                    var bestT = double.MaxValue;
                    for (var oi = 0; oi < horizontalRoads.Count; oi++)
                    {
                        var outer = horizontalRoads[oi];
                        if (DistancePointToSegment(southEndpoint, outer.A, outer.B) > touchTol)
                        {
                            continue;
                        }

                        if (!HasOuterHorizontalCompanion(oi))
                        {
                            continue;
                        }

                        var outerAxisY = AxisY(outer);
                        for (var pass = 0; pass <= 1; pass++)
                        {
                            for (var ti = 0; ti < horizontalRoads.Count; ti++)
                            {
                                if (ti == oi)
                                {
                                    continue;
                                }

                                var targetHasTwentyCompanion = HasTargetHorizontalCompanion(ti);
                                var targetHasThirtyCompanion = HasOuterHorizontalCompanion(ti);
                                if (pass == 0 && !targetHasTwentyCompanion)
                                {
                                    continue;
                                }

                                if (pass == 1)
                                {
                                    if (targetHasTwentyCompanion)
                                    {
                                        continue;
                                    }

                                    if (targetHasThirtyCompanion)
                                    {
                                        continue;
                                    }
                                }

                                var targetSeg = horizontalRoads[ti];
                                var targetAxisY = AxisY(targetSeg);
                                var t = (targetAxisY - outerAxisY) * inwardSign;
                                if (t < stepMin || t > stepMax)
                                {
                                    continue;
                                }

                                var score =
                                    (pass * 1000.0) +
                                    0.65 * Math.Min(
                                        Math.Abs(t - stepTargetPrimary),
                                        Math.Abs(t - stepTargetSecondary)) +
                                    0.35 * t;
                                if (targetHasTwentyCompanion)
                                {
                                    score -= 0.08;
                                }

                                if (targetSeg.Generated)
                                {
                                    score -= 0.03;
                                }

                                if (!found ||
                                    score < (bestScore - 1e-9) ||
                                    (Math.Abs(score - bestScore) <= 1e-9 && t < bestT))
                                {
                                    found = true;
                                    bestScore = score;
                                    bestT = t;
                                    bestTarget = new Point2d(southEndpoint.X, targetAxisY);
                                }
                            }
                        }
                    }

                    return found;
                }

                foreach (var id in secMovables)
                {
                    if (!(tr.GetObject(id, OpenMode.ForWrite, false) is Entity writable) || writable.IsErased)
                    {
                        continue;
                    }

                    if (!TryReadOpenSegment(writable, out var p0, out var p1) || !IsHorizontalLike(p0, p1))
                    {
                        continue;
                    }

                    var moveFound = false;
                    var moveEndpointIndex = -1;
                    var moveTarget = default(Point2d);
                    var moveScore = double.MaxValue;
                    var moveT = double.MaxValue;
                    for (var endpointIndex = 0; endpointIndex <= 1; endpointIndex++)
                    {
                        scanned++;
                        var endpoint = endpointIndex == 0 ? p0 : p1;
                        var other = endpointIndex == 0 ? p1 : p0;
                        // SW rule: only adjust the west end of horizontal lines.
                        // Prevents accidentally pulling the SE endpoint westward.
                        if (endpoint.X > (other.X + 1e-6))
                        {
                            continue;
                        }
                        var inward = other - endpoint;
                        if (inward.Length <= 1e-6)
                        {
                            continue;
                        }

                        var inwardDir = inward / inward.Length;
                        Point2d bestEndpointTarget;
                        double bestScore;
                        double bestT;
                        bool endpointTouchedOuter;
                        bool endpointTouchedOuterThirtyEighteen;
                        var foundTarget = TryFindBestTarget(
                            endpoint,
                            inwardDir,
                            out bestEndpointTarget,
                            out bestScore,
                            out bestT,
                            out endpointTouchedOuter,
                            out endpointTouchedOuterThirtyEighteen);
                        if (endpointTouchedOuter)
                        {
                            touchingOuter++;
                        }
                        if (endpointTouchedOuterThirtyEighteen)
                        {
                            touchingOuterThirtyEighteen++;
                        }

                        if (!foundTarget)
                        {
                            continue;
                        }

                        candidates++;
                        if (!moveFound ||
                            bestScore < (moveScore - 1e-9) ||
                            (Math.Abs(bestScore - moveScore) <= 1e-9 && bestT < moveT))
                        {
                            moveFound = true;
                            moveEndpointIndex = endpointIndex;
                            moveTarget = bestEndpointTarget;
                            moveScore = bestScore;
                            moveT = bestT;
                        }
                    }

                    if (!moveFound || moveEndpointIndex < 0)
                    {
                        continue;
                    }

                    if (!TryMoveEndpointByIndex(writable, moveEndpointIndex, moveTarget, endpointMoveTol))
                    {
                        continue;
                    }

                    adjusted++;
                }

                var lsdHorizontalAdjusted = 0;
                for (var li = 0; li < lsdHorizontalMovables.Count; li++)
                {
                    var lsdId = lsdHorizontalMovables[li];
                    if (!(tr.GetObject(lsdId, OpenMode.ForWrite, false) is Entity writableLsd) || writableLsd.IsErased)
                    {
                        continue;
                    }

                    if (!TryReadOpenSegment(writableLsd, out var l0, out var l1) || !IsHorizontalLike(l0, l1))
                    {
                        continue;
                    }

                    var moveFound = false;
                    var moveEndpointIndex = -1;
                    var moveTarget = default(Point2d);
                    var moveScore = double.MaxValue;
                    var moveT = double.MaxValue;
                    for (var endpointIndex = 0; endpointIndex <= 1; endpointIndex++)
                    {
                        scanned++;
                        var endpoint = endpointIndex == 0 ? l0 : l1;
                        var other = endpointIndex == 0 ? l1 : l0;
                        // Keep LSD horizontal correction on the west endpoint only.
                        if (endpoint.X > (other.X + 1e-6))
                        {
                            continue;
                        }
                        var inward = other - endpoint;
                        if (inward.Length <= 1e-6)
                        {
                            continue;
                        }

                        var inwardDir = inward / inward.Length;
                        Point2d bestEndpointTarget;
                        double bestScore;
                        double bestT;
                        bool endpointTouchedOuter;
                        bool endpointTouchedOuterThirtyEighteen;
                        var foundTarget = TryFindBestTarget(
                            endpoint,
                            inwardDir,
                            out bestEndpointTarget,
                            out bestScore,
                            out bestT,
                            out endpointTouchedOuter,
                            out endpointTouchedOuterThirtyEighteen);
                        if (endpointTouchedOuter)
                        {
                            touchingOuter++;
                        }
                        if (endpointTouchedOuterThirtyEighteen)
                        {
                            touchingOuterThirtyEighteen++;
                        }

                        if (!foundTarget)
                        {
                            continue;
                        }

                        candidates++;
                        if (!moveFound ||
                            bestScore < (moveScore - 1e-9) ||
                            (Math.Abs(bestScore - moveScore) <= 1e-9 && bestT < moveT))
                        {
                            moveFound = true;
                            moveEndpointIndex = endpointIndex;
                            moveTarget = bestEndpointTarget;
                            moveScore = bestScore;
                            moveT = bestT;
                        }
                    }

                    if (!moveFound || moveEndpointIndex < 0)
                    {
                        continue;
                    }

                    var moveLength = moveEndpointIndex == 0
                        ? l0.GetDistanceTo(moveTarget)
                        : l1.GetDistanceTo(moveTarget);
                    if (moveLength <= endpointMoveTol || moveLength > lsdMaxMove)
                    {
                        continue;
                    }

                    if (!TryMoveEndpointByIndex(writableLsd, moveEndpointIndex, moveTarget, endpointMoveTol))
                    {
                        continue;
                    }

                    lsdHorizontalAdjusted++;
                }

                var lsdVerticalAdjusted = 0;
                for (var li = 0; li < lsdVerticalMovables.Count; li++)
                {
                    var lsdId = lsdVerticalMovables[li];
                    if (!(tr.GetObject(lsdId, OpenMode.ForWrite, false) is Entity writableLsd) || writableLsd.IsErased)
                    {
                        continue;
                    }

                    if (!TryReadOpenSegment(writableLsd, out var v0, out var v1) || !IsVerticalLike(v0, v1))
                    {
                        continue;
                    }

                    var southIndex = v0.Y <= v1.Y ? 0 : 1;
                    var southEndpoint = southIndex == 0 ? v0 : v1;
                    var northEndpoint = southIndex == 0 ? v1 : v0;
                    if (!TryFindBestVerticalLsdTarget(southEndpoint, northEndpoint, out var targetSouth))
                    {
                        continue;
                    }

                    var moveLength = southEndpoint.GetDistanceTo(targetSouth);
                    if (moveLength <= endpointMoveTol || moveLength > lsdMaxMove)
                    {
                        continue;
                    }

                    if (!TryMoveEndpointByIndex(writableLsd, southIndex, targetSouth, endpointMoveTol))
                    {
                        continue;
                    }

                    lsdVerticalAdjusted++;
                }

                lsdAdjusted = lsdHorizontalAdjusted + lsdVerticalAdjusted;

                tr.Commit();
                logger?.WriteLine(
                    $"Cleanup: forced inward 10.06 from 30.17 outer boundary scanned={scanned}, touchingOuter={touchingOuter}, touchingOuter30.17={touchingOuterThirtyEighteen}, candidateHits={candidates}, secAdjusted={adjusted}, lsdAdjusted={lsdAdjusted} (h={lsdHorizontalAdjusted}, v={lsdVerticalAdjusted}).");
            }
        }

        private static void NormalizeShortRoadAllowanceLayersByNeighborhood(
            Database database,
            IEnumerable<ObjectId> requestedQuarterIds,
            IReadOnlyCollection<ObjectId> generatedRoadAllowanceIds,
            Logger? logger)
        {
            if (database == null || requestedQuarterIds == null)
            {
                return;
            }

            var clipWindows = BuildBufferedQuarterWindows(database, requestedQuarterIds, 102.0);
            if (clipWindows.Count == 0)
            {
                return;
            }

            bool IsPointInAnyWindow(Point2d p)
            {
                for (var i = 0; i < clipWindows.Count; i++)
                {
                    var w = clipWindows[i];
                    if (p.X >= w.MinPoint.X && p.X <= w.MaxPoint.X &&
                        p.Y >= w.MinPoint.Y && p.Y <= w.MaxPoint.Y)
                    {
                        return true;
                    }
                }

                return false;
            }

            bool DoesSegmentIntersectAnyWindow(Point2d a, Point2d b)
            {
                if (IsPointInAnyWindow(a) || IsPointInAnyWindow(b))
                {
                    return true;
                }

                for (var i = 0; i < clipWindows.Count; i++)
                {
                    if (TryClipSegmentToWindow(a, b, clipWindows[i], out _, out _))
                    {
                        return true;
                    }
                }

                return false;
            }

            using (var tr = database.TransactionManager.StartTransaction())
            {
                bool TryReadOpenSegment(Entity ent, out Point2d a, out Point2d b)
                {
                    a = default;
                    b = default;
                    if (ent == null)
                    {
                        return false;
                    }

                    if (ent is Line ln)
                    {
                        a = new Point2d(ln.StartPoint.X, ln.StartPoint.Y);
                        b = new Point2d(ln.EndPoint.X, ln.EndPoint.Y);
                        return a.GetDistanceTo(b) > 1e-4;
                    }

                    if (ent is Polyline pl)
                    {
                        if (pl.Closed || pl.NumberOfVertices != 2)
                        {
                            return false;
                        }

                        a = pl.GetPoint2dAt(0);
                        b = pl.GetPoint2dAt(1);
                        return a.GetDistanceTo(b) > 1e-4;
                    }

                    return false;
                }

                bool IsHorizontalLike(Point2d a, Point2d b)
                {
                    var d = b - a;
                    return Math.Abs(d.X) >= Math.Abs(d.Y);
                }

                bool IsVerticalLike(Point2d a, Point2d b)
                {
                    var d = b - a;
                    return Math.Abs(d.Y) > Math.Abs(d.X);
                }

                var generatedSet = generatedRoadAllowanceIds == null
                    ? new HashSet<ObjectId>()
                    : new HashSet<ObjectId>(generatedRoadAllowanceIds.Where(id => !id.IsNull));
                var segments = new List<(ObjectId Id, string Layer, Point2d A, Point2d B, bool Horizontal, bool Vertical, double Length)>();
                var generatedSegments = new List<(ObjectId Id, Point2d A, Point2d B, bool Horizontal, bool Vertical, double Length)>();
                var bt = (BlockTable)tr.GetObject(database.BlockTableId, OpenMode.ForRead);
                var ms = (BlockTableRecord)tr.GetObject(bt[BlockTableRecord.ModelSpace], OpenMode.ForRead);
                foreach (ObjectId id in ms)
                {
                    Entity? ent = null;
                    try
                    {
                        ent = tr.GetObject(id, OpenMode.ForRead, false) as Entity;
                    }
                    catch (Autodesk.AutoCAD.Runtime.Exception)
                    {
                        continue;
                    }

                    if (ent == null || ent.IsErased)
                    {
                        continue;
                    }

                    if (!string.Equals(ent.Layer, "L-SEC", StringComparison.OrdinalIgnoreCase) &&
                        !string.Equals(ent.Layer, "L-USEC", StringComparison.OrdinalIgnoreCase))
                    {
                        continue;
                    }

                    if (!TryReadOpenSegment(ent, out var a, out var b))
                    {
                        continue;
                    }

                    if (!DoesSegmentIntersectAnyWindow(a, b))
                    {
                        continue;
                    }

                    var len = a.GetDistanceTo(b);
                    var horizontal = IsHorizontalLike(a, b);
                    var vertical = IsVerticalLike(a, b);
                    if (!horizontal && !vertical)
                    {
                        continue;
                    }

                    segments.Add((id, ent.Layer, a, b, horizontal, vertical, len));
                    if (generatedSet.Contains(id))
                    {
                        generatedSegments.Add((id, a, b, horizontal, vertical, len));
                    }
                }

                if (segments.Count == 0)
                {
                    tr.Commit();
                    return;
                }

                const double candidateMinLen = 2.0;
                const double candidateMaxLen = 120.0;
                const double neighborAxisTol = 1.50;
                const double neighborEndTol = 2.50;
                const double neighborMinLen = 6.0;
                const double referenceDistanceTol = 1.20;
                const double corridorAxisTol = 31.0;
                const double corridorOverlapMin = 20.0;

                bool IsNearGeneratedCorridor((ObjectId Id, string Layer, Point2d A, Point2d B, bool Horizontal, bool Vertical, double Length) candidate)
                {
                    if (generatedSegments.Count == 0)
                    {
                        return false;
                    }

                    for (var gi = 0; gi < generatedSegments.Count; gi++)
                    {
                        var g = generatedSegments[gi];
                        if ((candidate.Horizontal != g.Horizontal) || (candidate.Vertical != g.Vertical))
                        {
                            continue;
                        }

                        if (candidate.Horizontal)
                        {
                            var yCandidate = 0.5 * (candidate.A.Y + candidate.B.Y);
                            var yGenerated = 0.5 * (g.A.Y + g.B.Y);
                            if (Math.Abs(yCandidate - yGenerated) > corridorAxisTol)
                            {
                                continue;
                            }

                            var cMin = Math.Min(candidate.A.X, candidate.B.X);
                            var cMax = Math.Max(candidate.A.X, candidate.B.X);
                            var gMin = Math.Min(g.A.X, g.B.X);
                            var gMax = Math.Max(g.A.X, g.B.X);
                            var overlap = Math.Min(cMax, gMax) - Math.Max(cMin, gMin);
                            if (overlap < Math.Max(corridorOverlapMin, Math.Min(candidate.Length, g.Length) * 0.35))
                            {
                                continue;
                            }
                        }
                        else
                        {
                            var xCandidate = 0.5 * (candidate.A.X + candidate.B.X);
                            var xGenerated = 0.5 * (g.A.X + g.B.X);
                            if (Math.Abs(xCandidate - xGenerated) > corridorAxisTol)
                            {
                                continue;
                            }

                            var cMin = Math.Min(candidate.A.Y, candidate.B.Y);
                            var cMax = Math.Max(candidate.A.Y, candidate.B.Y);
                            var gMin = Math.Min(g.A.Y, g.B.Y);
                            var gMax = Math.Max(g.A.Y, g.B.Y);
                            var overlap = Math.Min(cMax, gMax) - Math.Max(cMin, gMin);
                            if (overlap < Math.Max(corridorOverlapMin, Math.Min(candidate.Length, g.Length) * 0.35))
                            {
                                continue;
                            }
                        }

                        return true;
                    }

                    return false;
                }

                var inspected = 0;
                var normalized = 0;
                for (var i = 0; i < segments.Count; i++)
                {
                    var s = segments[i];
                    if (s.Length < candidateMinLen || s.Length > candidateMaxLen)
                    {
                        continue;
                    }

                    if (!s.Horizontal && !s.Vertical)
                    {
                        continue;
                    }

                    // Keep 30.17/20.11 generated RA corridors stable; they are normalized separately.
                    if (IsNearGeneratedCorridor(s))
                    {
                        continue;
                    }

                    inspected++;
                    var yS = 0.5 * (s.A.Y + s.B.Y);
                    var xS = 0.5 * (s.A.X + s.B.X);

                    double secVotesA = 0.0;
                    double usecVotesA = 0.0;
                    double secVotesB = 0.0;
                    double usecVotesB = 0.0;
                    var secCountA = 0;
                    var usecCountA = 0;
                    var secCountB = 0;
                    var usecCountB = 0;
                    var bestSecScore = double.MaxValue;
                    var bestUsecScore = double.MaxValue;

                    for (var j = 0; j < segments.Count; j++)
                    {
                        if (i == j)
                        {
                            continue;
                        }

                        var o = segments[j];
                        if (o.Length < neighborMinLen)
                        {
                            continue;
                        }

                        if (s.Horizontal != o.Horizontal || s.Vertical != o.Vertical)
                        {
                            continue;
                        }

                        if (s.Horizontal)
                        {
                            var yO = 0.5 * (o.A.Y + o.B.Y);
                            if (Math.Abs(yS - yO) > neighborAxisTol)
                            {
                                continue;
                            }
                        }
                        else
                        {
                            var xO = 0.5 * (o.A.X + o.B.X);
                            if (Math.Abs(xS - xO) > neighborAxisTol)
                            {
                                continue;
                            }
                        }

                        var dA = Math.Min(s.A.GetDistanceTo(o.A), s.A.GetDistanceTo(o.B));
                        var dB = Math.Min(s.B.GetDistanceTo(o.A), s.B.GetDistanceTo(o.B));
                        var isSec = string.Equals(o.Layer, "L-SEC", StringComparison.OrdinalIgnoreCase);
                        var isUsec = string.Equals(o.Layer, "L-USEC", StringComparison.OrdinalIgnoreCase);
                        if (!isSec && !isUsec)
                        {
                            continue;
                        }

                        var daRef = DistancePointToSegment(s.A, o.A, o.B);
                        var dbRef = DistancePointToSegment(s.B, o.A, o.B);
                        if (daRef <= referenceDistanceTol || dbRef <= referenceDistanceTol)
                        {
                            var score = daRef + dbRef;
                            if (isSec)
                            {
                                if (score < bestSecScore)
                                {
                                    bestSecScore = score;
                                }
                            }
                            else if (score < bestUsecScore)
                            {
                                bestUsecScore = score;
                            }
                        }

                        if (dA <= neighborEndTol)
                        {
                            var wA = 1.0 + (neighborEndTol - dA);
                            if (isSec)
                            {
                                secVotesA += wA;
                                secCountA++;
                            }
                            else
                            {
                                usecVotesA += wA;
                                usecCountA++;
                            }
                        }

                        if (dB <= neighborEndTol)
                        {
                            var wB = 1.0 + (neighborEndTol - dB);
                            if (isSec)
                            {
                                secVotesB += wB;
                                secCountB++;
                            }
                            else
                            {
                                usecVotesB += wB;
                                usecCountB++;
                            }
                        }
                    }

                    string? bestEndA = null;
                    if (secVotesA > usecVotesA + 0.25)
                    {
                        bestEndA = "L-SEC";
                    }
                    else if (usecVotesA > secVotesA + 0.25)
                    {
                        bestEndA = "L-USEC";
                    }

                    string? bestEndB = null;
                    if (secVotesB > usecVotesB + 0.25)
                    {
                        bestEndB = "L-SEC";
                    }
                    else if (usecVotesB > secVotesB + 0.25)
                    {
                        bestEndB = "L-USEC";
                    }

                    string? targetLayer = null;
                    if (!string.IsNullOrWhiteSpace(bestEndA) &&
                        !string.IsNullOrWhiteSpace(bestEndB) &&
                        string.Equals(bestEndA, bestEndB, StringComparison.OrdinalIgnoreCase))
                    {
                        targetLayer = bestEndA;
                    }
                    else
                    {
                        var secVotes = secVotesA + secVotesB;
                        var usecVotes = usecVotesA + usecVotesB;
                        var secCount = secCountA + secCountB;
                        var usecCount = usecCountA + usecCountB;
                        if (secCount >= 2 || usecCount >= 2)
                        {
                            if (secVotes > usecVotes + 1.00)
                            {
                                targetLayer = "L-SEC";
                            }
                            else if (usecVotes > secVotes + 1.00)
                            {
                                targetLayer = "L-USEC";
                            }
                        }
                    }

                    if (string.IsNullOrWhiteSpace(targetLayer) && s.Length <= 80.0)
                    {
                        if (bestSecScore < double.MaxValue || bestUsecScore < double.MaxValue)
                        {
                            if (bestSecScore == double.MaxValue)
                            {
                                targetLayer = "L-USEC";
                            }
                            else if (bestUsecScore == double.MaxValue)
                            {
                                targetLayer = "L-SEC";
                            }
                            else
                            {
                                var diff = Math.Abs(bestSecScore - bestUsecScore);
                                if (diff >= 0.35)
                                {
                                    targetLayer = bestSecScore < bestUsecScore
                                        ? "L-SEC"
                                        : "L-USEC";
                                }
                            }
                        }
                    }

                    if (string.IsNullOrWhiteSpace(targetLayer) ||
                        string.Equals(s.Layer, targetLayer, StringComparison.OrdinalIgnoreCase))
                    {
                        continue;
                    }

                    Entity? writable = null;
                    try
                    {
                        writable = tr.GetObject(s.Id, OpenMode.ForWrite, false) as Entity;
                    }
                    catch (Autodesk.AutoCAD.Runtime.Exception)
                    {
                        continue;
                    }

                    if (writable == null || writable.IsErased)
                    {
                        continue;
                    }

                    writable.Layer = targetLayer;
                    writable.ColorIndex = 256;
                    normalized++;
                }

                tr.Commit();
                logger?.WriteLine($"Cleanup: neighborhood-normalized {normalized} boundary segment(s) layer (inspected {inspected}).");
            }
        }

        private static void NormalizeHorizontalSecRoadAllowanceLayers(
            Database database,
            IEnumerable<ObjectId> requestedQuarterIds,
            IReadOnlyCollection<ObjectId> generatedRoadAllowanceIds,
            Logger? logger)
        {
            if (database == null || requestedQuarterIds == null || generatedRoadAllowanceIds == null || generatedRoadAllowanceIds.Count == 0)
            {
                return;
            }

            var clipWindows = BuildBufferedQuarterWindows(database, requestedQuarterIds, 102.0);
            if (clipWindows.Count == 0)
            {
                return;
            }

            bool IsPointInAnyWindow(Point2d p)
            {
                for (var i = 0; i < clipWindows.Count; i++)
                {
                    var w = clipWindows[i];
                    if (p.X >= w.MinPoint.X && p.X <= w.MaxPoint.X &&
                        p.Y >= w.MinPoint.Y && p.Y <= w.MaxPoint.Y)
                    {
                        return true;
                    }
                }

                return false;
            }

            bool DoesSegmentIntersectAnyWindow(Point2d a, Point2d b)
            {
                if (IsPointInAnyWindow(a) || IsPointInAnyWindow(b))
                {
                    return true;
                }

                for (var i = 0; i < clipWindows.Count; i++)
                {
                    if (TryClipSegmentToWindow(a, b, clipWindows[i], out _, out _))
                    {
                        return true;
                    }
                }

                return false;
            }

            bool TryReadOpenSegment(Entity ent, out Point2d a, out Point2d b)
            {
                a = default;
                b = default;
                if (ent == null)
                {
                    return false;
                }

                if (ent is Line ln)
                {
                    a = new Point2d(ln.StartPoint.X, ln.StartPoint.Y);
                    b = new Point2d(ln.EndPoint.X, ln.EndPoint.Y);
                    return a.GetDistanceTo(b) > 1e-4;
                }

                if (ent is Polyline pl)
                {
                    if (pl.Closed || pl.NumberOfVertices < 2)
                    {
                        return false;
                    }

                    a = pl.GetPoint2dAt(0);
                    b = pl.GetPoint2dAt(pl.NumberOfVertices - 1);
                    if (a.GetDistanceTo(b) <= 1e-4)
                    {
                        return false;
                    }

                    // Accept multi-vertex open polylines only when they are effectively collinear.
                    if (pl.NumberOfVertices > 2)
                    {
                        const double collinearTol = 0.35;
                        for (var vi = 1; vi < pl.NumberOfVertices - 1; vi++)
                        {
                            var p = pl.GetPoint2dAt(vi);
                            if (DistancePointToInfiniteLine(p, a, b) > collinearTol)
                            {
                                return false;
                            }
                        }
                    }

                    return true;
                }

                return false;
            }

            bool IsHorizontalLike(Point2d a, Point2d b)
            {
                var d = b - a;
                return Math.Abs(d.X) >= Math.Abs(d.Y);
            }

            bool HorizontalOverlaps((Point2d A, Point2d B) a, (Point2d A, Point2d B) b, double minOverlap)
            {
                var aMin = Math.Min(a.A.X, a.B.X);
                var aMax = Math.Max(a.A.X, a.B.X);
                var bMin = Math.Min(b.A.X, b.B.X);
                var bMax = Math.Max(b.A.X, b.B.X);
                var overlap = Math.Min(aMax, bMax) - Math.Max(aMin, bMin);
                return overlap >= minOverlap;
            }

            var generatedSet = new HashSet<ObjectId>(generatedRoadAllowanceIds.Where(id => !id.IsNull));
            using (var tr = database.TransactionManager.StartTransaction())
            {
                var generatedHorizontals = new List<(ObjectId Id, Point2d A, Point2d B, double Y, double Length)>();
                var secCandidates = new List<(ObjectId Id, string Layer, Point2d A, Point2d B, double Y, double Length)>();
                var bt = (BlockTable)tr.GetObject(database.BlockTableId, OpenMode.ForRead);
                var ms = (BlockTableRecord)tr.GetObject(bt[BlockTableRecord.ModelSpace], OpenMode.ForRead);
                foreach (ObjectId id in ms)
                {
                    Entity? ent = null;
                    try
                    {
                        ent = tr.GetObject(id, OpenMode.ForRead, false) as Entity;
                    }
                    catch (Autodesk.AutoCAD.Runtime.Exception)
                    {
                        continue;
                    }

                    if (ent == null || ent.IsErased)
                    {
                        continue;
                    }

                    var isUsec = string.Equals(ent.Layer, "L-USEC", StringComparison.OrdinalIgnoreCase);
                    var isSec = string.Equals(ent.Layer, "L-SEC", StringComparison.OrdinalIgnoreCase);
                    if (!isUsec && !isSec)
                    {
                        continue;
                    }

                    if (!TryReadOpenSegment(ent, out var a, out var b))
                    {
                        continue;
                    }

                    if (!DoesSegmentIntersectAnyWindow(a, b) || !IsHorizontalLike(a, b))
                    {
                        continue;
                    }

                    var len = a.GetDistanceTo(b);
                    if (len < 8.0)
                    {
                        continue;
                    }

                    var y = 0.5 * (a.Y + b.Y);
                    if (generatedSet.Contains(id))
                    {
                        generatedHorizontals.Add((id, a, b, y, len));
                    }
                    else
                    {
                        secCandidates.Add((id, ent.Layer ?? string.Empty, a, b, y, len));
                    }
                }

                if (generatedHorizontals.Count == 0 || secCandidates.Count == 0)
                {
                    tr.Commit();
                    return;
                }

                const double usecBandTol = 34.5;
                const double secTargetMin = 15.5;
                const double secTargetMax = 24.5;
                const double usecCompanionMin = 7.0;
                const double usecCompanionMax = 13.8;
                const double candidateMinLen = 10.0;
                const double candidateMaxLen = 140.0;
                const double neighborAxisTol = 0.80;
                const double neighborOverlapMin = 8.0;

                (bool SecLeft, bool SecRight, bool UsecLeft, bool UsecRight) AnalyzeNeighbors(int index)
                {
                    var s = secCandidates[index];
                    var sCenterX = 0.5 * (s.A.X + s.B.X);
                    var secLeft = false;
                    var secRight = false;
                    var usecLeft = false;
                    var usecRight = false;
                    for (var j = 0; j < secCandidates.Count; j++)
                    {
                        if (index == j)
                        {
                            continue;
                        }

                        var o = secCandidates[j];
                        if (Math.Abs(s.Y - o.Y) > neighborAxisTol)
                        {
                            continue;
                        }

                        if (!HorizontalOverlaps((s.A, s.B), (o.A, o.B), minOverlap: neighborOverlapMin))
                        {
                            continue;
                        }

                        var oCenterX = 0.5 * (o.A.X + o.B.X);
                        var left = oCenterX < (sCenterX - 0.25);
                        var right = oCenterX > (sCenterX + 0.25);
                        if (!left && !right)
                        {
                            left = true;
                            right = true;
                        }

                        if (string.Equals(o.Layer, "L-SEC", StringComparison.OrdinalIgnoreCase))
                        {
                            if (left)
                            {
                                secLeft = true;
                            }

                            if (right)
                            {
                                secRight = true;
                            }
                        }
                        else if (string.Equals(o.Layer, "L-USEC", StringComparison.OrdinalIgnoreCase))
                        {
                            if (left)
                            {
                                usecLeft = true;
                            }

                            if (right)
                            {
                                usecRight = true;
                            }
                        }
                    }

                    return (secLeft, secRight, usecLeft, usecRight);
                }

                bool HasThirtyEighteenCompanion(int generatedIndex, int candidateIndex)
                {
                    var g = generatedHorizontals[generatedIndex];
                    var s = secCandidates[candidateIndex];
                    for (var j = 0; j < secCandidates.Count; j++)
                    {
                        if (j == candidateIndex)
                        {
                            continue;
                        }

                        var o = secCandidates[j];
                        if (o.Length < candidateMinLen || o.Length > candidateMaxLen)
                        {
                            continue;
                        }

                        if (!HorizontalOverlaps((o.A, o.B), (g.A, g.B), minOverlap: 20.0))
                        {
                            continue;
                        }

                        if (!HorizontalOverlaps((o.A, o.B), (s.A, s.B), minOverlap: neighborOverlapMin))
                        {
                            continue;
                        }

                        var dy = Math.Abs(o.Y - g.Y);
                        if (dy >= usecCompanionMin && dy <= usecCompanionMax)
                        {
                            return true;
                        }
                    }

                    return false;
                }

                var normalized = 0;
                var skippedThirtyEighteen = 0;
                for (var i = 0; i < secCandidates.Count; i++)
                {
                    var s = secCandidates[i];
                    if (!string.Equals(s.Layer, "L-USEC", StringComparison.OrdinalIgnoreCase))
                    {
                        continue;
                    }

                    if (s.Length < candidateMinLen || s.Length > candidateMaxLen)
                    {
                        continue;
                    }

                    var bestDy = double.MaxValue;
                    var bestGeneratedIndex = -1;
                    for (var gi = 0; gi < generatedHorizontals.Count; gi++)
                    {
                        var g = generatedHorizontals[gi];
                        var dy = Math.Abs(s.Y - g.Y);
                        if (dy < 1.0 || dy > usecBandTol)
                        {
                            continue;
                        }

                        if (!HorizontalOverlaps((s.A, s.B), (g.A, g.B), minOverlap: 20.0))
                        {
                            continue;
                        }

                        if (dy < bestDy)
                        {
                            bestDy = dy;
                            bestGeneratedIndex = gi;
                        }
                    }

                    if (bestDy == double.MaxValue)
                    {
                        continue;
                    }

                    if (bestDy < secTargetMin || bestDy > secTargetMax)
                    {
                        continue;
                    }

                    // Guard: when a 10.06 companion exists for the same generated corridor, this is a 30.17
                    // RA boundary and should remain L-USEC (do not misclassify as 20.11 L-SEC).
                    if (bestGeneratedIndex >= 0 && HasThirtyEighteenCompanion(bestGeneratedIndex, i))
                    {
                        skippedThirtyEighteen++;
                        continue;
                    }

                    var neighbors = AnalyzeNeighbors(i);
                    var hasSecSupport =
                        (neighbors.SecLeft && neighbors.SecRight) ||
                        ((neighbors.SecLeft || neighbors.SecRight) && !(neighbors.UsecLeft || neighbors.UsecRight));
                    if (!hasSecSupport)
                    {
                        continue;
                    }

                    Entity? writable = null;
                    try
                    {
                        writable = tr.GetObject(s.Id, OpenMode.ForWrite, false) as Entity;
                    }
                    catch (Autodesk.AutoCAD.Runtime.Exception)
                    {
                        continue;
                    }

                    if (writable == null || writable.IsErased ||
                        string.Equals(writable.Layer, "L-SEC", StringComparison.OrdinalIgnoreCase))
                    {
                        continue;
                    }

                    writable.Layer = "L-SEC";
                    writable.ColorIndex = 256;
                    normalized++;
                }

                tr.Commit();
                if (normalized > 0)
                {
                    logger?.WriteLine($"Cleanup: normalized {normalized} horizontal 20.11 road allowance segment(s) to L-SEC.");
                }
                if (skippedThirtyEighteen > 0)
                {
                    logger?.WriteLine($"Cleanup: skipped {skippedThirtyEighteen} horizontal candidate(s) that matched 30.17 corridor companion pattern.");
                }
            }
        }

        private static void NormalizeBottomTownshipBoundaryLayers(
            Database database,
            IEnumerable<ObjectId> requestedQuarterIds,
            IReadOnlyCollection<ObjectId> generatedRoadAllowanceIds,
            Logger? logger)
        {
            if (database == null || requestedQuarterIds == null || generatedRoadAllowanceIds == null || generatedRoadAllowanceIds.Count == 0)
            {
                return;
            }

            var clipWindows = BuildBufferedQuarterWindows(database, requestedQuarterIds, 102.0);
            if (clipWindows.Count == 0)
            {
                return;
            }

            bool IsPointInAnyWindow(Point2d p)
            {
                for (var i = 0; i < clipWindows.Count; i++)
                {
                    var w = clipWindows[i];
                    if (p.X >= w.MinPoint.X && p.X <= w.MaxPoint.X &&
                        p.Y >= w.MinPoint.Y && p.Y <= w.MaxPoint.Y)
                    {
                        return true;
                    }
                }

                return false;
            }

            bool DoesSegmentIntersectAnyWindow(Point2d a, Point2d b)
            {
                if (IsPointInAnyWindow(a) || IsPointInAnyWindow(b))
                {
                    return true;
                }

                for (var i = 0; i < clipWindows.Count; i++)
                {
                    if (TryClipSegmentToWindow(a, b, clipWindows[i], out _, out _))
                    {
                        return true;
                    }
                }

                return false;
            }

            bool TryReadOpenSegment(Entity ent, out Point2d a, out Point2d b)
            {
                a = default;
                b = default;
                if (ent == null)
                {
                    return false;
                }

                if (ent is Line ln)
                {
                    a = new Point2d(ln.StartPoint.X, ln.StartPoint.Y);
                    b = new Point2d(ln.EndPoint.X, ln.EndPoint.Y);
                    return a.GetDistanceTo(b) > 1e-4;
                }

                if (ent is Polyline pl)
                {
                    if (pl.Closed || pl.NumberOfVertices < 2)
                    {
                        return false;
                    }

                    a = pl.GetPoint2dAt(0);
                    b = pl.GetPoint2dAt(pl.NumberOfVertices - 1);
                    return a.GetDistanceTo(b) > 1e-4;
                }

                return false;
            }

            bool IsHorizontalLike(Point2d a, Point2d b)
            {
                var d = b - a;
                return Math.Abs(d.X) >= Math.Abs(d.Y);
            }

            bool HorizontalOverlaps((Point2d A, Point2d B) a, (Point2d A, Point2d B) b, double minOverlap)
            {
                var aMin = Math.Min(a.A.X, a.B.X);
                var aMax = Math.Max(a.A.X, a.B.X);
                var bMin = Math.Min(b.A.X, b.B.X);
                var bMax = Math.Max(b.A.X, b.B.X);
                var overlap = Math.Min(aMax, bMax) - Math.Max(aMin, bMin);
                return overlap >= minOverlap;
            }

            var generatedSet = new HashSet<ObjectId>(generatedRoadAllowanceIds.Where(id => !id.IsNull));
            using (var tr = database.TransactionManager.StartTransaction())
            {
                var generatedBottomY = double.MaxValue;
                var generatedHorizontals = new List<(Point2d A, Point2d B, double Y)>();
                var candidates = new List<(ObjectId Id, string Layer, Point2d A, Point2d B, double Y, double Length)>();

                var bt = (BlockTable)tr.GetObject(database.BlockTableId, OpenMode.ForRead);
                var ms = (BlockTableRecord)tr.GetObject(bt[BlockTableRecord.ModelSpace], OpenMode.ForRead);
                foreach (ObjectId id in ms)
                {
                    Entity? ent = null;
                    try
                    {
                        ent = tr.GetObject(id, OpenMode.ForRead, false) as Entity;
                    }
                    catch (Autodesk.AutoCAD.Runtime.Exception)
                    {
                        continue;
                    }

                    if (ent == null || ent.IsErased)
                    {
                        continue;
                    }

                    var isUsec = string.Equals(ent.Layer, "L-USEC", StringComparison.OrdinalIgnoreCase);
                    var isSec = string.Equals(ent.Layer, "L-SEC", StringComparison.OrdinalIgnoreCase);
                    if (!isUsec && !isSec)
                    {
                        continue;
                    }

                    if (!TryReadOpenSegment(ent, out var a, out var b) ||
                        !DoesSegmentIntersectAnyWindow(a, b) ||
                        !IsHorizontalLike(a, b))
                    {
                        continue;
                    }

                    var len = a.GetDistanceTo(b);
                    if (len < 4.0)
                    {
                        continue;
                    }

                    var y = 0.5 * (a.Y + b.Y);
                    if (generatedSet.Contains(id))
                    {
                        generatedHorizontals.Add((a, b, y));
                        if (y < generatedBottomY)
                        {
                            generatedBottomY = y;
                        }
                    }

                    candidates.Add((id, ent.Layer ?? string.Empty, a, b, y, len));
                }

                if (candidates.Count == 0)
                {
                    tr.Commit();
                    return;
                }

                var candidateBottomY = candidates.Min(c => c.Y);
                var seamBaseY = generatedBottomY == double.MaxValue
                    ? candidateBottomY
                    : Math.Min(candidateBottomY, generatedBottomY);

                // Only fix around the bottom township seam where layering drifts.
                const double seamBandBelow = 20.0;
                const double seamBandAbove = 80.0;
                const double secTargetMin = 15.5;
                const double secTargetMax = 24.5;
                const double usecTargetMin = 25.5;
                const double usecTargetMax = 34.5;
                const double dyOverlapMin = 5.0;
                const double expectedSecDy = 20.11;
                const double expectedUsecDy = RoadAllowanceUsecWidthMeters;
                const double expectedDyTol = 6.0;
                const double expectedDyDecisionMargin = 0.45;

                double ComputeBestExpectedScore(int index, double expectedDy)
                {
                    var s = candidates[index];
                    var bestScore = double.MaxValue;
                    for (var oi = 0; oi < candidates.Count; oi++)
                    {
                        if (oi == index)
                        {
                            continue;
                        }

                        var o = candidates[oi];
                        if (o.Y < (seamBaseY - seamBandBelow) ||
                            o.Y > (seamBaseY + seamBandAbove))
                        {
                            continue;
                        }

                        if (!HorizontalOverlaps((s.A, s.B), (o.A, o.B), minOverlap: dyOverlapMin))
                        {
                            continue;
                        }

                        var dy = Math.Abs(s.Y - o.Y);
                        if (dy < 1.0)
                        {
                            continue;
                        }

                        var score = Math.Abs(dy - expectedDy);
                        if (score < bestScore)
                        {
                            bestScore = score;
                        }
                    }

                    return bestScore;
                }

                var normalized = 0;
                for (var i = 0; i < candidates.Count; i++)
                {
                    var c = candidates[i];
                    if (c.Y < (seamBaseY - seamBandBelow) ||
                        c.Y > (seamBaseY + seamBandAbove))
                    {
                        continue;
                    }

                    var canonicalSecScore = ComputeBestExpectedScore(i, expectedSecDy);
                    var canonicalUsecScore = ComputeBestExpectedScore(i, expectedUsecDy);
                    var canonicalDecision = false;
                    var bestDy = double.MaxValue;
                    string? targetLayer = null;
                    if (canonicalSecScore <= expectedDyTol &&
                        (canonicalSecScore + expectedDyDecisionMargin) < canonicalUsecScore)
                    {
                        targetLayer = "L-SEC";
                        canonicalDecision = true;
                    }
                    else if (canonicalUsecScore <= expectedDyTol &&
                             (canonicalUsecScore + expectedDyDecisionMargin) < canonicalSecScore)
                    {
                        targetLayer = "L-USEC";
                        canonicalDecision = true;
                    }

                    if (!canonicalDecision)
                    {
                        for (var gi = 0; gi < generatedHorizontals.Count; gi++)
                        {
                            var g = generatedHorizontals[gi];
                            if (!HorizontalOverlaps((c.A, c.B), (g.A, g.B), minOverlap: dyOverlapMin))
                            {
                                continue;
                            }

                            var dy = Math.Abs(c.Y - g.Y);
                            if (dy < 1.0)
                            {
                                continue;
                            }

                            if (dy < bestDy)
                            {
                                bestDy = dy;
                            }
                        }

                        if (bestDy == double.MaxValue)
                        {
                            for (var oi = 0; oi < candidates.Count; oi++)
                            {
                                if (oi == i)
                                {
                                    continue;
                                }

                                var o = candidates[oi];
                                if (o.Y < (seamBaseY - seamBandBelow) ||
                                    o.Y > (seamBaseY + seamBandAbove))
                                {
                                    continue;
                                }

                                if (!HorizontalOverlaps((c.A, c.B), (o.A, o.B), minOverlap: dyOverlapMin))
                                {
                                    continue;
                                }

                                var dy = Math.Abs(c.Y - o.Y);
                                if (dy < 1.0)
                                {
                                    continue;
                                }

                                if (dy < bestDy)
                                {
                                    bestDy = dy;
                                }
                            }
                        }

                        if (bestDy < usecTargetMin || bestDy > usecTargetMax)
                        {
                            if (bestDy < secTargetMin || bestDy > secTargetMax)
                            {
                                continue;
                            }
                        }

                        targetLayer = bestDy >= usecTargetMin && bestDy <= usecTargetMax
                            ? "L-USEC"
                            : "L-SEC";
                    }

                    if (targetLayer == null)
                    {
                        continue;
                    }

                    if (string.Equals(c.Layer, targetLayer, StringComparison.OrdinalIgnoreCase))
                    {
                        continue;
                    }

                    Entity? writable = null;
                    try
                    {
                        writable = tr.GetObject(c.Id, OpenMode.ForWrite, false) as Entity;
                    }
                    catch (Autodesk.AutoCAD.Runtime.Exception)
                    {
                        continue;
                    }

                    if (writable == null || writable.IsErased ||
                        string.Equals(writable.Layer, targetLayer, StringComparison.OrdinalIgnoreCase))
                    {
                        continue;
                    }

                    writable.Layer = targetLayer;
                    writable.ColorIndex = 256;
                    normalized++;
                }

                tr.Commit();
                if (normalized > 0)
                {
                    logger?.WriteLine($"Cleanup: normalized {normalized} bottom-township seam segment(s) to expected L-SEC/L-USEC layer.");
                }
            }
        }

        private static void NormalizeRangeEdgeHorizontalRoadAllowanceLayers(
            Database database,
            IEnumerable<ObjectId> requestedQuarterIds,
            IReadOnlyCollection<ObjectId> generatedRoadAllowanceIds,
            Logger? logger)
        {
            if (database == null || requestedQuarterIds == null || generatedRoadAllowanceIds == null || generatedRoadAllowanceIds.Count == 0)
            {
                return;
            }

            var clipWindows = BuildBufferedQuarterWindows(database, requestedQuarterIds, 102.0);
            if (clipWindows.Count == 0)
            {
                return;
            }

            bool IsPointInAnyWindow(Point2d p)
            {
                for (var i = 0; i < clipWindows.Count; i++)
                {
                    var w = clipWindows[i];
                    if (p.X >= w.MinPoint.X && p.X <= w.MaxPoint.X &&
                        p.Y >= w.MinPoint.Y && p.Y <= w.MaxPoint.Y)
                    {
                        return true;
                    }
                }

                return false;
            }

            bool DoesSegmentIntersectAnyWindow(Point2d a, Point2d b)
            {
                if (IsPointInAnyWindow(a) || IsPointInAnyWindow(b))
                {
                    return true;
                }

                for (var i = 0; i < clipWindows.Count; i++)
                {
                    if (TryClipSegmentToWindow(a, b, clipWindows[i], out _, out _))
                    {
                        return true;
                    }
                }

                return false;
            }

            bool TryReadOpenSegment(Entity ent, out Point2d a, out Point2d b)
            {
                a = default;
                b = default;
                if (ent == null)
                {
                    return false;
                }

                if (ent is Line ln)
                {
                    a = new Point2d(ln.StartPoint.X, ln.StartPoint.Y);
                    b = new Point2d(ln.EndPoint.X, ln.EndPoint.Y);
                    return a.GetDistanceTo(b) > 1e-4;
                }

                if (ent is Polyline pl)
                {
                    if (pl.Closed || pl.NumberOfVertices < 2)
                    {
                        return false;
                    }

                    a = pl.GetPoint2dAt(0);
                    b = pl.GetPoint2dAt(pl.NumberOfVertices - 1);
                    if (a.GetDistanceTo(b) <= 1e-4)
                    {
                        return false;
                    }

                    if (pl.NumberOfVertices > 2)
                    {
                        const double collinearTol = 0.35;
                        for (var vi = 1; vi < pl.NumberOfVertices - 1; vi++)
                        {
                            var p = pl.GetPoint2dAt(vi);
                            if (DistancePointToInfiniteLine(p, a, b) > collinearTol)
                            {
                                return false;
                            }
                        }
                    }

                    return true;
                }

                return false;
            }

            bool IsHorizontalLike(Point2d a, Point2d b)
            {
                var d = b - a;
                return Math.Abs(d.X) >= Math.Abs(d.Y);
            }

            bool HorizontalOverlaps((Point2d A, Point2d B) a, (Point2d A, Point2d B) b, double minOverlap)
            {
                var aMin = Math.Min(a.A.X, a.B.X);
                var aMax = Math.Max(a.A.X, a.B.X);
                var bMin = Math.Min(b.A.X, b.B.X);
                var bMax = Math.Max(b.A.X, b.B.X);
                var overlap = Math.Min(aMax, bMax) - Math.Max(aMin, bMin);
                return overlap >= minOverlap;
            }

            var clipMinX = clipWindows.Min(w => w.MinPoint.X);
            var clipMaxX = clipWindows.Max(w => w.MaxPoint.X);
            const double edgeBand = 145.0;
            const double minSegmentLength = 4.0;
            const double overlapMin = 8.0;
            const double usecNearMin = 7.0;    // 10.06 +- tolerance
            const double usecNearMax = 13.8;
            const double usecFarMin = 16.6;    // 20.11 +- tolerance
            const double usecFarMax = 23.8;

            using (var tr = database.TransactionManager.StartTransaction())
            {
                var generatedSet = new HashSet<ObjectId>(generatedRoadAllowanceIds.Where(id => !id.IsNull));
                var candidates = new List<(ObjectId Id, string Layer, Point2d A, Point2d B, double Y, bool Generated)>();
                var bt = (BlockTable)tr.GetObject(database.BlockTableId, OpenMode.ForRead);
                var ms = (BlockTableRecord)tr.GetObject(bt[BlockTableRecord.ModelSpace], OpenMode.ForRead);
                foreach (ObjectId id in ms)
                {
                    Entity? ent = null;
                    try
                    {
                        ent = tr.GetObject(id, OpenMode.ForRead, false) as Entity;
                    }
                    catch (Autodesk.AutoCAD.Runtime.Exception)
                    {
                        continue;
                    }

                    if (ent == null || ent.IsErased)
                    {
                        continue;
                    }

                    var isUsec = string.Equals(ent.Layer, "L-USEC", StringComparison.OrdinalIgnoreCase);
                    var isSec = string.Equals(ent.Layer, "L-SEC", StringComparison.OrdinalIgnoreCase);
                    if (!isUsec && !isSec)
                    {
                        continue;
                    }

                    if (!TryReadOpenSegment(ent, out var a, out var b) ||
                        !DoesSegmentIntersectAnyWindow(a, b) ||
                        !IsHorizontalLike(a, b))
                    {
                        continue;
                    }

                    if (a.GetDistanceTo(b) < minSegmentLength)
                    {
                        continue;
                    }

                    var y = 0.5 * (a.Y + b.Y);
                    var generated = generatedSet.Contains(id);
                    candidates.Add((id, ent.Layer ?? string.Empty, a, b, y, generated));
                }

                if (candidates.Count == 0)
                {
                    tr.Commit();
                    return;
                }

                bool IsRangeEdgeCandidate((ObjectId Id, string Layer, Point2d A, Point2d B, double Y, bool Generated) c)
                {
                    var segMinX = Math.Min(c.A.X, c.B.X);
                    var segMaxX = Math.Max(c.A.X, c.B.X);
                    var touchesWestEdge = segMinX <= (clipMinX + edgeBand);
                    var touchesEastEdge = segMaxX >= (clipMaxX - edgeBand);
                    return touchesWestEdge || touchesEastEdge;
                }

                var targets = new Dictionary<ObjectId, string>();
                var inspectedGenerated = 0;
                for (var i = 0; i < candidates.Count; i++)
                {
                    var g = candidates[i];
                    if (!g.Generated || !IsRangeEdgeCandidate(g))
                    {
                        continue;
                    }

                    inspectedGenerated++;

                    // Generated RA offsets represent the 20.11 interior corridor line.
                    if (!string.Equals(g.Layer, "L-SEC", StringComparison.OrdinalIgnoreCase))
                    {
                        targets[g.Id] = "L-SEC";
                    }

                    for (var j = 0; j < candidates.Count; j++)
                    {
                        if (i == j)
                        {
                            continue;
                        }

                        var c = candidates[j];
                        if (c.Generated || !IsRangeEdgeCandidate(c))
                        {
                            continue;
                        }

                        if (!HorizontalOverlaps((g.A, g.B), (c.A, c.B), minOverlap: overlapMin))
                        {
                            continue;
                        }

                        var dy = Math.Abs(c.Y - g.Y);
                        var shouldUsec =
                            (dy >= usecNearMin && dy <= usecNearMax) ||
                            (dy >= usecFarMin && dy <= usecFarMax);
                        if (!shouldUsec)
                        {
                            continue;
                        }

                        if (!string.Equals(c.Layer, "L-USEC", StringComparison.OrdinalIgnoreCase))
                        {
                            targets[c.Id] = "L-USEC";
                        }
                    }
                }

                if (targets.Count == 0)
                {
                    tr.Commit();
                    return;
                }

                var normalizedGenerated = 0;
                var normalizedBoundary = 0;
                foreach (var kvp in targets)
                {
                    Entity? writable = null;
                    try
                    {
                        writable = tr.GetObject(kvp.Key, OpenMode.ForWrite, false) as Entity;
                    }
                    catch (Autodesk.AutoCAD.Runtime.Exception)
                    {
                        continue;
                    }

                    if (writable == null || writable.IsErased ||
                        string.Equals(writable.Layer, kvp.Value, StringComparison.OrdinalIgnoreCase))
                    {
                        continue;
                    }

                    writable.Layer = kvp.Value;
                    writable.ColorIndex = 256;
                    if (string.Equals(kvp.Value, "L-SEC", StringComparison.OrdinalIgnoreCase))
                    {
                        normalizedGenerated++;
                    }
                    else
                    {
                        normalizedBoundary++;
                    }
                }

                tr.Commit();
                if (normalizedGenerated > 0 || normalizedBoundary > 0)
                {
                    logger?.WriteLine(
                        $"Cleanup: normalized {normalizedGenerated} range-edge generated 20.11 segment(s) to L-SEC and {normalizedBoundary} adjoining range-edge segment(s) to L-USEC (inspected generated={inspectedGenerated}).");
                }
            }
        }

        private static void NormalizeThirtyEighteenCorridorLayers(
            Database database,
            IEnumerable<ObjectId> requestedQuarterIds,
            Logger? logger)
        {
            if (database == null || requestedQuarterIds == null)
            {
                return;
            }

            var clipWindows = BuildBufferedQuarterWindows(database, requestedQuarterIds, 102.0);
            if (clipWindows.Count == 0)
            {
                return;
            }

            bool IsPointInAnyWindow(Point2d p)
            {
                for (var i = 0; i < clipWindows.Count; i++)
                {
                    var w = clipWindows[i];
                    if (p.X >= w.MinPoint.X && p.X <= w.MaxPoint.X &&
                        p.Y >= w.MinPoint.Y && p.Y <= w.MaxPoint.Y)
                    {
                        return true;
                    }
                }

                return false;
            }

            bool DoesSegmentIntersectAnyWindow(Point2d a, Point2d b)
            {
                if (IsPointInAnyWindow(a) || IsPointInAnyWindow(b))
                {
                    return true;
                }

                for (var i = 0; i < clipWindows.Count; i++)
                {
                    if (TryClipSegmentToWindow(a, b, clipWindows[i], out _, out _))
                    {
                        return true;
                    }
                }

                return false;
            }

            bool TryReadOpenSegment(Entity ent, out Point2d a, out Point2d b)
            {
                a = default;
                b = default;
                if (ent == null)
                {
                    return false;
                }

                if (ent is Line ln)
                {
                    a = new Point2d(ln.StartPoint.X, ln.StartPoint.Y);
                    b = new Point2d(ln.EndPoint.X, ln.EndPoint.Y);
                    return a.GetDistanceTo(b) > 1e-4;
                }

                if (ent is Polyline pl)
                {
                    if (pl.Closed || pl.NumberOfVertices < 2)
                    {
                        return false;
                    }

                    a = pl.GetPoint2dAt(0);
                    b = pl.GetPoint2dAt(pl.NumberOfVertices - 1);
                    if (a.GetDistanceTo(b) <= 1e-4)
                    {
                        return false;
                    }

                    if (pl.NumberOfVertices > 2)
                    {
                        const double collinearTol = 0.35;
                        for (var vi = 1; vi < pl.NumberOfVertices - 1; vi++)
                        {
                            var p = pl.GetPoint2dAt(vi);
                            if (DistancePointToInfiniteLine(p, a, b) > collinearTol)
                            {
                                return false;
                            }
                        }
                    }

                    return true;
                }

                return false;
            }

            bool IsHorizontalLike(Point2d a, Point2d b)
            {
                var d = b - a;
                return Math.Abs(d.X) >= Math.Abs(d.Y);
            }

            bool IsVerticalLike(Point2d a, Point2d b)
            {
                var d = b - a;
                return Math.Abs(d.Y) > Math.Abs(d.X);
            }

            using (var tr = database.TransactionManager.StartTransaction())
            {
                var segments = new List<(
                    ObjectId Id,
                    string Layer,
                    Point2d A,
                    Point2d B,
                    bool Horizontal,
                    bool Vertical,
                    double Length,
                    double Coord,
                    double SpanMin,
                    double SpanMax)>();

                var bt = (BlockTable)tr.GetObject(database.BlockTableId, OpenMode.ForRead);
                var ms = (BlockTableRecord)tr.GetObject(bt[BlockTableRecord.ModelSpace], OpenMode.ForRead);
                foreach (ObjectId id in ms)
                {
                    Entity? ent = null;
                    try
                    {
                        ent = tr.GetObject(id, OpenMode.ForRead, false) as Entity;
                    }
                    catch (Autodesk.AutoCAD.Runtime.Exception)
                    {
                        continue;
                    }

                    if (ent == null || ent.IsErased)
                    {
                        continue;
                    }

                    var isUsec = string.Equals(ent.Layer, "L-USEC", StringComparison.OrdinalIgnoreCase);
                    var isSec = string.Equals(ent.Layer, "L-SEC", StringComparison.OrdinalIgnoreCase);
                    if (!isUsec && !isSec)
                    {
                        continue;
                    }

                    if (!TryReadOpenSegment(ent, out var a, out var b) ||
                        !DoesSegmentIntersectAnyWindow(a, b))
                    {
                        continue;
                    }

                    var horizontal = IsHorizontalLike(a, b);
                    var vertical = IsVerticalLike(a, b);
                    if (!horizontal && !vertical)
                    {
                        continue;
                    }

                    var len = a.GetDistanceTo(b);
                    if (len < 25.0)
                    {
                        continue;
                    }

                    var coord = horizontal
                        ? (0.5 * (a.Y + b.Y))
                        : (0.5 * (a.X + b.X));
                    var spanMin = horizontal
                        ? Math.Min(a.X, b.X)
                        : Math.Min(a.Y, b.Y);
                    var spanMax = horizontal
                        ? Math.Max(a.X, b.X)
                        : Math.Max(a.Y, b.Y);
                    segments.Add((id, ent.Layer ?? string.Empty, a, b, horizontal, vertical, len, coord, spanMin, spanMax));
                }

                if (segments.Count == 0)
                {
                    tr.Commit();
                    return;
                }

                double OverlapAmount(
                    (ObjectId Id, string Layer, Point2d A, Point2d B, bool Horizontal, bool Vertical, double Length, double Coord, double SpanMin, double SpanMax) s1,
                    (ObjectId Id, string Layer, Point2d A, Point2d B, bool Horizontal, bool Vertical, double Length, double Coord, double SpanMin, double SpanMax) s2)
                {
                    return Math.Min(s1.SpanMax, s2.SpanMax) - Math.Max(s1.SpanMin, s2.SpanMin);
                }

                const double d10Min = 8.6;
                const double d10Max = 11.8;
                const double d20Min = 18.6;
                const double d20Max = 21.8;
                const double d30Min = 28.8;
                const double d30Max = 31.8;
                const double overlapMin = 18.0;
                static bool InRange(double value, double min, double max) => value >= min && value <= max;

                var usecVotes = new Dictionary<ObjectId, int>();
                void VoteUsec(ObjectId id)
                {
                    if (usecVotes.TryGetValue(id, out var n))
                    {
                        usecVotes[id] = n + 1;
                    }
                    else
                    {
                        usecVotes[id] = 1;
                    }
                }

                int RunOrientation(bool horizontal)
                {
                    var indexes = new List<int>();
                    for (var i = 0; i < segments.Count; i++)
                    {
                        var s = segments[i];
                        if (horizontal ? s.Horizontal : s.Vertical)
                        {
                            indexes.Add(i);
                        }
                    }

                    var patternMatches = 0;
                    for (var mi = 0; mi < indexes.Count; mi++)
                    {
                        var mIdx = indexes[mi];
                        var m = segments[mIdx];
                        var near10 = new List<int>();
                        var near20 = new List<int>();
                        for (var oi = 0; oi < indexes.Count; oi++)
                        {
                            if (oi == mi)
                            {
                                continue;
                            }

                            var oIdx = indexes[oi];
                            var o = segments[oIdx];
                            if (OverlapAmount(m, o) < overlapMin)
                            {
                                continue;
                            }

                            var d = Math.Abs(m.Coord - o.Coord);
                            if (InRange(d, d10Min, d10Max))
                            {
                                near10.Add(oIdx);
                            }
                            else if (InRange(d, d20Min, d20Max))
                            {
                                near20.Add(oIdx);
                            }
                        }

                        if (near10.Count == 0 || near20.Count == 0)
                        {
                            continue;
                        }

                        var matchedThisMid = false;
                        for (var i10 = 0; i10 < near10.Count; i10++)
                        {
                            var a = segments[near10[i10]];
                            var sideA = Math.Sign(a.Coord - m.Coord);
                            if (sideA == 0)
                            {
                                continue;
                            }

                            for (var i20 = 0; i20 < near20.Count; i20++)
                            {
                                var b = segments[near20[i20]];
                                var sideB = Math.Sign(b.Coord - m.Coord);
                                if (sideB == 0 || sideA == sideB)
                                {
                                    continue;
                                }

                                if (OverlapAmount(a, b) < overlapMin)
                                {
                                    continue;
                                }

                                var dAB = Math.Abs(a.Coord - b.Coord);
                                if (!InRange(dAB, d30Min, d30Max))
                                {
                                    continue;
                                }

                                // 30.17 corridor pattern:
                                // middle 20.11 plus 10.06/20.11 companions are all L-USEC.
                                VoteUsec(m.Id);
                                VoteUsec(a.Id);
                                VoteUsec(b.Id);
                                matchedThisMid = true;
                            }
                        }

                        if (matchedThisMid)
                        {
                            patternMatches++;
                        }
                    }

                    return patternMatches;
                }

                var matchesH = RunOrientation(horizontal: true);
                var matchesV = RunOrientation(horizontal: false);

                if (usecVotes.Count == 0)
                {
                    tr.Commit();
                    return;
                }

                var normalizedToSec = 0;
                var normalizedToUsec = 0;
                foreach (var id in usecVotes.Keys)
                {
                    const string target = "L-USEC";

                    Entity? writable = null;
                    try
                    {
                        writable = tr.GetObject(id, OpenMode.ForWrite, false) as Entity;
                    }
                    catch (Autodesk.AutoCAD.Runtime.Exception)
                    {
                        continue;
                    }

                    if (writable == null || writable.IsErased ||
                        string.Equals(writable.Layer, target, StringComparison.OrdinalIgnoreCase))
                    {
                        continue;
                    }

                    writable.Layer = target;
                    writable.ColorIndex = 256;
                    if (string.Equals(target, "L-SEC", StringComparison.OrdinalIgnoreCase))
                    {
                        normalizedToSec++;
                    }
                    else
                    {
                        normalizedToUsec++;
                    }
                }

                tr.Commit();
                if (normalizedToSec > 0 || normalizedToUsec > 0)
                {
                    logger?.WriteLine(
                        $"Cleanup: corridor-normalized {normalizedToSec} segment(s) to L-SEC and {normalizedToUsec} segment(s) to L-USEC (30.17 pattern matches H={matchesH}, V={matchesV}).");
                }
            }
        }

        private static void NormalizeUsecLayersToThreeBands(
            Database database,
            IEnumerable<ObjectId> requestedQuarterIds,
            IReadOnlyDictionary<ObjectId, int> sectionNumberByPolylineId,
            IReadOnlyCollection<ObjectId> generatedRoadAllowanceIds,
            Logger? logger)
        {
            if (database == null || requestedQuarterIds == null)
            {
                return;
            }

            var clipWindows = BuildBufferedQuarterWindows(database, requestedQuarterIds, 102.0);
            if (clipWindows.Count == 0)
            {
                return;
            }

            bool IsPointInAnyWindow(Point2d point)
            {
                for (var i = 0; i < clipWindows.Count; i++)
                {
                    var w = clipWindows[i];
                    if (point.X >= w.MinPoint.X && point.X <= w.MaxPoint.X &&
                        point.Y >= w.MinPoint.Y && point.Y <= w.MaxPoint.Y)
                    {
                        return true;
                    }
                }

                return false;
            }

            bool DoesSegmentIntersectAnyWindow(Point2d a, Point2d b)
            {
                if (IsPointInAnyWindow(a) || IsPointInAnyWindow(b))
                {
                    return true;
                }

                for (var i = 0; i < clipWindows.Count; i++)
                {
                    if (TryClipSegmentToWindow(a, b, clipWindows[i], out _, out _))
                    {
                        return true;
                    }
                }

                return false;
            }

            bool TryReadOpenSegment(Entity ent, out Point2d a, out Point2d b)
            {
                a = default;
                b = default;
                if (ent == null)
                {
                    return false;
                }

                if (ent is Line ln)
                {
                    a = new Point2d(ln.StartPoint.X, ln.StartPoint.Y);
                    b = new Point2d(ln.EndPoint.X, ln.EndPoint.Y);
                    return a.GetDistanceTo(b) > 1e-4;
                }

                if (ent is Polyline pl)
                {
                    if (pl.Closed || pl.NumberOfVertices < 2)
                    {
                        return false;
                    }

                    a = pl.GetPoint2dAt(0);
                    b = pl.GetPoint2dAt(pl.NumberOfVertices - 1);
                    return a.GetDistanceTo(b) > 1e-4;
                }

                return false;
            }

            bool IsHorizontalLike(Point2d a, Point2d b)
            {
                var d = b - a;
                return Math.Abs(d.X) >= Math.Abs(d.Y);
            }

            bool IsVerticalLike(Point2d a, Point2d b)
            {
                var d = b - a;
                return Math.Abs(d.Y) > Math.Abs(d.X);
            }

            bool IsBlindSouthBoundarySection(int sectionNumber)
            {
                return (sectionNumber >= 7 && sectionNumber <= 12) ||
                       (sectionNumber >= 19 && sectionNumber <= 24) ||
                       (sectionNumber >= 31 && sectionNumber <= 36);
            }

            bool IsSegmentOnBlindSouthBoundary(
                Point2d a,
                Point2d b,
                IReadOnlyList<(Point2d A, Point2d B, bool IsHorizontal)> blindBoundaries)
            {
                if (blindBoundaries == null || blindBoundaries.Count == 0 || a == b)
                {
                    return false;
                }

                const double boundaryDistanceTol = 0.60;
                const double overlapParamTolerance = 0.08;
                var midpoint = Midpoint(a, b);
                foreach (var boundary in blindBoundaries)
                {
                    if (IsHorizontalLike(a, b) != boundary.IsHorizontal)
                    {
                        continue;
                    }

                    if (DistancePointToSegment(a, boundary.A, boundary.B) > boundaryDistanceTol &&
                        DistancePointToSegment(b, boundary.A, boundary.B) > boundaryDistanceTol &&
                        DistancePointToSegment(midpoint, boundary.A, boundary.B) > boundaryDistanceTol)
                    {
                        continue;
                    }

                    var boundaryDir = boundary.B - boundary.A;
                    var boundaryLen2 = boundaryDir.DotProduct(boundaryDir);
                    if (boundaryLen2 <= 1e-9)
                    {
                        continue;
                    }

                    var t0 = (a - boundary.A).DotProduct(boundaryDir) / boundaryLen2;
                    var t1 = (b - boundary.A).DotProduct(boundaryDir) / boundaryLen2;
                    var overlapMin = Math.Max(Math.Min(t0, t1), 0.0);
                    var overlapMax = Math.Min(Math.Max(t0, t1), 1.0);
                    if (overlapMax - overlapMin < overlapParamTolerance)
                    {
                        continue;
                    }

                    return true;
                }

                return false;
            }

            using (var tr = database.TransactionManager.StartTransaction())
            {
                var generatedSet = generatedRoadAllowanceIds == null
                    ? new HashSet<ObjectId>()
                    : new HashSet<ObjectId>(generatedRoadAllowanceIds.Where(id => !id.IsNull));

                var blindSouthBoundarySegments = new List<(Point2d A, Point2d B, bool IsHorizontal)>(capacity: 12);
                if (sectionNumberByPolylineId != null)
                {
                    foreach (var pair in sectionNumberByPolylineId)
                    {
                        if (pair.Key.IsNull || !IsBlindSouthBoundarySection(pair.Value))
                        {
                            continue;
                        }

                        if (!(tr.GetObject(pair.Key, OpenMode.ForRead, false) is Polyline section) || section.IsErased)
                        {
                            continue;
                        }

                        if (!TryGetQuarterAnchors(section, out var anchors))
                        {
                            anchors = GetFallbackAnchors(section);
                        }

                        var eastUnit = GetUnitVector(anchors.Left, anchors.Right, new Vector2d(1, 0));
                        var northUnit = GetUnitVector(anchors.Bottom, anchors.Top, new Vector2d(0, 1));
                        if (!TryGetQuarterCorner(section, eastUnit, northUnit, QuarterCorner.SouthWest, out var sw) ||
                            !TryGetQuarterCorner(section, eastUnit, northUnit, QuarterCorner.SouthEast, out var se))
                        {
                            continue;
                        }

                        var boundaryIsHorizontal = IsHorizontalLike(sw, se);
                        var boundaryIsVertical = IsVerticalLike(sw, se);
                        if (!boundaryIsHorizontal && !boundaryIsVertical)
                        {
                            continue;
                        }

                        blindSouthBoundarySegments.Add((sw, se, boundaryIsHorizontal));
                    }
                }

                var roadSegments = new List<(ObjectId Id, bool IsUsecLayer, bool IsGenerated, bool IsHorizontal, bool IsBlindSouthBoundary, Point2d A, Point2d B, double Axis, double SpanMin, double SpanMax)>(
                    capacity: 256);
                var bt = (BlockTable)tr.GetObject(database.BlockTableId, OpenMode.ForRead);
                var ms = (BlockTableRecord)tr.GetObject(bt[BlockTableRecord.ModelSpace], OpenMode.ForRead);
                foreach (ObjectId id in ms)
                {
                    if (!(tr.GetObject(id, OpenMode.ForRead, false) is Entity ent) || ent.IsErased)
                    {
                        continue;
                    }

                    var isUsecLayer = IsUsecLayer(ent.Layer);
                    if (!isUsecLayer)
                    {
                        continue;
                    }

                    if (!TryReadOpenSegment(ent, out var a, out var b) ||
                        !DoesSegmentIntersectAnyWindow(a, b))
                    {
                        continue;
                    }

                    var horizontal = IsHorizontalLike(a, b);
                    var vertical = IsVerticalLike(a, b);
                    if (!horizontal && !vertical)
                    {
                        continue;
                    }

                    var isGenerated = generatedSet.Contains(id);
                    var len = a.GetDistanceTo(b);
                    if (len < 2.0)
                    {
                        continue;
                    }

                    var axis = horizontal
                        ? (0.5 * (a.Y + b.Y))
                        : (0.5 * (a.X + b.X));
                    var spanMin = horizontal
                        ? Math.Min(a.X, b.X)
                        : Math.Min(a.Y, b.Y);
                    var spanMax = horizontal
                        ? Math.Max(a.X, b.X)
                        : Math.Max(a.Y, b.Y);

                    var isBlindSouthBoundary = IsSegmentOnBlindSouthBoundary(a, b, blindSouthBoundarySegments);
                    roadSegments.Add((id, isUsecLayer, isGenerated, horizontal, isBlindSouthBoundary, a, b, axis, spanMin, spanMax));
                }

                if (roadSegments.Count == 0)
                {
                    tr.Commit();
                    return;
                }

                var generatedUsecIndices = new List<int>();
                for (var i = 0; i < roadSegments.Count; i++)
                {
                    if (roadSegments[i].IsGenerated)
                    {
                        generatedUsecIndices.Add(i);
                    }
                }

                if (generatedUsecIndices.Count == 0)
                {
                    tr.Commit();
                    return;
                }

                EnsureLayerWithColor(database, tr, LayerUsecZero, ResolveUsecLayerColorIndex(LayerUsecZero));
                EnsureLayerWithColor(database, tr, LayerUsecTwenty, ResolveUsecLayerColorIndex(LayerUsecTwenty));
                EnsureLayerWithColor(database, tr, LayerUsecThirty, ResolveUsecLayerColorIndex(LayerUsecThirty));

                const double overlapTolerance = 4.0;
                const double axisNeighborhoodTolerance = 55.0;
                const double bucketTolerance = 1.6;
                const double spanTouchTolerance = 6.0;
                const double twoLineSecGapTolerance = 1.2;
                const double twoLineThirtyGapTolerance = 1.6;
                const double twoLineMiddleToOuterGapTolerance = 1.4;
                const double lenTolerance = 0.35;
                const double secThirtyRatio = RoadAllowanceSecWidthMeters / RoadAllowanceUsecWidthMeters;
                var middleToOuterGap = RoadAllowanceUsecWidthMeters - RoadAllowanceSecWidthMeters;

                static bool HasSpanContact(
                    double aMin,
                    double aMax,
                    double bMin,
                    double bMax,
                    double minOverlap,
                    double maxGap)
                {
                    var overlap = Math.Min(aMax, bMax) - Math.Max(aMin, bMin);
                    if (overlap >= minOverlap)
                    {
                        return true;
                    }

                    if (overlap >= 0.0)
                    {
                        return false;
                    }

                    return -overlap <= maxGap;
                }

                var normalizedToZero = 0;
                var normalizedToTwenty = 0;
                var normalizedToThirty = 0;
                var unchanged = 0;

                var toVisit = new List<int>(Math.Max(4, generatedUsecIndices.Count));
                var processed = new bool[roadSegments.Count];
                for (var startIndex = 0; startIndex < roadSegments.Count; startIndex++)
                {
                    if (processed[startIndex])
                    {
                        continue;
                    }

                    toVisit.Clear();
                    toVisit.Add(startIndex);
                    processed[startIndex] = true;
                    var component = new List<int>();
                    var componentHasGenerated = false;
                    for (var visit = 0; visit < toVisit.Count; visit++)
                    {
                        var i = toVisit[visit];
                        var seg = roadSegments[i];
                        component.Add(i);
                        componentHasGenerated |= seg.IsGenerated;

                        for (var j = 0; j < roadSegments.Count; j++)
                        {
                            if (processed[j])
                            {
                                continue;
                            }

                            var other = roadSegments[j];
                            if (seg.IsHorizontal != other.IsHorizontal)
                            {
                                continue;
                            }

                            if (Math.Abs(seg.Axis - other.Axis) > axisNeighborhoodTolerance)
                            {
                                continue;
                            }

                            if (!HasSpanContact(
                                seg.SpanMin,
                                seg.SpanMax,
                                other.SpanMin,
                                other.SpanMax,
                                overlapTolerance,
                                spanTouchTolerance))
                            {
                                continue;
                            }

                            processed[j] = true;
                            toVisit.Add(j);
                        }
                    }

                    if (component.Count == 0)
                    {
                        continue;
                    }

                    component.Sort((l, r) => roadSegments[l].Axis.CompareTo(roadSegments[r].Axis));

                    var buckets = new List<(double Axis, List<int> Members)>();
                    foreach (var idx in component)
                    {
                        var axis = roadSegments[idx].Axis;
                        if (buckets.Count == 0)
                        {
                            buckets.Add((axis, new List<int> { idx }));
                            continue;
                        }

                        var last = buckets[buckets.Count - 1];
                        if (Math.Abs(axis - last.Axis) <= bucketTolerance)
                        {
                            last.Members.Add(idx);
                            last = ((last.Axis * (last.Members.Count - 1) + axis) / last.Members.Count, last.Members);
                            buckets[buckets.Count - 1] = last;
                        }
                        else
                        {
                            buckets.Add((axis, new List<int> { idx }));
                        }
                    }

                    var bucketCount = buckets.Count;
                    if (!componentHasGenerated && bucketCount < 2)
                    {
                        // Avoid relayering isolated legacy singletons with no generated context.
                        continue;
                    }

                    var bucketLayers = new string[bucketCount];
                    var generatedInComponent = component.Exists(i => roadSegments[i].IsGenerated);
                    if (bucketCount == 1)
                    {
                        bucketLayers[0] = generatedInComponent
                            ? LayerUsecTwenty
                            : LayerUsecZero;
                    }
                    else if (bucketCount == 2)
                    {
                        var zeroAxis = buckets[0].Axis;
                        var farAxis = buckets[1].Axis;
                        var gap = Math.Abs(farAxis - zeroAxis);
                        var lowSplitThreshold = (middleToOuterGap + RoadAllowanceSecWidthMeters) * 0.5;
                        var highSplitThreshold = (RoadAllowanceSecWidthMeters + RoadAllowanceUsecWidthMeters) * 0.5;

                        if (Math.Abs(gap - RoadAllowanceSecWidthMeters) <= twoLineSecGapTolerance)
                        {
                            bucketLayers[0] = LayerUsecZero;
                            bucketLayers[1] = LayerUsecTwenty;
                        }
                        else if (Math.Abs(gap - middleToOuterGap) <= twoLineMiddleToOuterGapTolerance)
                        {
                            bucketLayers[0] = LayerUsecTwenty;
                            bucketLayers[1] = LayerUsecThirty;
                        }
                        else if (Math.Abs(gap - RoadAllowanceUsecWidthMeters) <= twoLineThirtyGapTolerance)
                        {
                            bucketLayers[0] = LayerUsecZero;
                            bucketLayers[1] = LayerUsecThirty;
                        }
                        else if (gap <= (lowSplitThreshold - lenTolerance))
                        {
                            // Small two-line spacing most closely matches 20.12<->30.18.
                            bucketLayers[0] = LayerUsecTwenty;
                            bucketLayers[1] = LayerUsecThirty;
                        }
                        else if (gap < (highSplitThreshold - lenTolerance))
                        {
                            // Mid spacing most closely matches 0<->20.12.
                            bucketLayers[0] = LayerUsecZero;
                            bucketLayers[1] = LayerUsecTwenty;
                        }
                        else
                        {
                            // Large spacing defaults to 0<->30.18.
                            bucketLayers[0] = LayerUsecZero;
                            bucketLayers[1] = LayerUsecThirty;
                        }
                    }
                    else
                    {
                        var zeroAxis = buckets[0].Axis;
                        var farAxis = buckets[bucketCount - 1].Axis;
                        var targetTwentyAxis = zeroAxis + ((farAxis - zeroAxis) * secThirtyRatio);
                        var twentyBucketIndex = 1;
                        var bestTwentyDistance = double.MaxValue;
                        for (var b = 1; b < bucketCount - 1; b++)
                        {
                            var d = Math.Abs(buckets[b].Axis - targetTwentyAxis);
                            if (d < bestTwentyDistance)
                            {
                                bestTwentyDistance = d;
                                twentyBucketIndex = b;
                            }
                        }

                        for (var b = 0; b < bucketCount; b++)
                        {
                            if (b == 0)
                            {
                                bucketLayers[b] = LayerUsecZero;
                                continue;
                            }

                            if (b == bucketCount - 1)
                            {
                                bucketLayers[b] = LayerUsecThirty;
                                continue;
                            }

                            if (b == twentyBucketIndex)
                            {
                                bucketLayers[b] = LayerUsecTwenty;
                                continue;
                            }

                            var axis = buckets[b].Axis;
                            var d0 = Math.Abs(axis - zeroAxis);
                            var d20 = Math.Abs(axis - targetTwentyAxis);
                            var d30 = Math.Abs(axis - farAxis);
                            if (d20 <= d0 && d20 <= d30)
                            {
                                bucketLayers[b] = LayerUsecTwenty;
                            }
                            else if (d0 <= d20 && d0 <= d30)
                            {
                                bucketLayers[b] = LayerUsecZero;
                            }
                            else
                            {
                                bucketLayers[b] = LayerUsecThirty;
                            }
                        }
                    }

                    for (var b = 0; b < bucketCount; b++)
                    {
                        var targetLayer = bucketLayers[b];
                        var members = buckets[b].Members;
                        foreach (var member in members)
                        {
                            var seg = roadSegments[member];
                            if ((seg.IsBlindSouthBoundary && seg.IsHorizontal) ||
                                !(tr.GetObject(seg.Id, OpenMode.ForWrite, false) is Entity writable) ||
                                writable.IsErased)
                            {
                                continue;
                            }

                            var existingLayer = writable.Layer ?? string.Empty;
                            if (string.Equals(existingLayer, targetLayer, StringComparison.OrdinalIgnoreCase))
                            {
                                unchanged++;
                                continue;
                            }

                            var colorIndex = ResolveUsecLayerColorIndex(targetLayer);
                            EnsureLayerWithColor(database, tr, targetLayer, colorIndex);
                            writable.Layer = targetLayer;
                            writable.ColorIndex = 256;

                            if (string.Equals(targetLayer, LayerUsecThirty, StringComparison.OrdinalIgnoreCase))
                            {
                                normalizedToThirty++;
                            }
                            else if (string.Equals(targetLayer, LayerUsecTwenty, StringComparison.OrdinalIgnoreCase))
                            {
                                normalizedToTwenty++;
                            }
                            else
                            {
                                normalizedToZero++;
                            }
                        }
                    }
                }

                tr.Commit();
                var total = normalizedToZero + normalizedToTwenty + normalizedToThirty;
                if (total > 0)
                {
                    logger?.WriteLine(
                        $"Cleanup: normalized {total} usec segment(s) into three bands " +
                        $"[0:{normalizedToZero}, 20.11:{normalizedToTwenty}, 30.17:{normalizedToThirty}], unchanged={unchanged}.");
                }
            }
        }

        private static void NormalizeBlindLineLayersBySecConnections(
            Database database,
            IEnumerable<ObjectId> requestedQuarterIds,
            Logger? logger)
        {
            if (database == null || requestedQuarterIds == null)
            {
                return;
            }

            var clipWindows = BuildBufferedQuarterWindows(database, requestedQuarterIds, 102.0);
            if (clipWindows.Count == 0)
            {
                return;
            }

            bool IsPointInAnyWindow(Point2d p)
            {
                for (var i = 0; i < clipWindows.Count; i++)
                {
                    var w = clipWindows[i];
                    if (p.X >= w.MinPoint.X && p.X <= w.MaxPoint.X &&
                        p.Y >= w.MinPoint.Y && p.Y <= w.MaxPoint.Y)
                    {
                        return true;
                    }
                }

                return false;
            }

            bool DoesSegmentIntersectAnyWindow(Point2d a, Point2d b)
            {
                if (IsPointInAnyWindow(a) || IsPointInAnyWindow(b))
                {
                    return true;
                }

                for (var i = 0; i < clipWindows.Count; i++)
                {
                    if (TryClipSegmentToWindow(a, b, clipWindows[i], out _, out _))
                    {
                        return true;
                    }
                }

                return false;
            }

            using (var tr = database.TransactionManager.StartTransaction())
            {
                bool TryReadOpenSegment(Entity ent, out Point2d a, out Point2d b)
                {
                    a = default;
                    b = default;
                    if (ent == null)
                    {
                        return false;
                    }

                    if (ent is Line ln)
                    {
                        a = new Point2d(ln.StartPoint.X, ln.StartPoint.Y);
                        b = new Point2d(ln.EndPoint.X, ln.EndPoint.Y);
                        return a.GetDistanceTo(b) > 1e-4;
                    }

                    if (ent is Polyline pl)
                    {
                        if (pl.Closed || pl.NumberOfVertices != 2)
                        {
                            return false;
                        }

                        a = pl.GetPoint2dAt(0);
                        b = pl.GetPoint2dAt(1);
                        return a.GetDistanceTo(b) > 1e-4;
                    }

                    return false;
                }

                bool IsHorizontalLike(Point2d a, Point2d b)
                {
                    var d = b - a;
                    return Math.Abs(d.X) >= Math.Abs(d.Y);
                }

                bool IsVerticalLike(Point2d a, Point2d b)
                {
                    var d = b - a;
                    return Math.Abs(d.Y) > Math.Abs(d.X);
                }

                var segments = new List<(ObjectId Id, string Layer, Point2d A, Point2d B, bool Horizontal, bool Vertical, double Length)>();
                var bt = (BlockTable)tr.GetObject(database.BlockTableId, OpenMode.ForRead);
                var ms = (BlockTableRecord)tr.GetObject(bt[BlockTableRecord.ModelSpace], OpenMode.ForRead);
                foreach (ObjectId id in ms)
                {
                    Entity? ent = null;
                    try
                    {
                        ent = tr.GetObject(id, OpenMode.ForRead, false) as Entity;
                    }
                    catch (Autodesk.AutoCAD.Runtime.Exception)
                    {
                        continue;
                    }

                    if (ent == null || ent.IsErased)
                    {
                        continue;
                    }

                    var isUsec = string.Equals(ent.Layer, "L-USEC", StringComparison.OrdinalIgnoreCase);
                    var isSec = string.Equals(ent.Layer, "L-SEC", StringComparison.OrdinalIgnoreCase);
                    if (!isUsec && !isSec)
                    {
                        continue;
                    }

                    if (!TryReadOpenSegment(ent, out var a, out var b) ||
                        !DoesSegmentIntersectAnyWindow(a, b))
                    {
                        continue;
                    }

                    var horizontal = IsHorizontalLike(a, b);
                    var vertical = IsVerticalLike(a, b);
                    if (!horizontal && !vertical)
                    {
                        continue;
                    }

                    segments.Add((id, ent.Layer ?? string.Empty, a, b, horizontal, vertical, a.GetDistanceTo(b)));
                }

                if (segments.Count == 0)
                {
                    tr.Commit();
                    return;
                }

                const double endpointTol = 0.40;
                const double minBlindLength = 8.0;
                const double maxBlindLength = 320.0;
                var blindCandidates = 0;
                var secAnchoredBlind = 0;
                var normalized = 0;

                bool TouchesEndpoint(Point2d endpoint, (ObjectId Id, string Layer, Point2d A, Point2d B, bool Horizontal, bool Vertical, double Length) seg)
                {
                    return DistancePointToSegment(endpoint, seg.A, seg.B) <= endpointTol;
                }

                for (var i = 0; i < segments.Count; i++)
                {
                    var s = segments[i];
                    if (s.Length < minBlindLength || s.Length > maxBlindLength)
                    {
                        continue;
                    }

                    if (string.Equals(s.Layer, "L-SEC", StringComparison.OrdinalIgnoreCase))
                    {
                        continue;
                    }

                    var touchCountA = 0;
                    var touchCountB = 0;
                    var anchorSecAtA = false;
                    var anchorSecAtB = false;
                    for (var j = 0; j < segments.Count; j++)
                    {
                        if (i == j)
                        {
                            continue;
                        }

                        var o = segments[j];
                        if ((s.Horizontal && !o.Vertical) || (s.Vertical && !o.Horizontal))
                        {
                            continue;
                        }

                        if (TouchesEndpoint(s.A, o))
                        {
                            touchCountA++;
                            if (string.Equals(o.Layer, "L-SEC", StringComparison.OrdinalIgnoreCase))
                            {
                                anchorSecAtA = true;
                            }
                        }

                        if (TouchesEndpoint(s.B, o))
                        {
                            touchCountB++;
                            if (string.Equals(o.Layer, "L-SEC", StringComparison.OrdinalIgnoreCase))
                            {
                                anchorSecAtB = true;
                            }
                        }
                    }

                    var aBlind = touchCountA > 0 && touchCountB == 0;
                    var bBlind = touchCountB > 0 && touchCountA == 0;
                    if (!aBlind && !bBlind)
                    {
                        continue;
                    }

                    blindCandidates++;
                    var anchoredOnSec = aBlind ? anchorSecAtA : anchorSecAtB;
                    if (!anchoredOnSec)
                    {
                        continue;
                    }

                    secAnchoredBlind++;
                    Entity? writable = null;
                    try
                    {
                        writable = tr.GetObject(s.Id, OpenMode.ForWrite, false) as Entity;
                    }
                    catch (Autodesk.AutoCAD.Runtime.Exception)
                    {
                        continue;
                    }

                    if (writable == null || writable.IsErased ||
                        string.Equals(writable.Layer, "L-SEC", StringComparison.OrdinalIgnoreCase))
                    {
                        continue;
                    }

                    writable.Layer = "L-SEC";
                    writable.ColorIndex = 256;
                    normalized++;
                }

                tr.Commit();
                if (normalized > 0 || secAnchoredBlind > 0)
                {
                    logger?.WriteLine(
                        $"Cleanup: blind-line layer normalization candidates={blindCandidates}, secAnchored={secAnchoredBlind}, normalizedToSec={normalized}.");
                }
            }
        }

        private static bool IsWestRoadAllowanceCorrectionSection(int sectionNumber)
        {
            return (sectionNumber >= 7 && sectionNumber <= 12) ||
                   (sectionNumber >= 13 && sectionNumber <= 18) ||
                   (sectionNumber >= 19 && sectionNumber <= 24) ||
                   (sectionNumber >= 31 && sectionNumber <= 36);
        }

        private static void NormalizeWestRoadAllowanceBandsForKnownSections(
            Database database,
            IEnumerable<ObjectId> requestedQuarterIds,
            IReadOnlyDictionary<ObjectId, int> sectionNumberByPolylineId,
            Logger? logger)
        {
            if (database == null || requestedQuarterIds == null || sectionNumberByPolylineId == null)
            {
                return;
            }

            var clipWindows = BuildBufferedQuarterWindows(database, requestedQuarterIds, 102.0);
            if (clipWindows.Count == 0)
            {
                return;
            }

            bool IsPointInAnyWindow(Point2d p)
            {
                for (var i = 0; i < clipWindows.Count; i++)
                {
                    var w = clipWindows[i];
                    if (p.X >= w.MinPoint.X && p.X <= w.MaxPoint.X &&
                        p.Y >= w.MinPoint.Y && p.Y <= w.MaxPoint.Y)
                    {
                        return true;
                    }
                }

                return false;
            }

            bool DoesSegmentIntersectAnyWindow(Point2d a, Point2d b)
            {
                if (IsPointInAnyWindow(a) || IsPointInAnyWindow(b))
                {
                    return true;
                }

                for (var i = 0; i < clipWindows.Count; i++)
                {
                    if (TryClipSegmentToWindow(a, b, clipWindows[i], out _, out _))
                    {
                        return true;
                    }
                }

                return false;
            }

            bool TryReadOpenSegment(Entity ent, out Point2d a, out Point2d b)
            {
                a = default;
                b = default;
                if (ent == null)
                {
                    return false;
                }

                if (ent is Line ln)
                {
                    a = new Point2d(ln.StartPoint.X, ln.StartPoint.Y);
                    b = new Point2d(ln.EndPoint.X, ln.EndPoint.Y);
                    return a.GetDistanceTo(b) > 1e-4;
                }

                if (ent is Polyline pl)
                {
                    if (pl.Closed || pl.NumberOfVertices < 2)
                    {
                        return false;
                    }

                    a = pl.GetPoint2dAt(0);
                    b = pl.GetPoint2dAt(pl.NumberOfVertices - 1);
                    return a.GetDistanceTo(b) > 1e-4;
                }

                return false;
            }

            using (var tr = database.TransactionManager.StartTransaction())
            {
                var targetSections = new List<(
                    Point2d SwCorner,
                    Vector2d EastUnit,
                    Vector2d NorthUnit,
                    double MinV,
                    double MaxV,
                    double WestEdgeU,
                    double WestBandMinU,
                    double WestBandMaxU)>();
                foreach (var pair in sectionNumberByPolylineId)
                {
                    if (pair.Key.IsNull || !IsWestRoadAllowanceCorrectionSection(pair.Value))
                    {
                        continue;
                    }

                    if (!(tr.GetObject(pair.Key, OpenMode.ForRead, false) is Polyline section) || section.IsErased)
                    {
                        continue;
                    }

                    if (!TryGetQuarterAnchors(section, out var anchors))
                    {
                        anchors = GetFallbackAnchors(section);
                    }

                    var eastUnit = GetUnitVector(anchors.Left, anchors.Right, new Vector2d(1, 0));
                    var northUnit = GetUnitVector(anchors.Bottom, anchors.Top, new Vector2d(0, 1));
                    if (!TryGetQuarterCorner(section, eastUnit, northUnit, QuarterCorner.SouthWest, out var swCorner))
                    {
                        var ext = section.GeometricExtents;
                        swCorner = new Point2d(ext.MinPoint.X, ext.MinPoint.Y);
                    }

                    var minV = double.MaxValue;
                    var maxV = double.MinValue;
                    var westEdgeU = double.MaxValue;
                    for (var vi = 0; vi < section.NumberOfVertices; vi++)
                    {
                        var p = section.GetPoint2dAt(vi);
                        var rel = p - swCorner;
                        var v = rel.DotProduct(northUnit);
                        var u = rel.DotProduct(eastUnit);
                        if (v < minV)
                        {
                            minV = v;
                        }

                        if (v > maxV)
                        {
                            maxV = v;
                        }

                        if (u < westEdgeU)
                        {
                            westEdgeU = u;
                        }
                    }

                    if (minV >= maxV || westEdgeU == double.MaxValue)
                    {
                        continue;
                    }

                    var westBandMinU = westEdgeU - (RoadAllowanceUsecWidthMeters + 10.0);
                    var westBandMaxU = westEdgeU + 2.0;
                    targetSections.Add((swCorner, eastUnit, northUnit, minV, maxV, westEdgeU, westBandMinU, westBandMaxU));
                }

                if (targetSections.Count == 0)
                {
                    tr.Commit();
                    return;
                }

                var usecSegments = new List<(ObjectId Id, Point2d A, Point2d B)>();
                var bt = (BlockTable)tr.GetObject(database.BlockTableId, OpenMode.ForRead);
                var ms = (BlockTableRecord)tr.GetObject(bt[BlockTableRecord.ModelSpace], OpenMode.ForRead);
                foreach (ObjectId id in ms)
                {
                    if (!(tr.GetObject(id, OpenMode.ForRead, false) is Entity ent) || ent.IsErased)
                    {
                        continue;
                    }

                    if (!IsUsecLayer(ent.Layer))
                    {
                        continue;
                    }

                    if (!TryReadOpenSegment(ent, out var a, out var b))
                    {
                        continue;
                    }

                    if (!DoesSegmentIntersectAnyWindow(a, b))
                    {
                        continue;
                    }

                    usecSegments.Add((id, a, b));
                }

                if (usecSegments.Count == 0)
                {
                    tr.Commit();
                    return;
                }

                EnsureLayerWithColor(database, tr, LayerUsecZero, ResolveUsecLayerColorIndex(LayerUsecZero));
                EnsureLayerWithColor(database, tr, LayerUsecTwenty, ResolveUsecLayerColorIndex(LayerUsecTwenty));
                EnsureLayerWithColor(database, tr, LayerUsecThirty, ResolveUsecLayerColorIndex(LayerUsecThirty));

                const double bucketTolerance = 1.6;
                const double sectionOverlapTol = 16.0;
                var corrected = 0;
                var correctedSections = 0;
                for (var si = 0; si < targetSections.Count; si++)
                {
                    var section = targetSections[si];
                    var candidates = new List<(ObjectId Id, double ULine)>();
                    for (var i = 0; i < usecSegments.Count; i++)
                    {
                        var seg = usecSegments[i];
                        var d = seg.B - seg.A;
                        var eastComp = Math.Abs(d.DotProduct(section.EastUnit));
                        var northComp = Math.Abs(d.DotProduct(section.NorthUnit));
                        if (northComp <= eastComp)
                        {
                            continue;
                        }

                        var relA = seg.A - section.SwCorner;
                        var relB = seg.B - section.SwCorner;
                        var uA = relA.DotProduct(section.EastUnit);
                        var uB = relB.DotProduct(section.EastUnit);
                        var vA = relA.DotProduct(section.NorthUnit);
                        var vB = relB.DotProduct(section.NorthUnit);
                        var minV = Math.Min(vA, vB);
                        var maxV = Math.Max(vA, vB);
                        var overlap = Math.Min(maxV, section.MaxV + sectionOverlapTol) - Math.Max(minV, section.MinV - sectionOverlapTol);
                        if (overlap < 20.0)
                        {
                            continue;
                        }

                        var uLine = 0.5 * (uA + uB);
                        if (uLine < section.WestBandMinU || uLine > section.WestBandMaxU)
                        {
                            continue;
                        }

                        candidates.Add((seg.Id, uLine));
                    }

                    if (candidates.Count == 0)
                    {
                        continue;
                    }

                    candidates.Sort((a, b) => a.ULine.CompareTo(b.ULine));
                    var buckets = new List<(double Axis, List<ObjectId> Members)>();
                    for (var i = 0; i < candidates.Count; i++)
                    {
                        var c = candidates[i];
                        if (buckets.Count == 0)
                        {
                            buckets.Add((c.ULine, new List<ObjectId> { c.Id }));
                            continue;
                        }

                        var last = buckets[buckets.Count - 1];
                        if (Math.Abs(c.ULine - last.Axis) <= bucketTolerance)
                        {
                            last.Members.Add(c.Id);
                            last = ((last.Axis * (last.Members.Count - 1) + c.ULine) / last.Members.Count, last.Members);
                            buckets[buckets.Count - 1] = last;
                        }
                        else
                        {
                            buckets.Add((c.ULine, new List<ObjectId> { c.Id }));
                        }
                    }

                    if (buckets.Count == 0)
                    {
                        continue;
                    }

                    var sectionAdjusted = false;
                    void ApplyBucketLayer(int bucketIndex, string targetLayer)
                    {
                        var members = buckets[bucketIndex].Members;
                        for (var mi = 0; mi < members.Count; mi++)
                        {
                            var id = members[mi];
                            if (!(tr.GetObject(id, OpenMode.ForWrite, false) is Entity writable) || writable.IsErased)
                            {
                                continue;
                            }

                            if (string.Equals(writable.Layer, targetLayer, StringComparison.OrdinalIgnoreCase))
                            {
                                continue;
                            }

                            writable.Layer = targetLayer;
                            writable.ColorIndex = 256;
                            corrected++;
                            sectionAdjusted = true;
                        }
                    }

                    var thirtyAxis = section.WestEdgeU;
                    var twentyAxis = thirtyAxis - (RoadAllowanceUsecWidthMeters - RoadAllowanceSecWidthMeters);
                    var zeroAxis = thirtyAxis - RoadAllowanceUsecWidthMeters;
                    for (var bi = 0; bi < buckets.Count; bi++)
                    {
                        var axis = buckets[bi].Axis;
                        var dZero = Math.Abs(axis - zeroAxis);
                        var dTwenty = Math.Abs(axis - twentyAxis);
                        var dThirty = Math.Abs(axis - thirtyAxis);
                        var targetLayer = LayerUsecTwenty;
                        if (dZero <= dTwenty && dZero <= dThirty)
                        {
                            targetLayer = LayerUsecZero;
                        }
                        else if (dThirty <= dZero && dThirty <= dTwenty)
                        {
                            targetLayer = LayerUsecThirty;
                        }
                        else
                        {
                            targetLayer = LayerUsecTwenty;
                        }

                        ApplyBucketLayer(bi, targetLayer);
                    }

                    if (sectionAdjusted)
                    {
                        correctedSections++;
                    }
                }

                tr.Commit();
                if (corrected > 0)
                {
                    logger?.WriteLine(
                        $"Cleanup: west RA section-band correction relayered {corrected} segment(s) across {correctedSections} section(s).");
                }
            }
        }

        private static void NormalizeUsecLayersBySectionEdgeOffsets(
            Database database,
            IEnumerable<ObjectId> requestedQuarterIds,
            IReadOnlyDictionary<ObjectId, int> sectionNumberByPolylineId,
            Logger? logger)
        {
            if (database == null || requestedQuarterIds == null || sectionNumberByPolylineId == null)
            {
                return;
            }

            var clipWindows = BuildBufferedQuarterWindows(database, requestedQuarterIds, 102.0);
            if (clipWindows.Count == 0)
            {
                return;
            }

            bool IsPointInAnyWindow(Point2d p)
            {
                for (var i = 0; i < clipWindows.Count; i++)
                {
                    var w = clipWindows[i];
                    if (p.X >= w.MinPoint.X && p.X <= w.MaxPoint.X &&
                        p.Y >= w.MinPoint.Y && p.Y <= w.MaxPoint.Y)
                    {
                        return true;
                    }
                }

                return false;
            }

            bool DoesSegmentIntersectAnyWindow(Point2d a, Point2d b)
            {
                if (IsPointInAnyWindow(a) || IsPointInAnyWindow(b))
                {
                    return true;
                }

                for (var i = 0; i < clipWindows.Count; i++)
                {
                    if (TryClipSegmentToWindow(a, b, clipWindows[i], out _, out _))
                    {
                        return true;
                    }
                }

                return false;
            }

            bool TryReadOpenSegment(Entity ent, out Point2d a, out Point2d b)
            {
                a = default;
                b = default;
                if (ent == null)
                {
                    return false;
                }

                if (ent is Line ln)
                {
                    a = new Point2d(ln.StartPoint.X, ln.StartPoint.Y);
                    b = new Point2d(ln.EndPoint.X, ln.EndPoint.Y);
                    return a.GetDistanceTo(b) > 1e-4;
                }

                if (ent is Polyline pl)
                {
                    if (pl.Closed || pl.NumberOfVertices < 2)
                    {
                        return false;
                    }

                    a = pl.GetPoint2dAt(0);
                    b = pl.GetPoint2dAt(pl.NumberOfVertices - 1);
                    return a.GetDistanceTo(b) > 1e-4;
                }

                return false;
            }

            bool IsHorizontalLike(Point2d a, Point2d b)
            {
                var d = b - a;
                return Math.Abs(d.X) >= Math.Abs(d.Y);
            }

            bool IsVerticalLike(Point2d a, Point2d b)
            {
                var d = b - a;
                return Math.Abs(d.Y) > Math.Abs(d.X);
            }

            bool IsBlindSouthBoundarySection(int sectionNumber)
            {
                return (sectionNumber >= 7 && sectionNumber <= 12) ||
                       (sectionNumber >= 19 && sectionNumber <= 24) ||
                       (sectionNumber >= 31 && sectionNumber <= 36);
            }

            bool IsSegmentOnBlindSouthBoundary(
                Point2d a,
                Point2d b,
                IReadOnlyList<(Point2d A, Point2d B, bool IsHorizontal)> blindBoundaries)
            {
                if (blindBoundaries == null || blindBoundaries.Count == 0 || a == b)
                {
                    return false;
                }

                const double boundaryDistanceTol = 0.60;
                const double overlapParamTolerance = 0.08;
                var midpoint = Midpoint(a, b);
                foreach (var boundary in blindBoundaries)
                {
                    if (IsHorizontalLike(a, b) != boundary.IsHorizontal)
                    {
                        continue;
                    }

                    if (DistancePointToSegment(a, boundary.A, boundary.B) > boundaryDistanceTol &&
                        DistancePointToSegment(b, boundary.A, boundary.B) > boundaryDistanceTol &&
                        DistancePointToSegment(midpoint, boundary.A, boundary.B) > boundaryDistanceTol)
                    {
                        continue;
                    }

                    var boundaryDir = boundary.B - boundary.A;
                    var boundaryLen2 = boundaryDir.DotProduct(boundaryDir);
                    if (boundaryLen2 <= 1e-9)
                    {
                        continue;
                    }

                    var t0 = (a - boundary.A).DotProduct(boundaryDir) / boundaryLen2;
                    var t1 = (b - boundary.A).DotProduct(boundaryDir) / boundaryLen2;
                    var overlapMin = Math.Max(Math.Min(t0, t1), 0.0);
                    var overlapMax = Math.Min(Math.Max(t0, t1), 1.0);
                    if (overlapMax - overlapMin < overlapParamTolerance)
                    {
                        continue;
                    }

                    return true;
                }

                return false;
            }

            static int LayerTieRank(string layer)
            {
                if (string.Equals(layer, LayerUsecZero, StringComparison.OrdinalIgnoreCase))
                {
                    return 0;
                }

                if (string.Equals(layer, LayerUsecTwenty, StringComparison.OrdinalIgnoreCase))
                {
                    return 1;
                }

                if (string.Equals(layer, LayerUsecThirty, StringComparison.OrdinalIgnoreCase))
                {
                    return 2;
                }

                return 3;
            }

            using (var tr = database.TransactionManager.StartTransaction())
            {
                var blindSouthBoundarySegments = new List<(Point2d A, Point2d B, bool IsHorizontal)>(capacity: 12);
                var sectionFrames = new List<(
                    int SectionNumber,
                    Point2d Origin,
                    Vector2d EastUnit,
                    Vector2d NorthUnit,
                    double WestEdgeU,
                    double EastEdgeU,
                    double SouthEdgeV,
                    double NorthEdgeV)>();
                foreach (var pair in sectionNumberByPolylineId)
                {
                    if (pair.Key.IsNull)
                    {
                        continue;
                    }

                    if (!(tr.GetObject(pair.Key, OpenMode.ForRead, false) is Polyline section) || section.IsErased)
                    {
                        continue;
                    }

                    if (!TryGetQuarterAnchors(section, out var anchors))
                    {
                        anchors = GetFallbackAnchors(section);
                    }

                    var eastUnit = GetUnitVector(anchors.Left, anchors.Right, new Vector2d(1, 0));
                    var northUnit = GetUnitVector(anchors.Bottom, anchors.Top, new Vector2d(0, 1));
                    if (!TryGetQuarterCorner(section, eastUnit, northUnit, QuarterCorner.SouthWest, out var origin))
                    {
                        var ext = section.GeometricExtents;
                        origin = new Point2d(ext.MinPoint.X, ext.MinPoint.Y);
                    }

                    var westEdgeU = double.MaxValue;
                    var eastEdgeU = double.MinValue;
                    var southEdgeV = double.MaxValue;
                    var northEdgeV = double.MinValue;
                    for (var vi = 0; vi < section.NumberOfVertices; vi++)
                    {
                        var p = section.GetPoint2dAt(vi);
                        var rel = p - origin;
                        var u = rel.DotProduct(eastUnit);
                        var v = rel.DotProduct(northUnit);
                        if (u < westEdgeU)
                        {
                            westEdgeU = u;
                        }

                        if (u > eastEdgeU)
                        {
                            eastEdgeU = u;
                        }

                        if (v < southEdgeV)
                        {
                            southEdgeV = v;
                        }

                        if (v > northEdgeV)
                        {
                            northEdgeV = v;
                        }
                    }

                    if (westEdgeU >= eastEdgeU || southEdgeV >= northEdgeV)
                    {
                        continue;
                    }

                    if (IsBlindSouthBoundarySection(pair.Value) &&
                        TryGetQuarterCorner(section, eastUnit, northUnit, QuarterCorner.SouthWest, out var sw) &&
                        TryGetQuarterCorner(section, eastUnit, northUnit, QuarterCorner.SouthEast, out var se))
                    {
                        var boundaryIsHorizontal = IsHorizontalLike(sw, se);
                        var boundaryIsVertical = IsVerticalLike(sw, se);
                        if (boundaryIsHorizontal || boundaryIsVertical)
                        {
                            blindSouthBoundarySegments.Add((sw, se, boundaryIsHorizontal));
                        }
                    }

                    sectionFrames.Add((pair.Value, origin, eastUnit, northUnit, westEdgeU, eastEdgeU, southEdgeV, northEdgeV));
                }

                if (sectionFrames.Count == 0)
                {
                    tr.Commit();
                    return;
                }

                var segments = new List<(ObjectId Id, Point2d A, Point2d B)>();
                var bt = (BlockTable)tr.GetObject(database.BlockTableId, OpenMode.ForRead);
                var ms = (BlockTableRecord)tr.GetObject(bt[BlockTableRecord.ModelSpace], OpenMode.ForRead);
                foreach (ObjectId id in ms)
                {
                    if (!(tr.GetObject(id, OpenMode.ForRead, false) is Entity ent) || ent.IsErased)
                    {
                        continue;
                    }

                    if (!IsUsecLayer(ent.Layer))
                    {
                        continue;
                    }

                    if (!TryReadOpenSegment(ent, out var a, out var b) ||
                        !DoesSegmentIntersectAnyWindow(a, b))
                    {
                        continue;
                    }

                    if (IsHorizontalLike(a, b) &&
                        IsSegmentOnBlindSouthBoundary(a, b, blindSouthBoundarySegments))
                    {
                        continue;
                    }

                    if (a.GetDistanceTo(b) < 2.0)
                    {
                        continue;
                    }

                    segments.Add((id, a, b));
                }

                if (segments.Count == 0)
                {
                    tr.Commit();
                    return;
                }

                EnsureLayerWithColor(database, tr, LayerUsecZero, ResolveUsecLayerColorIndex(LayerUsecZero));
                EnsureLayerWithColor(database, tr, LayerUsecTwenty, ResolveUsecLayerColorIndex(LayerUsecTwenty));
                EnsureLayerWithColor(database, tr, LayerUsecThirty, ResolveUsecLayerColorIndex(LayerUsecThirty));

                const double axisTolerance = 3.6;
                const double overlapPadding = 16.0;
                const double minProjectedOverlap = 20.0;
                const double blindSouthTolerance = 1.2;
                var adjusted = 0;
                var unchanged = 0;
                var unresolved = 0;
                var skippedBlind = 0;

                for (var si = 0; si < segments.Count; si++)
                {
                    var seg = segments[si];
                    var delta = seg.B - seg.A;
                    var votes = new Dictionary<string, (int Count, double Weight, double BestDistance)>(StringComparer.OrdinalIgnoreCase);
                    var skipBlind = false;

                    void AddVote(string layer, double distance)
                    {
                        if (string.IsNullOrWhiteSpace(layer))
                        {
                            return;
                        }

                        if (!votes.TryGetValue(layer, out var score))
                        {
                            score = (0, 0.0, double.MaxValue);
                        }

                        score.Count++;
                        score.Weight += 1.0 / Math.Max(0.25, 1.0 + distance);
                        if (distance < score.BestDistance)
                        {
                            score.BestDistance = distance;
                        }

                        votes[layer] = score;
                    }

                    for (var fi = 0; fi < sectionFrames.Count; fi++)
                    {
                        var section = sectionFrames[fi];
                        var relA = seg.A - section.Origin;
                        var relB = seg.B - section.Origin;
                        var uA = relA.DotProduct(section.EastUnit);
                        var uB = relB.DotProduct(section.EastUnit);
                        var vA = relA.DotProduct(section.NorthUnit);
                        var vB = relB.DotProduct(section.NorthUnit);

                        var eastComp = Math.Abs(delta.DotProduct(section.EastUnit));
                        var northComp = Math.Abs(delta.DotProduct(section.NorthUnit));
                        if (northComp > eastComp)
                        {
                            var minV = Math.Min(vA, vB);
                            var maxV = Math.Max(vA, vB);
                            var overlap = Math.Min(maxV, section.NorthEdgeV + overlapPadding) -
                                          Math.Max(minV, section.SouthEdgeV - overlapPadding);
                            if (overlap < minProjectedOverlap)
                            {
                                continue;
                            }

                            var uLine = 0.5 * (uA + uB);
                            var bestLayer = string.Empty;
                            var bestDistance = double.MaxValue;
                            void ConsiderVertical(string layer, double axis)
                            {
                                var d = Math.Abs(uLine - axis);
                                if (d < bestDistance)
                                {
                                    bestDistance = d;
                                    bestLayer = layer;
                                }
                            }

                            ConsiderVertical(LayerUsecZero, section.WestEdgeU - RoadAllowanceUsecWidthMeters);
                            ConsiderVertical(LayerUsecTwenty, section.WestEdgeU - (RoadAllowanceUsecWidthMeters - RoadAllowanceSecWidthMeters));
                            ConsiderVertical(LayerUsecThirty, section.WestEdgeU);
                            ConsiderVertical(LayerUsecZero, section.EastEdgeU);
                            ConsiderVertical(LayerUsecTwenty, section.EastEdgeU + RoadAllowanceSecWidthMeters);
                            ConsiderVertical(LayerUsecThirty, section.EastEdgeU + RoadAllowanceUsecWidthMeters);

                            if (bestDistance <= axisTolerance)
                            {
                                AddVote(bestLayer, bestDistance);
                            }
                        }
                        else
                        {
                            var minU = Math.Min(uA, uB);
                            var maxU = Math.Max(uA, uB);
                            var overlap = Math.Min(maxU, section.EastEdgeU + overlapPadding) -
                                          Math.Max(minU, section.WestEdgeU - overlapPadding);
                            if (overlap < minProjectedOverlap)
                            {
                                continue;
                            }

                            var vLine = 0.5 * (vA + vB);
                            if (IsBlindSouthBoundarySection(section.SectionNumber) &&
                                Math.Abs(vLine - section.SouthEdgeV) <= blindSouthTolerance)
                            {
                                skipBlind = true;
                                break;
                            }

                            var bestLayer = string.Empty;
                            var bestDistance = double.MaxValue;
                            void ConsiderHorizontal(string layer, double axis)
                            {
                                var d = Math.Abs(vLine - axis);
                                if (d < bestDistance)
                                {
                                    bestDistance = d;
                                    bestLayer = layer;
                                }
                            }

                            ConsiderHorizontal(LayerUsecZero, section.SouthEdgeV - RoadAllowanceUsecWidthMeters);
                            ConsiderHorizontal(LayerUsecTwenty, section.SouthEdgeV - (RoadAllowanceUsecWidthMeters - RoadAllowanceSecWidthMeters));
                            ConsiderHorizontal(LayerUsecThirty, section.SouthEdgeV);
                            ConsiderHorizontal(LayerUsecZero, section.NorthEdgeV);
                            ConsiderHorizontal(LayerUsecTwenty, section.NorthEdgeV + RoadAllowanceSecWidthMeters);
                            ConsiderHorizontal(LayerUsecThirty, section.NorthEdgeV + RoadAllowanceUsecWidthMeters);

                            if (bestDistance <= axisTolerance)
                            {
                                AddVote(bestLayer, bestDistance);
                            }
                        }
                    }

                    if (skipBlind)
                    {
                        skippedBlind++;
                        continue;
                    }

                    if (votes.Count == 0)
                    {
                        unresolved++;
                        continue;
                    }

                    var targetLayer = votes
                        .OrderByDescending(v => v.Value.Count)
                        .ThenByDescending(v => v.Value.Weight)
                        .ThenBy(v => v.Value.BestDistance)
                        .ThenBy(v => LayerTieRank(v.Key))
                        .Select(v => v.Key)
                        .FirstOrDefault();
                    if (string.IsNullOrWhiteSpace(targetLayer))
                    {
                        unresolved++;
                        continue;
                    }

                    if (!(tr.GetObject(seg.Id, OpenMode.ForWrite, false) is Entity writable) || writable.IsErased)
                    {
                        continue;
                    }

                    if (string.Equals(writable.Layer, targetLayer, StringComparison.OrdinalIgnoreCase))
                    {
                        unchanged++;
                        continue;
                    }

                    writable.Layer = targetLayer;
                    writable.ColorIndex = 256;
                    adjusted++;
                }

                tr.Commit();
                if (adjusted > 0 || unresolved > 0 || skippedBlind > 0)
                {
                    logger?.WriteLine(
                        $"Cleanup: deterministic section-edge relayer adjusted={adjusted}, unchanged={unchanged}, unresolved={unresolved}, skippedBlind={skippedBlind}.");
                }
            }
        }

        private static void NormalizeUsecCollinearComponentLayerConsistency(
            Database database,
            IEnumerable<ObjectId> requestedQuarterIds,
            IReadOnlyDictionary<ObjectId, int> sectionNumberByPolylineId,
            Logger? logger)
        {
            if (database == null || requestedQuarterIds == null || sectionNumberByPolylineId == null)
            {
                return;
            }

            var clipWindows = BuildBufferedQuarterWindows(database, requestedQuarterIds, 102.0);
            if (clipWindows.Count == 0)
            {
                return;
            }

            bool IsPointInAnyWindow(Point2d p)
            {
                for (var i = 0; i < clipWindows.Count; i++)
                {
                    var w = clipWindows[i];
                    if (p.X >= w.MinPoint.X && p.X <= w.MaxPoint.X &&
                        p.Y >= w.MinPoint.Y && p.Y <= w.MaxPoint.Y)
                    {
                        return true;
                    }
                }

                return false;
            }

            bool DoesSegmentIntersectAnyWindow(Point2d a, Point2d b)
            {
                if (IsPointInAnyWindow(a) || IsPointInAnyWindow(b))
                {
                    return true;
                }

                for (var i = 0; i < clipWindows.Count; i++)
                {
                    if (TryClipSegmentToWindow(a, b, clipWindows[i], out _, out _))
                    {
                        return true;
                    }
                }

                return false;
            }

            bool TryReadOpenSegment(Entity ent, out Point2d a, out Point2d b)
            {
                a = default;
                b = default;
                if (ent == null)
                {
                    return false;
                }

                if (ent is Line ln)
                {
                    a = new Point2d(ln.StartPoint.X, ln.StartPoint.Y);
                    b = new Point2d(ln.EndPoint.X, ln.EndPoint.Y);
                    return a.GetDistanceTo(b) > 1e-4;
                }

                if (ent is Polyline pl)
                {
                    if (pl.Closed || pl.NumberOfVertices < 2)
                    {
                        return false;
                    }

                    a = pl.GetPoint2dAt(0);
                    b = pl.GetPoint2dAt(pl.NumberOfVertices - 1);
                    return a.GetDistanceTo(b) > 1e-4;
                }

                return false;
            }

            bool IsHorizontalLike(Point2d a, Point2d b)
            {
                var d = b - a;
                return Math.Abs(d.X) >= Math.Abs(d.Y);
            }

            bool IsVerticalLike(Point2d a, Point2d b)
            {
                var d = b - a;
                return Math.Abs(d.Y) > Math.Abs(d.X);
            }

            bool IsBlindSouthBoundarySection(int sectionNumber)
            {
                return (sectionNumber >= 7 && sectionNumber <= 12) ||
                       (sectionNumber >= 19 && sectionNumber <= 24) ||
                       (sectionNumber >= 31 && sectionNumber <= 36);
            }

            bool IsSegmentOnBlindSouthBoundary(
                Point2d a,
                Point2d b,
                IReadOnlyList<(Point2d A, Point2d B, bool IsHorizontal)> blindBoundaries)
            {
                if (blindBoundaries == null || blindBoundaries.Count == 0 || a == b)
                {
                    return false;
                }

                const double boundaryDistanceTol = 0.60;
                const double overlapParamTolerance = 0.08;
                var midpoint = Midpoint(a, b);
                foreach (var boundary in blindBoundaries)
                {
                    if (IsHorizontalLike(a, b) != boundary.IsHorizontal)
                    {
                        continue;
                    }

                    if (DistancePointToSegment(a, boundary.A, boundary.B) > boundaryDistanceTol &&
                        DistancePointToSegment(b, boundary.A, boundary.B) > boundaryDistanceTol &&
                        DistancePointToSegment(midpoint, boundary.A, boundary.B) > boundaryDistanceTol)
                    {
                        continue;
                    }

                    var boundaryDir = boundary.B - boundary.A;
                    var boundaryLen2 = boundaryDir.DotProduct(boundaryDir);
                    if (boundaryLen2 <= 1e-9)
                    {
                        continue;
                    }

                    var t0 = (a - boundary.A).DotProduct(boundaryDir) / boundaryLen2;
                    var t1 = (b - boundary.A).DotProduct(boundaryDir) / boundaryLen2;
                    var overlapMin = Math.Max(Math.Min(t0, t1), 0.0);
                    var overlapMax = Math.Min(Math.Max(t0, t1), 1.0);
                    if (overlapMax - overlapMin < overlapParamTolerance)
                    {
                        continue;
                    }

                    return true;
                }

                return false;
            }

            static bool HasSpanContact(
                double aMin,
                double aMax,
                double bMin,
                double bMax,
                double minOverlap,
                double maxGap)
            {
                var overlap = Math.Min(aMax, bMax) - Math.Max(aMin, bMin);
                if (overlap >= minOverlap)
                {
                    return true;
                }

                if (overlap >= 0.0)
                {
                    return false;
                }

                return -overlap <= maxGap;
            }

            static string CanonicalUsecLayer(string layer)
            {
                if (string.Equals(layer, LayerUsecZero, StringComparison.OrdinalIgnoreCase))
                {
                    return LayerUsecZero;
                }

                if (string.Equals(layer, LayerUsecTwenty, StringComparison.OrdinalIgnoreCase))
                {
                    return LayerUsecTwenty;
                }

                if (string.Equals(layer, LayerUsecThirty, StringComparison.OrdinalIgnoreCase))
                {
                    return LayerUsecThirty;
                }

                if (string.Equals(layer, LayerUsecBase, StringComparison.OrdinalIgnoreCase) ||
                    string.Equals(layer, "L-USEC", StringComparison.OrdinalIgnoreCase))
                {
                    return LayerUsecBase;
                }

                return string.Empty;
            }

            static int LayerPriority(string layer)
            {
                if (string.Equals(layer, LayerUsecThirty, StringComparison.OrdinalIgnoreCase))
                {
                    return 4;
                }

                if (string.Equals(layer, LayerUsecTwenty, StringComparison.OrdinalIgnoreCase))
                {
                    return 3;
                }

                if (string.Equals(layer, LayerUsecZero, StringComparison.OrdinalIgnoreCase))
                {
                    return 2;
                }

                if (string.Equals(layer, LayerUsecBase, StringComparison.OrdinalIgnoreCase))
                {
                    return 1;
                }

                return 0;
            }

            using (var tr = database.TransactionManager.StartTransaction())
            {
                var blindSouthBoundarySegments = new List<(Point2d A, Point2d B, bool IsHorizontal)>(capacity: 12);
                foreach (var pair in sectionNumberByPolylineId)
                {
                    if (pair.Key.IsNull || !IsBlindSouthBoundarySection(pair.Value))
                    {
                        continue;
                    }

                    if (!(tr.GetObject(pair.Key, OpenMode.ForRead, false) is Polyline section) || section.IsErased)
                    {
                        continue;
                    }

                    if (!TryGetQuarterAnchors(section, out var anchors))
                    {
                        anchors = GetFallbackAnchors(section);
                    }

                    var eastUnit = GetUnitVector(anchors.Left, anchors.Right, new Vector2d(1, 0));
                    var northUnit = GetUnitVector(anchors.Bottom, anchors.Top, new Vector2d(0, 1));
                    if (!TryGetQuarterCorner(section, eastUnit, northUnit, QuarterCorner.SouthWest, out var sw) ||
                        !TryGetQuarterCorner(section, eastUnit, northUnit, QuarterCorner.SouthEast, out var se))
                    {
                        continue;
                    }

                    var boundaryIsHorizontal = IsHorizontalLike(sw, se);
                    var boundaryIsVertical = IsVerticalLike(sw, se);
                    if (!boundaryIsHorizontal && !boundaryIsVertical)
                    {
                        continue;
                    }

                    blindSouthBoundarySegments.Add((sw, se, boundaryIsHorizontal));
                }

                var segments = new List<(ObjectId Id, bool Horizontal, double Axis, double SpanMin, double SpanMax, string Layer)>();
                var bt = (BlockTable)tr.GetObject(database.BlockTableId, OpenMode.ForRead);
                var ms = (BlockTableRecord)tr.GetObject(bt[BlockTableRecord.ModelSpace], OpenMode.ForRead);
                foreach (ObjectId id in ms)
                {
                    if (!(tr.GetObject(id, OpenMode.ForRead, false) is Entity ent) || ent.IsErased)
                    {
                        continue;
                    }

                    if (!IsUsecLayer(ent.Layer))
                    {
                        continue;
                    }

                    if (!TryReadOpenSegment(ent, out var a, out var b) ||
                        !DoesSegmentIntersectAnyWindow(a, b))
                    {
                        continue;
                    }

                    var horizontal = IsHorizontalLike(a, b);
                    var vertical = IsVerticalLike(a, b);
                    if (!horizontal && !vertical)
                    {
                        continue;
                    }

                    if (horizontal && IsSegmentOnBlindSouthBoundary(a, b, blindSouthBoundarySegments))
                    {
                        continue;
                    }

                    var axis = horizontal
                        ? 0.5 * (a.Y + b.Y)
                        : 0.5 * (a.X + b.X);
                    var spanMin = horizontal
                        ? Math.Min(a.X, b.X)
                        : Math.Min(a.Y, b.Y);
                    var spanMax = horizontal
                        ? Math.Max(a.X, b.X)
                        : Math.Max(a.Y, b.Y);
                    segments.Add((id, horizontal, axis, spanMin, spanMax, ent.Layer ?? string.Empty));
                }

                if (segments.Count == 0)
                {
                    tr.Commit();
                    return;
                }

                var adjusted = 0;
                var normalizedComponents = 0;
                const double axisTol = 0.9;
                const double overlapTol = 4.0;
                const double gapTol = 3.0;

                void ProcessOrientation(bool horizontal)
                {
                    var ordered = segments
                        .Select((s, idx) => (s, idx))
                        .Where(p => p.s.Horizontal == horizontal)
                        .OrderBy(p => p.s.Axis)
                        .ToList();
                    if (ordered.Count < 2)
                    {
                        return;
                    }

                    var axisGroups = new List<List<int>>();
                    for (var i = 0; i < ordered.Count; i++)
                    {
                        var idx = ordered[i].idx;
                        if (axisGroups.Count == 0)
                        {
                            axisGroups.Add(new List<int> { idx });
                            continue;
                        }

                        var lastGroup = axisGroups[axisGroups.Count - 1];
                        var refAxis = segments[lastGroup[lastGroup.Count - 1]].Axis;
                        if (Math.Abs(segments[idx].Axis - refAxis) <= axisTol)
                        {
                            lastGroup.Add(idx);
                        }
                        else
                        {
                            axisGroups.Add(new List<int> { idx });
                        }
                    }

                    for (var gi = 0; gi < axisGroups.Count; gi++)
                    {
                        var group = axisGroups[gi];
                        if (group.Count < 2)
                        {
                            continue;
                        }

                        var visited = new bool[group.Count];
                        for (var start = 0; start < group.Count; start++)
                        {
                            if (visited[start])
                            {
                                continue;
                            }

                            var queue = new Queue<int>();
                            var members = new List<int>();
                            visited[start] = true;
                            queue.Enqueue(start);
                            while (queue.Count > 0)
                            {
                                var cur = queue.Dequeue();
                                members.Add(group[cur]);
                                for (var other = 0; other < group.Count; other++)
                                {
                                    if (visited[other])
                                    {
                                        continue;
                                    }

                                    var a = segments[group[cur]];
                                    var b = segments[group[other]];
                                    if (!HasSpanContact(a.SpanMin, a.SpanMax, b.SpanMin, b.SpanMax, overlapTol, gapTol))
                                    {
                                        continue;
                                    }

                                    visited[other] = true;
                                    queue.Enqueue(other);
                                }
                            }

                            if (members.Count < 2)
                            {
                                continue;
                            }

                            var layerCounts = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
                            for (var m = 0; m < members.Count; m++)
                            {
                                var canonical = CanonicalUsecLayer(segments[members[m]].Layer);
                                if (string.IsNullOrWhiteSpace(canonical))
                                {
                                    continue;
                                }

                                if (!layerCounts.ContainsKey(canonical))
                                {
                                    layerCounts[canonical] = 0;
                                }

                                layerCounts[canonical]++;
                            }

                            if (layerCounts.Count <= 1)
                            {
                                continue;
                            }

                            var targetLayer = layerCounts
                                .OrderByDescending(p => p.Value)
                                .ThenByDescending(p => LayerPriority(p.Key))
                                .Select(p => p.Key)
                                .FirstOrDefault() ?? LayerUsecBase;

                            if (string.Equals(targetLayer, LayerUsecBase, StringComparison.OrdinalIgnoreCase) &&
                                layerCounts.Keys.Any(k => !string.Equals(k, LayerUsecBase, StringComparison.OrdinalIgnoreCase)))
                            {
                                targetLayer = layerCounts
                                    .Where(p => !string.Equals(p.Key, LayerUsecBase, StringComparison.OrdinalIgnoreCase))
                                    .OrderByDescending(p => p.Value)
                                    .ThenByDescending(p => LayerPriority(p.Key))
                                    .Select(p => p.Key)
                                    .FirstOrDefault() ?? targetLayer;
                            }

                            for (var m = 0; m < members.Count; m++)
                            {
                                var segment = segments[members[m]];
                                if (!(tr.GetObject(segment.Id, OpenMode.ForWrite, false) is Entity writable) || writable.IsErased)
                                {
                                    continue;
                                }

                                var existingCanonical = CanonicalUsecLayer(writable.Layer ?? string.Empty);
                                if (string.IsNullOrWhiteSpace(existingCanonical) ||
                                    string.Equals(existingCanonical, targetLayer, StringComparison.OrdinalIgnoreCase))
                                {
                                    continue;
                                }

                                writable.Layer = targetLayer;
                                writable.ColorIndex = 256;
                                adjusted++;
                            }

                            normalizedComponents++;
                        }
                    }
                }

                ProcessOrientation(horizontal: true);
                ProcessOrientation(horizontal: false);

                tr.Commit();
                if (adjusted > 0)
                {
                    logger?.WriteLine(
                        $"Cleanup: normalized {adjusted} collinear L-USEC segment(s) across {normalizedComponents} mixed-layer component(s).");
                }
            }
        }

        private static void StitchTrimmedContextSectionEndpoints(
            Database database,
            IReadOnlyCollection<ObjectId> contextSectionIds,
            IEnumerable<ObjectId> requestedQuarterIds,
            Logger? logger)
        {
            if (database == null || contextSectionIds == null || contextSectionIds.Count == 0 || requestedQuarterIds == null)
            {
                return;
            }

            var clipWindows = BuildBufferedQuarterWindows(database, requestedQuarterIds, 102.0);
            if (clipWindows.Count == 0)
            {
                return;
            }

            bool IsPointInAnyWindow(Point2d p)
            {
                for (var i = 0; i < clipWindows.Count; i++)
                {
                    var w = clipWindows[i];
                    if (p.X >= w.MinPoint.X && p.X <= w.MaxPoint.X &&
                        p.Y >= w.MinPoint.Y && p.Y <= w.MaxPoint.Y)
                    {
                        return true;
                    }
                }

                return false;
            }

            bool DoesSegmentIntersectAnyWindow(Point2d a, Point2d b)
            {
                if (IsPointInAnyWindow(a) || IsPointInAnyWindow(b))
                {
                    return true;
                }

                for (var i = 0; i < clipWindows.Count; i++)
                {
                    if (TryClipSegmentToWindow(a, b, clipWindows[i], out _, out _))
                    {
                        return true;
                    }
                }

                return false;
            }

            using (var tr = database.TransactionManager.StartTransaction())
            {
                bool TryReadOpenSegment(Entity ent, out Point2d a, out Point2d b)
                {
                    a = default;
                    b = default;
                    if (ent == null)
                    {
                        return false;
                    }

                    if (ent is Line ln)
                    {
                        a = new Point2d(ln.StartPoint.X, ln.StartPoint.Y);
                        b = new Point2d(ln.EndPoint.X, ln.EndPoint.Y);
                        return a.GetDistanceTo(b) > 1e-4;
                    }

                    if (ent is Polyline pl)
                    {
                        if (pl.Closed || pl.NumberOfVertices != 2)
                        {
                            return false;
                        }

                        a = pl.GetPoint2dAt(0);
                        b = pl.GetPoint2dAt(1);
                        return a.GetDistanceTo(b) > 1e-4;
                    }

                    return false;
                }

                bool TryWriteOpenSegment(Entity ent, Point2d a, Point2d b)
                {
                    if (a.GetDistanceTo(b) <= 1e-4)
                    {
                        return false;
                    }

                    if (ent is Line ln)
                    {
                        ln.StartPoint = new Point3d(a.X, a.Y, ln.StartPoint.Z);
                        ln.EndPoint = new Point3d(b.X, b.Y, ln.EndPoint.Z);
                        return true;
                    }

                    if (ent is Polyline pl && !pl.Closed && pl.NumberOfVertices == 2)
                    {
                        pl.SetPointAt(0, a);
                        pl.SetPointAt(1, b);
                        return true;
                    }

                    return false;
                }

                Point2d ClosestPointOnSegment(Point2d p, Point2d a, Point2d b)
                {
                    var ab = b - a;
                    var len2 = ab.DotProduct(ab);
                    if (len2 <= 1e-12)
                    {
                        return a;
                    }

                    var t = (p - a).DotProduct(ab) / len2;
                    t = Math.Max(0.0, Math.Min(1.0, t));
                    return a + (ab * t);
                }

                bool IsHorizontalLike(Point2d a, Point2d b)
                {
                    var d = b - a;
                    return Math.Abs(d.X) >= Math.Abs(d.Y);
                }

                bool IsVerticalLike(Point2d a, Point2d b)
                {
                    var d = b - a;
                    return Math.Abs(d.Y) > Math.Abs(d.X);
                }

                var contextSet = new HashSet<ObjectId>(contextSectionIds.Where(id => !id.IsNull));
                var allBoundarySegments = new List<(ObjectId Id, string Layer, bool IsContext, Point2d A, Point2d B)>();
                var endpointAnchors = new List<(ObjectId Id, string Layer, bool IsContext, Point2d P)>();
                var bt = (BlockTable)tr.GetObject(database.BlockTableId, OpenMode.ForRead);
                var ms = (BlockTableRecord)tr.GetObject(bt[BlockTableRecord.ModelSpace], OpenMode.ForRead);
                foreach (ObjectId id in ms)
                {
                    Entity? ent = null;
                    try
                    {
                        ent = tr.GetObject(id, OpenMode.ForRead, false) as Entity;
                    }
                    catch (Autodesk.AutoCAD.Runtime.Exception)
                    {
                        continue;
                    }

                    if (ent == null || ent.IsErased)
                    {
                        continue;
                    }

                    if (!string.Equals(ent.Layer, "L-SEC", StringComparison.OrdinalIgnoreCase) &&
                        !string.Equals(ent.Layer, "L-USEC", StringComparison.OrdinalIgnoreCase))
                    {
                        continue;
                    }

                    if (!TryReadOpenSegment(ent, out var a, out var b))
                    {
                        continue;
                    }

                    if (!DoesSegmentIntersectAnyWindow(a, b))
                    {
                        continue;
                    }

                    var isContext = contextSet.Contains(id);
                    var layerName = ent.Layer ?? string.Empty;
                    allBoundarySegments.Add((id, layerName, isContext, a, b));
                    endpointAnchors.Add((id, layerName, isContext, a));
                    endpointAnchors.Add((id, layerName, isContext, b));
                }

                if (allBoundarySegments.Count == 0 || endpointAnchors.Count == 0)
                {
                    tr.Commit();
                    return;
                }

                const double endpointSnapTol = 1.15;
                const double segmentSnapTol = 0.95;
                const double moveTol = 0.02;
                var adjusted = 0;
                foreach (var id in contextSet.ToList())
                {
                    Entity? ent = null;
                    try
                    {
                        ent = tr.GetObject(id, OpenMode.ForWrite, false) as Entity;
                    }
                    catch (Autodesk.AutoCAD.Runtime.Exception)
                    {
                        continue;
                    }

                    if (ent == null || ent.IsErased)
                    {
                        continue;
                    }

                    if (!TryReadOpenSegment(ent, out var p0, out var p1))
                    {
                        continue;
                    }

                    var currentLayer = ent.Layer ?? string.Empty;
                    bool TryBestEndpointSnap(Point2d endpoint, out Point2d snapped)
                    {
                        snapped = endpoint;
                        var found = false;
                        var bestDist = double.MaxValue;
                        var bestTargetIsContext = true;
                        for (var i = 0; i < endpointAnchors.Count; i++)
                        {
                            var anchor = endpointAnchors[i];
                            if (anchor.Id == id)
                            {
                                continue;
                            }

                            if (!string.Equals(anchor.Layer, currentLayer, StringComparison.OrdinalIgnoreCase))
                            {
                                continue;
                            }

                            var d = endpoint.GetDistanceTo(anchor.P);
                            if (d > endpointSnapTol)
                            {
                                continue;
                            }

                            var prefer = !anchor.IsContext;
                            var better = !found;
                            if (!better)
                            {
                                if (prefer && bestTargetIsContext)
                                {
                                    better = true;
                                }
                                else if (prefer == !bestTargetIsContext && d < (bestDist - 1e-9))
                                {
                                    better = true;
                                }
                            }

                            if (!better)
                            {
                                continue;
                            }

                            found = true;
                            bestDist = d;
                            bestTargetIsContext = anchor.IsContext;
                            snapped = anchor.P;
                        }

                        return found;
                    }

                    bool TryBestSegmentSnap(Point2d endpoint, Point2d otherEndpoint, out Point2d snapped)
                    {
                        snapped = endpoint;
                        var found = false;
                        var bestDist = double.MaxValue;
                        var thisIsHorizontal = IsHorizontalLike(endpoint, otherEndpoint);
                        var thisIsVertical = IsVerticalLike(endpoint, otherEndpoint);
                        for (var i = 0; i < allBoundarySegments.Count; i++)
                        {
                            var seg = allBoundarySegments[i];
                            if (seg.Id == id)
                            {
                                continue;
                            }

                            if (!string.Equals(seg.Layer, currentLayer, StringComparison.OrdinalIgnoreCase))
                            {
                                continue;
                            }

                            var segIsHorizontal = IsHorizontalLike(seg.A, seg.B);
                            var segIsVertical = IsVerticalLike(seg.A, seg.B);
                            if ((thisIsHorizontal && !segIsHorizontal) ||
                                (thisIsVertical && !segIsVertical))
                            {
                                continue;
                            }

                            var candidate = ClosestPointOnSegment(endpoint, seg.A, seg.B);
                            var d = endpoint.GetDistanceTo(candidate);
                            if (d > segmentSnapTol)
                            {
                                continue;
                            }

                            if (!found || d < (bestDist - 1e-9))
                            {
                                found = true;
                                bestDist = d;
                                snapped = candidate;
                            }
                        }

                        return found;
                    }

                    var new0 = p0;
                    var new1 = p1;
                    if (!TryBestEndpointSnap(new0, out new0))
                    {
                        TryBestSegmentSnap(p0, p1, out new0);
                    }

                    if (!TryBestEndpointSnap(new1, out new1))
                    {
                        TryBestSegmentSnap(p1, p0, out new1);
                    }

                    if (new0.GetDistanceTo(p0) <= moveTol && new1.GetDistanceTo(p1) <= moveTol)
                    {
                        continue;
                    }

                    if (TryWriteOpenSegment(ent, new0, new1))
                    {
                        adjusted++;
                    }
                }

                tr.Commit();
                if (adjusted > 0)
                {
                    logger?.WriteLine($"Cleanup: stitched {adjusted} trimmed context segment endpoint(s) to nearby final boundaries.");
                }
            }
        }

        private static void RebuildLsdLabelsAtFinalIntersections(
            Database database,
            IEnumerable<QuarterLabelInfo> quarterInfos,
            Logger? logger)
        {
            if (database == null || quarterInfos == null)
            {
                return;
            }

            var uniqueQuarterInfos = new Dictionary<ObjectId, QuarterLabelInfo>();
            foreach (var info in quarterInfos)
            {
                if (info == null || info.QuarterId.IsNull || info.QuarterId.IsErased)
                {
                    continue;
                }

                if (!uniqueQuarterInfos.ContainsKey(info.QuarterId))
                {
                    uniqueQuarterInfos.Add(info.QuarterId, info);
                }
            }

            if (uniqueQuarterInfos.Count == 0)
            {
                return;
            }

            var clipWindows = BuildBufferedQuarterWindows(database, uniqueQuarterInfos.Keys, 100.0);
            bool IsPointInAnyWindow(Point2d p)
            {
                if (clipWindows == null || clipWindows.Count == 0)
                {
                    return true;
                }

                for (var i = 0; i < clipWindows.Count; i++)
                {
                    var w = clipWindows[i];
                    if (p.X >= w.MinPoint.X && p.X <= w.MaxPoint.X &&
                        p.Y >= w.MinPoint.Y && p.Y <= w.MaxPoint.Y)
                    {
                        return true;
                    }
                }

                return false;
            }

            bool DoesSegmentIntersectAnyWindow(Point2d a, Point2d b)
            {
                if (clipWindows == null || clipWindows.Count == 0)
                {
                    return true;
                }

                if (IsPointInAnyWindow(a) || IsPointInAnyWindow(b))
                {
                    return true;
                }

                for (var i = 0; i < clipWindows.Count; i++)
                {
                    if (TryClipSegmentToWindow(a, b, clipWindows[i], out _, out _))
                    {
                        return true;
                    }
                }

                return false;
            }

            using (var tr = database.TransactionManager.StartTransaction())
            {
                bool TryReadOpenSegment(Entity ent, out Point2d a, out Point2d b)
                {
                    a = default;
                    b = default;
                    if (ent == null)
                    {
                        return false;
                    }

                    if (ent is Line ln)
                    {
                        a = new Point2d(ln.StartPoint.X, ln.StartPoint.Y);
                        b = new Point2d(ln.EndPoint.X, ln.EndPoint.Y);
                        return a.GetDistanceTo(b) > 1e-4;
                    }

                    if (ent is Polyline pl)
                    {
                        if (pl.Closed || pl.NumberOfVertices != 2)
                        {
                            return false;
                        }

                        a = pl.GetPoint2dAt(0);
                        b = pl.GetPoint2dAt(1);
                        return a.GetDistanceTo(b) > 1e-4;
                    }

                    return false;
                }

                bool TryGetEntityCenter(Entity ent, out Point2d center)
                {
                    center = default;
                    if (ent == null)
                    {
                        return false;
                    }

                    try
                    {
                        var ext = ent.GeometricExtents;
                        center = new Point2d(
                            0.5 * (ext.MinPoint.X + ext.MaxPoint.X),
                            0.5 * (ext.MinPoint.Y + ext.MaxPoint.Y));
                        return true;
                    }
                    catch
                    {
                        if (ent is DBText dbt)
                        {
                            center = new Point2d(dbt.Position.X, dbt.Position.Y);
                            return true;
                        }

                        if (ent is MText mt)
                        {
                            center = new Point2d(mt.Location.X, mt.Location.Y);
                            return true;
                        }

                        if (ent is BlockReference br)
                        {
                            center = new Point2d(br.Position.X, br.Position.Y);
                            return true;
                        }
                    }

                    return false;
                }

                bool IsHorizontalLike(Point2d a, Point2d b)
                {
                    var d = b - a;
                    return Math.Abs(d.X) >= Math.Abs(d.Y);
                }

                bool IsVerticalLike(Point2d a, Point2d b)
                {
                    var d = b - a;
                    return Math.Abs(d.Y) > Math.Abs(d.X);
                }

                bool TryIntersectSegments(Point2d a0, Point2d a1, Point2d b0, Point2d b1, out Point2d intersection)
                {
                    intersection = default;
                    var da = a1 - a0;
                    var db = b1 - b0;
                    var denom = Cross2d(da, db);
                    if (Math.Abs(denom) <= 1e-9)
                    {
                        return false;
                    }

                    var diff = b0 - a0;
                    var t = Cross2d(diff, db) / denom;
                    var u = Cross2d(diff, da) / denom;
                    if (t < -1e-6 || t > 1.0 + 1e-6 || u < -1e-6 || u > 1.0 + 1e-6)
                    {
                        return false;
                    }

                    intersection = a0 + (da * t);
                    return true;
                }

                bool TryIntersectInfiniteLines(Point2d a0, Point2d a1, Point2d b0, Point2d b1, out Point2d intersection)
                {
                    intersection = default;
                    var da = a1 - a0;
                    var db = b1 - b0;
                    var denom = Cross2d(da, db);
                    if (Math.Abs(denom) <= 1e-9)
                    {
                        return false;
                    }

                    var diff = b0 - a0;
                    var t = Cross2d(diff, db) / denom;
                    intersection = a0 + (da * t);
                    return true;
                }

                bool IsPointInExpandedExtents(Point2d p, Extents3d ext, double tol)
                {
                    return p.X >= (ext.MinPoint.X - tol) && p.X <= (ext.MaxPoint.X + tol) &&
                           p.Y >= (ext.MinPoint.Y - tol) && p.Y <= (ext.MaxPoint.Y + tol);
                }

                EnsureLayer(database, tr, "L-SECTION-LSD");
                var bt = (BlockTable)tr.GetObject(database.BlockTableId, OpenMode.ForRead);
                var ms = (BlockTableRecord)tr.GetObject(bt[BlockTableRecord.ModelSpace], OpenMode.ForWrite);

                var horizontalLsdSegments = new List<(Point2d A, Point2d B, Point2d Mid)>();
                var verticalLsdSegments = new List<(Point2d A, Point2d B, Point2d Mid)>();
                var oldLabelEntities = new Dictionary<ObjectId, Point2d>();
                foreach (ObjectId id in ms)
                {
                    if (!(tr.GetObject(id, OpenMode.ForRead, false) is Entity ent) || ent.IsErased)
                    {
                        continue;
                    }

                    if (!string.Equals(ent.Layer, "L-SECTION-LSD", StringComparison.OrdinalIgnoreCase))
                    {
                        continue;
                    }

                    if (TryReadOpenSegment(ent, out var a, out var b))
                    {
                        if (!DoesSegmentIntersectAnyWindow(a, b))
                        {
                            continue;
                        }

                        var mid = Midpoint(a, b);
                        if (IsAdjustableLsdLineSegment(a, b))
                        {
                            if (IsHorizontalLike(a, b))
                            {
                                horizontalLsdSegments.Add((a, b, mid));
                            }
                            else if (IsVerticalLike(a, b))
                            {
                                verticalLsdSegments.Add((a, b, mid));
                            }
                        }
                        else if (IsPointInAnyWindow(mid))
                        {
                            oldLabelEntities[id] = mid;
                        }

                        continue;
                    }

                    if (TryGetEntityCenter(ent, out var center) && IsPointInAnyWindow(center))
                    {
                        oldLabelEntities[id] = center;
                    }
                }

                if (horizontalLsdSegments.Count == 0 || verticalLsdSegments.Count == 0)
                {
                    tr.Commit();
                    return;
                }

                var placed = 0;
                var erased = 0;
                var skipped = 0;
                var consumedOldLabelIds = new HashSet<ObjectId>();
                foreach (var pair in uniqueQuarterInfos)
                {
                    var info = pair.Value;
                    if (!(tr.GetObject(pair.Key, OpenMode.ForRead, false) is Polyline quarter) || quarter.IsErased)
                    {
                        continue;
                    }

                    var blockName = GetLsdLabelBlockName(info.Quarter);
                    if (string.IsNullOrWhiteSpace(blockName))
                    {
                        continue;
                    }

                    Extents3d quarterExtents;
                    try
                    {
                        quarterExtents = quarter.GeometricExtents;
                    }
                    catch
                    {
                        skipped++;
                        continue;
                    }

                    var quarterCenter = new Point2d(
                        0.5 * (quarterExtents.MinPoint.X + quarterExtents.MaxPoint.X),
                        0.5 * (quarterExtents.MinPoint.Y + quarterExtents.MaxPoint.Y));
                    const double quarterTol = 2.0;
                    var horizontalCandidates = horizontalLsdSegments
                        .Where(s => IsPointInExpandedExtents(s.Mid, quarterExtents, quarterTol))
                        .ToList();
                    var verticalCandidates = verticalLsdSegments
                        .Where(s => IsPointInExpandedExtents(s.Mid, quarterExtents, quarterTol))
                        .ToList();
                    if (horizontalCandidates.Count == 0 || verticalCandidates.Count == 0)
                    {
                        skipped++;
                        continue;
                    }

                    var foundTarget = false;
                    var target = default(Point2d);
                    var bestScore = double.MaxValue;
                    for (var hi = 0; hi < horizontalCandidates.Count; hi++)
                    {
                        var h = horizontalCandidates[hi];
                        for (var vi = 0; vi < verticalCandidates.Count; vi++)
                        {
                            var v = verticalCandidates[vi];
                            if (!TryIntersectSegments(h.A, h.B, v.A, v.B, out var intersection))
                            {
                                continue;
                            }

                            if (!IsPointInExpandedExtents(intersection, quarterExtents, quarterTol))
                            {
                                continue;
                            }

                            var score = quarterCenter.GetDistanceTo(intersection);
                            if (!foundTarget || score < bestScore)
                            {
                                foundTarget = true;
                                bestScore = score;
                                target = intersection;
                            }
                        }
                    }

                    if (!foundTarget)
                    {
                        var bestH = horizontalCandidates
                            .OrderBy(s => DistancePointToSegment(quarterCenter, s.A, s.B))
                            .First();
                        var bestV = verticalCandidates
                            .OrderBy(s => DistancePointToSegment(quarterCenter, s.A, s.B))
                            .First();
                        if (TryIntersectInfiniteLines(bestH.A, bestH.B, bestV.A, bestV.B, out var fallback) &&
                            IsPointInExpandedExtents(fallback, quarterExtents, 4.0))
                        {
                            foundTarget = true;
                            target = fallback;
                        }
                    }

                    if (!foundTarget)
                    {
                        skipped++;
                        continue;
                    }

                    foreach (var old in oldLabelEntities)
                    {
                        if (consumedOldLabelIds.Contains(old.Key))
                        {
                            continue;
                        }

                        if (!IsPointInExpandedExtents(old.Value, quarterExtents, quarterTol))
                        {
                            continue;
                        }

                        if (!(tr.GetObject(old.Key, OpenMode.ForWrite, false) is Entity oldEnt) || oldEnt.IsErased)
                        {
                            continue;
                        }

                        oldEnt.Erase();
                        consumedOldLabelIds.Add(old.Key);
                        erased++;
                    }

                    InsertAndExplodeLsdLabelBlock(
                        database,
                        tr,
                        ms,
                        editor: null,
                        info.Quarter,
                        new Point3d(target.X, target.Y, 0.0),
                        "L-SECTION-LSD");
                    placed++;
                }

                tr.Commit();
                if (placed > 0 || erased > 0 || skipped > 0)
                {
                    logger?.WriteLine($"Cleanup: rebuilt {placed} LSD label block(s) at final quarter intersections (erased {erased} stale label entity/ies, skipped {skipped} quarter(s)).");
                }
            }
        }

        private static void SnapQuarterLsdLinesToSectionBoundaries(Database database, IEnumerable<ObjectId> requestedQuarterIds, Logger? logger)
        {
            if (database == null || requestedQuarterIds == null)
            {
                return;
            }

            var clipWindows = BuildBufferedQuarterWindows(database, requestedQuarterIds, 100.0);
            if (clipWindows.Count == 0)
            {
                return;
            }

            bool IsPointInAnyWindow(Point2d p)
            {
                for (var i = 0; i < clipWindows.Count; i++)
                {
                    var w = clipWindows[i];
                    if (p.X >= w.MinPoint.X && p.X <= w.MaxPoint.X &&
                        p.Y >= w.MinPoint.Y && p.Y <= w.MaxPoint.Y)
                    {
                        return true;
                    }
                }

                return false;
            }

            using (var tr = database.TransactionManager.StartTransaction())
            {
                bool TryReadOpenSegment(Entity ent, out Point2d a, out Point2d b)
                {
                    a = default;
                    b = default;
                    if (ent == null)
                    {
                        return false;
                    }

                    if (ent is Line ln)
                    {
                        a = new Point2d(ln.StartPoint.X, ln.StartPoint.Y);
                        b = new Point2d(ln.EndPoint.X, ln.EndPoint.Y);
                        return a.GetDistanceTo(b) > 1e-4;
                    }

                    if (ent is Polyline pl)
                    {
                        if (pl.Closed || pl.NumberOfVertices != 2)
                        {
                            return false;
                        }

                        a = pl.GetPoint2dAt(0);
                        b = pl.GetPoint2dAt(1);
                        return a.GetDistanceTo(b) > 1e-4;
                    }

                    return false;
                }

                var sectionBoundarySegments = new List<(Point2d A, Point2d B)>();
                var lsdLineIds = new List<ObjectId>();
                var bt = (BlockTable)tr.GetObject(database.BlockTableId, OpenMode.ForRead);
                var ms = (BlockTableRecord)tr.GetObject(bt[BlockTableRecord.ModelSpace], OpenMode.ForRead);
                foreach (ObjectId id in ms)
                {
                    if (!(tr.GetObject(id, OpenMode.ForRead, false) is Entity ent))
                    {
                        continue;
                    }

                    if (string.Equals(ent.Layer, "L-SECTION-LSD", StringComparison.OrdinalIgnoreCase))
                    {
                        if (ent is Line)
                        {
                            lsdLineIds.Add(id);
                        }

                        continue;
                    }

                    if (!string.Equals(ent.Layer, "L-SEC", StringComparison.OrdinalIgnoreCase) &&
                        !string.Equals(ent.Layer, "L-USEC", StringComparison.OrdinalIgnoreCase) &&
                        !string.Equals(ent.Layer, "L-QSEC", StringComparison.OrdinalIgnoreCase))
                    {
                        continue;
                    }

                    if (!TryReadOpenSegment(ent, out var a, out var b))
                    {
                        continue;
                    }

                    var mid = Midpoint(a, b);
                    if (!IsPointInAnyWindow(mid))
                    {
                        continue;
                    }

                    sectionBoundarySegments.Add((a, b));
                }

                if (sectionBoundarySegments.Count == 0 || lsdLineIds.Count == 0)
                {
                    tr.Commit();
                    return;
                }

                var adjusted = 0;
                const double minT = 1e-3;
                const double endpointMoveTol = 0.05;

                foreach (var id in lsdLineIds)
                {
                    if (!(tr.GetObject(id, OpenMode.ForWrite, false) is Line ln) || ln.IsErased)
                    {
                        continue;
                    }

                    var p0 = new Point2d(ln.StartPoint.X, ln.StartPoint.Y);
                    var p1 = new Point2d(ln.EndPoint.X, ln.EndPoint.Y);
                    if (!IsAdjustableLsdLineSegment(p0, p1))
                    {
                        continue;
                    }

                    var center = Midpoint(p0, p1);
                    if (!IsPointInAnyWindow(center))
                    {
                        continue;
                    }

                    var dirVec = p1 - p0;
                    var len = dirVec.Length;
                    if (len <= 1e-4)
                    {
                        continue;
                    }

                    var dir = dirVec / len;
                    var tMin = -0.5 * len;
                    var tMax = 0.5 * len;
                    double? bestNeg = null;
                    double? bestPos = null;

                    foreach (var seg in sectionBoundarySegments)
                    {
                        if (!TryIntersectInfiniteLineWithSegment(center, dir, seg.A, seg.B, out var t))
                        {
                            continue;
                        }

                        if (t < -minT)
                        {
                            if (!bestNeg.HasValue || t > bestNeg.Value)
                            {
                                bestNeg = t;
                            }
                        }
                        else if (t > minT)
                        {
                            if (!bestPos.HasValue || t < bestPos.Value)
                            {
                                bestPos = t;
                            }
                        }
                    }

                    var newTMin = bestNeg ?? tMin;
                    var newTMax = bestPos ?? tMax;
                    if (newTMax - newTMin <= minT)
                    {
                        continue;
                    }

                    var newA = center + (dir * newTMin);
                    var newB = center + (dir * newTMax);
                    if (newA.GetDistanceTo(p0) <= endpointMoveTol && newB.GetDistanceTo(p1) <= endpointMoveTol)
                    {
                        continue;
                    }

                    ln.StartPoint = new Point3d(newA.X, newA.Y, ln.StartPoint.Z);
                    ln.EndPoint = new Point3d(newB.X, newB.Y, ln.EndPoint.Z);
                    adjusted++;
                }

                tr.Commit();
                if (adjusted > 0)
                {
                    logger?.WriteLine($"Cleanup: adjusted {adjusted} L-SECTION-LSD line(s) to nearest L-SEC/L-USEC boundaries.");
                }
            }
        }

        private static void RecenterExplodedLsdLabelsToFinalLinework(
            Database database,
            IEnumerable<ObjectId> requestedQuarterIds,
            Logger? logger)
        {
            if (database == null || requestedQuarterIds == null)
            {
                return;
            }

            var clipWindows = BuildBufferedQuarterWindows(database, requestedQuarterIds, 100.0);
            if (clipWindows.Count == 0)
            {
                return;
            }

            bool IsPointInAnyWindow(Point2d p)
            {
                for (var i = 0; i < clipWindows.Count; i++)
                {
                    var w = clipWindows[i];
                    if (p.X >= w.MinPoint.X && p.X <= w.MaxPoint.X &&
                        p.Y >= w.MinPoint.Y && p.Y <= w.MaxPoint.Y)
                    {
                        return true;
                    }
                }

                return false;
            }

            bool DoesSegmentIntersectAnyWindow(Point2d a, Point2d b)
            {
                if (IsPointInAnyWindow(a) || IsPointInAnyWindow(b))
                {
                    return true;
                }

                for (var i = 0; i < clipWindows.Count; i++)
                {
                    if (TryClipSegmentToWindow(a, b, clipWindows[i], out _, out _))
                    {
                        return true;
                    }
                }

                return false;
            }

            bool TryReadOpenSegment(Entity ent, out Point2d a, out Point2d b)
            {
                a = default;
                b = default;
                if (ent == null)
                {
                    return false;
                }

                if (ent is Line ln)
                {
                    a = new Point2d(ln.StartPoint.X, ln.StartPoint.Y);
                    b = new Point2d(ln.EndPoint.X, ln.EndPoint.Y);
                    return a.GetDistanceTo(b) > 1e-4;
                }

                if (ent is Polyline pl)
                {
                    if (pl.Closed || pl.NumberOfVertices < 2)
                    {
                        return false;
                    }

                    a = pl.GetPoint2dAt(0);
                    b = pl.GetPoint2dAt(pl.NumberOfVertices - 1);
                    if (a.GetDistanceTo(b) <= 1e-4)
                    {
                        return false;
                    }

                    if (pl.NumberOfVertices > 2)
                    {
                        const double collinearTol = 0.35;
                        for (var vi = 1; vi < pl.NumberOfVertices - 1; vi++)
                        {
                            var p = pl.GetPoint2dAt(vi);
                            if (DistancePointToInfiniteLine(p, a, b) > collinearTol)
                            {
                                return false;
                            }
                        }
                    }

                    return true;
                }

                return false;
            }

            bool IsHorizontalLike(Point2d a, Point2d b)
            {
                var d = b - a;
                return Math.Abs(d.X) >= Math.Abs(d.Y);
            }

            bool IsVerticalLike(Point2d a, Point2d b)
            {
                var d = b - a;
                return Math.Abs(d.Y) > Math.Abs(d.X);
            }

            bool TryGetEntityCenter(Entity ent, out Point2d center)
            {
                center = default;
                if (ent == null)
                {
                    return false;
                }

                try
                {
                    var ext = ent.GeometricExtents;
                    center = new Point2d(
                        0.5 * (ext.MinPoint.X + ext.MaxPoint.X),
                        0.5 * (ext.MinPoint.Y + ext.MaxPoint.Y));
                    return true;
                }
                catch
                {
                    if (ent is DBText dbt)
                    {
                        center = new Point2d(dbt.Position.X, dbt.Position.Y);
                        return true;
                    }

                    if (ent is MText mt)
                    {
                        center = new Point2d(mt.Location.X, mt.Location.Y);
                        return true;
                    }

                    if (ent is BlockReference br)
                    {
                        center = new Point2d(br.Position.X, br.Position.Y);
                        return true;
                    }
                }

                return false;
            }

            bool TryIntersectSegments(Point2d a0, Point2d a1, Point2d b0, Point2d b1, out Point2d intersection)
            {
                intersection = default;
                var da = a1 - a0;
                var db = b1 - b0;
                var denom = Cross2d(da, db);
                if (Math.Abs(denom) <= 1e-9)
                {
                    return false;
                }

                var diff = b0 - a0;
                var t = Cross2d(diff, db) / denom;
                var u = Cross2d(diff, da) / denom;
                if (t < -1e-6 || t > 1.0 + 1e-6 || u < -1e-6 || u > 1.0 + 1e-6)
                {
                    return false;
                }

                intersection = a0 + (da * t);
                return true;
            }

            using (var tr = database.TransactionManager.StartTransaction())
            {
                var horizontalLsdSegments = new List<(Point2d A, Point2d B)>();
                var verticalLsdSegments = new List<(Point2d A, Point2d B)>();
                var labelEntityCenters = new Dictionary<ObjectId, Point2d>();
                var bt = (BlockTable)tr.GetObject(database.BlockTableId, OpenMode.ForRead);
                var ms = (BlockTableRecord)tr.GetObject(bt[BlockTableRecord.ModelSpace], OpenMode.ForRead);
                foreach (ObjectId id in ms)
                {
                    if (!(tr.GetObject(id, OpenMode.ForRead, false) is Entity ent) || ent.IsErased)
                    {
                        continue;
                    }

                    if (!string.Equals(ent.Layer, "L-SECTION-LSD", StringComparison.OrdinalIgnoreCase))
                    {
                        continue;
                    }

                    if (TryReadOpenSegment(ent, out var a, out var b))
                    {
                        if (IsAdjustableLsdLineSegment(a, b))
                        {
                            if (!DoesSegmentIntersectAnyWindow(a, b))
                            {
                                continue;
                            }

                            if (IsHorizontalLike(a, b))
                            {
                                horizontalLsdSegments.Add((a, b));
                            }
                            else if (IsVerticalLike(a, b))
                            {
                                verticalLsdSegments.Add((a, b));
                            }

                            continue;
                        }

                        var shortMid = Midpoint(a, b);
                        if (IsPointInAnyWindow(shortMid))
                        {
                            labelEntityCenters[id] = shortMid;
                        }

                        continue;
                    }

                    if (TryGetEntityCenter(ent, out var center) && IsPointInAnyWindow(center))
                    {
                        labelEntityCenters[id] = center;
                    }
                }

                if (horizontalLsdSegments.Count == 0 ||
                    verticalLsdSegments.Count == 0 ||
                    labelEntityCenters.Count == 0)
                {
                    tr.Commit();
                    return;
                }

                var targetCenters = new List<Point2d>();
                var targetDedupe = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
                for (var hi = 0; hi < horizontalLsdSegments.Count; hi++)
                {
                    var h = horizontalLsdSegments[hi];
                    for (var vi = 0; vi < verticalLsdSegments.Count; vi++)
                    {
                        var v = verticalLsdSegments[vi];
                        if (!TryIntersectSegments(h.A, h.B, v.A, v.B, out var intersection))
                        {
                            continue;
                        }

                        if (!IsPointInAnyWindow(intersection))
                        {
                            continue;
                        }

                        var key = string.Format(
                            CultureInfo.InvariantCulture,
                            "{0:0.###}|{1:0.###}",
                            intersection.X,
                            intersection.Y);
                        if (!targetDedupe.Add(key))
                        {
                            continue;
                        }

                        targetCenters.Add(intersection);
                    }
                }

                if (targetCenters.Count == 0)
                {
                    tr.Commit();
                    return;
                }

                const double clusterJoinTol = 24.0;
                var remaining = new HashSet<ObjectId>(labelEntityCenters.Keys);
                var clusters = new List<List<ObjectId>>();
                while (remaining.Count > 0)
                {
                    var seed = remaining.First();
                    remaining.Remove(seed);

                    var cluster = new List<ObjectId> { seed };
                    var queue = new Queue<ObjectId>();
                    queue.Enqueue(seed);
                    while (queue.Count > 0)
                    {
                        var current = queue.Dequeue();
                        var currentCenter = labelEntityCenters[current];
                        var nearby = new List<ObjectId>();
                        foreach (var other in remaining)
                        {
                            if (currentCenter.GetDistanceTo(labelEntityCenters[other]) <= clusterJoinTol)
                            {
                                nearby.Add(other);
                            }
                        }

                        for (var i = 0; i < nearby.Count; i++)
                        {
                            var other = nearby[i];
                            remaining.Remove(other);
                            cluster.Add(other);
                            queue.Enqueue(other);
                        }
                    }

                    clusters.Add(cluster);
                }

                if (clusters.Count == 0)
                {
                    tr.Commit();
                    return;
                }

                var clusterInfos = new List<(List<ObjectId> Ids, Point2d Center, double ClosestDistance)>();
                for (var i = 0; i < clusters.Count; i++)
                {
                    var cluster = clusters[i];
                    var sumX = 0.0;
                    var sumY = 0.0;
                    for (var j = 0; j < cluster.Count; j++)
                    {
                        var c = labelEntityCenters[cluster[j]];
                        sumX += c.X;
                        sumY += c.Y;
                    }

                    var center = new Point2d(sumX / cluster.Count, sumY / cluster.Count);
                    var nearest = double.MaxValue;
                    for (var ti = 0; ti < targetCenters.Count; ti++)
                    {
                        var d = center.GetDistanceTo(targetCenters[ti]);
                        if (d < nearest)
                        {
                            nearest = d;
                        }
                    }

                    clusterInfos.Add((cluster, center, nearest));
                }

                var orderedClusters = clusterInfos
                    .OrderBy(ci => ci.ClosestDistance)
                    .ToList();

                var usedTargets = new bool[targetCenters.Count];
                const double maxSnapDistance = 80.0;
                const double minMoveTol = 0.05;
                const double ambiguousTargetDeltaTol = 1.5;
                var movedClusters = 0;
                var movedEntities = 0;
                var ambiguousClustersSkipped = 0;
                for (var i = 0; i < orderedClusters.Count; i++)
                {
                    var cluster = orderedClusters[i];
                    var bestTargetIndex = -1;
                    var bestDistance = double.MaxValue;
                    var secondBestDistance = double.MaxValue;
                    for (var ti = 0; ti < targetCenters.Count; ti++)
                    {
                        if (usedTargets[ti])
                        {
                            continue;
                        }

                        var d = cluster.Center.GetDistanceTo(targetCenters[ti]);
                        if (d < bestDistance)
                        {
                            secondBestDistance = bestDistance;
                            bestDistance = d;
                            bestTargetIndex = ti;
                        }
                        else if (d < secondBestDistance)
                        {
                            secondBestDistance = d;
                        }
                    }

                    if (bestTargetIndex < 0 || bestDistance > maxSnapDistance)
                    {
                        continue;
                    }

                    if (secondBestDistance < double.MaxValue &&
                        (secondBestDistance - bestDistance) <= ambiguousTargetDeltaTol)
                    {
                        ambiguousClustersSkipped++;
                        continue;
                    }

                    usedTargets[bestTargetIndex] = true;
                    if (bestDistance <= minMoveTol)
                    {
                        continue;
                    }

                    var target = targetCenters[bestTargetIndex];
                    var displacement = new Vector3d(
                        target.X - cluster.Center.X,
                        target.Y - cluster.Center.Y,
                        0.0);
                    var transform = Matrix3d.Displacement(displacement);
                    var movedAny = false;
                    for (var j = 0; j < cluster.Ids.Count; j++)
                    {
                        var id = cluster.Ids[j];
                        if (!(tr.GetObject(id, OpenMode.ForWrite, false) is Entity writable) || writable.IsErased)
                        {
                            continue;
                        }

                        try
                        {
                            writable.TransformBy(transform);
                            movedEntities++;
                            movedAny = true;
                        }
                        catch
                        {
                        }
                    }

                    if (movedAny)
                    {
                        movedClusters++;
                    }
                }

                tr.Commit();
                if (movedClusters > 0)
                {
                    logger?.WriteLine($"Cleanup: recentered {movedClusters} LSD label block cluster(s) to final LSD line intersections ({movedEntities} entity move(s)).");
                }
                if (ambiguousClustersSkipped > 0)
                {
                    logger?.WriteLine($"Cleanup: skipped {ambiguousClustersSkipped} ambiguous LSD label cluster snap(s).");
                }
            }
        }

        private static bool TryIntersectInfiniteLineWithSegment(Point2d linePoint, Vector2d lineDir, Point2d segA, Point2d segB, out double tOnLine)
        {
            tOnLine = 0.0;
            var segDir = segB - segA;
            var denom = Cross2d(lineDir, segDir);
            if (Math.Abs(denom) <= 1e-9)
            {
                return false;
            }

            var diff = segA - linePoint;
            var t = Cross2d(diff, segDir) / denom;
            var u = Cross2d(diff, lineDir) / denom;
            if (u < -1e-6 || u > 1.0 + 1e-6)
            {
                return false;
            }

            tOnLine = t;
            return true;
        }

        private static double Cross2d(Vector2d a, Vector2d b)
        {
            return (a.X * b.Y) - (a.Y * b.X);
        }

        private static bool IsAdjustableLsdLineSegment(Point2d a, Point2d b)
        {
            return a.GetDistanceTo(b) >= MinAdjustableLsdLineLengthMeters;
        }

        private static void GetCanonicalSegmentEndpoints(Point2d a, Point2d b, out Point2d first, out Point2d second)
        {
            first = a;
            second = b;
            if (second.X < first.X || (Math.Abs(second.X - first.X) <= 1e-9 && second.Y < first.Y))
            {
                var tmp = first;
                first = second;
                second = tmp;
            }
        }

        private static bool AreSegmentEndpointsNear(Point2d a0, Point2d a1, Point2d b0, Point2d b1, double endpointTol)
        {
            GetCanonicalSegmentEndpoints(a0, a1, out var aFirst, out var aSecond);
            GetCanonicalSegmentEndpoints(b0, b1, out var bFirst, out var bSecond);
            return aFirst.GetDistanceTo(bFirst) <= endpointTol &&
                   aSecond.GetDistanceTo(bSecond) <= endpointTol;
        }

        private static bool AreSegmentsDuplicateOrCollinearOverlap(Point2d a0, Point2d a1, Point2d b0, Point2d b1)
        {
            const double endpointTol = 0.12;
            const double angleTol = 0.003;
            const double distanceTol = 0.25;
            const double overlapTol = 0.20;

            bool Near(Point2d p, Point2d q) => p.GetDistanceTo(q) <= endpointTol;
            if ((Near(a0, b0) && Near(a1, b1)) || (Near(a0, b1) && Near(a1, b0)))
            {
                return true;
            }

            var ua = a1 - a0;
            var ub = b1 - b0;
            var la = ua.Length;
            var lb = ub.Length;
            if (la <= 1e-6 || lb <= 1e-6)
            {
                return false;
            }

            var cross = Math.Abs((ua.X * ub.Y) - (ua.Y * ub.X)) / (la * lb);
            if (cross > angleTol)
            {
                return false;
            }

            if (DistancePointToInfiniteLine(b0, a0, a1) > distanceTol ||
                DistancePointToInfiniteLine(b1, a0, a1) > distanceTol)
            {
                return false;
            }

            var axis = ua / la;
            var aMin = 0.0;
            var aMax = la;
            var tB0 = (b0 - a0).DotProduct(axis);
            var tB1 = (b1 - a0).DotProduct(axis);
            var bMin = Math.Min(tB0, tB1);
            var bMax = Math.Max(tB0, tB1);
            var overlap = Math.Min(aMax, bMax) - Math.Max(aMin, bMin);
            return overlap > overlapTol;
        }

        private static double DistancePointToInfiniteLine(Point2d p, Point2d a, Point2d b)
        {
            var ab = b - a;
            var len = ab.Length;
            if (len <= 1e-9)
            {
                return p.GetDistanceTo(a);
            }

            return Math.Abs((ab.X * (p.Y - a.Y)) - (ab.Y * (p.X - a.X))) / len;
        }

        private static bool TryClipSegmentToWindow(Point2d start, Point2d end, Extents3d? window, out Point2d clippedStart, out Point2d clippedEnd)
        {
            clippedStart = start;
            clippedEnd = end;
            if (!window.HasValue)
            {
                return start.GetDistanceTo(end) > 1e-6;
            }

            var w = window.Value;
            var xmin = w.MinPoint.X;
            var xmax = w.MaxPoint.X;
            var ymin = w.MinPoint.Y;
            var ymax = w.MaxPoint.Y;

            double x0 = start.X;
            double y0 = start.Y;
            double x1 = end.X;
            double y1 = end.Y;
            double dx = x1 - x0;
            double dy = y1 - y0;
            double t0 = 0.0;
            double t1 = 1.0;

            bool Clip(double p, double q)
            {
                if (Math.Abs(p) <= 1e-12)
                {
                    return q >= 0.0;
                }

                var r = q / p;
                if (p < 0.0)
                {
                    if (r > t1) return false;
                    if (r > t0) t0 = r;
                }
                else
                {
                    if (r < t0) return false;
                    if (r < t1) t1 = r;
                }

                return true;
            }

            if (!Clip(-dx, x0 - xmin) ||
                !Clip(dx, xmax - x0) ||
                !Clip(-dy, y0 - ymin) ||
                !Clip(dy, ymax - y0) ||
                t1 < t0)
            {
                return false;
            }

            clippedStart = new Point2d(x0 + t0 * dx, y0 + t0 * dy);
            clippedEnd = new Point2d(x0 + t1 * dx, y0 + t1 * dy);
            return clippedStart.GetDistanceTo(clippedEnd) > 1e-6;
        }

        private static SectionBuildResult DrawSectionFromIndex(
            Editor editor,
            Database database,
            SectionOutline outline,
            SectionKey key,
            bool drawLsds,
            string secType,
            IReadOnlyDictionary<QuarterSelection, string>? quarterSecTypes = null)
        {
            var quarterIds = new Dictionary<QuarterSelection, ObjectId>();
            var quarterHelperEntityIds = new List<ObjectId>();
            ObjectId sectionLabelId = ObjectId.Null;
            ObjectId sectionId;
            var normalizedSecType = NormalizeSecType(secType);
            using (var transaction = database.TransactionManager.StartTransaction())
            {
                var blockTable = (BlockTable)transaction.GetObject(database.BlockTableId, OpenMode.ForRead);
                var modelSpace = (BlockTableRecord)transaction.GetObject(blockTable[BlockTableRecord.ModelSpace], OpenMode.ForWrite);
                EnsureSecTypeLayers(database, transaction, normalizedSecType, quarterSecTypes);
                EnsureLayer(database, transaction, "L-QSEC");
                EnsureLayer(database, transaction, "L-QSEC-BOX");
                SetLayerVisibility(database, transaction, "L-QSEC-BOX", isOff: true, isPlottable: false);

                var sectionPolyline = new Polyline(outline.Vertices.Count)
                {
                    Closed = outline.Closed,
                    Layer = "L-QSEC-BOX",
                    ColorIndex = 256
                };

                for (var i = 0; i < outline.Vertices.Count; i++)
                {
                    var vertex = outline.Vertices[i];
                    sectionPolyline.AddVertexAt(i, vertex, 0, 0, 0);
                }

                sectionId = modelSpace.AppendEntity(sectionPolyline);
                transaction.AddNewlyCreatedDBObject(sectionPolyline, true);

                if (TryBuildQuarterMap(sectionPolyline, out var quarterMap, out var anchors))
                {
                    var eastUnit = GetUnitVector(anchors.Left, anchors.Right, new Vector2d(1, 0));
                    var northUnit = GetUnitVector(anchors.Bottom, anchors.Top, new Vector2d(0, 1));
                    if (TryGetQuarterCorner(sectionPolyline, eastUnit, northUnit, QuarterCorner.NorthWest, out var nw) &&
                        TryGetQuarterCorner(sectionPolyline, eastUnit, northUnit, QuarterCorner.NorthEast, out var ne) &&
                        TryGetQuarterCorner(sectionPolyline, eastUnit, northUnit, QuarterCorner.SouthWest, out var sw) &&
                        TryGetQuarterCorner(sectionPolyline, eastUnit, northUnit, QuarterCorner.SouthEast, out var se))
                    {
                        foreach (var id in DrawSectionBoundaryQuarterSegmentPolylines(
                            modelSpace,
                            transaction,
                            nw,
                            ne,
                            sw,
                            se,
                            normalizedSecType,
                            quarterSecTypes,
                            clipToWindow: null,
                            anchors.Top,
                            anchors.Right,
                            anchors.Bottom,
                            anchors.Left))
                        {
                            quarterHelperEntityIds.Add(id);
                        }
                    }

                    foreach (var quarter in quarterMap)
                    {
                        quarter.Value.Layer = "L-QSEC-BOX";
                        quarter.Value.ColorIndex = 256;
                        var quarterId = modelSpace.AppendEntity(quarter.Value);
                        transaction.AddNewlyCreatedDBObject(quarter.Value, true);
                        quarterIds[quarter.Key] = quarterId;
                    }

                    var qv = new Line(new Point3d(anchors.Top.X, anchors.Top.Y, 0), new Point3d(anchors.Bottom.X, anchors.Bottom.Y, 0))
                    {
                        Layer = "L-QSEC",
                        ColorIndex = 256
                    };
                    var qh = new Line(new Point3d(anchors.Left.X, anchors.Left.Y, 0), new Point3d(anchors.Right.X, anchors.Right.Y, 0))
                    {
                        Layer = "L-QSEC",
                        ColorIndex = 256
                    };
                    var qvId = modelSpace.AppendEntity(qv);
                    transaction.AddNewlyCreatedDBObject(qv, true);
                    var qhId = modelSpace.AppendEntity(qh);
                    transaction.AddNewlyCreatedDBObject(qh, true);

                    quarterHelperEntityIds.Add(qvId);
                    quarterHelperEntityIds.Add(qhId);

                    if (drawLsds)
                    {
                        DrawLsdSubdivisionLines(
                            database,
                            transaction,
                            modelSpace,
                            editor,
                            quarterMap,
                            anchors,
                            key,
                            normalizedSecType);
                    }

                    var center = new Point3d(
                        0.5 * (anchors.Top.X + anchors.Bottom.X),
                        0.5 * (anchors.Left.Y + anchors.Right.Y),
                        0);
                    sectionLabelId = InsertSectionLabelBlock(modelSpace, blockTable, transaction, editor, center, key);
                }

                transaction.Commit();
            }

            return new SectionBuildResult(sectionId, quarterIds, quarterHelperEntityIds, sectionLabelId);
        }

        private static void EnsureSecTypeLayers(
            Database database,
            Transaction transaction,
            string fallbackSecType,
            IReadOnlyDictionary<QuarterSelection, string>? quarterSecTypes)
        {
            if (database == null || transaction == null)
            {
                return;
            }

            var layers = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
            {
                NormalizeSecType(fallbackSecType)
            };

            if (quarterSecTypes != null)
            {
                foreach (var secType in quarterSecTypes.Values)
                {
                    layers.Add(NormalizeSecType(secType));
                }
            }

            foreach (var layer in layers)
            {
                EnsureLayer(database, transaction, layer);
            }
        }

        private static string ResolveQuarterSecTypeForQuarter(
            IReadOnlyDictionary<QuarterSelection, string>? quarterSecTypes,
            QuarterSelection quarter,
            string fallbackSecType)
        {
            if (quarterSecTypes != null &&
                quarterSecTypes.TryGetValue(quarter, out var secType) &&
                !string.IsNullOrWhiteSpace(secType))
            {
                return NormalizeSecType(secType);
            }

            return NormalizeSecType(fallbackSecType);
        }

        private static void DrawLsdSubdivisionLines(
            Database database,
            Transaction transaction,
            BlockTableRecord modelSpace,
            Editor editor,
            Dictionary<QuarterSelection, Polyline> quarterMap,
            QuarterAnchors sectionAnchors,
            SectionKey key,
            string secType)
        {
            if (quarterMap == null || quarterMap.Count == 0)
            {
                return;
            }

            var lsdLayer = "L-SECTION-LSD";
            EnsureLayer(database, transaction, lsdLayer);

            var eastUnit = GetUnitVector(sectionAnchors.Left, sectionAnchors.Right, new Vector2d(1, 0));
            var northUnit = GetUnitVector(sectionAnchors.Bottom, sectionAnchors.Top, new Vector2d(0, 1));

            foreach (var pair in quarterMap)
            {
                var quarterAnchors = GetLsdAnchorsForQuarter(pair.Value, eastUnit, northUnit);

                var verticalStart = quarterAnchors.Top;
                var verticalEnd = quarterAnchors.Bottom;
                var horizontalStart = quarterAnchors.Left;
                var horizontalEnd = quarterAnchors.Right;

                var vertical = new Line(
                    new Point3d(verticalStart.X, verticalStart.Y, 0),
                    new Point3d(verticalEnd.X, verticalEnd.Y, 0))
                {
                    Layer = lsdLayer,
                    ColorIndex = 256
                };
                var horizontal = new Line(
                    new Point3d(horizontalStart.X, horizontalStart.Y, 0),
                    new Point3d(horizontalEnd.X, horizontalEnd.Y, 0))
                {
                    Layer = lsdLayer,
                    ColorIndex = 256
                };

                modelSpace.AppendEntity(vertical);
                transaction.AddNewlyCreatedDBObject(vertical, true);
                modelSpace.AppendEntity(horizontal);
                transaction.AddNewlyCreatedDBObject(horizontal, true);

                var labelCenter = new Point3d(
                    0.25 * (verticalStart.X + verticalEnd.X + horizontalStart.X + horizontalEnd.X),
                    0.25 * (verticalStart.Y + verticalEnd.Y + horizontalStart.Y + horizontalEnd.Y),
                    0.0);
                InsertAndExplodeLsdLabelBlock(database, transaction, modelSpace, editor, pair.Key, labelCenter, lsdLayer);
            }
        }

        private static List<ObjectId> DrawSectionBoundaryQuarterSegmentPolylines(
            BlockTableRecord modelSpace,
            Transaction transaction,
            Point2d nw,
            Point2d ne,
            Point2d sw,
            Point2d se,
            string secType,
            IReadOnlyDictionary<QuarterSelection, string>? quarterSecTypes,
            Extents3d? clipToWindow,
            Point2d? northQuarter = null,
            Point2d? eastQuarter = null,
            Point2d? southQuarter = null,
            Point2d? westQuarter = null)
        {
            var ids = new List<ObjectId>();
            if (modelSpace == null || transaction == null)
            {
                return ids;
            }

            var wMid = westQuarter ?? Midpoint(nw, sw);
            var eMid = eastQuarter ?? Midpoint(ne, se);
            var nMid = northQuarter ?? Midpoint(nw, ne);
            var sMid = southQuarter ?? Midpoint(sw, se);

            var swType = ResolveQuarterSecTypeForQuarter(quarterSecTypes, QuarterSelection.SouthWest, secType);
            var seType = ResolveQuarterSecTypeForQuarter(quarterSecTypes, QuarterSelection.SouthEast, secType);
            var neType = ResolveQuarterSecTypeForQuarter(quarterSecTypes, QuarterSelection.NorthEast, secType);
            var nwType = ResolveQuarterSecTypeForQuarter(quarterSecTypes, QuarterSelection.NorthWest, secType);

            var segments = new[]
            {
                // Assign each half-edge from its owning quarter to avoid cross-quarter bleed.
                (A: sw, B: sMid, Layer: swType),
                (A: sMid, B: se, Layer: seType),
                (A: se, B: eMid, Layer: seType),
                (A: eMid, B: ne, Layer: neType),
                (A: ne, B: nMid, Layer: neType),
                (A: nMid, B: nw, Layer: nwType),
                (A: nw, B: wMid, Layer: nwType),
                (A: wMid, B: sw, Layer: swType),
            };

            foreach (var seg in segments)
            {
                if (!TryClipSegmentToWindow(seg.A, seg.B, clipToWindow, out var a, out var b))
                {
                    continue;
                }

                var poly = new Polyline(2)
                {
                    Layer = seg.Layer,
                    ColorIndex = 256
                };
                poly.AddVertexAt(0, a, 0, 0, 0);
                poly.AddVertexAt(1, b, 0, 0, 0);
                var id = modelSpace.AppendEntity(poly);
                transaction.AddNewlyCreatedDBObject(poly, true);
                ids.Add(id);
            }

            return ids;
        }

        private static List<ObjectId> DrawSectionBoundaryQuarterSegmentPolylines(
            BlockTableRecord modelSpace,
            Transaction transaction,
            Point2d nw,
            Point2d ne,
            Point2d sw,
            Point2d se,
            string secType,
            IReadOnlyDictionary<QuarterSelection, string>? quarterSecTypes,
            IReadOnlyList<Extents3d> clipWindows,
            Point2d? northQuarter = null,
            Point2d? eastQuarter = null,
            Point2d? southQuarter = null,
            Point2d? westQuarter = null)
        {
            if (clipWindows == null || clipWindows.Count == 0)
            {
                return DrawSectionBoundaryQuarterSegmentPolylines(
                    modelSpace, transaction, nw, ne, sw, se, secType, quarterSecTypes, (Extents3d?)null,
                    northQuarter, eastQuarter, southQuarter, westQuarter);
            }

            var ids = new List<ObjectId>();
            var wMid = westQuarter ?? Midpoint(nw, sw);
            var eMid = eastQuarter ?? Midpoint(ne, se);
            var nMid = northQuarter ?? Midpoint(nw, ne);
            var sMid = southQuarter ?? Midpoint(sw, se);

            var swType = ResolveQuarterSecTypeForQuarter(quarterSecTypes, QuarterSelection.SouthWest, secType);
            var seType = ResolveQuarterSecTypeForQuarter(quarterSecTypes, QuarterSelection.SouthEast, secType);
            var neType = ResolveQuarterSecTypeForQuarter(quarterSecTypes, QuarterSelection.NorthEast, secType);
            var nwType = ResolveQuarterSecTypeForQuarter(quarterSecTypes, QuarterSelection.NorthWest, secType);

            var segments = new[]
            {
                // Assign each half-edge from its owning quarter to avoid cross-quarter bleed.
                (A: sw, B: sMid, Layer: swType),
                (A: sMid, B: se, Layer: seType),
                (A: se, B: eMid, Layer: seType),
                (A: eMid, B: ne, Layer: neType),
                (A: ne, B: nMid, Layer: neType),
                (A: nMid, B: nw, Layer: nwType),
                (A: nw, B: wMid, Layer: nwType),
                (A: wMid, B: sw, Layer: swType),
            };

            var dedupe = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
            foreach (var seg in segments)
            {
                foreach (var win in clipWindows)
                {
                    if (!TryClipSegmentToWindow(seg.A, seg.B, win, out var a, out var b))
                    {
                        continue;
                    }

                    var p0 = a;
                    var p1 = b;
                    if (p1.X < p0.X || (Math.Abs(p1.X - p0.X) <= 1e-9 && p1.Y < p0.Y))
                    {
                        var tmp = p0;
                        p0 = p1;
                        p1 = tmp;
                    }

                    var key = string.Format(
                        CultureInfo.InvariantCulture,
                        "{0:0.###},{1:0.###},{2:0.###},{3:0.###}",
                        p0.X, p0.Y, p1.X, p1.Y);
                    if (!dedupe.Add(key))
                    {
                        continue;
                    }

                    var poly = new Polyline(2)
                    {
                        Layer = seg.Layer,
                        ColorIndex = 256
                    };
                    poly.AddVertexAt(0, a, 0, 0, 0);
                    poly.AddVertexAt(1, b, 0, 0, 0);
                    var id = modelSpace.AppendEntity(poly);
                    transaction.AddNewlyCreatedDBObject(poly, true);
                    ids.Add(id);
                }
            }

            return ids;
        }

        private static void InsertAndExplodeLsdLabelBlock(
            Database database,
            Transaction transaction,
            BlockTableRecord modelSpace,
            Editor? editor,
            QuarterSelection quarter,
            Point3d position,
            string layerName)
        {
            var preferredName = GetLsdLabelBlockName(quarter);
            if (!TryEnsureLsdBlockLoaded(database, transaction, preferredName, editor))
            {
                editor?.WriteMessage($"\nLSD label load failed: {preferredName}");
            }

            if (!TryResolveLsdLabelBlock(database, transaction, quarter, out var blockId))
            {
                editor?.WriteMessage($"\nLSD label block not found for {quarter}.");
                return;
            }

            var blockRef = new BlockReference(position, blockId)
            {
                ScaleFactors = new Scale3d(1.0),
                Layer = layerName,
                ColorIndex = 256
            };
            modelSpace.AppendEntity(blockRef);
            transaction.AddNewlyCreatedDBObject(blockRef, true);

            var exploded = new DBObjectCollection();
            blockRef.Explode(exploded);
            var explodedEntities = new List<Entity>();
            var haveExtents = false;
            var minX = 0.0;
            var minY = 0.0;
            var maxX = 0.0;
            var maxY = 0.0;
            foreach (DBObject dbObject in exploded)
            {
                if (dbObject is Entity entity)
                {
                    if (!string.IsNullOrWhiteSpace(layerName))
                    {
                        entity.Layer = layerName;
                    }

                    entity.ColorIndex = 256;
                    modelSpace.AppendEntity(entity);
                    transaction.AddNewlyCreatedDBObject(entity, true);
                    explodedEntities.Add(entity);

                    try
                    {
                        var ext = entity.GeometricExtents;
                        if (!haveExtents)
                        {
                            minX = ext.MinPoint.X;
                            minY = ext.MinPoint.Y;
                            maxX = ext.MaxPoint.X;
                            maxY = ext.MaxPoint.Y;
                            haveExtents = true;
                        }
                        else
                        {
                            minX = Math.Min(minX, ext.MinPoint.X);
                            minY = Math.Min(minY, ext.MinPoint.Y);
                            maxX = Math.Max(maxX, ext.MaxPoint.X);
                            maxY = Math.Max(maxY, ext.MaxPoint.Y);
                        }
                    }
                    catch
                    {
                    }
                }
                else
                {
                    dbObject.Dispose();
                }
            }

            if (haveExtents && explodedEntities.Count > 0)
            {
                var center = new Point3d(
                    0.5 * (minX + maxX),
                    0.5 * (minY + maxY),
                    position.Z);
                var displacement = position - center;
                if (displacement.Length > 1e-4)
                {
                    var transform = Matrix3d.Displacement(displacement);
                    for (var i = 0; i < explodedEntities.Count; i++)
                    {
                        try
                        {
                            explodedEntities[i].TransformBy(transform);
                        }
                        catch
                        {
                        }
                    }
                }
            }

            blockRef.Erase();
            editor?.WriteMessage($"\nLSD label inserted/exploded: {preferredName} ({quarter}).");
        }

        private static bool TryEnsureLsdBlockLoaded(Database database, Transaction transaction, string blockName, Editor? editor)
        {
            if (string.IsNullOrWhiteSpace(blockName))
            {
                return false;
            }

            var bt = (BlockTable)transaction.GetObject(database.BlockTableId, OpenMode.ForRead);
            if (bt.Has(blockName))
            {
                return true;
            }

            const string blockFolder = @"C:\AUTOCAD-SETUP CG\BLOCKS\_CG BLOCKS";
            var blockPath = Path.Combine(blockFolder, blockName + ".dwg");
            if (!File.Exists(blockPath))
            {
                editor?.WriteMessage($"\nLSD block file missing: {blockPath}");
                return false;
            }

            try
            {
                using (var sourceDb = new Database(false, true))
                {
                    sourceDb.ReadDwgFile(blockPath, FileOpenMode.OpenForReadAndAllShare, true, string.Empty);
                    database.Insert(blockName, sourceDb, false);
                }

                editor?.WriteMessage($"\nLSD block loaded: {blockName}");
                return true;
            }
            catch (System.Exception ex)
            {
                editor?.WriteMessage($"\nLSD block load exception for {blockName}: {ex.Message}");
                return false;
            }
        }

        private static bool TryResolveLsdLabelBlock(
            Database database,
            Transaction transaction,
            QuarterSelection quarter,
            out ObjectId blockId)
        {
            blockId = ObjectId.Null;

            var targetSuffix = quarter switch
            {
                QuarterSelection.NorthWest => "NW",
                QuarterSelection.NorthEast => "NE",
                QuarterSelection.SouthWest => "SW",
                QuarterSelection.SouthEast => "SE",
                _ => string.Empty
            };

            if (string.IsNullOrWhiteSpace(targetSuffix))
            {
                return false;
            }

            var blockTable = (BlockTable)transaction.GetObject(database.BlockTableId, OpenMode.ForRead);

            // Preferred explicit names first.
            var preferred = new[]
            {
                $"label_lsd_{targetSuffix.ToLowerInvariant()}",
                $"LABEL_LSD_{targetSuffix}",
                $"label-lsd-{targetSuffix.ToLowerInvariant()}",
                $"LABEL-LSD-{targetSuffix}"
            };

            foreach (var name in preferred)
            {
                if (blockTable.Has(name))
                {
                    blockId = blockTable[name];
                    return true;
                }
            }

            // Fallback: fuzzy lookup by normalized block name.
            var targetToken = $"LABELLSD{targetSuffix}";
            foreach (ObjectId id in blockTable)
            {
                var btr = transaction.GetObject(id, OpenMode.ForRead) as BlockTableRecord;
                if (btr == null || btr.IsAnonymous || btr.IsLayout || btr.IsFromExternalReference)
                {
                    continue;
                }

                var normalized = NormalizeBlockName(btr.Name);
                if (normalized == targetToken || normalized.EndsWith(targetToken, StringComparison.Ordinal))
                {
                    blockId = id;
                    return true;
                }
            }

            return false;
        }

        private static string NormalizeBlockName(string name)
        {
            if (string.IsNullOrWhiteSpace(name))
            {
                return string.Empty;
            }

            var sb = new System.Text.StringBuilder(name.Length);
            foreach (var ch in name)
            {
                if (char.IsLetterOrDigit(ch))
                {
                    sb.Append(char.ToUpperInvariant(ch));
                }
            }

            return sb.ToString();
        }

        private static string GetLsdLabelBlockName(QuarterSelection quarter)
        {
            switch (quarter)
            {
                case QuarterSelection.NorthWest:
                    return "label_lsd_nw";
                case QuarterSelection.NorthEast:
                    return "label_lsd_ne";
                case QuarterSelection.SouthWest:
                    return "label_lsd_sw";
                case QuarterSelection.SouthEast:
                    return "label_lsd_se";
                default:
                    return string.Empty;
            }
        }

        private static QuarterAnchors GetLsdAnchorsForQuarter(Polyline quarter, Vector2d eastUnit, Vector2d northUnit)
        {
            if (TryGetQuarterCorner(quarter, eastUnit, northUnit, QuarterCorner.NorthWest, out var nw) &&
                TryGetQuarterCorner(quarter, eastUnit, northUnit, QuarterCorner.NorthEast, out var ne) &&
                TryGetQuarterCorner(quarter, eastUnit, northUnit, QuarterCorner.SouthWest, out var sw) &&
                TryGetQuarterCorner(quarter, eastUnit, northUnit, QuarterCorner.SouthEast, out var se))
            {
                return new QuarterAnchors(
                    Midpoint(nw, ne), // top
                    Midpoint(sw, se), // bottom
                    Midpoint(nw, sw), // left
                    Midpoint(ne, se)); // right
            }

            // Fallback: quarter extents midpoint anchors.
            return GetFallbackAnchors(quarter);
        }

        private static string NormalizeSecType(string secType)
        {
            return string.Equals(secType?.Trim(), "L-SEC", StringComparison.OrdinalIgnoreCase)
                ? "L-SEC"
                : "L-USEC";
        }

        private static string ResolveSectionType(
            SectionKey key,
            string requestedSecType,
            IReadOnlyDictionary<string, string> inferredSecTypes)
        {
            var keyId = BuildSectionKeyId(key);
            if (inferredSecTypes != null &&
                inferredSecTypes.TryGetValue(keyId, out var inferred) &&
                !string.IsNullOrWhiteSpace(inferred))
            {
                return NormalizeSecType(inferred);
            }

            // "AUTO" or unknown values normalize to L-USEC.
            return NormalizeSecType(requestedSecType);
        }

        private static string BuildSectionQuarterKeyId(SectionKey key, QuarterSelection quarter)
        {
            return BuildSectionQuarterKeyId(BuildSectionKeyId(key), quarter);
        }

        private static string BuildSectionQuarterKeyId(string sectionKeyId, QuarterSelection quarter)
        {
            if (string.IsNullOrWhiteSpace(sectionKeyId))
            {
                return string.Empty;
            }

            var token = QuarterSelectionToToken(quarter);
            if (string.IsNullOrWhiteSpace(token))
            {
                return string.Empty;
            }

            return $"{sectionKeyId}|{token}";
        }

        private static Dictionary<QuarterSelection, string> ResolveQuarterSectionTypes(
            SectionKey key,
            string fallbackSecType,
            IReadOnlyDictionary<string, string> inferredQuarterSecTypes)
        {
            var resolved = new Dictionary<QuarterSelection, string>();
            var fallback = NormalizeSecType(fallbackSecType);
            var sectionQuarterKeys = new[]
            {
                QuarterSelection.NorthWest,
                QuarterSelection.NorthEast,
                QuarterSelection.SouthWest,
                QuarterSelection.SouthEast
            };

            foreach (var quarter in sectionQuarterKeys)
            {
                var quarterKeyId = BuildSectionQuarterKeyId(key, quarter);
                if (!string.IsNullOrWhiteSpace(quarterKeyId) &&
                    inferredQuarterSecTypes != null &&
                    inferredQuarterSecTypes.TryGetValue(quarterKeyId, out var inferred) &&
                    !string.IsNullOrWhiteSpace(inferred))
                {
                    resolved[quarter] = NormalizeSecType(inferred);
                }
                else
                {
                    resolved[quarter] = fallback;
                }
            }

            return resolved;
        }

        private static Dictionary<string, string> InferQuarterSectionTypes(
            IReadOnlyList<SectionRequest> requests,
            IReadOnlyList<string> searchFolders,
            Logger logger)
        {
            var resolved = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
            if (requests == null || requests.Count == 0 || searchFolders == null || searchFolders.Count == 0)
            {
                return resolved;
            }

            bool TryGetAtsSectionGridPosition(int section, out int row, out int col)
            {
                row = -1;
                col = -1;
                if (section < 1 || section > 36)
                {
                    return false;
                }

                var rows = new[]
                {
                    new[] { 31, 32, 33, 34, 35, 36 },
                    new[] { 30, 29, 28, 27, 26, 25 },
                    new[] { 19, 20, 21, 22, 23, 24 },
                    new[] { 18, 17, 16, 15, 14, 13 },
                    new[] { 7, 8, 9, 10, 11, 12 },
                    new[] { 6, 5, 4, 3, 2, 1 }
                };

                for (var r = 0; r < rows.Length; r++)
                {
                    for (var c = 0; c < rows[r].Length; c++)
                    {
                        if (rows[r][c] == section)
                        {
                            row = r;
                            col = c;
                            return true;
                        }
                    }
                }

                return false;
            }

            var selectedSectionKeyIds = new HashSet<string>(
                requests.Select(r => BuildSectionKeyId(r.Key)),
                StringComparer.OrdinalIgnoreCase);
            var contextTownshipKeys = BuildContextTownshipKeys(requests);
            var geoms = new List<(
                string KeyId,
                string Label,
                Point2d SW,
                Point2d SE,
                Point2d NW,
                Point2d NE,
                Point2d Center,
                int Zone,
                string Meridian,
                int GlobalX,
                int GlobalY)>();

            foreach (var townshipKey in contextTownshipKeys)
            {
                if (!TryParseTownshipKey(townshipKey, out var zone, out var meridian, out var range, out var township))
                {
                    continue;
                }

                for (var section = 1; section <= 36; section++)
                {
                    var sectionKey = new SectionKey(zone, section.ToString(CultureInfo.InvariantCulture), township, range, meridian);
                    if (!TryLoadSectionOutline(searchFolders, sectionKey, logger, out var outline))
                    {
                        continue;
                    }

                    using (var poly = new Polyline(outline.Vertices.Count))
                    {
                        poly.Closed = outline.Closed;
                        for (var vi = 0; vi < outline.Vertices.Count; vi++)
                        {
                            poly.AddVertexAt(vi, outline.Vertices[vi], 0, 0, 0);
                        }

                        if (!TryGetQuarterAnchors(poly, out var anchors))
                        {
                            anchors = GetFallbackAnchors(poly);
                        }

                        var eastUnit = GetUnitVector(anchors.Left, anchors.Right, new Vector2d(1, 0));
                        var northUnit = GetUnitVector(anchors.Bottom, anchors.Top, new Vector2d(0, 1));
                        if (!TryGetQuarterCorner(poly, eastUnit, northUnit, QuarterCorner.SouthWest, out var sw) ||
                            !TryGetQuarterCorner(poly, eastUnit, northUnit, QuarterCorner.SouthEast, out var se) ||
                            !TryGetQuarterCorner(poly, eastUnit, northUnit, QuarterCorner.NorthWest, out var nw) ||
                            !TryGetQuarterCorner(poly, eastUnit, northUnit, QuarterCorner.NorthEast, out var ne))
                        {
                            continue;
                        }

                        var center = new Point2d(
                            0.25 * (sw.X + se.X + nw.X + ne.X),
                            0.25 * (sw.Y + se.Y + nw.Y + ne.Y));
                        var rangeNum = 0;
                        var townshipNum = 0;
                        var hasRange = TryParsePositiveToken(range, out rangeNum);
                        var hasTownship = TryParsePositiveToken(township, out townshipNum);
                        var hasGrid = TryGetAtsSectionGridPosition(section, out var row, out var col);
                        var globalX = (hasRange && hasGrid) ? ((-rangeNum * 6) + col) : int.MinValue;
                        var globalY = (hasTownship && hasGrid) ? ((townshipNum * 6) + (5 - row)) : int.MinValue;

                        geoms.Add((
                            BuildSectionKeyId(sectionKey),
                            BuildSectionDescriptor(sectionKey),
                            sw, se, nw, ne, center,
                            zone,
                            NormalizeNumberToken(meridian),
                            globalX,
                            globalY));
                    }
                }
            }

            if (geoms.Count == 0)
            {
                return resolved;
            }

            var euVec = geoms[0].SE - geoms[0].SW;
            var nuVec = geoms[0].NW - geoms[0].SW;
            var eu = euVec.Length > 1e-9 ? (euVec / euVec.Length) : new Vector2d(1, 0);
            var nu = nuVec.Length > 1e-9 ? (nuVec / nuVec.Length) : new Vector2d(0, 1);

            var localKeyIds = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
            var selectedGeoms = geoms
                .Where(g => selectedSectionKeyIds.Contains(g.KeyId))
                .ToList();
            if (selectedGeoms.Count > 0)
            {
                foreach (var g in geoms)
                {
                    foreach (var s in selectedGeoms)
                    {
                        if (g.Zone != s.Zone ||
                            !string.Equals(g.Meridian, s.Meridian, StringComparison.OrdinalIgnoreCase))
                        {
                            continue;
                        }

                        var dx = g.Center.X - s.Center.X;
                        var dy = g.Center.Y - s.Center.Y;
                        var centerDistance = Math.Sqrt((dx * dx) + (dy * dy));
                        var spanG = Math.Max((g.SE - g.SW).Length, (g.NW - g.SW).Length);
                        var spanS = Math.Max((s.SE - s.SW).Length, (s.NW - s.SW).Length);
                        var neighborThreshold = Math.Max(spanG, spanS) * 1.8;
                        if (centerDistance <= neighborThreshold)
                        {
                            localKeyIds.Add(g.KeyId);
                            break;
                        }
                    }
                }
            }

            var selectedOrLocalKeyIds = localKeyIds.Count > 0
                ? localKeyIds
                : selectedSectionKeyIds;
            var quarterGapSamples = new Dictionary<string, List<double>>(StringComparer.OrdinalIgnoreCase);

            void AddQuarterGap(string sectionKeyId, QuarterSelection quarter, double gapMeters)
            {
                if (gapMeters < 1.0)
                {
                    return;
                }

                var quarterKeyId = BuildSectionQuarterKeyId(sectionKeyId, quarter);
                if (string.IsNullOrWhiteSpace(quarterKeyId))
                {
                    return;
                }

                if (!quarterGapSamples.TryGetValue(quarterKeyId, out var samples))
                {
                    samples = new List<double>();
                    quarterGapSamples[quarterKeyId] = samples;
                }

                samples.Add(gapMeters);
            }

            void TryAddQuarterEvidenceFromPair(
                string keyA,
                Point2d a0,
                Point2d a1,
                string keyB,
                Point2d b0,
                Point2d b1,
                bool verticalMode)
            {
                var da = a1 - a0;
                var db = b1 - b0;
                var la = da.Length;
                var lb = db.Length;
                if (la <= 1e-6 || lb <= 1e-6)
                {
                    return;
                }

                var ua = da / la;
                var ub = db / lb;
                if (Math.Abs(ua.DotProduct(ub)) < 0.99)
                {
                    return;
                }

                var axis = ua;
                if (axis.DotProduct(ub) < 0.0)
                {
                    ub = -ub;
                }

                if ((a1 - a0).DotProduct(axis) < 0.0)
                {
                    var tmp = a0;
                    a0 = a1;
                    a1 = tmp;
                    da = a1 - a0;
                    la = da.Length;
                    ua = da / la;
                }

                if ((b1 - b0).DotProduct(axis) < 0.0)
                {
                    var tmp = b0;
                    b0 = b1;
                    b1 = tmp;
                    db = b1 - b0;
                    lb = db.Length;
                    ub = db / lb;
                }

                var aMid = Midpoint(a0, a1);
                var bMid = Midpoint(b0, b1);
                var pa = verticalMode
                    ? (aMid.X * eu.X + aMid.Y * eu.Y)
                    : (aMid.X * nu.X + aMid.Y * nu.Y);
                var pb = verticalMode
                    ? (bMid.X * eu.X + bMid.Y * eu.Y)
                    : (bMid.X * nu.X + bMid.Y * nu.Y);

                var westOrSouth0 = pa <= pb ? a0 : b0;
                var westOrSouth1 = pa <= pb ? a1 : b1;
                var eastOrNorth0 = pa <= pb ? b0 : a0;
                var eastOrNorth1 = pa <= pb ? b1 : a1;
                var baseKey = pa <= pb ? keyA : keyB;
                var otherKey = pa <= pb ? keyB : keyA;

                var baseDir = westOrSouth1 - westOrSouth0;
                var baseLen = baseDir.Length;
                if (baseLen <= 1e-6)
                {
                    return;
                }

                var baseU = baseDir / baseLen;
                var tBase0 = 0.0;
                var tBase1 = baseLen;
                var tOther0 = (eastOrNorth0 - westOrSouth0).DotProduct(baseU);
                var tOther1 = (eastOrNorth1 - westOrSouth0).DotProduct(baseU);
                var overlapMin = Math.Max(Math.Min(tBase0, tBase1), Math.Min(tOther0, tOther1));
                var overlapMax = Math.Min(Math.Max(tBase0, tBase1), Math.Max(tOther0, tOther1));
                const double endpointSnapToleranceMeters = 1.0;
                if (overlapMin > 0.0 && overlapMin < endpointSnapToleranceMeters)
                {
                    overlapMin = 0.0;
                }

                if (overlapMax < baseLen && (baseLen - overlapMax) < endpointSnapToleranceMeters)
                {
                    overlapMax = baseLen;
                }

                var overlapLength = overlapMax - overlapMin;
                var minEdgeLength = Math.Min(baseLen, lb);
                if (overlapLength < Math.Max(100.0, minEdgeLength * 0.75))
                {
                    return;
                }

                var baseStart = westOrSouth0 + (baseU * overlapMin);
                var baseEnd = westOrSouth0 + (baseU * overlapMax);

                var otherDir = eastOrNorth1 - eastOrNorth0;
                var otherLen2 = otherDir.DotProduct(otherDir);
                if (otherLen2 <= 1e-9)
                {
                    return;
                }

                double MeasureGap(Point2d baseSample)
                {
                    var proj = (baseSample - eastOrNorth0).DotProduct(otherDir) / otherLen2;
                    proj = Math.Max(0.0, Math.Min(1.0, proj));
                    var otherSample = eastOrNorth0 + (otherDir * proj);

                    var normal = new Vector2d(-baseU.Y, baseU.X);
                    if ((otherSample - baseSample).DotProduct(normal) < 0.0)
                    {
                        normal = -normal;
                    }

                    return Math.Abs((otherSample - baseSample).DotProduct(normal));
                }

                var splitT = overlapMin + (0.5 * (overlapMax - overlapMin));
                splitT = Math.Max(overlapMin, Math.Min(overlapMax, splitT));
                var baseMid = westOrSouth0 + (baseU * splitT);
                var span = overlapMax - overlapMin;
                var sampleQ1 = westOrSouth0 + (baseU * (overlapMin + (0.25 * span)));
                var sampleQ3 = westOrSouth0 + (baseU * (overlapMin + (0.75 * span)));
                var gapQ1 = MeasureGap(sampleQ1);
                var gapQ3 = MeasureGap(sampleQ3);

                var segments = new[]
                {
                    (
                        Gap: gapQ1,
                        BaseQuarter: verticalMode ? QuarterSelection.SouthEast : QuarterSelection.NorthWest,
                        OtherQuarter: verticalMode ? QuarterSelection.SouthWest : QuarterSelection.SouthWest),
                    (
                        Gap: gapQ3,
                        BaseQuarter: verticalMode ? QuarterSelection.NorthEast : QuarterSelection.NorthEast,
                        OtherQuarter: verticalMode ? QuarterSelection.NorthWest : QuarterSelection.SouthEast)
                };

                foreach (var seg in segments)
                {
                    AddQuarterGap(baseKey, seg.BaseQuarter, seg.Gap);
                    AddQuarterGap(otherKey, seg.OtherQuarter, seg.Gap);
                }
            }

            string BuildGridKey(int zone, string meridian, int globalX, int globalY)
            {
                return string.Format(
                    CultureInfo.InvariantCulture,
                    "{0}|{1}|{2}|{3}",
                    zone,
                    meridian ?? string.Empty,
                    globalX,
                    globalY);
            }

            var geomIndexByGrid = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
            for (var i = 0; i < geoms.Count; i++)
            {
                var g = geoms[i];
                if (g.GlobalX == int.MinValue || g.GlobalY == int.MinValue)
                {
                    continue;
                }

                var key = BuildGridKey(g.Zone, g.Meridian, g.GlobalX, g.GlobalY);
                if (!geomIndexByGrid.ContainsKey(key))
                {
                    geomIndexByGrid[key] = i;
                }
            }

            bool TryGetNeighborIndex(int zone, string meridian, int globalX, int globalY, int dx, int dy, out int index)
            {
                var key = BuildGridKey(zone, meridian, globalX + dx, globalY + dy);
                return geomIndexByGrid.TryGetValue(key, out index);
            }

            bool IsNeighborPairEligible(
                (string KeyId, string Label, Point2d SW, Point2d SE, Point2d NW, Point2d NE, Point2d Center, int Zone, string Meridian, int GlobalX, int GlobalY) a,
                (string KeyId, string Label, Point2d SW, Point2d SE, Point2d NW, Point2d NE, Point2d Center, int Zone, string Meridian, int GlobalX, int GlobalY) b)
            {
                if (!selectedOrLocalKeyIds.Contains(a.KeyId) &&
                    !selectedOrLocalKeyIds.Contains(b.KeyId))
                {
                    return false;
                }

                var centerDx = b.Center.X - a.Center.X;
                var centerDy = b.Center.Y - a.Center.Y;
                var centerDistance = Math.Sqrt((centerDx * centerDx) + (centerDy * centerDy));
                var spanA = Math.Max((a.SE - a.SW).Length, (a.NW - a.SW).Length);
                var spanB = Math.Max((b.SE - b.SW).Length, (b.NW - b.SW).Length);
                return centerDistance <= (Math.Max(spanA, spanB) * 1.8);
            }

            for (var i = 0; i < geoms.Count; i++)
            {
                var a = geoms[i];
                if (a.GlobalX == int.MinValue || a.GlobalY == int.MinValue)
                {
                    continue;
                }

                if (TryGetNeighborIndex(a.Zone, a.Meridian, a.GlobalX, a.GlobalY, 1, 0, out var eastNeighborIndex))
                {
                    var b = geoms[eastNeighborIndex];
                    if (IsNeighborPairEligible(a, b))
                    {
                        var aIsWest = a.Center.X <= b.Center.X;
                        var west = aIsWest ? a : b;
                        var east = aIsWest ? b : a;
                        TryAddQuarterEvidenceFromPair(
                            west.KeyId,
                            west.SE,
                            west.NE,
                            east.KeyId,
                            east.SW,
                            east.NW,
                            verticalMode: true);
                    }
                }

                if (TryGetNeighborIndex(a.Zone, a.Meridian, a.GlobalX, a.GlobalY, 0, 1, out var northNeighborIndex))
                {
                    var b = geoms[northNeighborIndex];
                    if (IsNeighborPairEligible(a, b))
                    {
                        var aIsSouth = a.Center.Y <= b.Center.Y;
                        var south = aIsSouth ? a : b;
                        var north = aIsSouth ? b : a;
                        TryAddQuarterEvidenceFromPair(
                            south.KeyId,
                            south.NW,
                            south.NE,
                            north.KeyId,
                            north.SW,
                            north.SE,
                            verticalMode: false);
                    }
                }
            }

            foreach (var pair in quarterGapSamples)
            {
                resolved[pair.Key] = InferQuarterSecTypeFromRoadAllowance(pair.Value);
            }

            logger?.WriteLine($"Quarter SEC TYPE inferred: {resolved.Count} quarter(s).");
            return resolved;
        }

        private static Dictionary<string, string> InferSectionTypes(
            IReadOnlyList<SectionRequest> requests,
            IReadOnlyList<string> searchFolders,
            Logger logger)
        {
            var resolved = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
            if (requests == null || requests.Count == 0)
            {
                return resolved;
            }

            var uniqueTownships = BuildContextTownshipKeys(requests).ToList();
            var entries = new List<(SectionKey Key, SectionSpatialInfo Info)>();
            try
            {
                foreach (var townshipKey in uniqueTownships)
                {
                    if (!TryParseTownshipKey(townshipKey, out var zone, out var meridian, out var range, out var township))
                    {
                        continue;
                    }

                    for (var section = 1; section <= 36; section++)
                    {
                        var key = new SectionKey(zone, section.ToString(CultureInfo.InvariantCulture), township, range, meridian);
                        if (!TryLoadSectionOutline(searchFolders, key, logger, out var outline))
                        {
                            continue;
                        }

                        if (TryCreateSectionSpatialInfo(outline, section, out var info))
                        {
                            entries.Add((key, info));
                        }
                    }
                }

                if (entries.Count == 0)
                {
                    return resolved;
                }

                foreach (var entry in entries)
                {
                    var peerInfos = entries
                        .Where(e => e.Info != null &&
                                    e.Key.Zone == entry.Key.Zone &&
                                    string.Equals(NormalizeNumberToken(e.Key.Meridian), NormalizeNumberToken(entry.Key.Meridian), StringComparison.OrdinalIgnoreCase))
                        .Select(e => e.Info)
                        .ToList();

                    var haveEastGap = TryMeasureRoadAllowanceGap(entry.Info, peerInfos, eastDirection: true, out var eastGap);
                    var haveSouthGap = TryMeasureRoadAllowanceGap(entry.Info, peerInfos, eastDirection: false, out var southGap);

                    var inferred = InferSecTypeFromRoadAllowance(haveEastGap ? eastGap : (double?)null, haveSouthGap ? southGap : (double?)null);
                    var keyId = BuildSectionKeyId(entry.Key);
                    resolved[keyId] = inferred;

                    if (EnableRoadAllowanceDiagnostics)
                    {
                        logger?.WriteLine(
                            $"SEC TYPE inferred: {keyId} -> {inferred} (eastGap={(haveEastGap ? eastGap.ToString("0.###", CultureInfo.InvariantCulture) : "n/a")}, southGap={(haveSouthGap ? southGap.ToString("0.###", CultureInfo.InvariantCulture) : "n/a")})");
                    }
                }
            }
            finally
            {
                DisposeSectionInfos(entries.Select(e => e.Info).ToList());
            }

            return resolved;
        }

        private static string InferSecTypeFromRoadAllowance(double? eastGap, double? southGap)
        {
            var gaps = new List<double>();
            if (eastGap.HasValue) gaps.Add(eastGap.Value);
            if (southGap.HasValue) gaps.Add(southGap.Value);

            // Blind/correction lines can produce near-zero or overlap gaps; treat as unknown.
            var measurableGaps = gaps.Where(g => g >= 1.0).ToList();
            if (measurableGaps.Count == 0)
            {
                return "L-USEC";
            }

            // Rule: width >= 25m is unsurveyed, otherwise surveyed.
            // Use the dominant (largest) measurable width so mixed evidence
            // near correction lines does not flip section type inconsistently.
            var representativeGap = measurableGaps.Max();
            if (representativeGap >= SurveyedUnsurveyedThresholdMeters)
            {
                return "L-USEC";
            }

            if (representativeGap >= (RoadAllowanceSecWidthMeters * 0.50))
            {
                return "L-SEC";
            }

            var hasUsec = measurableGaps.Any(g => Math.Abs(g - RoadAllowanceUsecWidthMeters) <= RoadAllowanceWidthToleranceMeters);
            var hasSec = measurableGaps.Any(g => Math.Abs(g - RoadAllowanceSecWidthMeters) <= RoadAllowanceWidthToleranceMeters);

            if (hasUsec && !hasSec)
            {
                return "L-USEC";
            }

            if (hasSec && !hasUsec)
            {
                return "L-SEC";
            }

            if (hasSec && hasUsec)
            {
                // Prefer surveyed when evidence is mixed so shared 20.11 boundaries
                // on adjacent sections resolve to the same section layer.
                return "L-SEC";
            }

            // Strict classification: if neither 20.11 nor 30.17 is observed inside tolerance,
            // keep unsurveyed instead of nearest-gap fallback.
            return "L-USEC";
        }

        private static string InferQuarterSecTypeFromRoadAllowance(IReadOnlyCollection<double> gaps)
        {
            if (gaps == null || gaps.Count == 0)
            {
                return "L-USEC";
            }

            var measurableGaps = gaps.Where(g => g >= 1.0).ToList();
            if (measurableGaps.Count == 0)
            {
                return "L-USEC";
            }

            // Rule: width >= 25m is unsurveyed, otherwise surveyed.
            var representativeGap = measurableGaps.Max();
            if (representativeGap >= SurveyedUnsurveyedThresholdMeters)
            {
                return "L-USEC";
            }

            if (representativeGap >= (RoadAllowanceSecWidthMeters * 0.50))
            {
                return "L-SEC";
            }

            var secMatches = measurableGaps
                .Where(g => Math.Abs(g - RoadAllowanceSecWidthMeters) <= RoadAllowanceWidthToleranceMeters)
                .ToList();
            var usecMatches = measurableGaps
                .Where(g => Math.Abs(g - RoadAllowanceUsecWidthMeters) <= RoadAllowanceGapOffsetToleranceMeters)
                .ToList();

            if (secMatches.Count > 0 && usecMatches.Count == 0)
            {
                return "L-SEC";
            }

            if (usecMatches.Count > 0 && secMatches.Count == 0)
            {
                return "L-USEC";
            }

            if (secMatches.Count > 0 && usecMatches.Count > 0)
            {
                if (secMatches.Count > usecMatches.Count)
                {
                    return "L-SEC";
                }

                if (usecMatches.Count > secMatches.Count)
                {
                    return "L-USEC";
                }

                var nearestSecMatched = secMatches.Min(g => Math.Abs(g - RoadAllowanceSecWidthMeters));
                var nearestUsecMatched = usecMatches.Min(g => Math.Abs(g - RoadAllowanceUsecWidthMeters));
                if (nearestSecMatched < nearestUsecMatched)
                {
                    return "L-SEC";
                }

                if (nearestUsecMatched < nearestSecMatched)
                {
                    return "L-USEC";
                }

                // When quarter evidence is evenly mixed, keep unsurveyed to avoid
                // promoting an entire 1/4 to surveyed from only one matching edge.
                return "L-USEC";
            }

            // Strict classification: require an explicit 20.11/30.17 match;
            // do not use nearest-gap fallback.
            return "L-USEC";
        }

        private static bool TryMeasureRoadAllowanceGap(
            SectionSpatialInfo source,
            IReadOnlyList<SectionSpatialInfo> townshipInfos,
            bool eastDirection,
            out double gapMeters)
        {
            gapMeters = 0.0;
            if (source == null || townshipInfos == null || townshipInfos.Count == 0)
            {
                return false;
            }

            var sourceCenter = GetSectionCenter(source);
            var bestGap = double.MaxValue;
            var found = false;

            foreach (var candidate in townshipInfos)
            {
                if (candidate == null || ReferenceEquals(candidate, source))
                {
                    continue;
                }

                var candidateCenter = GetSectionCenter(candidate);
                var delta = candidateCenter - sourceCenter;
                var eastDelta = delta.DotProduct(source.EastUnit);
                var northDelta = delta.DotProduct(source.NorthUnit);

                if (eastDirection)
                {
                    if (Math.Abs(northDelta) > Math.Max(source.Height, candidate.Height) * 0.60)
                        continue;

                    var projectedGap = Math.Abs(eastDelta) - (source.Width * 0.5) - (candidate.Width * 0.5);
                    if (projectedGap < -RoadAllowanceWidthToleranceMeters)
                        continue;
                    // Ignore near-zero/overlap artifacts from correction-line geometry.
                    if (projectedGap < 1.0)
                        continue;

                    if (!found || projectedGap < bestGap)
                    {
                        bestGap = projectedGap;
                        found = true;
                    }
                }
                else
                {
                    if (Math.Abs(eastDelta) > Math.Max(source.Width, candidate.Width) * 0.60)
                        continue;

                    var projectedGap = Math.Abs(northDelta) - (source.Height * 0.5) - (candidate.Height * 0.5);
                    if (projectedGap < -RoadAllowanceWidthToleranceMeters)
                        continue;
                    // Ignore near-zero/overlap artifacts from correction-line geometry.
                    if (projectedGap < 1.0)
                        continue;

                    if (!found || projectedGap < bestGap)
                    {
                        bestGap = projectedGap;
                        found = true;
                    }
                }
            }

            if (!found)
            {
                return false;
            }

            gapMeters = Math.Max(0.0, bestGap);
            return true;
        }

        private static Point2d GetSectionCenter(SectionSpatialInfo section)
        {
            return section.SouthWest +
                   (section.EastUnit * (section.Width * 0.5)) +
                   (section.NorthUnit * (section.Height * 0.5));
        }

        private static void DrawBufferedQuarterWindowsOnDefpoints(
            Database database,
            IEnumerable<ObjectId> quarterIds,
            double buffer,
            Logger? logger)
        {
            if (database == null || quarterIds == null)
            {
                return;
            }

            var quarterIdList = quarterIds.Distinct().ToList();
            logger?.WriteLine($"DEFPOINTS BUFFER: requested quarter ids = {quarterIdList.Count}, buffer={buffer:0.###}m");
            var offsetPolylines = BuildBufferedQuarterOffsetPolylines(database, quarterIdList, buffer, logger);
            if (offsetPolylines.Count == 0)
            {
                logger?.WriteLine("DEFPOINTS BUFFER: no offset polylines created.");
                return;
            }

            List<Polyline> unionBoundaries;
            try
            {
                unionBoundaries = BuildUnionBoundaries(offsetPolylines, logger);
            }
            finally
            {
                foreach (var poly in offsetPolylines)
                {
                    poly.Dispose();
                }
            }

            if (unionBoundaries.Count == 0)
            {
                logger?.WriteLine("DEFPOINTS BUFFER: union produced 0 boundaries.");
                return;
            }

            using (var tr = database.TransactionManager.StartTransaction())
            {
                var bt = (BlockTable)tr.GetObject(database.BlockTableId, OpenMode.ForRead);
                var ms = (BlockTableRecord)tr.GetObject(bt[BlockTableRecord.ModelSpace], OpenMode.ForWrite);
                EnsureDefpointsLayer(database, tr);
                ClearPreviousBufferedDefpointsWindows(tr);

                var count = 0;
                var newWindowIds = new List<ObjectId>();
                foreach (var boundary in unionBoundaries)
                {
                    try
                    {
                        logger?.WriteLine($"DEFPOINTS BUFFER: draw boundary area={Math.Abs(boundary.Area):0.###} verts={boundary.NumberOfVertices}");
                    }
                    catch
                    {
                    }

                    boundary.Layer = "DEFPOINTS";
                    boundary.ColorIndex = 8;
                    var windowId = ms.AppendEntity(boundary);
                    tr.AddNewlyCreatedDBObject(boundary, true);
                    newWindowIds.Add(windowId);
                    count++;
                }

                tr.Commit();
                lock (BufferedDefpointsWindowLock)
                {
                    BufferedDefpointsWindowIds.Clear();
                    foreach (var id in newWindowIds)
                    {
                        if (!id.IsNull)
                        {
                            BufferedDefpointsWindowIds.Add(id);
                        }
                    }
                }
                logger?.WriteLine($"Buffered DEFPOINTS windows drawn: {count} outline(s).");
            }

            foreach (var boundary in unionBoundaries)
            {
                if (!boundary.IsDisposed && boundary.Database == null)
                {
                    boundary.Dispose();
                }
            }
        }

        private static void ClearPreviousBufferedDefpointsWindows(Transaction tr)
        {
            if (tr == null)
            {
                return;
            }

            List<ObjectId> previousIds;
            lock (BufferedDefpointsWindowLock)
            {
                previousIds = BufferedDefpointsWindowIds
                    .Where(id => !id.IsNull)
                    .Distinct()
                    .ToList();
                BufferedDefpointsWindowIds.Clear();
            }

            foreach (var id in previousIds)
            {
                try
                {
                    if (tr.GetObject(id, OpenMode.ForWrite, false) is Entity entity && !entity.IsErased)
                    {
                        entity.Erase();
                    }
                }
                catch
                {
                }
            }
        }

        private static void ExtendQuarterLinesFromUsecWestSouthToNextUsec(
            Database database,
            IEnumerable<ObjectId> requestedQuarterIds,
            IReadOnlyCollection<ObjectId> generatedRoadAllowanceIds,
            Logger? logger)
        {
            if (database == null || requestedQuarterIds == null || generatedRoadAllowanceIds == null || generatedRoadAllowanceIds.Count == 0)
            {
                return;
            }

            var clipWindows = BuildBufferedQuarterWindows(database, requestedQuarterIds, 100.0);
            if (clipWindows.Count == 0)
            {
                return;
            }

            bool IsPointInAnyWindow(Point2d p)
            {
                for (var i = 0; i < clipWindows.Count; i++)
                {
                    var w = clipWindows[i];
                    if (p.X >= w.MinPoint.X && p.X <= w.MaxPoint.X &&
                        p.Y >= w.MinPoint.Y && p.Y <= w.MaxPoint.Y)
                    {
                        return true;
                    }
                }

                return false;
            }

            bool DoesSegmentIntersectAnyWindow(Point2d a, Point2d b)
            {
                if (IsPointInAnyWindow(a) || IsPointInAnyWindow(b))
                {
                    return true;
                }

                for (var i = 0; i < clipWindows.Count; i++)
                {
                    if (TryClipSegmentToWindow(a, b, clipWindows[i], out _, out _))
                    {
                        return true;
                    }
                }

                return false;
            }

            bool TryReadOpenSegment(Entity ent, out Point2d a, out Point2d b)
            {
                a = default;
                b = default;
                if (ent == null)
                {
                    return false;
                }

                if (ent is Line ln)
                {
                    a = new Point2d(ln.StartPoint.X, ln.StartPoint.Y);
                    b = new Point2d(ln.EndPoint.X, ln.EndPoint.Y);
                    return a.GetDistanceTo(b) > 1e-4;
                }

                if (ent is Polyline pl)
                {
                    if (pl.Closed || pl.NumberOfVertices < 2)
                    {
                        return false;
                    }

                    a = pl.GetPoint2dAt(0);
                    b = pl.GetPoint2dAt(pl.NumberOfVertices - 1);
                    if (a.GetDistanceTo(b) <= 1e-4)
                    {
                        return false;
                    }

                    // Accept multi-vertex open polylines only when effectively collinear.
                    if (pl.NumberOfVertices > 2)
                    {
                        const double collinearTol = 0.35;
                        for (var vi = 1; vi < pl.NumberOfVertices - 1; vi++)
                        {
                            var p = pl.GetPoint2dAt(vi);
                            if (DistancePointToInfiniteLine(p, a, b) > collinearTol)
                            {
                                return false;
                            }
                        }
                    }

                    return true;
                }

                return false;
            }

            bool IsHorizontalLike(Point2d a, Point2d b)
            {
                var d = b - a;
                return Math.Abs(d.X) >= Math.Abs(d.Y);
            }

            bool IsVerticalLike(Point2d a, Point2d b)
            {
                var d = b - a;
                return Math.Abs(d.Y) > Math.Abs(d.X);
            }

            var generatedSet = new HashSet<ObjectId>(generatedRoadAllowanceIds.Where(id => !id.IsNull));
            using (var tr = database.TransactionManager.StartTransaction())
            {
                var usecBoundarySegments = new List<(Point2d A, Point2d B)>();
                var sourceVerticalUsecSegments = new List<(Point2d A, Point2d B)>();
                var secTargetSegments = new List<(Point2d A, Point2d B)>();
                var generatedVerticalUsecTargets = new List<(Point2d A, Point2d B)>();
                var qsecLineIds = new List<ObjectId>();
                var lsdLineIds = new List<ObjectId>();
                var qsecVerticalSegments = new List<(Point2d A, Point2d B)>();
                var bt = (BlockTable)tr.GetObject(database.BlockTableId, OpenMode.ForRead);
                var ms = (BlockTableRecord)tr.GetObject(bt[BlockTableRecord.ModelSpace], OpenMode.ForRead);
                foreach (ObjectId id in ms)
                {
                    if (!(tr.GetObject(id, OpenMode.ForRead, false) is Entity ent) || ent.IsErased)
                    {
                        continue;
                    }

                    if (!TryReadOpenSegment(ent, out var a, out var b))
                    {
                        continue;
                    }

                    if (!DoesSegmentIntersectAnyWindow(a, b))
                    {
                        continue;
                    }

                    if (string.Equals(ent.Layer, "L-SECTION-LSD", StringComparison.OrdinalIgnoreCase))
                    {
                        lsdLineIds.Add(id);
                        continue;
                    }

                    if (string.Equals(ent.Layer, "L-QSEC", StringComparison.OrdinalIgnoreCase))
                    {
                        if (IsVerticalLike(a, b))
                        {
                            qsecVerticalSegments.Add((a, b));
                        }

                        qsecLineIds.Add(id);
                        continue;
                    }

                    if (generatedSet.Contains(id))
                    {
                        secTargetSegments.Add((a, b));
                        var isUsecLayer = string.Equals(ent.Layer, "L-USEC", StringComparison.OrdinalIgnoreCase);
                        var isSecLayer = string.Equals(ent.Layer, "L-SEC", StringComparison.OrdinalIgnoreCase);
                        if ((isUsecLayer || isSecLayer) && IsVerticalLike(a, b))
                        {
                            generatedVerticalUsecTargets.Add((a, b));
                        }

                        continue;
                    }

                    if (string.Equals(ent.Layer, "L-USEC", StringComparison.OrdinalIgnoreCase))
                    {
                        usecBoundarySegments.Add((a, b));
                        if (IsVerticalLike(a, b))
                        {
                            sourceVerticalUsecSegments.Add((a, b));
                        }
                    }
                }

                if (qsecLineIds.Count == 0 || secTargetSegments.Count == 0 || usecBoundarySegments.Count == 0)
                {
                    tr.Commit();
                    return;
                }

                const double touchTol = 0.20;
                const double minExtend = 0.05;
                const double maxExtend = 40.0;
                const double endpointMoveTol = 0.05;
                var adjusted = 0;
                var horizontalQsecMidpointAdjustments = new List<(Point2d OldA, Point2d OldB, Point2d OldMid, Point2d NewMid)>();

                foreach (var id in qsecLineIds)
                {
                    if (!(tr.GetObject(id, OpenMode.ForWrite, false) is Entity writable) || writable.IsErased)
                    {
                        continue;
                    }

                    if (!TryReadOpenSegment(writable, out var p0, out var p1))
                    {
                        continue;
                    }

                    var lineDir = p1 - p0;
                    if (lineDir.Length <= 1e-4)
                    {
                        continue;
                    }

                    var isVerticalQsec = IsVerticalLike(p0, p1);
                    // Apply explicit rule:
                    // - Vertical 1/4 line: extend only S.1/4 endpoint (south end)
                    // - Horizontal 1/4 line: extend only W.1/4 endpoint (west end)
                    var selectedOriginal = p0;
                    var other = p1;
                    if (isVerticalQsec)
                    {
                        if (p1.Y < p0.Y)
                        {
                            selectedOriginal = p1;
                            other = p0;
                        }
                    }
                    else
                    {
                        if (p1.X < p0.X)
                        {
                            selectedOriginal = p1;
                            other = p0;
                        }
                    }

                    var touchesRelevantUsec = false;
                    for (var si = 0; si < usecBoundarySegments.Count; si++)
                    {
                        var boundary = usecBoundarySegments[si];
                        if (isVerticalQsec && !IsHorizontalLike(boundary.A, boundary.B))
                        {
                            continue;
                        }

                        if (!isVerticalQsec && !IsVerticalLike(boundary.A, boundary.B))
                        {
                            continue;
                        }

                        if (DistancePointToSegment(selectedOriginal, boundary.A, boundary.B) <= touchTol)
                        {
                            touchesRelevantUsec = true;
                            break;
                        }
                    }

                    if (!touchesRelevantUsec)
                    {
                        continue;
                    }

                    var outward = selectedOriginal - other;
                    var outwardLen = outward.Length;
                    if (outwardLen <= 1e-6)
                    {
                        continue;
                    }

                    var outwardDir = outward / outwardLen;
                    double? bestTargetDistance = null;
                    for (var ti = 0; ti < secTargetSegments.Count; ti++)
                    {
                        var target = secTargetSegments[ti];
                        if (isVerticalQsec && !IsHorizontalLike(target.A, target.B))
                        {
                            continue;
                        }

                        if (!isVerticalQsec && !IsVerticalLike(target.A, target.B))
                        {
                            continue;
                        }

                        if (!TryIntersectInfiniteLineWithSegment(selectedOriginal, outwardDir, target.A, target.B, out var t))
                        {
                            continue;
                        }

                        if (t <= minExtend || t > maxExtend)
                        {
                            continue;
                        }

                        if (!bestTargetDistance.HasValue || t < bestTargetDistance.Value)
                        {
                            bestTargetDistance = t;
                        }
                    }

                    if (!bestTargetDistance.HasValue)
                    {
                        continue;
                    }

                    var selectedNew = selectedOriginal + (outwardDir * bestTargetDistance.Value);
                    if (selectedNew.GetDistanceTo(selectedOriginal) <= endpointMoveTol)
                    {
                        continue;
                    }

                    if (writable is Line ln)
                    {
                        if (selectedOriginal.GetDistanceTo(p0) <= selectedOriginal.GetDistanceTo(p1))
                        {
                            ln.StartPoint = new Point3d(selectedNew.X, selectedNew.Y, ln.StartPoint.Z);
                        }
                        else
                        {
                            ln.EndPoint = new Point3d(selectedNew.X, selectedNew.Y, ln.EndPoint.Z);
                        }
                    }
                    else if (writable is Polyline pl && !pl.Closed && pl.NumberOfVertices == 2)
                    {
                        if (selectedOriginal.GetDistanceTo(p0) <= selectedOriginal.GetDistanceTo(p1))
                        {
                            pl.SetPointAt(0, selectedNew);
                        }
                        else
                        {
                            pl.SetPointAt(1, selectedNew);
                        }
                    }
                    else
                    {
                        continue;
                    }

                    adjusted++;
                    if (!isVerticalQsec)
                    {
                        var centerAnchor = other;
                        var towardCenterVec = other - selectedOriginal;
                        var towardCenterLen = towardCenterVec.Length;
                        if (towardCenterLen > 1e-6 && qsecVerticalSegments.Count > 0)
                        {
                            var towardCenterDir = towardCenterVec / towardCenterLen;
                            double? bestCenterT = null;
                            const double centerEndpointTol = 1.0;
                            for (var vi = 0; vi < qsecVerticalSegments.Count; vi++)
                            {
                                var vseg = qsecVerticalSegments[vi];
                                if (!TryIntersectInfiniteLineWithSegment(selectedOriginal, towardCenterDir, vseg.A, vseg.B, out var tCenter))
                                {
                                    continue;
                                }

                                if (tCenter <= centerEndpointTol || tCenter >= (towardCenterLen - centerEndpointTol))
                                {
                                    continue;
                                }

                                if (!bestCenterT.HasValue || tCenter < bestCenterT.Value)
                                {
                                    bestCenterT = tCenter;
                                }
                            }

                            if (bestCenterT.HasValue)
                            {
                                centerAnchor = selectedOriginal + (towardCenterDir * bestCenterT.Value);
                            }
                        }

                        horizontalQsecMidpointAdjustments.Add((
                            selectedOriginal,
                            centerAnchor,
                            Midpoint(selectedOriginal, centerAnchor),
                            Midpoint(selectedNew, centerAnchor)));
                    }
                }

                var lsdAdjusted = 0;
                if (horizontalQsecMidpointAdjustments.Count > 0 && lsdLineIds.Count > 0)
                {
                    const double lsdOnOldQsecTol = 0.35;
                    const double lsdOldMidTol = 12.0;
                    const double lsdMaxMove = 25.0;

                    bool TryMappedMidpoint(Point2d endpoint, out Point2d mappedMid, out double bestSegDistance, out double bestMidDistance)
                    {
                        mappedMid = endpoint;
                        bestSegDistance = double.MaxValue;
                        bestMidDistance = double.MaxValue;
                        var bestMoveDistance = double.MaxValue;

                        for (var i = 0; i < horizontalQsecMidpointAdjustments.Count; i++)
                        {
                            var adj = horizontalQsecMidpointAdjustments[i];
                            var segDistance = DistancePointToSegment(endpoint, adj.OldA, adj.OldB);
                            if (segDistance > lsdOnOldQsecTol)
                            {
                                continue;
                            }

                            var midDistance = endpoint.GetDistanceTo(adj.OldMid);
                            if (midDistance > lsdOldMidTol)
                            {
                                continue;
                            }

                            var moveDistance = endpoint.GetDistanceTo(adj.NewMid);
                            if (moveDistance <= endpointMoveTol || moveDistance > lsdMaxMove)
                            {
                                continue;
                            }

                            var betterSeg = segDistance < (bestSegDistance - 1e-6);
                            var tiedSeg = Math.Abs(segDistance - bestSegDistance) <= 1e-6;
                            var betterMid = tiedSeg && midDistance < (bestMidDistance - 1e-6);
                            var tiedMid = tiedSeg && Math.Abs(midDistance - bestMidDistance) <= 1e-6;
                            var betterMove = tiedMid && moveDistance < bestMoveDistance;
                            if (!betterSeg && !betterMid && !betterMove)
                            {
                                continue;
                            }

                            bestSegDistance = segDistance;
                            bestMidDistance = midDistance;
                            bestMoveDistance = moveDistance;
                            mappedMid = adj.NewMid;
                        }

                        return bestSegDistance < double.MaxValue;
                    }

                    for (var i = 0; i < lsdLineIds.Count; i++)
                    {
                        var id = lsdLineIds[i];
                        if (!(tr.GetObject(id, OpenMode.ForWrite, false) is Entity writableLsd) || writableLsd.IsErased)
                        {
                            continue;
                        }

                        if (!TryReadOpenSegment(writableLsd, out var p0, out var p1))
                        {
                            continue;
                        }

                        if (!IsAdjustableLsdLineSegment(p0, p1))
                        {
                            continue;
                        }

                        var has0 = TryMappedMidpoint(p0, out var mid0, out var seg0, out var md0);
                        var has1 = TryMappedMidpoint(p1, out var mid1, out var seg1, out var md1);
                        if (!has0 && !has1)
                        {
                            continue;
                        }

                        var moveStart = has0;
                        var targetMid = mid0;
                        if (!has0 || (has1 && (seg1 < seg0 || (Math.Abs(seg1 - seg0) <= 1e-6 && md1 < md0))))
                        {
                            moveStart = false;
                            targetMid = mid1;
                        }

                        if (writableLsd is Line lsdLine)
                        {
                            if (moveStart)
                            {
                                lsdLine.StartPoint = new Point3d(targetMid.X, targetMid.Y, lsdLine.StartPoint.Z);
                            }
                            else
                            {
                                lsdLine.EndPoint = new Point3d(targetMid.X, targetMid.Y, lsdLine.EndPoint.Z);
                            }
                        }
                        else if (writableLsd is Polyline lsdPoly && !lsdPoly.Closed && lsdPoly.NumberOfVertices >= 2)
                        {
                            var index = moveStart ? 0 : lsdPoly.NumberOfVertices - 1;
                            lsdPoly.SetPointAt(index, targetMid);
                        }
                        else
                        {
                            continue;
                        }

                        lsdAdjusted++;
                    }
                }

                var westHalfLsdAdjusted = 0;
                if (lsdLineIds.Count > 0 && sourceVerticalUsecSegments.Count > 0 && generatedVerticalUsecTargets.Count > 0)
                {
                    for (var i = 0; i < lsdLineIds.Count; i++)
                    {
                        var id = lsdLineIds[i];
                        if (!(tr.GetObject(id, OpenMode.ForWrite, false) is Entity writableLsd) || writableLsd.IsErased)
                        {
                            continue;
                        }

                        if (!TryReadOpenSegment(writableLsd, out var p0, out var p1))
                        {
                            continue;
                        }

                        if (!IsAdjustableLsdLineSegment(p0, p1) || !IsHorizontalLike(p0, p1))
                        {
                            continue;
                        }

                        var west = p0;
                        var east = p1;
                        if (east.X < west.X)
                        {
                            var tmp = west;
                            west = east;
                            east = tmp;
                        }

                        // Strict source gate: only LSD endpoints anchored on original L-USEC (30.17) boundaries.
                        var touchesOriginalUsec = false;
                        for (var si = 0; si < sourceVerticalUsecSegments.Count; si++)
                        {
                            var src = sourceVerticalUsecSegments[si];
                            if (DistancePointToSegment(west, src.A, src.B) <= touchTol)
                            {
                                touchesOriginalUsec = true;
                                break;
                            }
                        }

                        if (!touchesOriginalUsec)
                        {
                            continue;
                        }

                        var outward = west - east;
                        var outwardLen = outward.Length;
                        if (outwardLen <= 1e-6)
                        {
                            continue;
                        }

                        var outwardDir = outward / outwardLen;
                        double? bestTargetDistance = null;
                        const double westHalfTargetDistance = CorrectionLinePairGapMeters;
                        const double westHalfTargetTol = 2.8;
                        var bestTargetScore = double.MaxValue;
                        for (var ti = 0; ti < generatedVerticalUsecTargets.Count; ti++)
                        {
                            var target = generatedVerticalUsecTargets[ti];
                            if (!TryIntersectInfiniteLineWithSegment(west, outwardDir, target.A, target.B, out var t))
                            {
                                continue;
                            }

                            if (t <= minExtend || t > maxExtend)
                            {
                                continue;
                            }

                            var score = Math.Abs(t - westHalfTargetDistance);
                            if (score > westHalfTargetTol)
                            {
                                continue;
                            }

                            if (!bestTargetDistance.HasValue ||
                                score < (bestTargetScore - 1e-9) ||
                                (Math.Abs(score - bestTargetScore) <= 1e-9 && t < bestTargetDistance.Value))
                            {
                                bestTargetDistance = t;
                                bestTargetScore = score;
                            }
                        }

                        if (!bestTargetDistance.HasValue)
                        {
                            continue;
                        }

                        var westNew = west + (outwardDir * bestTargetDistance.Value);
                        if (westNew.GetDistanceTo(west) <= endpointMoveTol)
                        {
                            continue;
                        }

                        if (writableLsd is Line lsdLine)
                        {
                            var d0 = west.GetDistanceTo(p0);
                            var d1 = west.GetDistanceTo(p1);
                            if (d0 <= d1)
                            {
                                lsdLine.StartPoint = new Point3d(westNew.X, westNew.Y, lsdLine.StartPoint.Z);
                            }
                            else
                            {
                                lsdLine.EndPoint = new Point3d(westNew.X, westNew.Y, lsdLine.EndPoint.Z);
                            }
                        }
                        else if (writableLsd is Polyline lsdPoly && !lsdPoly.Closed && lsdPoly.NumberOfVertices == 2)
                        {
                            var d0 = west.GetDistanceTo(p0);
                            var d1 = west.GetDistanceTo(p1);
                            lsdPoly.SetPointAt(d0 <= d1 ? 0 : 1, westNew);
                        }
                        else
                        {
                            continue;
                        }

                        westHalfLsdAdjusted++;
                    }
                }

                tr.Commit();
                if (adjusted > 0)
                {
                    logger?.WriteLine($"Cleanup: extended {adjusted} L-QSEC W.1/4/S.1/4 endpoint(s) to next L-USEC line.");
                }
                if (lsdAdjusted > 0)
                {
                    logger?.WriteLine($"Cleanup: adjusted {lsdAdjusted} L-SECTION-LSD endpoint(s) to midpoint of W.1/4 L-QSEC extension line(s).");
                }
                if (westHalfLsdAdjusted > 0)
                {
                    logger?.WriteLine($"Cleanup: extended {westHalfLsdAdjusted} W.1/2 E-W L-SECTION-LSD endpoint(s) from original L-USEC to generated 20.11 boundary.");
                }
            }
        }

        private static void ExtendSouthBoundarySwQuarterWestToNextUsec(
            Database database,
            IEnumerable<ObjectId> requestedQuarterIds,
            IReadOnlyCollection<ObjectId> generatedRoadAllowanceIds,
            Logger? logger)
        {
            if (database == null || requestedQuarterIds == null || generatedRoadAllowanceIds == null || generatedRoadAllowanceIds.Count == 0)
            {
                return;
            }

            var clipWindows = BuildBufferedQuarterWindows(database, requestedQuarterIds, 100.0);
            if (clipWindows.Count == 0)
            {
                return;
            }

            bool IsPointInAnyWindow(Point2d p)
            {
                for (var i = 0; i < clipWindows.Count; i++)
                {
                    var w = clipWindows[i];
                    if (p.X >= w.MinPoint.X && p.X <= w.MaxPoint.X &&
                        p.Y >= w.MinPoint.Y && p.Y <= w.MaxPoint.Y)
                    {
                        return true;
                    }
                }

                return false;
            }

            bool DoesSegmentIntersectAnyWindow(Point2d a, Point2d b)
            {
                if (IsPointInAnyWindow(a) || IsPointInAnyWindow(b))
                {
                    return true;
                }

                for (var i = 0; i < clipWindows.Count; i++)
                {
                    if (TryClipSegmentToWindow(a, b, clipWindows[i], out _, out _))
                    {
                        return true;
                    }
                }

                return false;
            }

            bool TryReadOpenSegment(Entity ent, out Point2d a, out Point2d b)
            {
                a = default;
                b = default;
                if (ent == null)
                {
                    return false;
                }

                if (ent is Line ln)
                {
                    a = new Point2d(ln.StartPoint.X, ln.StartPoint.Y);
                    b = new Point2d(ln.EndPoint.X, ln.EndPoint.Y);
                    return a.GetDistanceTo(b) > 1e-4;
                }

                if (ent is Polyline pl)
                {
                    if (pl.Closed || pl.NumberOfVertices != 2)
                    {
                        return false;
                    }

                    a = pl.GetPoint2dAt(0);
                    b = pl.GetPoint2dAt(1);
                    return a.GetDistanceTo(b) > 1e-4;
                }

                return false;
            }

            bool IsHorizontalLike(Point2d a, Point2d b)
            {
                var d = b - a;
                return Math.Abs(d.X) >= Math.Abs(d.Y);
            }

            bool IsVerticalLike(Point2d a, Point2d b)
            {
                var d = b - a;
                return Math.Abs(d.Y) > Math.Abs(d.X);
            }

            bool Near(Point2d p, Point2d q, double tol)
            {
                return p.GetDistanceTo(q) <= tol;
            }

            var generatedSet = new HashSet<ObjectId>(generatedRoadAllowanceIds.Where(id => !id.IsNull));
            using (var tr = database.TransactionManager.StartTransaction())
            {
                var sourceSegments = new List<(ObjectId Id, Point2d A, Point2d B, bool IsUsec, bool IsSec)>();
                var verticalUsecBoundaries = new List<(Point2d A, Point2d B)>();
                var generatedUsecVerticalTargets = new List<(Point2d A, Point2d B, bool IsUsecLayer)>();
                var lsdSegments = new List<(ObjectId Id, Point2d A, Point2d B)>();
                var bt = (BlockTable)tr.GetObject(database.BlockTableId, OpenMode.ForRead);
                var ms = (BlockTableRecord)tr.GetObject(bt[BlockTableRecord.ModelSpace], OpenMode.ForRead);
                foreach (ObjectId id in ms)
                {
                    if (!(tr.GetObject(id, OpenMode.ForRead, false) is Entity ent) || ent.IsErased)
                    {
                        continue;
                    }

                    if (!TryReadOpenSegment(ent, out var a, out var b))
                    {
                        continue;
                    }

                    if (!DoesSegmentIntersectAnyWindow(a, b))
                    {
                        continue;
                    }

                    if (generatedSet.Contains(id))
                    {
                        var isUsecGeneratedLayer = string.Equals(ent.Layer, "L-USEC", StringComparison.OrdinalIgnoreCase);
                        var isSecGeneratedLayer = string.Equals(ent.Layer, "L-SEC", StringComparison.OrdinalIgnoreCase);
                        if ((isUsecGeneratedLayer || isSecGeneratedLayer) && IsVerticalLike(a, b))
                        {
                            generatedUsecVerticalTargets.Add((a, b, isUsecGeneratedLayer));
                        }

                        continue;
                    }

                    if (string.Equals(ent.Layer, "L-QSEC", StringComparison.OrdinalIgnoreCase))
                    {
                        continue;
                    }

                    if (string.Equals(ent.Layer, "L-SECTION-LSD", StringComparison.OrdinalIgnoreCase))
                    {
                        if (IsAdjustableLsdLineSegment(a, b))
                        {
                            lsdSegments.Add((id, a, b));
                        }

                        continue;
                    }

                    if (!string.Equals(ent.Layer, "L-SEC", StringComparison.OrdinalIgnoreCase) &&
                        !string.Equals(ent.Layer, "L-USEC", StringComparison.OrdinalIgnoreCase) &&
                        !string.Equals(ent.Layer, "L-QSEC", StringComparison.OrdinalIgnoreCase))
                    {
                        continue;
                    }

                    var isUsecLayer = string.Equals(ent.Layer, "L-USEC", StringComparison.OrdinalIgnoreCase);
                    var isSecLayer = string.Equals(ent.Layer, "L-SEC", StringComparison.OrdinalIgnoreCase);
                    sourceSegments.Add((id, a, b, isUsecLayer, isSecLayer));
                    if (isUsecLayer && IsVerticalLike(a, b))
                    {
                        verticalUsecBoundaries.Add((a, b));
                    }
                }

                if (sourceSegments.Count == 0 || verticalUsecBoundaries.Count == 0 || generatedUsecVerticalTargets.Count == 0)
                {
                    tr.Commit();
                    return;
                }

                const double touchTol = 0.20;
                const double cornerTol = 0.10;
                const double minExtend = 0.05;
                const double maxExtend = 40.0;
                const double twentyTwelveBandMin = 7.2;
                const double twentyTwelveBandMax = 13.4;
                const double endpointMoveTol = 0.05;
                var adjusted = 0;
                var secHorizontalSources = 0;
                var secHorizontalWithTwentyBandTarget = 0;
                var secHorizontalRejectedNoTwentyBandTarget = 0;
                var lsdMidpointAdjustments = new List<(Point2d OldA, Point2d OldB, Point2d OldMid, Point2d NewMid)>();
                var movedSourceSegments = new List<(ObjectId Id, Point2d OldA, Point2d OldB, Point2d NewA, Point2d NewB)>();

                foreach (var src in sourceSegments)
                {
                    // Never shift original L-USEC south-boundary segments to generated 20.11 targets.
                    if (src.IsUsec)
                    {
                        continue;
                    }

                    if (!IsHorizontalLike(src.A, src.B))
                    {
                        continue;
                    }
                    secHorizontalSources++;

                    var west = src.A;
                    var east = src.B;
                    if (east.X < west.X)
                    {
                        var tmp = west;
                        west = east;
                        east = tmp;
                    }

                    // Must be west-half style segment: east endpoint has horizontal continuation to the east.
                    var hasEastContinuation = false;
                    foreach (var other in sourceSegments)
                    {
                        if (other.Id == src.Id || !IsHorizontalLike(other.A, other.B))
                        {
                            continue;
                        }

                        if (Near(east, other.A, cornerTol) && other.B.X > (east.X + cornerTol))
                        {
                            hasEastContinuation = true;
                            break;
                        }

                        if (Near(east, other.B, cornerTol) && other.A.X > (east.X + cornerTol))
                        {
                            hasEastContinuation = true;
                            break;
                        }
                    }

                    if (!hasEastContinuation)
                    {
                        continue;
                    }

                    // Must touch west vertical L-USEC and represent SW corner behavior
                    // (connected vertical line goes north from this corner).
                    var touchesWestUsec = false;
                    var hasNorthwardVertical = false;
                    foreach (var boundary in verticalUsecBoundaries)
                    {
                        var d = DistancePointToSegment(west, boundary.A, boundary.B);
                        if (d > touchTol)
                        {
                            continue;
                        }

                        touchesWestUsec = true;
                        var da = west.GetDistanceTo(boundary.A);
                        var db = west.GetDistanceTo(boundary.B);
                        var far = da >= db ? boundary.A : boundary.B;
                        if (far.Y > (west.Y + cornerTol))
                        {
                            hasNorthwardVertical = true;
                        }
                    }

                    if (!touchesWestUsec || !hasNorthwardVertical)
                    {
                        continue;
                    }

                    var outward = west - east;
                    var outwardLen = outward.Length;
                    if (outwardLen <= 1e-6)
                    {
                        continue;
                    }

                    var outwardDir = outward / outwardLen;
                    double? bestT = null;
                    var targetCandidates = new List<(double T, bool IsUsecLayer)>();
                    for (var ti = 0; ti < generatedUsecVerticalTargets.Count; ti++)
                    {
                        var target = generatedUsecVerticalTargets[ti];
                        if (!TryIntersectInfiniteLineWithSegment(west, outwardDir, target.A, target.B, out var t))
                        {
                            continue;
                        }

                        if (t <= minExtend || t > maxExtend)
                        {
                            continue;
                        }

                        targetCandidates.Add((t, target.IsUsecLayer));
                    }

                    for (var ti = 0; ti < verticalUsecBoundaries.Count; ti++)
                    {
                        var target = verticalUsecBoundaries[ti];
                        if (!TryIntersectInfiniteLineWithSegment(west, outwardDir, target.A, target.B, out var t))
                        {
                            continue;
                        }

                        if (t <= minExtend || t > maxExtend)
                        {
                            continue;
                        }

                        targetCandidates.Add((t, true));
                    }

                    if (targetCandidates.Count > 0)
                    {
                        var twentyUsecCandidates = targetCandidates
                            .Where(c => c.IsUsecLayer &&
                                        c.T >= twentyTwelveBandMin &&
                                        c.T <= twentyTwelveBandMax)
                            .OrderBy(c => c.T)
                            .ToList();
                        var twentyAnyCandidates = targetCandidates
                            .Where(c => c.T >= twentyTwelveBandMin &&
                                        c.T <= twentyTwelveBandMax)
                            .OrderBy(c => c.T)
                            .ToList();

                        if (src.IsSec)
                        {
                            if (twentyUsecCandidates.Count > 0)
                            {
                                bestT = twentyUsecCandidates[0].T;
                                secHorizontalWithTwentyBandTarget++;
                            }
                            else if (twentyAnyCandidates.Count > 0)
                            {
                                bestT = twentyAnyCandidates[0].T;
                                secHorizontalWithTwentyBandTarget++;
                            }
                            else
                            {
                                secHorizontalRejectedNoTwentyBandTarget++;
                            }
                        }
                    }

                    var finalWest = west;
                    if (bestT.HasValue)
                    {
                        finalWest = west + (outwardDir * bestT.Value);
                    }
                    else
                    {
                        var westAtGeneratedTarget = false;
                        for (var gi = 0; gi < generatedUsecVerticalTargets.Count; gi++)
                        {
                            var target = generatedUsecVerticalTargets[gi];
                            if (DistancePointToSegment(west, target.A, target.B) <= touchTol)
                            {
                                westAtGeneratedTarget = true;
                                break;
                            }
                        }

                        if (!westAtGeneratedTarget)
                        {
                            continue;
                        }
                    }

                    var eastAnchor = east;

                    if (finalWest.GetDistanceTo(west) <= endpointMoveTol)
                    {
                        continue;
                    }

                    if (!(tr.GetObject(src.Id, OpenMode.ForWrite, false) is Entity writable) || writable.IsErased)
                    {
                        continue;
                    }

                    if (writable is Line ln)
                    {
                        if (west.GetDistanceTo(src.A) <= west.GetDistanceTo(src.B))
                        {
                            ln.StartPoint = new Point3d(finalWest.X, finalWest.Y, ln.StartPoint.Z);
                        }
                        else
                        {
                            ln.EndPoint = new Point3d(finalWest.X, finalWest.Y, ln.EndPoint.Z);
                        }
                    }
                    else if (writable is Polyline pl && !pl.Closed && pl.NumberOfVertices == 2)
                    {
                        if (west.GetDistanceTo(src.A) <= west.GetDistanceTo(src.B))
                        {
                            pl.SetPointAt(0, finalWest);
                        }
                        else
                        {
                            pl.SetPointAt(1, finalWest);
                        }
                    }
                    else
                    {
                        continue;
                    }

                    adjusted++;
                    lsdMidpointAdjustments.Add((west, eastAnchor, Midpoint(west, eastAnchor), Midpoint(finalWest, eastAnchor)));
                    movedSourceSegments.Add((src.Id, west, eastAnchor, finalWest, eastAnchor));
                }

                var blindSiblingErased = 0;
                if (movedSourceSegments.Count > 0)
                {
                    const double siblingEndpointTol = 0.35;
                    var movedIds = new HashSet<ObjectId>(movedSourceSegments.Select(m => m.Id));
                    foreach (var source in sourceSegments)
                    {
                        if (movedIds.Contains(source.Id))
                        {
                            continue;
                        }

                        if (!(tr.GetObject(source.Id, OpenMode.ForWrite, false) is Entity sibling) || sibling.IsErased)
                        {
                            continue;
                        }

                        if (!TryReadOpenSegment(sibling, out var aSibling, out var bSibling) || !IsHorizontalLike(aSibling, bSibling))
                        {
                            continue;
                        }

                        var erase = false;
                        for (var mi = 0; mi < movedSourceSegments.Count; mi++)
                        {
                            var moved = movedSourceSegments[mi];
                            if (!AreSegmentsDuplicateOrCollinearOverlap(aSibling, bSibling, moved.OldA, moved.OldB))
                            {
                                continue;
                            }

                            if (!AreSegmentEndpointsNear(aSibling, bSibling, moved.OldA, moved.OldB, siblingEndpointTol))
                            {
                                continue;
                            }

                            if (AreSegmentEndpointsNear(aSibling, bSibling, moved.NewA, moved.NewB, siblingEndpointTol))
                            {
                                continue;
                            }

                            erase = true;
                            break;
                        }

                        if (!erase)
                        {
                            continue;
                        }

                        sibling.Erase();
                        blindSiblingErased++;
                    }
                }

                var lsdAdjusted = 0;
                if (lsdMidpointAdjustments.Count > 0 && lsdSegments.Count > 0)
                {
                    const double lsdOldSegmentTol = 0.35;
                    const double lsdOldMidpointTol = 8.5;
                    const double lsdMaxMove = 80.0;

                    bool TryBestMidpoint(Point2d endpoint, out Point2d midpoint, out double bestDistance, out double moveDistance)
                    {
                        midpoint = endpoint;
                        bestDistance = double.MaxValue;
                        moveDistance = double.MaxValue;
                        var bestSegDistance = double.MaxValue;

                        for (var ei = 0; ei < lsdMidpointAdjustments.Count; ei++)
                        {
                            var adj = lsdMidpointAdjustments[ei];
                            var segDistance = DistancePointToSegment(endpoint, adj.OldA, adj.OldB);
                            if (segDistance > lsdOldSegmentTol)
                            {
                                continue;
                            }

                            var d = endpoint.GetDistanceTo(adj.OldMid);
                            if (d > lsdOldMidpointTol)
                            {
                                continue;
                            }

                            var move = endpoint.GetDistanceTo(adj.NewMid);
                            if (move <= endpointMoveTol || move > lsdMaxMove)
                            {
                                continue;
                            }

                            var isBetterSegment = segDistance < (bestSegDistance - 1e-6);
                            var isTiedSegment = Math.Abs(segDistance - bestSegDistance) <= 1e-6;
                            var isBetterMidDistance = isTiedSegment && d < (bestDistance - 1e-6);
                            var isTiedMidDistance = isTiedSegment && Math.Abs(d - bestDistance) <= 1e-6;
                            var isBetterMoveOnTie = isTiedMidDistance && move < moveDistance;
                            if (!isBetterSegment && !isBetterMidDistance && !isBetterMoveOnTie)
                            {
                                continue;
                            }

                            bestSegDistance = segDistance;
                            bestDistance = d;
                            moveDistance = move;
                            midpoint = adj.NewMid;
                        }

                        return bestDistance < double.MaxValue;
                    }

                    foreach (var lsd in lsdSegments)
                    {
                        if (!(tr.GetObject(lsd.Id, OpenMode.ForWrite, false) is Entity writableLsd) || writableLsd.IsErased)
                        {
                            continue;
                        }

                        if (!TryReadOpenSegment(writableLsd, out var p0, out var p1))
                        {
                            continue;
                        }

                        if (!IsAdjustableLsdLineSegment(p0, p1))
                        {
                            continue;
                        }

                        var has0 = TryBestMidpoint(p0, out var mid0, out var d0, out _);
                        var has1 = TryBestMidpoint(p1, out var mid1, out var d1, out _);
                        if (!has0 && !has1)
                        {
                            continue;
                        }

                        var moveStart = has0;
                        var targetMid = mid0;
                        if (!has0 || (has1 && d1 < d0))
                        {
                            moveStart = false;
                            targetMid = mid1;
                        }

                        if (writableLsd is Line lsdLine)
                        {
                            if (moveStart)
                            {
                                lsdLine.StartPoint = new Point3d(targetMid.X, targetMid.Y, lsdLine.StartPoint.Z);
                            }
                            else
                            {
                                lsdLine.EndPoint = new Point3d(targetMid.X, targetMid.Y, lsdLine.EndPoint.Z);
                            }
                        }
                        else if (writableLsd is Polyline lsdPoly && !lsdPoly.Closed && lsdPoly.NumberOfVertices == 2)
                        {
                            lsdPoly.SetPointAt(moveStart ? 0 : 1, targetMid);
                        }
                        else
                        {
                            continue;
                        }

                        lsdAdjusted++;
                    }
                }

                tr.Commit();
                if (adjusted > 0)
                {
                    logger?.WriteLine($"Cleanup: extended {adjusted} SW south-boundary west endpoint(s) to next L-USEC line.");
                }
                if (lsdAdjusted > 0)
                {
                    logger?.WriteLine($"Cleanup: adjusted {lsdAdjusted} L-SECTION-LSD endpoint(s) to midpoint of SW south-boundary extension line(s) [segment-anchored].");
                }
                if (blindSiblingErased > 0)
                {
                    logger?.WriteLine($"Cleanup: erased {blindSiblingErased} blind-line sibling segment(s) after SW extension.");
                }
                logger?.WriteLine(
                    $"Cleanup: SW south-boundary 20.11 target stats sources={secHorizontalSources}, with20.11Target={secHorizontalWithTwentyBandTarget}, rejectedNo20.11Target={secHorizontalRejectedNoTwentyBandTarget}, adjusted={adjusted}.");
            }
        }
        private static void ExtendNwQuarterWestUsecNorthToNextHorizontalUsec(
            Database database,
            IEnumerable<QuarterLabelInfo> labelQuarterInfos,
            IReadOnlyCollection<ObjectId> generatedRoadAllowanceIds,
            Logger? logger)
        {
            if (database == null || labelQuarterInfos == null || generatedRoadAllowanceIds == null || generatedRoadAllowanceIds.Count == 0)
            {
                return;
            }

            var requestedQuarterIds = labelQuarterInfos
                .Where(info =>
                    info != null &&
                    info.Quarter == QuarterSelection.NorthWest &&
                    !info.QuarterId.IsNull)
                .Select(info => info.QuarterId)
                .Distinct()
                .ToList();
            if (requestedQuarterIds.Count == 0)
            {
                return;
            }

            var clipWindows = BuildBufferedQuarterWindows(database, requestedQuarterIds, 100.0);
            if (clipWindows.Count == 0)
            {
                return;
            }

            bool IsPointInAnyWindow(Point2d p)
            {
                for (var i = 0; i < clipWindows.Count; i++)
                {
                    var w = clipWindows[i];
                    if (p.X >= w.MinPoint.X && p.X <= w.MaxPoint.X &&
                        p.Y >= w.MinPoint.Y && p.Y <= w.MaxPoint.Y)
                    {
                        return true;
                    }
                }

                return false;
            }

            bool DoesSegmentIntersectAnyWindow(Point2d a, Point2d b)
            {
                if (IsPointInAnyWindow(a) || IsPointInAnyWindow(b))
                {
                    return true;
                }

                for (var i = 0; i < clipWindows.Count; i++)
                {
                    if (TryClipSegmentToWindow(a, b, clipWindows[i], out _, out _))
                    {
                        return true;
                    }
                }

                return false;
            }

            bool TryReadOpenSegment(Entity ent, out Point2d a, out Point2d b)
            {
                a = default;
                b = default;
                if (ent == null)
                {
                    return false;
                }

                if (ent is Line ln)
                {
                    a = new Point2d(ln.StartPoint.X, ln.StartPoint.Y);
                    b = new Point2d(ln.EndPoint.X, ln.EndPoint.Y);
                    return a.GetDistanceTo(b) > 1e-4;
                }

                if (ent is Polyline pl)
                {
                    if (pl.Closed || pl.NumberOfVertices != 2)
                    {
                        return false;
                    }

                    a = pl.GetPoint2dAt(0);
                    b = pl.GetPoint2dAt(1);
                    return a.GetDistanceTo(b) > 1e-4;
                }

                return false;
            }

            bool IsHorizontalLike(Point2d a, Point2d b)
            {
                var d = b - a;
                return Math.Abs(d.X) >= Math.Abs(d.Y);
            }

            bool IsVerticalLike(Point2d a, Point2d b)
            {
                var d = b - a;
                return Math.Abs(d.Y) > Math.Abs(d.X);
            }

            bool TryIntersectInfiniteLines(Point2d a0, Point2d a1, Point2d b0, Point2d b1, out Point2d intersection)
            {
                intersection = default;
                var da = a1 - a0;
                var db = b1 - b0;
                var denom = Cross2d(da, db);
                if (Math.Abs(denom) <= 1e-9)
                {
                    return false;
                }

                var diff = b0 - a0;
                var t = Cross2d(diff, db) / denom;
                intersection = a0 + (da * t);
                return true;
            }

            var generatedSet = new HashSet<ObjectId>(generatedRoadAllowanceIds.Where(id => !id.IsNull));
            using (var tr = database.TransactionManager.StartTransaction())
            {
                var horizontalSources = new List<(ObjectId Id, Point2d A, Point2d B, bool Generated)>();
                var generatedVerticalUsec = new List<(ObjectId Id, Point2d North, Point2d South)>();
                var verticalRoadBoundaries = new List<(ObjectId Id, Point2d A, Point2d B)>();
                var horizontalRoadBoundaries = new List<(ObjectId Id, Point2d A, Point2d B, bool IsSec, bool IsUsec, bool Generated)>();
                var verticalRoadCandidates = new List<(ObjectId Id, Point2d A, Point2d B, bool IsSec, bool IsUsec, bool Generated)>();
                var lsdSegments = new List<(ObjectId Id, Point2d A, Point2d B)>();

                var bt = (BlockTable)tr.GetObject(database.BlockTableId, OpenMode.ForRead);
                var ms = (BlockTableRecord)tr.GetObject(bt[BlockTableRecord.ModelSpace], OpenMode.ForRead);
                foreach (ObjectId id in ms)
                {
                    if (!(tr.GetObject(id, OpenMode.ForRead, false) is Entity ent) || ent.IsErased)
                    {
                        continue;
                    }

                    if (!TryReadOpenSegment(ent, out var a, out var b))
                    {
                        continue;
                    }

                    if (!DoesSegmentIntersectAnyWindow(a, b))
                    {
                        continue;
                    }

                    if (string.Equals(ent.Layer, "L-SECTION-LSD", StringComparison.OrdinalIgnoreCase))
                    {
                        if (IsAdjustableLsdLineSegment(a, b))
                        {
                            lsdSegments.Add((id, a, b));
                        }

                        continue;
                    }

                    var isUsec = string.Equals(ent.Layer, "L-USEC", StringComparison.OrdinalIgnoreCase);
                    var isSec = string.Equals(ent.Layer, "L-SEC", StringComparison.OrdinalIgnoreCase);
                    if (!isUsec && !isSec)
                    {
                        continue;
                    }

                    var generated = generatedSet.Contains(id);
                    if (isUsec && generated && IsHorizontalLike(a, b))
                    {
                        horizontalSources.Add((id, a, b, generated));
                    }
                    if (IsHorizontalLike(a, b))
                    {
                        horizontalRoadBoundaries.Add((id, a, b, isSec, isUsec, generated));
                    }

                    if ((isUsec || isSec) && IsVerticalLike(a, b))
                    {
                        verticalRoadBoundaries.Add((id, a, b));
                        verticalRoadCandidates.Add((id, a, b, isSec, isUsec, generated));
                    }

                    if (isUsec && generated && IsVerticalLike(a, b))
                    {
                        var north = a;
                        var south = b;
                        if (south.Y > north.Y)
                        {
                            var tmp = north;
                            north = south;
                            south = tmp;
                        }

                        generatedVerticalUsec.Add((id, north, south));
                    }
                }

                var canRunLegacyPass = horizontalSources.Count > 0 && generatedVerticalUsec.Count > 0;

                const double endpointMoveTol = 0.05;
                const double searchRadius = 18.0;
                const double maxExtend = 40.0;
                const double boundaryHitTol = 0.35;
                const double boundaryEndpointTol = 0.20;
                const double classTwentyGap = 20.11;
                const double classThirtyGap = RoadAllowanceUsecWidthMeters;
                const double classTenGap = CorrectionLinePairGapMeters;
                const double classTwentyTol = 1.10;
                const double classThirtyTol = 1.60;
                const double classTenTol = 2.40;
                const double classMinOverlap = 4.0;
                const int roadClassUnknown = 0;
                const int roadClassTwenty = 20;
                const int roadClassThirty = 30;

                var roadClassSegments = new List<(ObjectId Id, Point2d A, Point2d B, bool Horizontal, bool Vertical, double Axis, double MajorMin, double MajorMax)>();
                var roadClassById = new Dictionary<ObjectId, int>();
                var blindRoadIds = new HashSet<ObjectId>();
                {
                    var classSeen = new HashSet<ObjectId>();
                    for (var i = 0; i < horizontalRoadBoundaries.Count; i++)
                    {
                        var seg = horizontalRoadBoundaries[i];
                        if (!classSeen.Add(seg.Id))
                        {
                            continue;
                        }

                        var axis = 0.5 * (seg.A.Y + seg.B.Y);
                        roadClassSegments.Add((seg.Id, seg.A, seg.B, true, false, axis, Math.Min(seg.A.X, seg.B.X), Math.Max(seg.A.X, seg.B.X)));
                    }

                    for (var i = 0; i < verticalRoadCandidates.Count; i++)
                    {
                        var seg = verticalRoadCandidates[i];
                        if (!classSeen.Add(seg.Id))
                        {
                            continue;
                        }

                        var axis = 0.5 * (seg.A.X + seg.B.X);
                        roadClassSegments.Add((seg.Id, seg.A, seg.B, false, true, axis, Math.Min(seg.A.Y, seg.B.Y), Math.Max(seg.A.Y, seg.B.Y)));
                    }

                    var hasTwenty = new bool[roadClassSegments.Count];
                    var hasThirty = new bool[roadClassSegments.Count];
                    var hasTen = new bool[roadClassSegments.Count];
                    for (var i = 0; i < roadClassSegments.Count; i++)
                    {
                        var a = roadClassSegments[i];
                        for (var j = i + 1; j < roadClassSegments.Count; j++)
                        {
                            var b = roadClassSegments[j];
                            if ((a.Horizontal != b.Horizontal) || (a.Vertical != b.Vertical))
                            {
                                continue;
                            }

                            var overlap = Math.Min(a.MajorMax, b.MajorMax) - Math.Max(a.MajorMin, b.MajorMin);
                            if (overlap < classMinOverlap)
                            {
                                continue;
                            }

                            var gap = Math.Abs(a.Axis - b.Axis);
                            if (Math.Abs(gap - classTwentyGap) <= classTwentyTol)
                            {
                                hasTwenty[i] = true;
                                hasTwenty[j] = true;
                            }

                            if (Math.Abs(gap - classThirtyGap) <= classThirtyTol)
                            {
                                hasThirty[i] = true;
                                hasThirty[j] = true;
                            }

                            if (Math.Abs(gap - classTenGap) <= classTenTol)
                            {
                                hasTen[i] = true;
                                hasTen[j] = true;
                            }
                        }
                    }

                    bool HasAnyTouch(ObjectId selfId, Point2d endpoint)
                    {
                        for (var ri = 0; ri < roadClassSegments.Count; ri++)
                        {
                            var road = roadClassSegments[ri];
                            if (road.Id == selfId)
                            {
                                continue;
                            }

                            if (DistancePointToSegment(endpoint, road.A, road.B) <= boundaryHitTol)
                            {
                                return true;
                            }
                        }

                        return false;
                    }

                    for (var i = 0; i < roadClassSegments.Count; i++)
                    {
                        var seg = roadClassSegments[i];
                        var cls = roadClassUnknown;
                        if (hasThirty[i] && hasTen[i])
                        {
                            cls = roadClassThirty;
                        }
                        else if (hasTwenty[i] || hasTen[i] || hasThirty[i])
                        {
                            cls = roadClassTwenty;
                        }

                        roadClassById[seg.Id] = cls;

                        var endATouch = HasAnyTouch(seg.Id, seg.A);
                        var endBTouch = HasAnyTouch(seg.Id, seg.B);
                        if (!endATouch || !endBTouch)
                        {
                            blindRoadIds.Add(seg.Id);
                        }
                    }
                }

                bool IsAllowedClassConnection(
                    ObjectId sourceId,
                    ObjectId targetId)
                {
                    roadClassById.TryGetValue(sourceId, out var sourceClass);
                    roadClassById.TryGetValue(targetId, out var targetClass);

                    if (sourceClass == roadClassTwenty)
                    {
                        return targetClass == roadClassTwenty || blindRoadIds.Contains(targetId);
                    }

                    if (sourceClass == roadClassThirty)
                    {
                        return targetClass == roadClassThirty;
                    }

                    return true;
                }

                bool TryGetNearestThirtyVerticalAxis(Point2d referencePoint, double overlapMinY, double overlapMaxY, out double axisX)
                {
                    axisX = 0.0;
                    var bestScore = double.MaxValue;
                    var found = false;
                    for (var i = 0; i < roadClassSegments.Count; i++)
                    {
                        var road = roadClassSegments[i];
                        if (!road.Vertical)
                        {
                            continue;
                        }

                        if (!roadClassById.TryGetValue(road.Id, out var cls) || cls != roadClassThirty)
                        {
                            continue;
                        }

                        var overlap = Math.Min(overlapMaxY, road.MajorMax) - Math.Max(overlapMinY, road.MajorMin);
                        if (overlap < classMinOverlap)
                        {
                            continue;
                        }

                        var score = Math.Abs(referencePoint.X - road.Axis);
                        if (score < bestScore)
                        {
                            bestScore = score;
                            axisX = road.Axis;
                            found = true;
                        }
                    }

                    return found;
                }

                bool IsTwentyHorizontalToVerticalSameSideConnection(
                    ObjectId sourceId,
                    Point2d sourceA,
                    Point2d sourceB,
                    Point2d sourceReference,
                    ObjectId targetId,
                    Point2d targetA,
                    Point2d targetB,
                    Point2d targetReference)
                {
                    if (!roadClassById.TryGetValue(sourceId, out var sourceClass) || sourceClass != roadClassTwenty)
                    {
                        return true;
                    }

                    if (!roadClassById.TryGetValue(targetId, out var targetClass) || targetClass != roadClassTwenty)
                    {
                        return true;
                    }

                    if (!IsHorizontalLike(sourceA, sourceB) || !IsVerticalLike(targetA, targetB))
                    {
                        return true;
                    }

                    var targetMinY = Math.Min(targetA.Y, targetB.Y);
                    var targetMaxY = Math.Max(targetA.Y, targetB.Y);
                    if (!TryGetNearestThirtyVerticalAxis(sourceReference, targetMinY, targetMaxY, out var axisX))
                    {
                        return true;
                    }

                    var sourceDx = sourceReference.X - axisX;
                    var targetDx = targetReference.X - axisX;
                    if (Math.Abs(sourceDx) <= boundaryEndpointTol || Math.Abs(targetDx) <= boundaryEndpointTol)
                    {
                        return true;
                    }

                    return Math.Sign(sourceDx) == Math.Sign(targetDx);
                }

                bool HasInterveningVerticalRoad(Point2d from, Point2d to, ObjectId anchorId)
                {
                    for (var i = 0; i < verticalRoadBoundaries.Count; i++)
                    {
                        var candidate = verticalRoadBoundaries[i];
                        if (candidate.Id == anchorId)
                        {
                            continue;
                        }

                        if (!TryIntersectInfiniteLines(from, to, candidate.A, candidate.B, out var hit))
                        {
                            continue;
                        }

                        if (DistancePointToSegment(hit, from, to) > boundaryHitTol)
                        {
                            continue;
                        }

                        if (DistancePointToSegment(hit, candidate.A, candidate.B) > boundaryHitTol)
                        {
                            continue;
                        }

                        if (hit.GetDistanceTo(from) <= boundaryEndpointTol ||
                            hit.GetDistanceTo(to) <= boundaryEndpointTol)
                        {
                            continue;
                        }

                        return true;
                    }

                    return false;
                }

                bool TryMoveEndpoint(Entity writable, Point2d oldEndpoint, Point2d newEndpoint)
                {
                    if (newEndpoint.GetDistanceTo(oldEndpoint) <= endpointMoveTol)
                    {
                        return false;
                    }

                    if (writable is Line ln)
                    {
                        var start = new Point2d(ln.StartPoint.X, ln.StartPoint.Y);
                        var end = new Point2d(ln.EndPoint.X, ln.EndPoint.Y);
                        if (start.GetDistanceTo(oldEndpoint) <= end.GetDistanceTo(oldEndpoint))
                        {
                            ln.StartPoint = new Point3d(newEndpoint.X, newEndpoint.Y, ln.StartPoint.Z);
                        }
                        else
                        {
                            ln.EndPoint = new Point3d(newEndpoint.X, newEndpoint.Y, ln.EndPoint.Z);
                        }

                        return true;
                    }

                    if (writable is Polyline pl && !pl.Closed && pl.NumberOfVertices == 2)
                    {
                        var p0 = pl.GetPoint2dAt(0);
                        var p1 = pl.GetPoint2dAt(1);
                        if (p0.GetDistanceTo(oldEndpoint) <= p1.GetDistanceTo(oldEndpoint))
                        {
                            pl.SetPointAt(0, newEndpoint);
                        }
                        else
                        {
                            pl.SetPointAt(1, newEndpoint);
                        }

                        return true;
                    }

                    return false;
                }

                bool TryAddConnectorSegment(Point2d from, Point2d to, string layerName)
                {
                    if (to.GetDistanceTo(from) <= endpointMoveTol)
                    {
                        return false;
                    }

                    try
                    {
                        var btWrite = (BlockTable)tr.GetObject(database.BlockTableId, OpenMode.ForRead);
                        var msWrite = (BlockTableRecord)tr.GetObject(btWrite[BlockTableRecord.ModelSpace], OpenMode.ForWrite);
                        var connector = new Line(
                            new Point3d(from.X, from.Y, 0.0),
                            new Point3d(to.X, to.Y, 0.0));
                        if (!string.IsNullOrWhiteSpace(layerName))
                        {
                            connector.Layer = layerName;
                        }

                        msWrite.AppendEntity(connector);
                        tr.AddNewlyCreatedDBObject(connector, true);
                        return true;
                    }
                    catch
                    {
                        return false;
                    }
                }

                var adjusted = 0;
                var usedHorizontals = new HashSet<ObjectId>();
                var pairTried = 0;
                var pairChosen = 0;
                var pairAmbiguousSkipped = 0;
                var blockedByInterveningVerticalRoad = 0;
                var classRuleRejected = 0;
                var twentySideRuleRejected = 0;
                var lsdMidpointAdjustments = new List<(Point2d OldA, Point2d OldB, Point2d OldMid, Point2d NewMid)>();
                var movedHorizontalSegments = new List<(ObjectId Id, Point2d OldA, Point2d OldB, Point2d NewA, Point2d NewB)>();

                if (canRunLegacyPass)
                {
                    for (var pass = 0; pass < 2; pass++)
                    {
                        var allowGenerated = pass == 1;
                        var adjustedThisPass = 0;

                        foreach (var anchor in generatedVerticalUsec)
                        {
                            var bestId = ObjectId.Null;
                            var bestOld = default(Point2d);
                            var bestOther = default(Point2d);
                            var bestNew = default(Point2d);
                            var bestScore = double.MaxValue;
                            var secondBestScore = double.MaxValue;

                            for (var i = 0; i < horizontalSources.Count; i++)
                            {
                                var src = horizontalSources[i];
                                if (!allowGenerated && src.Generated)
                                {
                                    continue;
                                }

                                if (usedHorizontals.Contains(src.Id))
                                {
                                    continue;
                                }

                                var endpoint0 = src.A;
                                var endpoint1 = src.B;
                                var anchorPoint = endpoint0.GetDistanceTo(anchor.South) <= endpoint1.GetDistanceTo(anchor.South)
                                    ? anchor.South
                                    : anchor.North;
                                var movePoint = endpoint0;
                                var otherPoint = endpoint1;
                                if (endpoint1.GetDistanceTo(anchorPoint) < endpoint0.GetDistanceTo(anchorPoint))
                                {
                                    movePoint = endpoint1;
                                    otherPoint = endpoint0;
                                }

                                var midpointTarget = Midpoint(anchor.North, anchor.South);

                                var dx = src.B.X - src.A.X;
                                if (Math.Abs(dx) <= 1e-8)
                                {
                                    continue;
                                }

                                var t = (anchorPoint.X - src.A.X) / dx;
                                var yTarget = src.A.Y + (t * (src.B.Y - src.A.Y));
                                var candidateTarget = new Point2d(anchorPoint.X, yTarget);

                                var moveDist = movePoint.GetDistanceTo(candidateTarget);
                                if (moveDist <= endpointMoveTol || moveDist > maxExtend)
                                {
                                    continue;
                                }

                                var anchorDist = movePoint.GetDistanceTo(anchorPoint);
                                if (anchorDist > searchRadius)
                                {
                                    continue;
                                }

                                const double midpointSnapTol = 0.10;
                                var finalTarget = candidateTarget;
                                if (candidateTarget.GetDistanceTo(midpointTarget) <= midpointSnapTol)
                                {
                                    finalTarget = midpointTarget;
                                }

                                if (!IsAllowedClassConnection(src.Id, anchor.Id))
                                {
                                    classRuleRejected++;
                                    continue;
                                }

                                if (!IsTwentyHorizontalToVerticalSameSideConnection(
                                        src.Id,
                                        src.A,
                                        src.B,
                                        movePoint,
                                        anchor.Id,
                                        anchor.North,
                                        anchor.South,
                                        anchorPoint))
                                {
                                    twentySideRuleRejected++;
                                    continue;
                                }

                                if (HasInterveningVerticalRoad(movePoint, finalTarget, anchor.Id))
                                {
                                    blockedByInterveningVerticalRoad++;
                                    continue;
                                }

                                var score = moveDist + (2.0 * Math.Abs(movePoint.Y - anchorPoint.Y));
                                pairTried++;
                                if (score < bestScore)
                                {
                                    secondBestScore = bestScore;
                                    bestScore = score;
                                    bestId = src.Id;
                                    bestOld = movePoint;
                                    bestOther = otherPoint;
                                    bestNew = finalTarget;
                                }
                                else if (score < secondBestScore)
                                {
                                    secondBestScore = score;
                                }
                            }

                            if (bestId.IsNull)
                            {
                                continue;
                            }

                            // Skip ambiguous picks where two opposite-side candidates score nearly the same.
                            if (secondBestScore < double.MaxValue && (secondBestScore - bestScore) < 1.0)
                            {
                                pairAmbiguousSkipped++;
                                continue;
                            }

                            if (!(tr.GetObject(bestId, OpenMode.ForRead, false) is Entity readable) || readable.IsErased)
                            {
                                continue;
                            }

                            // Non-destructive: add connector only, do not move existing endpoints.
                            if (TryAddConnectorSegment(bestOld, bestNew, readable.Layer))
                            {
                                adjusted++;
                                adjustedThisPass++;
                                pairChosen++;
                                usedHorizontals.Add(bestId);
                            }
                        }

                        if (adjustedThisPass > 0)
                        {
                            break;
                        }
                    }
                }

                var blindSiblingErased = 0;
                if (movedHorizontalSegments.Count > 0)
                {
                    const double siblingEndpointTol = 0.35;
                    var movedIds = new HashSet<ObjectId>(movedHorizontalSegments.Select(m => m.Id));
                    for (var i = 0; i < horizontalSources.Count; i++)
                    {
                        var source = horizontalSources[i];
                        if (movedIds.Contains(source.Id))
                        {
                            continue;
                        }

                        if (!(tr.GetObject(source.Id, OpenMode.ForWrite, false) is Entity sibling) || sibling.IsErased)
                        {
                            continue;
                        }

                        if (!TryReadOpenSegment(sibling, out var aSibling, out var bSibling) || !IsHorizontalLike(aSibling, bSibling))
                        {
                            continue;
                        }

                        var erase = false;
                        for (var mi = 0; mi < movedHorizontalSegments.Count; mi++)
                        {
                            var moved = movedHorizontalSegments[mi];
                            if (!AreSegmentsDuplicateOrCollinearOverlap(aSibling, bSibling, moved.OldA, moved.OldB))
                            {
                                continue;
                            }

                            if (!AreSegmentEndpointsNear(aSibling, bSibling, moved.OldA, moved.OldB, siblingEndpointTol))
                            {
                                continue;
                            }

                            if (AreSegmentEndpointsNear(aSibling, bSibling, moved.NewA, moved.NewB, siblingEndpointTol))
                            {
                                continue;
                            }

                            erase = true;
                            break;
                        }

                        if (!erase)
                        {
                            continue;
                        }

                        sibling.Erase();
                        blindSiblingErased++;
                    }
                }

                var lsdAdjusted = 0;
                if (lsdMidpointAdjustments.Count > 0 && lsdSegments.Count > 0)
                {
                    const double lsdOldSegmentTol = 0.35;
                    const double lsdOldMidpointTol = 12.0;
                    const double lsdMaxMove = 40.0;

                    bool TryBestMidpoint(Point2d endpoint, out Point2d midpoint, out double bestDistance)
                    {
                        midpoint = endpoint;
                        bestDistance = double.MaxValue;
                        var bestSegDistance = double.MaxValue;
                        var bestMoveDistance = double.MaxValue;

                        for (var i = 0; i < lsdMidpointAdjustments.Count; i++)
                        {
                            var adj = lsdMidpointAdjustments[i];
                            var segDistance = DistancePointToSegment(endpoint, adj.OldA, adj.OldB);
                            if (segDistance > lsdOldSegmentTol)
                            {
                                continue;
                            }

                            var d = endpoint.GetDistanceTo(adj.OldMid);
                            if (d > lsdOldMidpointTol)
                            {
                                continue;
                            }

                            var move = endpoint.GetDistanceTo(adj.NewMid);
                            if (move <= endpointMoveTol || move > lsdMaxMove)
                            {
                                continue;
                            }

                            var betterSeg = segDistance < (bestSegDistance - 1e-6);
                            var tiedSeg = Math.Abs(segDistance - bestSegDistance) <= 1e-6;
                            var betterMid = tiedSeg && d < (bestDistance - 1e-6);
                            var tiedMid = tiedSeg && Math.Abs(d - bestDistance) <= 1e-6;
                            var betterMove = tiedMid && move < bestMoveDistance;
                            if (!betterSeg && !betterMid && !betterMove)
                            {
                                continue;
                            }

                            bestSegDistance = segDistance;
                            bestDistance = d;
                            bestMoveDistance = move;
                            midpoint = adj.NewMid;
                        }

                        return bestDistance < double.MaxValue;
                    }

                    for (var i = 0; i < lsdSegments.Count; i++)
                    {
                        var lsd = lsdSegments[i];
                        if (!(tr.GetObject(lsd.Id, OpenMode.ForWrite, false) is Entity writableLsd) || writableLsd.IsErased)
                        {
                            continue;
                        }

                        if (!TryReadOpenSegment(writableLsd, out var p0, out var p1))
                        {
                            continue;
                        }

                        if (!IsAdjustableLsdLineSegment(p0, p1))
                        {
                            continue;
                        }

                        var has0 = TryBestMidpoint(p0, out var mid0, out var d0);
                        var has1 = TryBestMidpoint(p1, out var mid1, out var d1);
                        if (!has0 && !has1)
                        {
                            continue;
                        }

                        var moveStart = has0;
                        var targetMid = mid0;
                        if (!has0 || (has1 && d1 < d0))
                        {
                            moveStart = false;
                            targetMid = mid1;
                        }

                        if (writableLsd is Line lsdLine)
                        {
                            if (moveStart)
                            {
                                lsdLine.StartPoint = new Point3d(targetMid.X, targetMid.Y, lsdLine.StartPoint.Z);
                            }
                            else
                            {
                                lsdLine.EndPoint = new Point3d(targetMid.X, targetMid.Y, lsdLine.EndPoint.Z);
                            }
                        }
                        else if (writableLsd is Polyline lsdPoly && !lsdPoly.Closed && lsdPoly.NumberOfVertices == 2)
                        {
                            lsdPoly.SetPointAt(moveStart ? 0 : 1, targetMid);
                        }
                        else
                        {
                            continue;
                        }

                        lsdAdjusted++;
                    }
                }

                var nwSecondWestSecAdjusted = 0;
                var nwSecondWestSecCandidates = 0;
                var nwSecondWestSecWithNorthTarget = 0;
                var nwSecondWestSecUsecFallback = 0;
                var nwSecondWestSecRejectedSouthHalf = 0;
                var nwSecondWestSecMissingSecondCluster = 0;
                var nwSecondWestSecApparentCandidates = 0;
                var nwSecondWestSecApparentAdjusted = 0;
                const double westBandWidth = 75.0;
                const double northBandHeight = 80.0;
                const double minNorthJoin = 0.05;
                const double maxNorthJoin = 45.0;
                const double endpointTouchTol = 1.0;
                const double apparentSpanGapMax = 15.0;
                const double apparentJoinDistanceMax = 2.0;
                const double northSpanTol = 0.35;
                const double windowBandTol = 0.35;
                const double secondWestClusterTol = 2.0;
                const double minSelectedVerticalLength = 40.0;
                const double quarterWindowBufferMeters = 100.0;
                const double westOwnershipWidthMax = 35.0;

                bool SegmentIntersectsWindow(Point2d a, Point2d b, Extents3d window)
                {
                    if (a.X >= window.MinPoint.X && a.X <= window.MaxPoint.X &&
                        a.Y >= window.MinPoint.Y && a.Y <= window.MaxPoint.Y)
                    {
                        return true;
                    }

                    if (b.X >= window.MinPoint.X && b.X <= window.MaxPoint.X &&
                        b.Y >= window.MinPoint.Y && b.Y <= window.MaxPoint.Y)
                    {
                        return true;
                    }

                    return TryClipSegmentToWindow(a, b, window, out _, out _);
                }

                for (var wi = 0; wi < clipWindows.Count; wi++)
                {
                    var window = clipWindows[wi];
                    var coreMinX = window.MinPoint.X + quarterWindowBufferMeters;
                    var coreMaxX = window.MaxPoint.X - quarterWindowBufferMeters;
                    var coreMinY = window.MinPoint.Y + quarterWindowBufferMeters;
                    var coreMaxY = window.MaxPoint.Y - quarterWindowBufferMeters;
                    if (coreMaxX <= coreMinX || coreMaxY <= coreMinY)
                    {
                        coreMinX = window.MinPoint.X;
                        coreMaxX = window.MaxPoint.X;
                        coreMinY = window.MinPoint.Y;
                        coreMaxY = window.MaxPoint.Y;
                    }

                    var westBandMinX = coreMinX - westOwnershipWidthMax;
                    var westBandMaxX = coreMinX + westBandWidth;
                    var northBandMinY = coreMaxY - northBandHeight;
                    var northHalfMinY = (0.5 * (coreMinY + coreMaxY)) - 0.20;

                    var westCandidates = new List<(ObjectId Id, Point2d A, Point2d B, bool IsSec, bool Generated, double MidX, double NorthY, double Length)>();

                    for (var vi = 0; vi < verticalRoadCandidates.Count; vi++)
                    {
                        var candidate = verticalRoadCandidates[vi];
                        if (!SegmentIntersectsWindow(candidate.A, candidate.B, window))
                        {
                            continue;
                        }

                        var midX = 0.5 * (candidate.A.X + candidate.B.X);
                        if (midX < (westBandMinX - windowBandTol) || midX > (westBandMaxX + windowBandTol))
                        {
                            continue;
                        }

                        var candidateNorthY = Math.Max(candidate.A.Y, candidate.B.Y);
                        if (candidateNorthY < northHalfMinY)
                        {
                            nwSecondWestSecRejectedSouthHalf++;
                            continue;
                        }
                        westCandidates.Add((
                            candidate.Id,
                            candidate.A,
                            candidate.B,
                            candidate.IsSec,
                            candidate.Generated,
                            midX,
                            candidateNorthY,
                            candidate.A.GetDistanceTo(candidate.B)));
                    }

                    if (westCandidates.Count == 0)
                    {
                        continue;
                    }

                    var sourceCandidates = westCandidates
                        .Where(c => c.IsSec)
                        .ToList();
                    var selectedFromUsecFallback = false;
                    if (sourceCandidates.Count == 0)
                    {
                        sourceCandidates = westCandidates;
                        selectedFromUsecFallback = true;
                    }

                    var sortedWestCandidates = sourceCandidates
                        .OrderBy(c => c.MidX)
                        .ToList();
                    var westClusters = new List<List<(ObjectId Id, Point2d A, Point2d B, bool IsSec, bool Generated, double MidX, double NorthY, double Length)>>();
                    for (var i = 0; i < sortedWestCandidates.Count; i++)
                    {
                        var candidate = sortedWestCandidates[i];
                        if (westClusters.Count == 0)
                        {
                            westClusters.Add(new List<(ObjectId Id, Point2d A, Point2d B, bool IsSec, bool Generated, double MidX, double NorthY, double Length)> { candidate });
                            continue;
                        }

                        var lastCluster = westClusters[westClusters.Count - 1];
                        var lastClusterX = lastCluster.Average(c => c.MidX);
                        if (Math.Abs(candidate.MidX - lastClusterX) <= secondWestClusterTol)
                        {
                            lastCluster.Add(candidate);
                        }
                        else
                        {
                            westClusters.Add(new List<(ObjectId Id, Point2d A, Point2d B, bool IsSec, bool Generated, double MidX, double NorthY, double Length)> { candidate });
                        }
                    }

                    if (westClusters.Count < 2)
                    {
                        // Safety: this rule is defined as second-most-west. If we cannot form at least
                        // two distinct west-side clusters, do not fall back to westernmost.
                        nwSecondWestSecMissingSecondCluster++;
                        continue;
                    }

                    var selectedCluster = westClusters[1];
                    var nonStubCluster = selectedCluster
                        .Where(c => c.Length >= minSelectedVerticalLength)
                        .ToList();
                    var rankedCluster = nonStubCluster.Count > 0
                        ? nonStubCluster
                        : selectedCluster;
                    var selectedWestSec = rankedCluster
                        .OrderByDescending(c => c.NorthY)
                        .ThenByDescending(c => c.Length)
                        .ThenByDescending(c => c.MidX)
                        .ThenBy(c => c.Generated)
                        .First();
                    var selectedWestHandle = selectedWestSec.Id.Handle.ToString();
                    if (selectedFromUsecFallback)
                    {
                        nwSecondWestSecUsecFallback++;
                    }
                    nwSecondWestSecCandidates++;

                    var westSec = (selectedWestSec.Id, selectedWestSec.A, selectedWestSec.B, selectedWestSec.Generated);
                    if (!(tr.GetObject(westSec.Id, OpenMode.ForRead, false) is Entity readableWestSec) || readableWestSec.IsErased)
                    {
                        continue;
                    }

                    if (!TryReadOpenSegment(readableWestSec, out var v0, out var v1) || !IsVerticalLike(v0, v1))
                    {
                        continue;
                    }

                    var northEndpoint = v0.Y >= v1.Y ? v0 : v1;
                    var verticalX = northEndpoint.X;

                    var hasJoin = false;
                    var bestJoinPoint = default(Point2d);
                    var bestJoinDistance = double.MaxValue;
                    var hasApparentJoin = false;
                    var bestApparentJoinPoint = default(Point2d);
                    var bestApparentEndpoint = default(Point2d);
                    var bestApparentHorizontalId = ObjectId.Null;
                    var bestApparentScore = double.MaxValue;

                    for (var hi = 0; hi < horizontalRoadBoundaries.Count; hi++)
                    {
                        var horizontal = horizontalRoadBoundaries[hi];
                        if (!SegmentIntersectsWindow(horizontal.A, horizontal.B, window))
                        {
                            continue;
                        }

                        var yMid = 0.5 * (horizontal.A.Y + horizontal.B.Y);
                        if (yMid < northBandMinY)
                        {
                            continue;
                        }

                        if (!TryIntersectInfiniteLines(v0, v1, horizontal.A, horizontal.B, out var joinPoint))
                        {
                            continue;
                        }

                        if (!IsAllowedClassConnection(westSec.Id, horizontal.Id))
                        {
                            classRuleRejected++;
                            continue;
                        }

                        if (joinPoint.Y < (northEndpoint.Y - 0.25))
                        {
                            continue;
                        }

                        var joinDistance = northEndpoint.GetDistanceTo(joinPoint);
                        var endpointTouch = joinDistance <= endpointTouchTol;
                        var regularJoin = joinDistance > minNorthJoin && joinDistance <= maxNorthJoin;
                        if (!endpointTouch && !regularJoin)
                        {
                            continue;
                        }

                        var minX = Math.Min(horizontal.A.X, horizontal.B.X) - northSpanTol;
                        var maxX = Math.Max(horizontal.A.X, horizontal.B.X) + northSpanTol;
                        var spansVertical = verticalX >= minX && verticalX <= maxX;
                        if (spansVertical)
                        {
                            if (DistancePointToSegment(joinPoint, horizontal.A, horizontal.B) > boundaryHitTol)
                            {
                                continue;
                            }

                            if (!hasJoin || joinDistance < bestJoinDistance)
                            {
                                hasJoin = true;
                                bestJoinDistance = joinDistance;
                                bestJoinPoint = joinPoint;
                            }

                            continue;
                        }

                        var xGap = verticalX < minX
                            ? (minX - verticalX)
                            : (verticalX - maxX);
                        if (xGap > apparentSpanGapMax || joinDistance > apparentJoinDistanceMax)
                        {
                            continue;
                        }

                        var endpointA = horizontal.A;
                        var endpointB = horizontal.B;
                        var moveEndpoint = endpointA.GetDistanceTo(joinPoint) <= endpointB.GetDistanceTo(joinPoint)
                            ? endpointA
                            : endpointB;
                        var endpointMove = moveEndpoint.GetDistanceTo(joinPoint);
                        if (endpointMove > (apparentSpanGapMax + 2.0))
                        {
                            continue;
                        }

                        var apparentScore = endpointMove + (2.0 * joinDistance);
                        if (!hasApparentJoin || apparentScore < bestApparentScore)
                        {
                            hasApparentJoin = true;
                            bestApparentScore = apparentScore;
                            bestApparentHorizontalId = horizontal.Id;
                            bestApparentEndpoint = moveEndpoint;
                            bestApparentJoinPoint = joinPoint;
                        }
                    }

                    if (!hasJoin && !hasApparentJoin)
                    {
                        continue;
                    }
                    nwSecondWestSecWithNorthTarget++;

                    var preferApparent =
                        hasApparentJoin &&
                        (!hasJoin || (bestApparentScore + 0.25) < bestJoinDistance);

                    if (hasJoin && !preferApparent)
                    {
                        if (!HasInterveningVerticalRoad(northEndpoint, bestJoinPoint, westSec.Id))
                        {
                            if (TryAddConnectorSegment(northEndpoint, bestJoinPoint, readableWestSec.Layer))
                            {
                                nwSecondWestSecAdjusted++;
                                adjusted++;
                                if (EnableRoadAllowanceDiagnostics)
                                {
                                    logger?.WriteLine(
                                        $"RA-DIAG NW-2WEST DIRECT W{wi + 1}: src={selectedWestHandle} join=({bestJoinPoint.X:0.###},{bestJoinPoint.Y:0.###}) dist={bestJoinDistance:0.###}");
                                }
                                continue;
                            }
                        }
                        else
                        {
                            blockedByInterveningVerticalRoad++;
                        }
                    }

                    if (!hasApparentJoin || bestApparentHorizontalId.IsNull)
                    {
                        continue;
                    }
                    nwSecondWestSecApparentCandidates++;

                    if (HasInterveningVerticalRoad(bestApparentEndpoint, bestApparentJoinPoint, westSec.Id))
                    {
                        blockedByInterveningVerticalRoad++;
                        continue;
                    }

                    if (!(tr.GetObject(bestApparentHorizontalId, OpenMode.ForRead, false) is Entity readableHorizontal) || readableHorizontal.IsErased)
                    {
                        continue;
                    }

                    if (TryAddConnectorSegment(bestApparentEndpoint, bestApparentJoinPoint, readableHorizontal.Layer))
                    {
                        nwSecondWestSecAdjusted++;
                        nwSecondWestSecApparentAdjusted++;
                        adjusted++;
                        if (EnableRoadAllowanceDiagnostics)
                        {
                            logger?.WriteLine(
                                $"RA-DIAG NW-2WEST APPARENT W{wi + 1}: src={selectedWestHandle} tgt={bestApparentHorizontalId.Handle} join=({bestApparentJoinPoint.X:0.###},{bestApparentJoinPoint.Y:0.###})");
                        }
                    }
                }

                tr.Commit();
                logger?.WriteLine($"Cleanup: connected {adjusted} NW RA corner gap endpoint(s) (H={adjusted}, V=0).");
                if (nwSecondWestSecAdjusted > 0)
                {
                    logger?.WriteLine($"Cleanup: connected {nwSecondWestSecAdjusted} NW second-most-west-side 20.11 line(s) to north quarter boundary.");
                }
                logger?.WriteLine(
                    $"Cleanup: NW second-most-west-side 20.11 diagnostics candidates={nwSecondWestSecCandidates}, withNorthTarget={nwSecondWestSecWithNorthTarget}, adjusted={nwSecondWestSecAdjusted}, usecFallback={nwSecondWestSecUsecFallback}, rejectedSouthHalf={nwSecondWestSecRejectedSouthHalf}, missingSecondCluster={nwSecondWestSecMissingSecondCluster}, apparentCandidates={nwSecondWestSecApparentCandidates}, apparentAdjusted={nwSecondWestSecApparentAdjusted}, classRuleRejected={classRuleRejected}, twentySideRuleRejected={twentySideRuleRejected}.");
                if (blockedByInterveningVerticalRoad > 0)
                {
                    logger?.WriteLine($"Cleanup: NW guard blocked {blockedByInterveningVerticalRoad} candidate endpoint move(s) due to intervening vertical road boundaries.");
                }
                if (lsdAdjusted > 0)
                {
                    logger?.WriteLine($"Cleanup: adjusted {lsdAdjusted} L-SECTION-LSD endpoint(s) to midpoint of NW west-end extension line(s).");
                }
                if (blindSiblingErased > 0)
                {
                    logger?.WriteLine($"Cleanup: erased {blindSiblingErased} blind-line sibling segment(s) after NW extension.");
                }
                if (adjusted == 0)
                {
                    logger?.WriteLine($"Cleanup: NW simple candidates (H={horizontalSources.Count}, GV={generatedVerticalUsec.Count}, tries={pairTried}, chosen={pairChosen}).");
                }
            }
        }

        private static void ApplyCanonicalRoadAllowanceEndpointRules(
            Database database,
            IEnumerable<ObjectId> requestedQuarterIds,
            IReadOnlyCollection<ObjectId>? generatedRoadAllowanceIds,
            Logger? logger,
            bool allowBlindFallback = true)
        {
            if (database == null || requestedQuarterIds == null)
            {
                return;
            }

            var clipWindows = BuildBufferedQuarterWindows(database, requestedQuarterIds, 102.0);
            if (clipWindows.Count == 0)
            {
                return;
            }

            var generatedSet = generatedRoadAllowanceIds != null && generatedRoadAllowanceIds.Count > 0
                ? new HashSet<ObjectId>(generatedRoadAllowanceIds.Where(id => !id.IsNull))
                : new HashSet<ObjectId>();

            bool IsPointInAnyWindow(Point2d p)
            {
                for (var i = 0; i < clipWindows.Count; i++)
                {
                    var w = clipWindows[i];
                    if (p.X >= w.MinPoint.X && p.X <= w.MaxPoint.X &&
                        p.Y >= w.MinPoint.Y && p.Y <= w.MaxPoint.Y)
                    {
                        return true;
                    }
                }

                return false;
            }

            bool DoesSegmentIntersectAnyWindow(Point2d a, Point2d b)
            {
                if (IsPointInAnyWindow(a) || IsPointInAnyWindow(b))
                {
                    return true;
                }

                for (var i = 0; i < clipWindows.Count; i++)
                {
                    if (TryClipSegmentToWindow(a, b, clipWindows[i], out _, out _))
                    {
                        return true;
                    }
                }

                return false;
            }

            bool IsHorizontalLike(Point2d a, Point2d b)
            {
                var d = b - a;
                return Math.Abs(d.X) >= Math.Abs(d.Y);
            }

            bool IsVerticalLike(Point2d a, Point2d b)
            {
                var d = b - a;
                return Math.Abs(d.Y) > Math.Abs(d.X);
            }

            bool TryIntersectInfiniteLines(Point2d a0, Point2d a1, Point2d b0, Point2d b1, out Point2d intersection)
            {
                intersection = default;
                var da = a1 - a0;
                var db = b1 - b0;
                var denom = Cross2d(da, db);
                if (Math.Abs(denom) <= 1e-9)
                {
                    return false;
                }

                var diff = b0 - a0;
                var t = Cross2d(diff, db) / denom;
                intersection = a0 + (da * t);
                    return true;
                }

                bool TryGetUnitDirection(Point2d a, Point2d b, out Vector2d unit)
                {
                    unit = b - a;
                    var len = unit.Length;
                    if (len <= 1e-9)
                    {
                        return false;
                    }

                    unit = unit / len;
                    return true;
                }

                int SignWithTol(double value, double tol)
                {
                if (value > tol)
                {
                    return 1;
                }

                if (value < -tol)
                {
                    return -1;
                }

                return 0;
            }

            using (var tr = database.TransactionManager.StartTransaction())
            {
                var roadSegments = new List<(
                    ObjectId Id,
                    Point2d A,
                    Point2d B,
                    bool Horizontal,
                    bool Vertical,
                    bool IsSecLayer,
                    bool IsUsecLayer,
                    bool Generated,
                    double Axis,
                    double MajorMin,
                    double MajorMax,
                    string Layer)>();

                void AddRoadSegment(
                    ObjectId id,
                    Point2d a,
                    Point2d b,
                    bool isSecLayer,
                    bool isUsecLayer,
                    bool generated,
                    string layer)
                {
                    if (a.GetDistanceTo(b) <= 1e-4 || !DoesSegmentIntersectAnyWindow(a, b))
                    {
                        return;
                    }

                    var horizontal = IsHorizontalLike(a, b);
                    var vertical = IsVerticalLike(a, b);
                    if (!horizontal && !vertical)
                    {
                        return;
                    }

                    var axis = horizontal
                        ? 0.5 * (a.Y + b.Y)
                        : 0.5 * (a.X + b.X);
                    var majorMin = horizontal
                        ? Math.Min(a.X, b.X)
                        : Math.Min(a.Y, b.Y);
                    var majorMax = horizontal
                        ? Math.Max(a.X, b.X)
                        : Math.Max(a.Y, b.Y);
                    roadSegments.Add((id, a, b, horizontal, vertical, isSecLayer, isUsecLayer, generated, axis, majorMin, majorMax, layer));
                }

                var bt = (BlockTable)tr.GetObject(database.BlockTableId, OpenMode.ForRead);
                var ms = (BlockTableRecord)tr.GetObject(bt[BlockTableRecord.ModelSpace], OpenMode.ForWrite);
                foreach (ObjectId id in ms)
                {
                    if (!(tr.GetObject(id, OpenMode.ForRead, false) is Entity ent) || ent.IsErased)
                    {
                        continue;
                    }

                    var layerName = ent.Layer ?? string.Empty;
                    var isUsec = IsUsecLayer(layerName);
                    var isSec = string.Equals(layerName, "L-SEC", StringComparison.OrdinalIgnoreCase);
                    if (!isUsec && !isSec)
                    {
                        continue;
                    }

                    var isGenerated = generatedSet.Contains(id);
                    var layer = layerName;
                    if (ent is Line ln)
                    {
                        AddRoadSegment(
                            id,
                            new Point2d(ln.StartPoint.X, ln.StartPoint.Y),
                            new Point2d(ln.EndPoint.X, ln.EndPoint.Y),
                            isSec,
                            isUsec,
                            isGenerated,
                            layer);
                        continue;
                    }

                    if (!(ent is Polyline pl) || pl.Closed || pl.NumberOfVertices < 2)
                    {
                        continue;
                    }

                    for (var vi = 0; vi < pl.NumberOfVertices - 1; vi++)
                    {
                        AddRoadSegment(id, pl.GetPoint2dAt(vi), pl.GetPoint2dAt(vi + 1), isSec, isUsec, isGenerated, layer);
                    }
                }

                if (roadSegments.Count == 0)
                {
                    tr.Commit();
                    return;
                }

                const double classTwentyGap = 20.11;
                const double classThirtyGap = RoadAllowanceUsecWidthMeters;
                const double classTenGap = CorrectionLinePairGapMeters;
                const double classTwentyTol = 1.10;
                const double classThirtyTol = 1.60;
                const double classTenTol = 2.40;
                const double classMinOverlap = 4.0;
                const int roadClassUnknown = 0;
                const int roadClassTwenty = 20;
                const int roadClassThirty = 30;

                var hasTwenty = new bool[roadSegments.Count];
                var hasThirty = new bool[roadSegments.Count];
                var hasTen = new bool[roadSegments.Count];
                for (var i = 0; i < roadSegments.Count; i++)
                {
                    var a = roadSegments[i];
                    for (var j = i + 1; j < roadSegments.Count; j++)
                    {
                        var b = roadSegments[j];
                        if ((a.Horizontal != b.Horizontal) || (a.Vertical != b.Vertical))
                        {
                            continue;
                        }

                        var overlap = Math.Min(a.MajorMax, b.MajorMax) - Math.Max(a.MajorMin, b.MajorMin);
                        if (overlap < classMinOverlap)
                        {
                            continue;
                        }

                        var gap = Math.Abs(a.Axis - b.Axis);
                        if (Math.Abs(gap - classTwentyGap) <= classTwentyTol)
                        {
                            hasTwenty[i] = true;
                            hasTwenty[j] = true;
                        }

                        if (Math.Abs(gap - classThirtyGap) <= classThirtyTol)
                        {
                            hasThirty[i] = true;
                            hasThirty[j] = true;
                        }

                        if (Math.Abs(gap - classTenGap) <= classTenTol)
                        {
                            hasTen[i] = true;
                            hasTen[j] = true;
                        }
                    }
                }

                var roadClass = new int[roadSegments.Count];
                var blindSegments = new bool[roadSegments.Count];
                var generatedThirtyHardAsTwenty = new bool[roadSegments.Count];
                const double boundaryHitTol = 0.35;
                for (var i = 0; i < roadSegments.Count; i++)
                {
                    var cls = roadClassUnknown;
                    if (hasThirty[i] && hasTen[i])
                    {
                        cls = roadClassThirty;
                    }
                    else if (hasTwenty[i] || hasTen[i] || hasThirty[i])
                    {
                        cls = roadClassTwenty;
                    }

                    roadClass[i] = cls;

                    bool EndpointTouchesAnyOther(Point2d endpoint)
                    {
                        for (var j = 0; j < roadSegments.Count; j++)
                        {
                            if (j == i)
                            {
                                continue;
                            }

                            var other = roadSegments[j];
                            if (DistancePointToSegment(endpoint, other.A, other.B) <= boundaryHitTol)
                            {
                                return true;
                            }
                        }

                        return false;
                    }

                    blindSegments[i] = !EndpointTouchesAnyOther(roadSegments[i].A) || !EndpointTouchesAnyOther(roadSegments[i].B);
                }

                // Canonical interpretation:
                // a 30.17 boundary is also a 0 hard section boundary when it is
                // west of a 20.11 vertical companion (or south of a 20.11 horizontal companion).
                for (var i = 0; i < roadSegments.Count; i++)
                {
                    var seg = roadSegments[i];
                    if (roadClass[i] != roadClassThirty || !seg.IsUsecLayer)
                    {
                        continue;
                    }

                    var isHardBoundary = false;
                    for (var j = 0; j < roadSegments.Count; j++)
                    {
                        if (i == j || roadClass[j] != roadClassTwenty)
                        {
                            continue;
                        }

                        var companion = roadSegments[j];
                        if ((seg.Horizontal != companion.Horizontal) || (seg.Vertical != companion.Vertical))
                        {
                            continue;
                        }

                        var overlap = Math.Min(seg.MajorMax, companion.MajorMax) - Math.Max(seg.MajorMin, companion.MajorMin);
                        if (overlap < classMinOverlap)
                        {
                            continue;
                        }

                        if (seg.Vertical)
                        {
                            var eastDelta = companion.Axis - seg.Axis;
                            if (eastDelta > 0.10 && Math.Abs(eastDelta - classTwentyGap) <= classTwentyTol)
                            {
                                isHardBoundary = true;
                                break;
                            }
                        }
                        else if (seg.Horizontal)
                        {
                            var northDelta = companion.Axis - seg.Axis;
                            if (northDelta > 0.10 && Math.Abs(northDelta - classTwentyGap) <= classTwentyTol)
                            {
                                isHardBoundary = true;
                                break;
                            }
                        }
                    }

                    generatedThirtyHardAsTwenty[i] = isHardBoundary;
                }

                var roadClassList = roadClass.ToList();
                var blindSegmentList = blindSegments.ToList();
                var generatedThirtyHardAsTwentyList = generatedThirtyHardAsTwenty.ToList();
                const int endpointRoleUnknown = -1;
                const int endpointRoleZero = 0;
                const int endpointRoleTwenty = 20;

                bool TryGetNearestThirtyAxis(bool wantVertical, Point2d referencePoint, out double axis)
                {
                    axis = 0.0;
                    var found = false;
                    var bestDistance = double.MaxValue;
                    const double axisRangeTol = 4.0;

                    for (var i = 0; i < roadSegments.Count; i++)
                    {
                        if (roadClassList[i] != roadClassThirty)
                        {
                            continue;
                        }

                        var candidate = roadSegments[i];
                        if (wantVertical && !candidate.Vertical)
                        {
                            continue;
                        }

                        if (!wantVertical && !candidate.Horizontal)
                        {
                            continue;
                        }

                        var inRange = wantVertical
                            ? (referencePoint.Y >= (candidate.MajorMin - axisRangeTol) && referencePoint.Y <= (candidate.MajorMax + axisRangeTol))
                            : (referencePoint.X >= (candidate.MajorMin - axisRangeTol) && referencePoint.X <= (candidate.MajorMax + axisRangeTol));
                        if (!inRange)
                        {
                            continue;
                        }

                        var d = wantVertical
                            ? Math.Abs(referencePoint.X - candidate.Axis)
                            : Math.Abs(referencePoint.Y - candidate.Axis);
                        if (d >= bestDistance)
                        {
                            continue;
                        }

                        bestDistance = d;
                        axis = candidate.Axis;
                        found = true;
                    }

                    return found;
                }

                int GetEndpointRole(int idx)
                {
                    if (idx < 0 || idx >= roadSegments.Count)
                    {
                        return endpointRoleUnknown;
                    }

                    var seg = roadSegments[idx];
                    var layer = seg.Layer ?? string.Empty;
                    if (seg.IsSecLayer ||
                        string.Equals(layer, LayerUsecZero, StringComparison.OrdinalIgnoreCase))
                    {
                        return endpointRoleZero;
                    }

                    if (string.Equals(layer, LayerUsecTwenty, StringComparison.OrdinalIgnoreCase))
                    {
                        return endpointRoleTwenty;
                    }

                    if (generatedThirtyHardAsTwentyList[idx])
                    {
                        return endpointRoleZero;
                    }

                    if (roadClassList[idx] == roadClassTwenty)
                    {
                        return endpointRoleTwenty;
                    }

                    return endpointRoleUnknown;
                }

                bool IsSameSideOfRoadAllowance(
                    int sourceIndex,
                    Point2d sourcePoint,
                    Point2d sourceOtherPoint,
                    Point2d targetPoint)
                {
                    if (sourceIndex < 0 || sourceIndex >= roadSegments.Count)
                    {
                        return false;
                    }

                    var source = roadSegments[sourceIndex];
                    const double sideTol = 0.25;

                    if (source.Vertical)
                    {
                        if (!TryGetNearestThirtyAxis(wantVertical: false, sourcePoint, out var axisY))
                        {
                            return false;
                        }

                        var sourceSign = SignWithTol(sourcePoint.Y - axisY, sideTol);
                        if (sourceSign == 0)
                        {
                            sourceSign = SignWithTol(sourceOtherPoint.Y - axisY, sideTol);
                        }

                        var targetSign = SignWithTol(targetPoint.Y - axisY, sideTol);
                        if (sourceSign == 0 || targetSign == 0)
                        {
                            return false;
                        }

                        return sourceSign == targetSign;
                    }

                    if (source.Horizontal)
                    {
                        if (!TryGetNearestThirtyAxis(wantVertical: true, sourcePoint, out var axisX))
                        {
                            return false;
                        }

                        var sourceSign = SignWithTol(sourcePoint.X - axisX, sideTol);
                        if (sourceSign == 0)
                        {
                            sourceSign = SignWithTol(sourceOtherPoint.X - axisX, sideTol);
                        }

                        var targetSign = SignWithTol(targetPoint.X - axisX, sideTol);
                        if (sourceSign == 0 || targetSign == 0)
                        {
                            return false;
                        }

                        return sourceSign == targetSign;
                    }

                    return false;
                }

                bool IsAllowedEndpointTarget(
                    int sourceIndex,
                    int targetIndex,
                    out bool usedGeneratedThirtyAsZero,
                    out bool usedBlindFallback)
                {
                    usedGeneratedThirtyAsZero = false;
                    usedBlindFallback = false;

                    var sourceRole = GetEndpointRole(sourceIndex);
                    if (sourceRole != endpointRoleZero && sourceRole != endpointRoleTwenty)
                    {
                        return false;
                    }

                    var targetRole = GetEndpointRole(targetIndex);
                    var targetIsThirtyOnly =
                        roadClassList[targetIndex] == roadClassThirty &&
                        !generatedThirtyHardAsTwentyList[targetIndex] &&
                        !roadSegments[targetIndex].IsSecLayer;

                    if (allowBlindFallback && blindSegmentList[targetIndex] && !targetIsThirtyOnly)
                    {
                        usedBlindFallback = true;
                        if (targetRole == endpointRoleZero &&
                            !roadSegments[targetIndex].IsSecLayer &&
                            generatedThirtyHardAsTwentyList[targetIndex])
                        {
                            usedGeneratedThirtyAsZero = true;
                        }

                        return true;
                    }

                    if (targetRole != sourceRole)
                    {
                        return false;
                    }

                    if (targetRole == endpointRoleZero &&
                        !roadSegments[targetIndex].IsSecLayer &&
                        generatedThirtyHardAsTwentyList[targetIndex])
                    {
                        usedGeneratedThirtyAsZero = true;
                    }

                    return true;
                }

                bool IsOppositeDirectionTarget(int sourceIndex, int targetIndex)
                {
                    if (!TryGetUnitDirection(roadSegments[sourceIndex].A, roadSegments[sourceIndex].B, out var sourceDir))
                    {
                        return false;
                    }

                    if (!TryGetUnitDirection(roadSegments[targetIndex].A, roadSegments[targetIndex].B, out var targetDir))
                    {
                        return false;
                    }

                    // Require near-perpendicular segments.
                    const double maxAbsDot = 0.25; // approx >= 75 degrees apart
                    return Math.Abs(sourceDir.DotProduct(targetDir)) <= maxAbsDot;
                }

                bool HasExistingOppositeConnection(int sourceIndex, Point2d endpoint, Point2d sourceOtherPoint)
                {
                    const double touchTol = 0.35;
                    for (var j = 0; j < roadSegments.Count; j++)
                    {
                        if (j == sourceIndex)
                        {
                            continue;
                        }

                        if (!IsOppositeDirectionTarget(sourceIndex, j))
                        {
                            continue;
                        }

                        if (!IsAllowedEndpointTarget(sourceIndex, j, out _, out _))
                        {
                            continue;
                        }

                        var target = roadSegments[j];
                        if (DistancePointToSegment(endpoint, target.A, target.B) > touchTol)
                        {
                            continue;
                        }

                        if (!IsSameSideOfRoadAllowance(sourceIndex, endpoint, sourceOtherPoint, endpoint))
                        {
                            continue;
                        }

                        return true;
                    }

                    return false;
                }

                bool TryExtendSourceEndpoint(int sourceIndex, Point2d oldEndpoint, Point2d newEndpoint)
                {
                    const double endpointTol = 0.35;
                    const double minMove = 0.05;
                    const double collinearTol = 0.35;
                    if (sourceIndex < 0 || sourceIndex >= roadSegments.Count)
                    {
                        return false;
                    }

                    if (newEndpoint.GetDistanceTo(oldEndpoint) <= minMove)
                    {
                        return false;
                    }

                    var source = roadSegments[sourceIndex];
                    if (source.Id.IsNull)
                    {
                        return false;
                    }

                    if (DistancePointToInfiniteLine(newEndpoint, source.A, source.B) > collinearTol)
                    {
                        return false;
                    }

                    if (!(tr.GetObject(source.Id, OpenMode.ForWrite, false) is Entity writable) || writable.IsErased)
                    {
                        return false;
                    }

                    var moved = false;
                    var newA = source.A;
                    var newB = source.B;
                    if (writable is Line ln)
                    {
                        var p0 = new Point2d(ln.StartPoint.X, ln.StartPoint.Y);
                        var p1 = new Point2d(ln.EndPoint.X, ln.EndPoint.Y);
                        var d0 = p0.GetDistanceTo(oldEndpoint);
                        var d1 = p1.GetDistanceTo(oldEndpoint);
                        if (d0 > endpointTol && d1 > endpointTol)
                        {
                            return false;
                        }

                        var moveStart = d0 <= d1;
                        if (moveStart)
                        {
                            ln.StartPoint = new Point3d(newEndpoint.X, newEndpoint.Y, ln.StartPoint.Z);
                            newA = newEndpoint;
                            newB = p1;
                        }
                        else
                        {
                            ln.EndPoint = new Point3d(newEndpoint.X, newEndpoint.Y, ln.EndPoint.Z);
                            newA = p0;
                            newB = newEndpoint;
                        }

                        moved = true;
                    }
                    else if (writable is Polyline pl && !pl.Closed && pl.NumberOfVertices >= 2)
                    {
                        var startIndex = 0;
                        var endIndex = pl.NumberOfVertices - 1;
                        var p0 = pl.GetPoint2dAt(startIndex);
                        var p1 = pl.GetPoint2dAt(endIndex);
                        var d0 = p0.GetDistanceTo(oldEndpoint);
                        var d1 = p1.GetDistanceTo(oldEndpoint);
                        if (d0 > endpointTol && d1 > endpointTol)
                        {
                            return false;
                        }

                        var moveStart = d0 <= d1;
                        if (moveStart)
                        {
                            pl.SetPointAt(startIndex, newEndpoint);
                            newA = newEndpoint;
                            newB = p1;
                        }
                        else
                        {
                            pl.SetPointAt(endIndex, newEndpoint);
                            newA = p0;
                            newB = newEndpoint;
                        }

                        moved = true;
                    }

                    if (!moved || newA.GetDistanceTo(newB) <= minMove)
                    {
                        return false;
                    }

                    var horizontal = IsHorizontalLike(newA, newB);
                    var vertical = IsVerticalLike(newA, newB);
                    var axis = horizontal
                        ? 0.5 * (newA.Y + newB.Y)
                        : 0.5 * (newA.X + newB.X);
                    var majorMin = horizontal
                        ? Math.Min(newA.X, newB.X)
                        : Math.Min(newA.Y, newB.Y);
                    var majorMax = horizontal
                        ? Math.Max(newA.X, newB.X)
                        : Math.Max(newA.Y, newB.Y);
                    roadSegments[sourceIndex] = (
                        source.Id,
                        newA,
                        newB,
                        horizontal,
                        vertical,
                        source.IsSecLayer,
                        source.IsUsecLayer,
                        source.Generated,
                        axis,
                        majorMin,
                        majorMax,
                        source.Layer);
                    return true;
                }

                var scannedTwentyEndpoints = 0;
                var alreadyConnected = 0;
                var extended = 0;
                var extendedInPlace = 0;
                var inPlaceRejected = 0;
                var noTarget = 0;
                var roleRejected = 0;
                var sideRejected = 0;
                var maxDistanceRejected = 0;
                var targetDistanceRejected = 0;
                var generatedThirtyAsZeroUsed = 0;
                var blindFallbackUsed = 0;
                var sourceRoleZeroSegments = 0;
                var sourceRoleTwentySegments = 0;
                const double minExtend = 0.05;
                const double maxExtend = 40.0;
                const double targetApparentTol = 40.0;

                var baseSegmentCount = roadSegments.Count;
                for (var i = 0; i < baseSegmentCount; i++)
                {
                    var source = roadSegments[i];
                    var sourceRole = GetEndpointRole(i);
                    if (sourceRole != endpointRoleZero && sourceRole != endpointRoleTwenty)
                    {
                        continue;
                    }

                    // Deterministic ownership: do not drive endpoint extension from horizontal 20.11 sources.
                    // Their joins are resolved by moving the opposing vertical 20.11/0 boundaries.
                    if (sourceRole == endpointRoleTwenty && source.Horizontal)
                    {
                        continue;
                    }

                    if (sourceRole == endpointRoleZero)
                    {
                        sourceRoleZeroSegments++;
                    }
                    else if (sourceRole == endpointRoleTwenty)
                    {
                        sourceRoleTwentySegments++;
                    }

                    for (var endpointIndex = 0; endpointIndex <= 1; endpointIndex++)
                    {
                        scannedTwentyEndpoints++;
                        var endpoint = endpointIndex == 0 ? source.A : source.B;
                        var other = endpointIndex == 0 ? source.B : source.A;
                        var outward = endpoint - other;
                        if (outward.Length <= 1e-6)
                        {
                            continue;
                        }

                        var outwardUnit = outward / outward.Length;
                        if (HasExistingOppositeConnection(i, endpoint, other))
                        {
                            alreadyConnected++;
                            continue;
                        }

                        var found = false;
                        var bestScore = double.MaxValue;
                        var bestTargetPoint = endpoint;
                        var bestUsedGeneratedThirtyAsZero = false;
                        var bestUsedBlindFallback = false;
                        for (var j = 0; j < roadSegments.Count; j++)
                        {
                            if (j == i)
                            {
                                continue;
                            }

                            var target = roadSegments[j];
                            if (!IsOppositeDirectionTarget(i, j))
                            {
                                continue;
                            }

                            if (!IsAllowedEndpointTarget(i, j, out var usedGeneratedThirtyAsZero, out var usedBlindFallback))
                            {
                                roleRejected++;
                                continue;
                            }

                            if (!TryIntersectInfiniteLines(source.A, source.B, target.A, target.B, out var intersection))
                            {
                                continue;
                            }

                            var along = (intersection - endpoint).DotProduct(outwardUnit);
                            if (along <= minExtend || along > maxExtend)
                            {
                                maxDistanceRejected++;
                                continue;
                            }

                            if (!IsSameSideOfRoadAllowance(i, endpoint, other, intersection))
                            {
                                sideRejected++;
                                continue;
                            }

                            var targetDistance = DistancePointToSegment(intersection, target.A, target.B);
                            if (targetDistance > targetApparentTol)
                            {
                                targetDistanceRejected++;
                                continue;
                            }

                            var score = along + (2.0 * targetDistance);
                            if (score >= bestScore)
                            {
                                continue;
                            }

                            found = true;
                            bestScore = score;
                            bestTargetPoint = intersection;
                            bestUsedGeneratedThirtyAsZero = usedGeneratedThirtyAsZero;
                            bestUsedBlindFallback = usedBlindFallback;
                        }

                        if (!found)
                        {
                            noTarget++;
                            continue;
                        }

                        if (TryExtendSourceEndpoint(i, endpoint, bestTargetPoint))
                        {
                            extended++;
                            extendedInPlace++;
                            if (bestUsedGeneratedThirtyAsZero)
                            {
                                generatedThirtyAsZeroUsed++;
                            }

                            if (bestUsedBlindFallback)
                            {
                                blindFallbackUsed++;
                            }
                            continue;
                        }

                        inPlaceRejected++;
                    }
                }

                tr.Commit();
                logger?.WriteLine(
                    $"Cleanup: canonical endpoint rule scanned={scannedTwentyEndpoints}, sources0={sourceRoleZeroSegments}, sources20={sourceRoleTwentySegments}, alreadyConnected={alreadyConnected}, extended={extended}, inPlace={extendedInPlace}, inPlaceRejected={inPlaceRejected}, noTarget={noTarget}, roleRejected={roleRejected}, sideRejected={sideRejected}, rangeRejected={maxDistanceRejected}, targetDistanceRejected={targetDistanceRejected}, generated30As0Used={generatedThirtyAsZeroUsed}, blindFallbackUsed={blindFallbackUsed}.");
            }
        }

        private static void ConnectUsecBlindSouthwestTwentyTwelveLines(
            Database database,
            IEnumerable<QuarterLabelInfo> labelQuarterInfos,
            IReadOnlyCollection<ObjectId> generatedRoadAllowanceIds,
            Logger? logger)
        {
            if (database == null || labelQuarterInfos == null || generatedRoadAllowanceIds == null || generatedRoadAllowanceIds.Count == 0)
            {
                return;
            }

            var targetInfos = labelQuarterInfos
                .Where(info =>
                    info != null &&
                    IsUsecBlindSouthSection(info.SectionKey.Section))
                .ToList();
            if (targetInfos.Count == 0)
            {
                logger?.WriteLine("Cleanup: SW L-USEC 20.11 blind-line connect skipped (no target section info).");
                return;
            }

            var targetSectionIds = targetInfos
                .Where(info => !info.SectionPolylineId.IsNull)
                .Select(info => info.SectionPolylineId)
                .Distinct()
                .ToList();
            var sectionTargets = new List<(ObjectId SectionId, Point2d SwCorner, Vector2d EastUnit, Vector2d NorthUnit, double Width, double Height, Extents3d Window)>();
            var clipWindows = new List<Extents3d>();
            if (targetSectionIds.Count > 0)
            {
                const double swWindowBuffer = 120.0;
                using (var tr = database.TransactionManager.StartTransaction())
                {
                    foreach (var sectionId in targetSectionIds)
                    {
                        if (!(tr.GetObject(sectionId, OpenMode.ForRead, false) is Polyline section) || section.IsErased)
                        {
                            continue;
                        }

                        try
                        {
                            var ext = section.GeometricExtents;
                            if (!TryGetQuarterAnchors(section, out var sectionAnchors))
                            {
                                sectionAnchors = GetFallbackAnchors(section);
                            }

                            var eastUnit = GetUnitVector(sectionAnchors.Left, sectionAnchors.Right, new Vector2d(1, 0));
                            var northUnit = GetUnitVector(sectionAnchors.Bottom, sectionAnchors.Top, new Vector2d(0, 1));
                            var sectionWidth = sectionAnchors.Left.GetDistanceTo(sectionAnchors.Right);
                            var sectionHeight = sectionAnchors.Bottom.GetDistanceTo(sectionAnchors.Top);
                            if (sectionWidth <= 1e-6)
                            {
                                sectionWidth = Math.Abs(ext.MaxPoint.X - ext.MinPoint.X);
                            }

                            if (sectionHeight <= 1e-6)
                            {
                                sectionHeight = Math.Abs(ext.MaxPoint.Y - ext.MinPoint.Y);
                            }

                            Point2d swCorner;
                            if (!TryGetQuarterCorner(section, eastUnit, northUnit, QuarterCorner.SouthWest, out swCorner))
                            {
                                swCorner = new Point2d(ext.MinPoint.X, ext.MinPoint.Y);
                            }

                            var midX = 0.5 * (ext.MinPoint.X + ext.MaxPoint.X);
                            var midY = 0.5 * (ext.MinPoint.Y + ext.MaxPoint.Y);
                            var swWindow = new Extents3d(
                                new Point3d(ext.MinPoint.X - swWindowBuffer, ext.MinPoint.Y - swWindowBuffer, 0.0),
                                new Point3d(midX + swWindowBuffer, midY + swWindowBuffer, 0.0));
                            clipWindows.Add(swWindow);
                            sectionTargets.Add((sectionId, swCorner, eastUnit, northUnit, sectionWidth, sectionHeight, swWindow));
                        }
                        catch
                        {
                        }
                    }

                    tr.Commit();
                }
            }

            if (clipWindows.Count == 0 || sectionTargets.Count == 0)
            {
                logger?.WriteLine("Cleanup: SW L-USEC 20.11 blind-line connect skipped (no clip windows).");
                return;
            }

            bool IsPointInAnyWindow(Point2d p)
            {
                for (var i = 0; i < clipWindows.Count; i++)
                {
                    var w = clipWindows[i];
                    if (p.X >= w.MinPoint.X && p.X <= w.MaxPoint.X &&
                        p.Y >= w.MinPoint.Y && p.Y <= w.MaxPoint.Y)
                    {
                        return true;
                    }
                }

                return false;
            }

            bool DoesSegmentIntersectAnyWindow(Point2d a, Point2d b)
            {
                if (IsPointInAnyWindow(a) || IsPointInAnyWindow(b))
                {
                    return true;
                }

                for (var i = 0; i < clipWindows.Count; i++)
                {
                    if (TryClipSegmentToWindow(a, b, clipWindows[i], out _, out _))
                    {
                        return true;
                    }
                }

                return false;
            }

            bool TryReadOpenSegment(Entity ent, out Point2d a, out Point2d b)
            {
                a = default;
                b = default;
                if (ent == null)
                {
                    return false;
                }

                if (ent is Line ln)
                {
                    a = new Point2d(ln.StartPoint.X, ln.StartPoint.Y);
                    b = new Point2d(ln.EndPoint.X, ln.EndPoint.Y);
                    return a.GetDistanceTo(b) > 1e-4;
                }

                if (ent is Polyline pl)
                {
                    if (pl.Closed || pl.NumberOfVertices != 2)
                    {
                        return false;
                    }

                    a = pl.GetPoint2dAt(0);
                    b = pl.GetPoint2dAt(1);
                    return a.GetDistanceTo(b) > 1e-4;
                }

                return false;
            }

            bool TryMoveEndpoint(Entity writable, bool moveStart, Point2d target, double moveTol)
            {
                if (writable is Line ln)
                {
                    var old = moveStart
                        ? new Point2d(ln.StartPoint.X, ln.StartPoint.Y)
                        : new Point2d(ln.EndPoint.X, ln.EndPoint.Y);
                    if (old.GetDistanceTo(target) <= moveTol)
                    {
                        return false;
                    }

                    if (moveStart)
                    {
                        ln.StartPoint = new Point3d(target.X, target.Y, ln.StartPoint.Z);
                    }
                    else
                    {
                        ln.EndPoint = new Point3d(target.X, target.Y, ln.EndPoint.Z);
                    }

                    return true;
                }

                if (writable is Polyline pl && !pl.Closed && pl.NumberOfVertices >= 2)
                {
                    var index = moveStart ? 0 : pl.NumberOfVertices - 1;
                    var old = pl.GetPoint2dAt(index);
                    if (old.GetDistanceTo(target) <= moveTol)
                    {
                        return false;
                    }

                    pl.SetPointAt(index, target);
                    return true;
                }

                return false;
            }

            bool IsVerticalLike(Point2d a, Point2d b)
            {
                var d = b - a;
                return Math.Abs(d.Y) > Math.Abs(d.X);
            }

            bool IsHorizontalLike(Point2d a, Point2d b)
            {
                var d = b - a;
                return Math.Abs(d.X) >= Math.Abs(d.Y);
            }

            var generatedSet = new HashSet<ObjectId>(generatedRoadAllowanceIds.Where(id => !id.IsNull));
            using (var tr = database.TransactionManager.StartTransaction())
            {
                bool IsPointInWindow(Point2d p, Extents3d window)
                {
                    return p.X >= window.MinPoint.X && p.X <= window.MaxPoint.X &&
                           p.Y >= window.MinPoint.Y && p.Y <= window.MaxPoint.Y;
                }

                bool DoesSegmentIntersectWindow(Point2d a, Point2d b, Extents3d window)
                {
                    return IsPointInWindow(a, window) ||
                           IsPointInWindow(b, window) ||
                           TryClipSegmentToWindow(a, b, window, out _, out _);
                }

                bool TryIntersectInfiniteLines(Point2d a0, Point2d a1, Point2d b0, Point2d b1, out Point2d intersection)
                {
                    intersection = default;
                    var da = a1 - a0;
                    var db = b1 - b0;
                    var denom = Cross2d(da, db);
                    if (Math.Abs(denom) <= 1e-9)
                    {
                        return false;
                    }

                    var diff = b0 - a0;
                    var t = Cross2d(diff, db) / denom;
                    intersection = a0 + (da * t);
                    return true;
                }

                // Ownership note for 30.17/20.11 logic:
                // - west-side road allowances belong to the section on their west (left)
                // - south-side road allowances belong to the section above (north)
                // so this pass gathers nearby sec/usec segments from both generated and existing geometry.
                var roadAllowanceSegments = new List<(ObjectId Id, Point2d A, Point2d B, bool Generated, bool IsUsecLayer)>();
                var hardConnectorSegments = new List<(ObjectId Id, Point2d A, Point2d B)>();
                var lsdSegments = new List<(ObjectId Id, Point2d A, Point2d B)>();
                var bt = (BlockTable)tr.GetObject(database.BlockTableId, OpenMode.ForRead);
                var ms = (BlockTableRecord)tr.GetObject(bt[BlockTableRecord.ModelSpace], OpenMode.ForRead);
                foreach (ObjectId id in ms)
                {
                    if (!(tr.GetObject(id, OpenMode.ForRead, false) is Entity ent) || ent.IsErased)
                    {
                        continue;
                    }

                    if (!TryReadOpenSegment(ent, out var a, out var b))
                    {
                        continue;
                    }

                    if (!DoesSegmentIntersectAnyWindow(a, b))
                    {
                        continue;
                    }

                    if (string.Equals(ent.Layer, "L-SECTION-LSD", StringComparison.OrdinalIgnoreCase))
                    {
                        if (IsAdjustableLsdLineSegment(a, b))
                        {
                            lsdSegments.Add((id, a, b));
                        }

                        continue;
                    }

                    var layerName = ent.Layer ?? string.Empty;
                    var isSecLayer = string.Equals(layerName, "L-SEC", StringComparison.OrdinalIgnoreCase);
                    var isUsecLayer = IsUsecLayer(layerName);
                    if (!isSecLayer && !isUsecLayer)
                    {
                        continue;
                    }

                    if (isSecLayer ||
                        string.Equals(layerName, LayerUsecZero, StringComparison.OrdinalIgnoreCase) ||
                        string.Equals(layerName, LayerUsecTwenty, StringComparison.OrdinalIgnoreCase))
                    {
                        hardConnectorSegments.Add((id, a, b));
                    }

                    roadAllowanceSegments.Add((id, a, b, generatedSet.Contains(id), isUsecLayer));
                }

                if (roadAllowanceSegments.Count == 0)
                {
                    tr.Commit();
                    logger?.WriteLine("Cleanup: SW L-USEC 20.11 blind-line connect skipped (no generated RA segments).");
                    return;
                }

                const double endpointMoveTol = 0.05;
                const double primaryExpectedOffset = 20.11;
                const double secondaryExpectedOffset = CorrectionLinePairGapMeters;
                const double offsetTol = 3.0;
                const double maxEndpointGap = 70.0;
                var usedHorizontalSegments = new HashSet<ObjectId>();
                var connectedPairs = 0;
                var movedHorizontalEndpoints = 0;
                var movedVerticalEndpoints = 0;
                var sectionsWithCandidates = 0;
                var pairCandidatesEvaluated = 0;
                var forcedCornerAttempts = 0;
                var forcedCornerConnected = 0;
                var lsdMidpointAdjustments = new List<(ObjectId SectionId, Point2d OldA, Point2d OldB, Point2d OldMid, Point2d NewMid)>();
                var lsdVerticalMidpointAdjustments = new List<(ObjectId SectionId, Point2d OldA, Point2d OldB, Point2d OldMid, Point2d NewMid)>();
                var lsdFallbackEndpointAdjustments = 0;
                const bool allowSwBlindLineLsdMidpointAdjustments = false;

                for (var si = 0; si < sectionTargets.Count; si++)
                {
                    var sectionTarget = sectionTargets[si];
                    var swCorner = sectionTarget.SwCorner;
                    var eastUnit = sectionTarget.EastUnit;
                    var northUnit = sectionTarget.NorthUnit;

                    double ToU(Point2d p) => (p - swCorner).DotProduct(eastUnit);
                    double ToV(Point2d p) => (p - swCorner).DotProduct(northUnit);
                    bool EndpointTouchesHardConnector(Point2d endpoint, ObjectId sourceId)
                    {
                        const double connectorTol = 0.35;
                        for (var ci = 0; ci < hardConnectorSegments.Count; ci++)
                        {
                            var c = hardConnectorSegments[ci];
                            if (c.Id == sourceId)
                            {
                                continue;
                            }

                            if (DistancePointToSegment(endpoint, c.A, c.B) <= connectorTol)
                            {
                                return true;
                            }
                        }

                        return false;
                    }
                    (
                        List<(ObjectId Id, bool IsGenerated, bool IsUsecLayer, Point2d WestPoint, Point2d EastPoint, bool WestIsStart, double VLine, double WestU, double WestV)> Horizontals,
                        List<(ObjectId Id, bool IsGenerated, bool IsUsecLayer, Point2d SouthPoint, Point2d NorthPoint, bool SouthIsStart, double ULine, double SouthU, double SouthV)> Verticals
                    )
                    CollectCandidatesForOffset(double expectedOffsetForBand)
                    {
                        var horizontalsForOffset = new List<(ObjectId Id, bool IsGenerated, bool IsUsecLayer, Point2d WestPoint, Point2d EastPoint, bool WestIsStart, double VLine, double WestU, double WestV)>();
                        var verticalsForOffset = new List<(ObjectId Id, bool IsGenerated, bool IsUsecLayer, Point2d SouthPoint, Point2d NorthPoint, bool SouthIsStart, double ULine, double SouthU, double SouthV)>();
                        for (var gi = 0; gi < roadAllowanceSegments.Count; gi++)
                        {
                            var seg = roadAllowanceSegments[gi];
                            if (usedHorizontalSegments.Contains(seg.Id))
                            {
                                continue;
                            }

                            if (!DoesSegmentIntersectWindow(seg.A, seg.B, sectionTarget.Window))
                            {
                                continue;
                            }

                            var d = seg.B - seg.A;
                            var len = d.Length;
                            if (len <= 1e-6)
                            {
                                continue;
                            }

                            var uA = ToU(seg.A);
                            var vA = ToV(seg.A);
                            var uB = ToU(seg.B);
                            var vB = ToV(seg.B);
                            var eastComp = Math.Abs(d.DotProduct(eastUnit));
                            var northComp = Math.Abs(d.DotProduct(northUnit));
                            if (eastComp >= northComp)
                            {
                                var westIsStart = uA <= uB;
                                var westPoint = westIsStart ? seg.A : seg.B;
                                var eastPoint = westIsStart ? seg.B : seg.A;
                                var westU = westIsStart ? uA : uB;
                                var westV = westIsStart ? vA : vB;
                                var vLine = 0.5 * (vA + vB);
                                if (Math.Abs(Math.Abs(vLine) - expectedOffsetForBand) > offsetTol)
                                {
                                    continue;
                                }

                                horizontalsForOffset.Add((seg.Id, seg.Generated, seg.IsUsecLayer, westPoint, eastPoint, westIsStart, vLine, westU, westV));
                            }
                            else
                            {
                                var southIsStart = vA <= vB;
                                var southPoint = southIsStart ? seg.A : seg.B;
                                var northPoint = southIsStart ? seg.B : seg.A;
                                var southU = southIsStart ? uA : uB;
                                var southV = southIsStart ? vA : vB;
                                var uLine = 0.5 * (uA + uB);
                                if (Math.Abs(Math.Abs(uLine) - expectedOffsetForBand) > offsetTol)
                                {
                                    continue;
                                }

                                verticalsForOffset.Add((seg.Id, seg.Generated, seg.IsUsecLayer, southPoint, northPoint, southIsStart, uLine, southU, southV));
                            }
                        }

                        return (horizontalsForOffset, verticalsForOffset);
                    }

                    var activeExpectedOffset = primaryExpectedOffset;
                    var primaryCandidates = CollectCandidatesForOffset(primaryExpectedOffset);
                    var horizontals = primaryCandidates.Horizontals;
                    var verticals = primaryCandidates.Verticals;

                    if (horizontals.Count == 0)
                    {
                        var secondaryCandidates = CollectCandidatesForOffset(secondaryExpectedOffset);
                        if (secondaryCandidates.Horizontals.Count == 0)
                        {
                            continue;
                        }

                        activeExpectedOffset = secondaryExpectedOffset;
                        horizontals = secondaryCandidates.Horizontals;
                        verticals = secondaryCandidates.Verticals;
                    }
                    else if (verticals.Count == 0)
                    {
                        var secondaryCandidates = CollectCandidatesForOffset(secondaryExpectedOffset);
                        if (secondaryCandidates.Horizontals.Count > 0 && secondaryCandidates.Verticals.Count > 0)
                        {
                            activeExpectedOffset = secondaryExpectedOffset;
                            horizontals = secondaryCandidates.Horizontals;
                            verticals = secondaryCandidates.Verticals;
                        }
                    }

                    if (verticals.Count == 0)
                    {
                        // Sparse/single-section builds can miss the vertical SW corner leg.
                        // Keep LSD south-end adjustment alive by synthesizing the source (old) segment
                        // one 10.06m band north of the generated 20.11 horizontal.
                        sectionsWithCandidates++;
                        var bestFallbackHorizontal = horizontals
                            .OrderBy(h => Math.Abs(Math.Abs(h.VLine) - activeExpectedOffset))
                            .ThenByDescending(h => h.WestPoint.GetDistanceTo(h.EastPoint))
                            .First();
                        var oldWest = bestFallbackHorizontal.WestPoint + (northUnit * activeExpectedOffset);
                        var oldEast = bestFallbackHorizontal.EastPoint + (northUnit * activeExpectedOffset);
                        lsdMidpointAdjustments.Add((
                            sectionTarget.SectionId,
                            oldWest,
                            oldEast,
                            Midpoint(oldWest, oldEast),
                            Midpoint(bestFallbackHorizontal.WestPoint, bestFallbackHorizontal.EastPoint)));
                        continue;
                    }

                    sectionsWithCandidates++;
                    const double swCornerBand = 190.0;
                    var forcedHorizontalPool = horizontals
                        .Where(h => Math.Min(
                            h.WestPoint.GetDistanceTo(swCorner),
                            h.EastPoint.GetDistanceTo(swCorner)) <= swCornerBand)
                        .ToList();
                    if (forcedHorizontalPool.Count == 0)
                    {
                        forcedHorizontalPool = horizontals;
                    }
                    var forcedUsecHorizontals = forcedHorizontalPool
                        .Where(h => h.IsUsecLayer)
                        .ToList();
                    if (forcedUsecHorizontals.Count > 0)
                    {
                        forcedHorizontalPool = forcedUsecHorizontals;
                    }
                    var forcedGeneratedHorizontals = forcedHorizontalPool
                        .Where(h => h.IsGenerated)
                        .ToList();
                    if (forcedGeneratedHorizontals.Count > 0)
                    {
                        forcedHorizontalPool = forcedGeneratedHorizontals;
                    }

                    var forcedVerticalPool = verticals
                        .Where(v => Math.Min(
                            v.SouthPoint.GetDistanceTo(swCorner),
                            v.NorthPoint.GetDistanceTo(swCorner)) <= swCornerBand)
                        .ToList();
                    if (forcedVerticalPool.Count == 0)
                    {
                        forcedVerticalPool = verticals;
                    }
                    var forcedUsecVerticals = forcedVerticalPool
                        .Where(v => v.IsUsecLayer)
                        .ToList();
                    if (forcedUsecVerticals.Count > 0)
                    {
                        forcedVerticalPool = forcedUsecVerticals;
                    }
                    var forcedGeneratedVerticals = forcedVerticalPool
                        .Where(v => v.IsGenerated)
                        .ToList();
                    if (forcedGeneratedVerticals.Count > 0)
                    {
                        forcedVerticalPool = forcedGeneratedVerticals;
                    }

                    if (forcedHorizontalPool.Count > 0 && forcedVerticalPool.Count > 0)
                    {
                        var forcedHorizontal = forcedHorizontalPool
                            .OrderBy(h => Math.Min(
                                h.WestPoint.GetDistanceTo(swCorner),
                                h.EastPoint.GetDistanceTo(swCorner)))
                            .ThenByDescending(h => h.IsUsecLayer)
                            .ThenByDescending(h => h.IsGenerated)
                            .ThenBy(h => Math.Abs(Math.Abs(h.VLine) - activeExpectedOffset))
                            .ThenBy(h => h.WestPoint.GetDistanceTo(h.EastPoint))
                            .First();
                        var forcedVertical = forcedVerticalPool
                            .OrderBy(v => Math.Min(
                                v.SouthPoint.GetDistanceTo(swCorner),
                                v.NorthPoint.GetDistanceTo(swCorner)))
                            .ThenByDescending(v => v.IsUsecLayer)
                            .ThenByDescending(v => v.IsGenerated)
                            .ThenBy(v => Math.Abs(Math.Abs(v.ULine) - activeExpectedOffset))
                            .ThenBy(v => v.SouthPoint.GetDistanceTo(v.NorthPoint))
                            .First();
                        var forcedTarget = swCorner + (eastUnit * forcedVertical.ULine) + (northUnit * forcedHorizontal.VLine);
                        if (TryIntersectInfiniteLines(
                            forcedHorizontal.WestPoint,
                            forcedHorizontal.EastPoint,
                            forcedVertical.SouthPoint,
                            forcedVertical.NorthPoint,
                            out var forcedIntersection))
                        {
                            forcedTarget = forcedIntersection;
                        }

                        if (IsPointInWindow(forcedTarget, sectionTarget.Window) ||
                            forcedHorizontal.WestPoint.GetDistanceTo(forcedTarget) <= maxEndpointGap ||
                            forcedVertical.SouthPoint.GetDistanceTo(forcedTarget) <= maxEndpointGap)
                        {
                            forcedCornerAttempts++;
                            // SW rule: only pull the corner-facing endpoints.
                            var forceMoveHStart = forcedHorizontal.WestIsStart;
                            var fixedHPoint = forcedHorizontal.EastPoint;
                            var forceHMove = forcedHorizontal.WestPoint.GetDistanceTo(forcedTarget);

                            var forceMoveVStart = forcedVertical.SouthIsStart;
                            var fixedVPoint = forcedVertical.NorthPoint;
                            var forceVMove = forcedVertical.SouthPoint.GetDistanceTo(forcedTarget);

                            // Strict SW rule: move only vertical 20.11 endpoint; never extend horizontal here.
                            var allowForceH = false;
                            var allowForceV = forcedVertical.IsUsecLayer && forceVMove <= maxEndpointGap;
                            if (allowForceV &&
                                (EndpointTouchesHardConnector(forcedVertical.SouthPoint, forcedVertical.Id) ||
                                 ToV(forcedTarget) > (forcedVertical.SouthV + 0.25)))
                            {
                                allowForceV = false;
                            }

                            if (allowForceV)
                            {
                                Entity? forcedHWritable = null;
                                if (allowForceH)
                                {
                                    forcedHWritable = tr.GetObject(forcedHorizontal.Id, OpenMode.ForWrite, false) as Entity;
                                    if (forcedHWritable == null || forcedHWritable.IsErased)
                                    {
                                        allowForceH = false;
                                    }
                                }

                                Entity? forcedVWritable = null;
                                if (allowForceV)
                                {
                                    forcedVWritable = tr.GetObject(forcedVertical.Id, OpenMode.ForWrite, false) as Entity;
                                    if (forcedVWritable == null || forcedVWritable.IsErased)
                                    {
                                        allowForceV = false;
                                    }
                                }

                                var movedForcedV = allowForceV &&
                                                   forcedVWritable != null &&
                                                   TryMoveEndpoint(forcedVWritable, forceMoveVStart, forcedTarget, endpointMoveTol);
                                var movedForcedH = allowForceH &&
                                                   forcedHWritable != null &&
                                                   TryMoveEndpoint(forcedHWritable, forceMoveHStart, forcedTarget, endpointMoveTol);
                                if (movedForcedH || movedForcedV)
                                {
                                    forcedCornerConnected++;
                                    connectedPairs++;
                                    if (movedForcedH)
                                    {
                                        usedHorizontalSegments.Add(forcedHorizontal.Id);
                                        movedHorizontalEndpoints++;
                                        lsdMidpointAdjustments.Add((
                                            sectionTarget.SectionId,
                                            forcedHorizontal.WestPoint,
                                            forcedHorizontal.EastPoint,
                                            Midpoint(forcedHorizontal.WestPoint, forcedHorizontal.EastPoint),
                                            Midpoint(forcedTarget, fixedHPoint)));
                                    }

                                    if (movedForcedV)
                                    {
                                        movedVerticalEndpoints++;
                                        lsdVerticalMidpointAdjustments.Add((
                                            sectionTarget.SectionId,
                                            forcedVertical.SouthPoint,
                                            forcedVertical.NorthPoint,
                                            Midpoint(forcedVertical.SouthPoint, forcedVertical.NorthPoint),
                                            Midpoint(forcedTarget, fixedVPoint)));
                                    }

                                    // Deterministic SW 20.11 L-corner handled for this section.
                                    continue;
                                }
                            }
                        }
                    }

                    var pairCandidates = new List<(
                        ObjectId HId,
                        Point2d HOldMoved,
                        Point2d HOldFixed,
                        bool HMoveStart,
                        double HMove,
                        ObjectId VId,
                        Point2d VOldMoved,
                        Point2d VOldFixed,
                        bool VMoveStart,
                        double VMove,
                        bool MoveHorizontal,
                        bool MoveVertical,
                        Point2d Target,
                        double Score)>();
                    for (var hi = 0; hi < horizontals.Count; hi++)
                    {
                        var h = horizontals[hi];
                        for (var vi = 0; vi < verticals.Count; vi++)
                        {
                            var v = verticals[vi];
                            if (h.Id == v.Id)
                            {
                                continue;
                            }

                            // Keep pairing local to the section SW corner; avoid long-range snaps.
                            var hCornerDist = Math.Min(
                                h.WestPoint.GetDistanceTo(swCorner),
                                h.EastPoint.GetDistanceTo(swCorner));
                            var vCornerDist = Math.Min(
                                v.SouthPoint.GetDistanceTo(swCorner),
                                v.NorthPoint.GetDistanceTo(swCorner));
                            if (hCornerDist > swCornerBand || vCornerDist > swCornerBand)
                            {
                                continue;
                            }

                            // Allow non-generated pairs here: after trim/layer normalization the open-T
                            // counterpart can be non-generated. Movement is still restricted to L-USEC
                            // endpoints by canMoveHorizontal/canMoveVertical below.
                            if (!h.IsUsecLayer && !v.IsUsecLayer)
                            {
                                continue;
                            }

                            var target = swCorner + (eastUnit * v.ULine) + (northUnit * h.VLine);
                            if (!IsPointInWindow(target, sectionTarget.Window))
                            {
                                continue;
                            }

                            var hMoveStart = h.WestIsStart;
                            var hOldMoved = h.WestPoint;
                            var hOldFixed = h.EastPoint;
                            var hMove = h.WestPoint.GetDistanceTo(target);

                            // Accept long vertical 20.11 lines by evaluating against the vertical segment,
                            // not the south endpoint distance.
                            var vDistance = DistancePointToSegment(target, v.SouthPoint, v.NorthPoint);
                            if (vDistance > 3.5)
                            {
                                continue;
                            }

                            var vMoveStart = v.SouthIsStart;
                            var vOldMoved = v.SouthPoint;
                            var vOldFixed = v.NorthPoint;
                            var vMove = v.SouthPoint.GetDistanceTo(target);
                            var targetV = ToV(target);
                            if (targetV > (v.SouthV + 0.25))
                            {
                                continue;
                            }

                            // Strict SW rule: move vertical 20.11 endpoint only, and only if dangling.
                            var canMoveHorizontal = false;
                            var canMoveVertical =
                                v.IsUsecLayer &&
                                vMove <= maxEndpointGap &&
                                !EndpointTouchesHardConnector(vOldMoved, v.Id);
                            if (!canMoveHorizontal && !canMoveVertical)
                            {
                                continue;
                            }

                            // Deterministic SW 20.11 L-corner rule: move the vertical endpoint
                            // to the computed 20.11 intersection.
                            var moveHorizontal = canMoveHorizontal;
                            var moveVertical = canMoveVertical;
                            var chosenMove = (moveHorizontal ? hMove : 0.0) + (moveVertical ? vMove : 0.0);
                            var cornerGap = h.WestPoint.GetDistanceTo(v.SouthPoint);

                            var score =
                                cornerGap +
                                chosenMove +
                                vDistance +
                                Math.Abs(Math.Abs(v.ULine) - activeExpectedOffset) +
                                Math.Abs(Math.Abs(h.VLine) - activeExpectedOffset);
                            pairCandidates.Add((
                                h.Id,
                                hOldMoved,
                                hOldFixed,
                                hMoveStart,
                                hMove,
                                v.Id,
                                vOldMoved,
                                vOldFixed,
                                vMoveStart,
                                vMove,
                                moveHorizontal,
                                moveVertical,
                                target,
                                score));
                        }
                    }

                    pairCandidatesEvaluated += pairCandidates.Count;
                    if (pairCandidates.Count == 0)
                    {
                        var bestFallbackHorizontal = horizontals
                            .OrderBy(h => Math.Abs(Math.Abs(h.VLine) - activeExpectedOffset))
                            .ThenByDescending(h => h.WestPoint.GetDistanceTo(h.EastPoint))
                            .First();
                        var oldWest = bestFallbackHorizontal.WestPoint + (northUnit * activeExpectedOffset);
                        var oldEast = bestFallbackHorizontal.EastPoint + (northUnit * activeExpectedOffset);
                        lsdMidpointAdjustments.Add((
                            sectionTarget.SectionId,
                            oldWest,
                            oldEast,
                            Midpoint(oldWest, oldEast),
                            Midpoint(bestFallbackHorizontal.WestPoint, bestFallbackHorizontal.EastPoint)));
                        continue;
                    }

                    var orderedCandidates = pairCandidates
                        .OrderBy(c => c.Score)
                        .ToList();
                    for (var ci = 0; ci < orderedCandidates.Count; ci++)
                    {
                        var candidate = orderedCandidates[ci];
                        if (usedHorizontalSegments.Contains(candidate.HId))
                        {
                            continue;
                        }

                        Entity? hWritable = null;
                        if (candidate.MoveHorizontal)
                        {
                            hWritable = tr.GetObject(candidate.HId, OpenMode.ForWrite, false) as Entity;
                            if (hWritable == null || hWritable.IsErased)
                            {
                                continue;
                            }
                        }

                        Entity? vWritable = null;
                        if (candidate.MoveVertical)
                        {
                            vWritable = tr.GetObject(candidate.VId, OpenMode.ForWrite, false) as Entity;
                            if (vWritable == null || vWritable.IsErased)
                            {
                                continue;
                            }
                        }

                        var movedV = candidate.MoveVertical &&
                                     vWritable != null &&
                                     TryMoveEndpoint(vWritable, candidate.VMoveStart, candidate.Target, endpointMoveTol);
                        var movedH = candidate.MoveHorizontal &&
                                     hWritable != null &&
                                     TryMoveEndpoint(hWritable, candidate.HMoveStart, candidate.Target, endpointMoveTol);
                        if (!movedH && !movedV)
                        {
                            continue;
                        }

                        if (movedH)
                        {
                            usedHorizontalSegments.Add(candidate.HId);
                        }
                        if (movedH || movedV)
                        {
                            connectedPairs++;
                        }
                        if (movedH)
                        {
                            movedHorizontalEndpoints++;
                            lsdMidpointAdjustments.Add((
                                sectionTarget.SectionId,
                                candidate.HOldMoved,
                                candidate.HOldFixed,
                                Midpoint(candidate.HOldMoved, candidate.HOldFixed),
                                Midpoint(candidate.Target, candidate.HOldFixed)));
                        }

                        if (movedV)
                        {
                            movedVerticalEndpoints++;
                            lsdVerticalMidpointAdjustments.Add((
                                sectionTarget.SectionId,
                                candidate.VOldMoved,
                                candidate.VOldFixed,
                                Midpoint(candidate.VOldMoved, candidate.VOldFixed),
                                Midpoint(candidate.Target, candidate.VOldFixed)));
                        }

                        // One corner-connection per target section is enough.
                        break;
                    }
                }

                var lsdAdjusted = 0;
                if (allowSwBlindLineLsdMidpointAdjustments &&
                    (lsdMidpointAdjustments.Count > 0 || lsdVerticalMidpointAdjustments.Count > 0) &&
                    lsdSegments.Count > 0)
                {
                    const double lsdOldSegmentTol = 2.0;
                    const double lsdOldMidpointTol = 45.0;
                    const double lsdFallbackOldMidpointTol = 90.0;
                    const double lsdMaxMove = 80.0;
                    const double southwardTol = 0.50;
                    const double maxSouthwardDelta = 28.0;
                    const double eastwardTol = 1.0;
                    const double maxWestwardDelta = 70.0;
                    const double ownershipUTol = 40.0;
                    const double ownershipVTol = 55.0;

                    bool TryGetOwningSectionIndex(Point2d a, Point2d b, out int sectionIndex)
                    {
                        sectionIndex = -1;
                        var mid = Midpoint(a, b);
                        var bestDistance = double.MaxValue;
                        for (var si = 0; si < sectionTargets.Count; si++)
                        {
                            var sectionTarget = sectionTargets[si];
                            if (!DoesSegmentIntersectWindow(a, b, sectionTarget.Window) &&
                                !IsPointInWindow(mid, sectionTarget.Window))
                            {
                                continue;
                            }

                            var midU = (mid - sectionTarget.SwCorner).DotProduct(sectionTarget.EastUnit);
                            if (midU < -ownershipUTol || midU > (sectionTarget.Width + ownershipUTol))
                            {
                                continue;
                            }

                            var midV = (mid - sectionTarget.SwCorner).DotProduct(sectionTarget.NorthUnit);
                            if (midV < -(primaryExpectedOffset + ownershipVTol) || midV > (sectionTarget.Height + ownershipVTol))
                            {
                                continue;
                            }

                            var d = mid.GetDistanceTo(sectionTarget.SwCorner);
                            if (d < bestDistance)
                            {
                                bestDistance = d;
                                sectionIndex = si;
                            }
                        }

                        return sectionIndex >= 0;
                    }

                    bool TrySelectSouthTargetMidpoint(
                        Point2d southEndpoint,
                        int sectionIndex,
                        out Point2d targetMidpoint,
                        out bool usedFallback)
                    {
                        targetMidpoint = southEndpoint;
                        usedFallback = false;
                        var sectionTarget = sectionTargets[sectionIndex];
                        var endpointV = (southEndpoint - sectionTarget.SwCorner).DotProduct(sectionTarget.NorthUnit);

                        var found = false;
                        var bestSouthDelta = double.MaxValue;
                        var bestMoveDistance = double.MaxValue;
                        for (var i = 0; i < lsdMidpointAdjustments.Count; i++)
                        {
                            var adj = lsdMidpointAdjustments[i];
                            if (adj.SectionId != sectionTarget.SectionId)
                            {
                                continue;
                            }

                            var segDistance = DistancePointToSegment(southEndpoint, adj.OldA, adj.OldB);
                            if (segDistance > lsdOldSegmentTol)
                            {
                                continue;
                            }

                            var oldMidDistance = southEndpoint.GetDistanceTo(adj.OldMid);
                            if (oldMidDistance > lsdOldMidpointTol)
                            {
                                continue;
                            }

                            var targetV = (adj.NewMid - sectionTarget.SwCorner).DotProduct(sectionTarget.NorthUnit);
                            var southDelta = endpointV - targetV;
                            if (southDelta < -southwardTol || southDelta > maxSouthwardDelta)
                            {
                                continue;
                            }

                            var move = southEndpoint.GetDistanceTo(adj.NewMid);
                            if (move <= endpointMoveTol || move > lsdMaxMove)
                            {
                                continue;
                            }

                            var betterSouth = southDelta < (bestSouthDelta - 1e-6);
                            var tiedSouth = Math.Abs(southDelta - bestSouthDelta) <= 1e-6;
                            var betterMove = tiedSouth && move < bestMoveDistance;
                            if (!betterSouth && !betterMove)
                            {
                                continue;
                            }

                            found = true;
                            bestSouthDelta = southDelta;
                            bestMoveDistance = move;
                            targetMidpoint = adj.NewMid;
                        }

                        if (found)
                        {
                            return true;
                        }

                        // Fallback for noisy exploded LSD geometry: same section only, still southward-only.
                        for (var i = 0; i < lsdMidpointAdjustments.Count; i++)
                        {
                            var adj = lsdMidpointAdjustments[i];
                            if (adj.SectionId != sectionTarget.SectionId)
                            {
                                continue;
                            }

                            var oldMidDistance = southEndpoint.GetDistanceTo(adj.OldMid);
                            if (oldMidDistance > lsdFallbackOldMidpointTol)
                            {
                                continue;
                            }

                            var targetV = (adj.NewMid - sectionTarget.SwCorner).DotProduct(sectionTarget.NorthUnit);
                            var southDelta = endpointV - targetV;
                            if (southDelta < -southwardTol || southDelta > maxSouthwardDelta)
                            {
                                continue;
                            }

                            var move = southEndpoint.GetDistanceTo(adj.NewMid);
                            if (move <= endpointMoveTol || move > lsdMaxMove)
                            {
                                continue;
                            }

                            var betterSouth = southDelta < (bestSouthDelta - 1e-6);
                            var tiedSouth = Math.Abs(southDelta - bestSouthDelta) <= 1e-6;
                            var betterMove = tiedSouth && move < bestMoveDistance;
                            if (!betterSouth && !betterMove)
                            {
                                continue;
                            }

                            found = true;
                            usedFallback = true;
                            bestSouthDelta = southDelta;
                            bestMoveDistance = move;
                            targetMidpoint = adj.NewMid;
                        }

                        if (found)
                        {
                            return true;
                        }

                        // Strict: do not use neighboring-section nearest fallback.
                        // Only allow same-section midpoint mappings.
                        return false;
                    }

                    bool TrySelectWestTargetMidpoint(
                        Point2d westEndpoint,
                        int sectionIndex,
                        out Point2d targetMidpoint,
                        out bool usedFallback)
                    {
                        targetMidpoint = westEndpoint;
                        usedFallback = false;
                        var sectionTarget = sectionTargets[sectionIndex];
                        var endpointU = (westEndpoint - sectionTarget.SwCorner).DotProduct(sectionTarget.EastUnit);

                        var found = false;
                        var bestSegDistance = double.MaxValue;
                        var bestMidDistance = double.MaxValue;
                        var bestMoveDistance = double.MaxValue;
                        for (var i = 0; i < lsdVerticalMidpointAdjustments.Count; i++)
                        {
                            var adj = lsdVerticalMidpointAdjustments[i];
                            if (adj.SectionId != sectionTarget.SectionId)
                            {
                                continue;
                            }

                            var segDistance = DistancePointToSegment(westEndpoint, adj.OldA, adj.OldB);
                            if (segDistance > lsdOldSegmentTol)
                            {
                                continue;
                            }

                            var oldMidDistance = westEndpoint.GetDistanceTo(adj.OldMid);
                            if (oldMidDistance > lsdOldMidpointTol)
                            {
                                continue;
                            }

                            var targetU = (adj.NewMid - sectionTarget.SwCorner).DotProduct(sectionTarget.EastUnit);
                            var westDelta = endpointU - targetU;
                            if (westDelta < -eastwardTol || westDelta > maxWestwardDelta)
                            {
                                continue;
                            }

                            var move = westEndpoint.GetDistanceTo(adj.NewMid);
                            if (move <= endpointMoveTol || move > lsdMaxMove)
                            {
                                continue;
                            }

                            var betterSeg = segDistance < (bestSegDistance - 1e-6);
                            var tiedSeg = Math.Abs(segDistance - bestSegDistance) <= 1e-6;
                            var betterMid = tiedSeg && oldMidDistance < (bestMidDistance - 1e-6);
                            var tiedMid = tiedSeg && Math.Abs(oldMidDistance - bestMidDistance) <= 1e-6;
                            var betterMove = tiedMid && move < bestMoveDistance;
                            if (!betterSeg && !betterMid && !betterMove)
                            {
                                continue;
                            }

                            found = true;
                            bestSegDistance = segDistance;
                            bestMidDistance = oldMidDistance;
                            bestMoveDistance = move;
                            targetMidpoint = adj.NewMid;
                        }

                        if (found)
                        {
                            return true;
                        }

                        for (var i = 0; i < lsdVerticalMidpointAdjustments.Count; i++)
                        {
                            var adj = lsdVerticalMidpointAdjustments[i];
                            if (adj.SectionId != sectionTarget.SectionId)
                            {
                                continue;
                            }

                            var oldMidDistance = westEndpoint.GetDistanceTo(adj.OldMid);
                            if (oldMidDistance > lsdFallbackOldMidpointTol)
                            {
                                continue;
                            }

                            var targetU = (adj.NewMid - sectionTarget.SwCorner).DotProduct(sectionTarget.EastUnit);
                            var westDelta = endpointU - targetU;
                            if (westDelta < -eastwardTol || westDelta > maxWestwardDelta)
                            {
                                continue;
                            }

                            var move = westEndpoint.GetDistanceTo(adj.NewMid);
                            if (move <= endpointMoveTol || move > lsdMaxMove)
                            {
                                continue;
                            }

                            var betterMid = oldMidDistance < (bestMidDistance - 1e-6);
                            var tiedMid = Math.Abs(oldMidDistance - bestMidDistance) <= 1e-6;
                            var betterMove = tiedMid && move < bestMoveDistance;
                            if (!betterMid && !betterMove)
                            {
                                continue;
                            }

                            found = true;
                            usedFallback = true;
                            bestMidDistance = oldMidDistance;
                            bestMoveDistance = move;
                            targetMidpoint = adj.NewMid;
                        }

                        return found;
                    }

                    for (var i = 0; i < lsdSegments.Count; i++)
                    {
                        var lsd = lsdSegments[i];
                        if (!(tr.GetObject(lsd.Id, OpenMode.ForWrite, false) is Entity writableLsd) || writableLsd.IsErased)
                        {
                            continue;
                        }

                        if (!TryReadOpenSegment(writableLsd, out var p0, out var p1))
                        {
                            continue;
                        }

                        if (!IsAdjustableLsdLineSegment(p0, p1))
                        {
                            continue;
                        }

                        if (!TryGetOwningSectionIndex(p0, p1, out var sectionIndex))
                        {
                            continue;
                        }

                        var sectionTarget = sectionTargets[sectionIndex];
                        var moveStart = false;
                        var targetMid = default(Point2d);
                        var usedFallback = false;
                        if (IsVerticalLike(p0, p1))
                        {
                            var v0 = (p0 - sectionTarget.SwCorner).DotProduct(sectionTarget.NorthUnit);
                            var v1 = (p1 - sectionTarget.SwCorner).DotProduct(sectionTarget.NorthUnit);
                            moveStart = v0 <= v1;
                            var southEndpoint = moveStart ? p0 : p1;
                            if (!TrySelectSouthTargetMidpoint(
                                southEndpoint,
                                sectionIndex,
                                out targetMid,
                                out usedFallback))
                            {
                                continue;
                            }
                        }
                        else if (IsHorizontalLike(p0, p1))
                        {
                            var u0 = (p0 - sectionTarget.SwCorner).DotProduct(sectionTarget.EastUnit);
                            var u1 = (p1 - sectionTarget.SwCorner).DotProduct(sectionTarget.EastUnit);
                            moveStart = u0 <= u1;
                            var westEndpoint = moveStart ? p0 : p1;
                            if (!TrySelectWestTargetMidpoint(
                                westEndpoint,
                                sectionIndex,
                                out targetMid,
                                out usedFallback))
                            {
                                continue;
                            }
                        }
                        else
                        {
                            continue;
                        }

                        if (writableLsd is Line lsdLine)
                        {
                            if (moveStart)
                            {
                                lsdLine.StartPoint = new Point3d(targetMid.X, targetMid.Y, lsdLine.StartPoint.Z);
                            }
                            else
                            {
                                lsdLine.EndPoint = new Point3d(targetMid.X, targetMid.Y, lsdLine.EndPoint.Z);
                            }
                        }
                        else if (writableLsd is Polyline lsdPoly && !lsdPoly.Closed && lsdPoly.NumberOfVertices == 2)
                        {
                            lsdPoly.SetPointAt(moveStart ? 0 : 1, targetMid);
                        }
                        else
                        {
                            continue;
                        }

                        lsdAdjusted++;
                        if (usedFallback)
                        {
                            lsdFallbackEndpointAdjustments++;
                        }
                    }
                }

                tr.Commit();
                if (connectedPairs > 0)
                {
                    logger?.WriteLine(
                        $"Cleanup: connected {connectedPairs} SW blind-line 20.11 pair(s) " +
                        $"(H={movedHorizontalEndpoints}, V={movedVerticalEndpoints}).");
                    logger?.WriteLine(
                        $"Cleanup: SW 20.11 forced-corner attempts={forcedCornerAttempts}, connected={forcedCornerConnected}.");
                    if (lsdAdjusted > 0)
                    {
                        logger?.WriteLine($"Cleanup: adjusted {lsdAdjusted} L-SECTION-LSD endpoint(s) to midpoint of SW L-USEC 20.11 blind-line connection(s).");
                        if (lsdFallbackEndpointAdjustments > 0)
                        {
                            logger?.WriteLine($"Cleanup: {lsdFallbackEndpointAdjustments} SW L-SECTION-LSD endpoint(s) used same-section relaxed SW blind-line midpoint fallback.");
                        }
                    }
                }
                else
                {
                    logger?.WriteLine(
                        $"Cleanup: SW L-USEC 20.11 blind-line connect found no candidates " +
                        $"(sections={sectionTargets.Count}, withHV={sectionsWithCandidates}, pairs={pairCandidatesEvaluated}).");
                }
            }
        }

        private static void ConnectUsecSeSouthTwentyTwelveLinesToEastOriginalBoundary(
            Database database,
            IReadOnlyList<string> searchFolders,
            IEnumerable<QuarterLabelInfo> labelQuarterInfos,
            IReadOnlyCollection<ObjectId> generatedRoadAllowanceIds,
            Logger? logger)
        {
            // TODO(2026-02-09): SE L-USEC east-boundary extension still misses some cases;
            // revisit boundary candidate selection and downward target-horizontal matching.
            if (database == null ||
                searchFolders == null ||
                labelQuarterInfos == null ||
                generatedRoadAllowanceIds == null ||
                generatedRoadAllowanceIds.Count == 0)
            {
                return;
            }

            var targetInfos = labelQuarterInfos
                .Where(info =>
                    info != null &&
                    IsUsecSeSouthSection(info.SectionKey.Section))
                .ToList();
            if (targetInfos.Count == 0)
            {
                logger?.WriteLine("Cleanup: SE L-USEC south 20.11 connect skipped (no target section info).");
                return;
            }

            var targetSectionIds = targetInfos
                .Where(info => !info.SectionPolylineId.IsNull)
                .Select(info => info.SectionPolylineId)
                .Distinct()
                .ToList();
            var sectionKeyById = targetInfos
                .Where(info => info != null && !info.SectionPolylineId.IsNull)
                .GroupBy(info => info.SectionPolylineId)
                .ToDictionary(g => g.Key, g => g.First().SectionKey);

            var sectionTargets = new List<(ObjectId SectionId, Point2d SwCorner, Vector2d EastUnit, Vector2d NorthUnit, Extents3d Window, double EastEdgeU, Point2d OriginalSeCorner, bool HasOriginalSeCorner)>();
            var clipWindows = new List<Extents3d>();
            if (targetSectionIds.Count > 0)
            {
                const double seWindowBuffer = 120.0;
                var outlineLogger = logger ?? new Logger();
                using (var tr = database.TransactionManager.StartTransaction())
                {
                    foreach (var sectionId in targetSectionIds)
                    {
                        if (!(tr.GetObject(sectionId, OpenMode.ForRead, false) is Polyline section) || section.IsErased)
                        {
                            continue;
                        }

                        try
                        {
                            var ext = section.GeometricExtents;
                            if (!TryGetQuarterAnchors(section, out var sectionAnchors))
                            {
                                sectionAnchors = GetFallbackAnchors(section);
                            }

                            var eastUnit = GetUnitVector(sectionAnchors.Left, sectionAnchors.Right, new Vector2d(1, 0));
                            var northUnit = GetUnitVector(sectionAnchors.Bottom, sectionAnchors.Top, new Vector2d(0, 1));
                            Point2d swCorner;
                            if (!TryGetQuarterCorner(section, eastUnit, northUnit, QuarterCorner.SouthWest, out swCorner))
                            {
                                swCorner = new Point2d(ext.MinPoint.X, ext.MinPoint.Y);
                            }

                            Point2d seCorner;
                            if (!TryGetQuarterCorner(section, eastUnit, northUnit, QuarterCorner.SouthEast, out seCorner))
                            {
                                seCorner = new Point2d(ext.MaxPoint.X, ext.MinPoint.Y);
                            }

                            var eastEdgeU = (seCorner - swCorner).DotProduct(eastUnit);
                            if (eastEdgeU <= 1e-6)
                            {
                                eastEdgeU = 0.0;
                                for (var vi = 0; vi < section.NumberOfVertices; vi++)
                                {
                                    var u = (section.GetPoint2dAt(vi) - swCorner).DotProduct(eastUnit);
                                    if (u > eastEdgeU)
                                    {
                                        eastEdgeU = u;
                                    }
                                }
                            }

                            var originalSeCorner = seCorner;
                            var hasOriginalSeCorner = false;
                            if (sectionKeyById.TryGetValue(sectionId, out var sectionKey) &&
                                TryLoadSectionOutline(searchFolders, sectionKey, outlineLogger, out var outline))
                            {
                                var sectionNumber = ParseSectionNumber(sectionKey.Section);
                                if (TryCreateSectionSpatialInfo(outline, sectionNumber, out var spatialInfo) &&
                                    spatialInfo != null)
                                {
                                    try
                                    {
                                        originalSeCorner = spatialInfo.SouthWest + (spatialInfo.EastUnit * spatialInfo.Width);
                                        hasOriginalSeCorner = true;
                                    }
                                    finally
                                    {
                                        spatialInfo.SectionPolyline.Dispose();
                                    }
                                }
                            }

                            var midX = 0.5 * (ext.MinPoint.X + ext.MaxPoint.X);
                            var midY = 0.5 * (ext.MinPoint.Y + ext.MaxPoint.Y);
                            var seWindow = new Extents3d(
                                new Point3d(midX - seWindowBuffer, ext.MinPoint.Y - seWindowBuffer, 0.0),
                                new Point3d(ext.MaxPoint.X + seWindowBuffer, midY + seWindowBuffer, 0.0));
                            clipWindows.Add(seWindow);
                            sectionTargets.Add((sectionId, swCorner, eastUnit, northUnit, seWindow, eastEdgeU, originalSeCorner, hasOriginalSeCorner));
                        }
                        catch
                        {
                        }
                    }

                    tr.Commit();
                }
            }

            if (clipWindows.Count == 0 || sectionTargets.Count == 0)
            {
                logger?.WriteLine("Cleanup: SE L-USEC south 20.11 connect skipped (no clip windows).");
                return;
            }

            bool IsPointInAnyWindow(Point2d p)
            {
                for (var i = 0; i < clipWindows.Count; i++)
                {
                    var w = clipWindows[i];
                    if (p.X >= w.MinPoint.X && p.X <= w.MaxPoint.X &&
                        p.Y >= w.MinPoint.Y && p.Y <= w.MaxPoint.Y)
                    {
                        return true;
                    }
                }

                return false;
            }

            bool DoesSegmentIntersectAnyWindow(Point2d a, Point2d b)
            {
                if (IsPointInAnyWindow(a) || IsPointInAnyWindow(b))
                {
                    return true;
                }

                for (var i = 0; i < clipWindows.Count; i++)
                {
                    if (TryClipSegmentToWindow(a, b, clipWindows[i], out _, out _))
                    {
                        return true;
                    }
                }

                return false;
            }

            bool TryReadOpenSegment(Entity ent, out Point2d a, out Point2d b)
            {
                a = default;
                b = default;
                if (ent == null)
                {
                    return false;
                }

                if (ent is Line ln)
                {
                    a = new Point2d(ln.StartPoint.X, ln.StartPoint.Y);
                    b = new Point2d(ln.EndPoint.X, ln.EndPoint.Y);
                    return a.GetDistanceTo(b) > 1e-4;
                }

                if (ent is Polyline pl)
                {
                    if (pl.Closed || pl.NumberOfVertices != 2)
                    {
                        return false;
                    }

                    a = pl.GetPoint2dAt(0);
                    b = pl.GetPoint2dAt(1);
                    return a.GetDistanceTo(b) > 1e-4;
                }

                return false;
            }

            bool TryMoveEndpoint(Entity writable, bool moveStart, Point2d target, double moveTol)
            {
                if (writable is Line ln)
                {
                    var old = moveStart
                        ? new Point2d(ln.StartPoint.X, ln.StartPoint.Y)
                        : new Point2d(ln.EndPoint.X, ln.EndPoint.Y);
                    if (old.GetDistanceTo(target) <= moveTol)
                    {
                        return false;
                    }

                    if (moveStart)
                    {
                        ln.StartPoint = new Point3d(target.X, target.Y, ln.StartPoint.Z);
                    }
                    else
                    {
                        ln.EndPoint = new Point3d(target.X, target.Y, ln.EndPoint.Z);
                    }

                    return true;
                }

                if (writable is Polyline pl && !pl.Closed && pl.NumberOfVertices == 2)
                {
                    var old = pl.GetPoint2dAt(moveStart ? 0 : 1);
                    if (old.GetDistanceTo(target) <= moveTol)
                    {
                        return false;
                    }

                    pl.SetPointAt(moveStart ? 0 : 1, target);
                    return true;
                }

                return false;
            }

            bool IsHorizontalLike(Point2d a, Point2d b)
            {
                var d = b - a;
                return Math.Abs(d.X) >= Math.Abs(d.Y);
            }

            bool IsVerticalLike(Point2d a, Point2d b)
            {
                var d = b - a;
                return Math.Abs(d.Y) > Math.Abs(d.X);
            }

            var generatedSet = new HashSet<ObjectId>(generatedRoadAllowanceIds.Where(id => !id.IsNull));
            using (var tr = database.TransactionManager.StartTransaction())
            {
                bool IsPointInWindow(Point2d p, Extents3d window)
                {
                    return p.X >= window.MinPoint.X && p.X <= window.MaxPoint.X &&
                           p.Y >= window.MinPoint.Y && p.Y <= window.MaxPoint.Y;
                }

                bool DoesSegmentIntersectWindow(Point2d a, Point2d b, Extents3d window)
                {
                    return IsPointInWindow(a, window) ||
                           IsPointInWindow(b, window) ||
                           TryClipSegmentToWindow(a, b, window, out _, out _);
                }

                bool TryIntersectInfiniteLines(Point2d a0, Point2d a1, Point2d b0, Point2d b1, out Point2d intersection)
                {
                    intersection = default;
                    var da = a1 - a0;
                    var db = b1 - b0;
                    var denom = Cross2d(da, db);
                    if (Math.Abs(denom) <= 1e-9)
                    {
                        return false;
                    }

                    var diff = b0 - a0;
                    var t = Cross2d(diff, db) / denom;
                    intersection = a0 + (da * t);
                    return true;
                }

                var usecHorizontals = new List<(ObjectId Id, Point2d A, Point2d B, bool IsGenerated, bool IsUsecTwentyLayer, bool IsUsecBaseLayer)>();
                var originalVerticals = new List<(ObjectId Id, Point2d A, Point2d B, bool IsSecLayer, bool IsGenerated, bool IsUsecZeroLayer)>();
                var bt = (BlockTable)tr.GetObject(database.BlockTableId, OpenMode.ForRead);
                var ms = (BlockTableRecord)tr.GetObject(bt[BlockTableRecord.ModelSpace], OpenMode.ForRead);
                foreach (ObjectId id in ms)
                {
                    if (!(tr.GetObject(id, OpenMode.ForRead, false) is Entity ent) || ent.IsErased)
                    {
                        continue;
                    }

                    if (!TryReadOpenSegment(ent, out var a, out var b))
                    {
                        continue;
                    }

                    if (!DoesSegmentIntersectAnyWindow(a, b))
                    {
                        continue;
                    }

                    var isUsecLayer = string.Equals(ent.Layer, "L-USEC", StringComparison.OrdinalIgnoreCase);
                    var isUsecZeroLayer = string.Equals(ent.Layer, LayerUsecZero, StringComparison.OrdinalIgnoreCase);
                    var isUsecThirtyLayer = string.Equals(ent.Layer, LayerUsecThirty, StringComparison.OrdinalIgnoreCase);
                    var isUsecTwentyLayer = string.Equals(ent.Layer, LayerUsecTwenty, StringComparison.OrdinalIgnoreCase);
                    var isUsecBaseLayer = string.Equals(ent.Layer, LayerUsecBase, StringComparison.OrdinalIgnoreCase);
                    if (!isUsecLayer)
                    {
                        isUsecLayer = isUsecZeroLayer || isUsecThirtyLayer;
                    }

                    isUsecLayer = isUsecLayer || isUsecTwentyLayer || isUsecBaseLayer;
                    var isSecLayer = string.Equals(ent.Layer, "L-SEC", StringComparison.OrdinalIgnoreCase);
                    if (!isUsecLayer && !isSecLayer)
                    {
                        continue;
                    }

                    if (IsHorizontalLike(a, b))
                    {
                        if (isUsecLayer)
                        {
                            usecHorizontals.Add((id, a, b, generatedSet.Contains(id), isUsecTwentyLayer, isUsecBaseLayer));
                        }
                    }

                    if (IsVerticalLike(a, b))
                    {
                        originalVerticals.Add((id, a, b, isSecLayer, generatedSet.Contains(id), isUsecZeroLayer));
                    }
                }

                if (usecHorizontals.Count == 0 || originalVerticals.Count == 0)
                {
                    tr.Commit();
                    logger?.WriteLine("Cleanup: SE L-USEC south 20.11 connect skipped (missing horizontals or original vertical boundaries).");
                    return;
                }

                const double endpointMoveTol = 0.05;
                const double minExtend = 0.10;
                const double maxExtend = 40.0;
                const double expectedSouthOffset = CorrectionLinePairGapMeters;
                const double southOffsetTol = 3.0;
                const double southBandMatchTol = 1.5;
                const double originalSeSnapBuffer = 11.0;
                // Allow small drafting noise/rotation drift while still requiring on-segment intersection.
                const double targetOnHorizontalTol = 2.50;
                var usedVerticalBoundaries = new HashSet<ObjectId>();
                var connected = 0;
                var sectionsWithOriginalBoundary = 0;
                var sectionsWithHorizontalCandidate = 0;
                var candidatesEvaluated = 0;
                var blockedByInterveningHorizontalRoad = 0;
                var skippedHorizontalNonSpanning = 0;
                var movedVerticalBoundaryEndpoints = 0;
                var movedHorizontalBoundaryEndpoints = 0;
                var rejectedNonVerticalBoundary = 0;
                var rejectedNonHorizontalBoundary = 0;
                var lsdTargetMidpoints = new List<(ObjectId SectionId, Point2d Midpoint)>();

                for (var si = 0; si < sectionTargets.Count; si++)
                {
                    var sectionTarget = sectionTargets[si];
                    var swCorner = sectionTarget.SwCorner;
                    var eastUnit = sectionTarget.EastUnit;
                    var northUnit = sectionTarget.NorthUnit;

                    double ToU(Point2d p) => (p - swCorner).DotProduct(eastUnit);
                    double ToV(Point2d p) => (p - swCorner).DotProduct(northUnit);
                    bool FirstPointIsSouth(Point2d p0, Point2d p1)
                    {
                        // Prefer world-Y south for endpoint selection; fall back to local-V only when nearly flat in Y.
                        if (Math.Abs(p0.Y - p1.Y) > 1e-3)
                        {
                            return p0.Y <= p1.Y;
                        }

                        return ToV(p0) <= ToV(p1);
                    }

                    var southBandHorizontalSpans = new List<(double MinU, double MaxU)>();
                    for (var hi = 0; hi < usecHorizontals.Count; hi++)
                    {
                        var h = usecHorizontals[hi];
                        if (!DoesSegmentIntersectWindow(h.A, h.B, sectionTarget.Window))
                        {
                            continue;
                        }

                        var hd = h.B - h.A;
                        var hEastComp = Math.Abs(hd.DotProduct(eastUnit));
                        var hNorthComp = Math.Abs(hd.DotProduct(northUnit));
                        if (hEastComp < hNorthComp)
                        {
                            continue;
                        }

                        var hVa = ToV(h.A);
                        var hVb = ToV(h.B);
                        var hVLine = 0.5 * (hVa + hVb);
                        if (Math.Abs(Math.Abs(hVLine) - expectedSouthOffset) > southOffsetTol)
                        {
                            continue;
                        }

                        var hUa = ToU(h.A);
                        var hUb = ToU(h.B);
                        southBandHorizontalSpans.Add((Math.Min(hUa, hUb), Math.Max(hUa, hUb)));
                    }

                    double ClosestSouthBandGap(double boundaryU)
                    {
                        if (southBandHorizontalSpans.Count == 0)
                        {
                            return double.MaxValue;
                        }

                        var best = double.MaxValue;
                        for (var i = 0; i < southBandHorizontalSpans.Count; i++)
                        {
                            var span = southBandHorizontalSpans[i];
                            var gap = 0.0;
                            if (boundaryU < span.MinU)
                            {
                                gap = span.MinU - boundaryU;
                            }
                            else if (boundaryU > span.MaxU)
                            {
                                gap = boundaryU - span.MaxU;
                            }

                            if (gap < best)
                            {
                                best = gap;
                            }
                        }

                        return best;
                    }

                    var eastBoundaryCandidates = new List<(
                        ObjectId Id,
                        Point2d A,
                        Point2d B,
                        double ULine,
                        double ClosestSouthBandGap,
                        bool IsSecLayer,
                        bool IsGenerated,
                        bool IsUsecZeroLayer,
                        bool ContainsSouthBand,
                        double SouthBandDistance,
                        bool NearOriginalSe,
                        double OriginalSeDistance)>();
                    for (var i = 0; i < originalVerticals.Count; i++)
                    {
                        var seg = originalVerticals[i];
                        if (usedVerticalBoundaries.Contains(seg.Id))
                        {
                            continue;
                        }

                        if (!DoesSegmentIntersectWindow(seg.A, seg.B, sectionTarget.Window))
                        {
                            continue;
                        }

                        var d = seg.B - seg.A;
                        var eastComp = Math.Abs(d.DotProduct(eastUnit));
                        var northComp = Math.Abs(d.DotProduct(northUnit));
                        if (northComp <= eastComp)
                        {
                            continue;
                        }

                        var uA = ToU(seg.A);
                        var uB = ToU(seg.B);
                        var vA = ToV(seg.A);
                        var vB = ToV(seg.B);
                        var uLine = 0.5 * (uA + uB);
                        var minV = Math.Min(vA, vB);
                        var maxV = Math.Max(vA, vB);
                        var southBandV = -expectedSouthOffset;
                        var containsSouthBand =
                            southBandV >= (minV - southBandMatchTol) &&
                            southBandV <= (maxV + southBandMatchTol);
                        var southBandDistance =
                            southBandV < minV
                                ? (minV - southBandV)
                                : southBandV > maxV
                                    ? (southBandV - maxV)
                                    : 0.0;

                        var southEndpointCandidate = FirstPointIsSouth(seg.A, seg.B) ? seg.A : seg.B;
                        var originalSeDistance = sectionTarget.HasOriginalSeCorner
                            ? southEndpointCandidate.GetDistanceTo(sectionTarget.OriginalSeCorner)
                            : double.MaxValue;
                        var nearOriginalSe = sectionTarget.HasOriginalSeCorner &&
                                             originalSeDistance <= originalSeSnapBuffer;

                        var closestSouthBandGap = ClosestSouthBandGap(uLine);
                        eastBoundaryCandidates.Add((seg.Id, seg.A, seg.B, uLine, closestSouthBandGap, seg.IsSecLayer, seg.IsGenerated, seg.IsUsecZeroLayer, containsSouthBand, southBandDistance, nearOriginalSe, originalSeDistance));
                    }

                    if (eastBoundaryCandidates.Count == 0)
                    {
                        continue;
                    }

                    if (southBandHorizontalSpans.Count == 0)
                    {
                        continue;
                    }

                    var availableBoundaryCandidates = eastBoundaryCandidates;

                    if (sectionTarget.HasOriginalSeCorner)
                    {
                        availableBoundaryCandidates = availableBoundaryCandidates
                            .OrderByDescending(c => c.NearOriginalSe)
                            .ThenBy(c => c.OriginalSeDistance)
                            .ThenBy(c => Math.Abs(c.ULine))
                            .ToList();
                    }

                    const double boundaryToSouthBandMaxGap = 24.0;
                    var nearSouthBandBoundaries = availableBoundaryCandidates
                        .Where(c => c.ClosestSouthBandGap <= boundaryToSouthBandMaxGap)
                        .ToList();
                    if (nearSouthBandBoundaries.Count > 0)
                    {
                        availableBoundaryCandidates = nearSouthBandBoundaries;
                    }

                    var sectionNumber = 0;
                    if (sectionKeyById.TryGetValue(sectionTarget.SectionId, out var sectionKeyForFilter))
                    {
                        sectionNumber = ParseSectionNumber(sectionKeyForFilter.Section);
                    }

                    var preferWestMostSeRaBoundary =
                        (sectionNumber >= 1 && sectionNumber <= 6) ||
                        (sectionNumber >= 13 && sectionNumber <= 18) ||
                        (sectionNumber >= 25 && sectionNumber <= 30);
                    var trimHorizontalToBoundaryInSpecialSe = preferWestMostSeRaBoundary;

                    var eastRoadAllowanceWestBand = preferWestMostSeRaBoundary ? 75.0 : 45.0;
                    var eastRoadAllowanceEastBand = preferWestMostSeRaBoundary ? 25.0 : 20.0;
                    var eastBandBoundaries = availableBoundaryCandidates
                        .Where(c =>
                            c.ULine >= (sectionTarget.EastEdgeU - eastRoadAllowanceWestBand) &&
                            c.ULine <= (sectionTarget.EastEdgeU + eastRoadAllowanceEastBand))
                        .ToList();
                    if (eastBandBoundaries.Count > 0)
                    {
                        availableBoundaryCandidates = eastBandBoundaries;
                    }

                    if (preferWestMostSeRaBoundary)
                    {
                        var usecZeroBoundaries = availableBoundaryCandidates
                            .Where(c => c.IsUsecZeroLayer)
                            .ToList();
                        if (usecZeroBoundaries.Count > 0)
                        {
                            availableBoundaryCandidates = usecZeroBoundaries;
                        }
                    }

                    var orderedBoundaryCandidates = preferWestMostSeRaBoundary
                        ? availableBoundaryCandidates
                            .OrderByDescending(c => c.IsUsecZeroLayer)
                            .ThenByDescending(c => c.NearOriginalSe)
                            .ThenBy(c => c.OriginalSeDistance)
                            .ThenBy(c => c.ContainsSouthBand ? 0 : 1)
                            .ThenBy(c => c.SouthBandDistance)
                            .ThenBy(c => c.ClosestSouthBandGap)
                            .ThenBy(c => c.ULine)
                            .ThenBy(c => c.IsGenerated ? 1 : 0)
                            .ThenByDescending(c => c.IsSecLayer)
                            .ToList()
                        : availableBoundaryCandidates
                        .OrderBy(c => c.ContainsSouthBand ? 0 : 1)
                        .ThenBy(c => c.SouthBandDistance)
                        .ThenBy(c => c.ClosestSouthBandGap)
                        .ThenBy(c => c.OriginalSeDistance)
                        .ThenByDescending(c => c.IsSecLayer)
                        .ThenBy(c => c.ULine)
                        .ToList();
                    if (orderedBoundaryCandidates.Count == 0)
                    {
                        continue;
                    }

                    // SE bridge must only move the 0-side vertical boundary.
                    // Moving SEC/USEC/2012/3018 boundaries causes cross-township inconsistency.
                    var usecZeroBoundaryCandidates = orderedBoundaryCandidates
                        .Where(c => c.IsUsecZeroLayer)
                        .ToList();
                    if (usecZeroBoundaryCandidates.Count == 0)
                    {
                        continue;
                    }

                    orderedBoundaryCandidates = usecZeroBoundaryCandidates;

                    sectionsWithOriginalBoundary++;

                    var horizontalCandidates = new List<(
                        ObjectId SegmentId,
                        Point2d SegmentA,
                        Point2d SegmentB,
                        Point2d TargetPoint,
                        Point2d HorizontalMidpoint,
                        double Score,
                        bool IsUsecTwentyLayer,
                        bool IsUsecBaseLayer)>();
                    var selectedBoundary = orderedBoundaryCandidates[0];
                    var selectedBoundaryFound = false;

                    for (var bi = 0; bi < orderedBoundaryCandidates.Count; bi++)
                    {
                        var boundaryCandidate = orderedBoundaryCandidates[bi];
                        var boundaryVa = ToV(boundaryCandidate.A);
                        var boundaryVb = ToV(boundaryCandidate.B);
                        var southIsStart = FirstPointIsSouth(boundaryCandidate.A, boundaryCandidate.B);
                        var southPoint = southIsStart ? boundaryCandidate.A : boundaryCandidate.B;
                        var northPoint = southIsStart ? boundaryCandidate.B : boundaryCandidate.A;
                        var boundaryDir = northPoint - southPoint;
                        var boundaryLen = boundaryDir.Length;
                        if (boundaryLen <= 1e-6)
                        {
                            continue;
                        }

                        boundaryDir = boundaryDir / boundaryLen;
                        var boundaryU = boundaryCandidate.ULine;

                        var candidatesForBoundary = new List<(
                            ObjectId SegmentId,
                            Point2d SegmentA,
                            Point2d SegmentB,
                            Point2d TargetPoint,
                            Point2d HorizontalMidpoint,
                            double Score,
                            bool IsUsecTwentyLayer,
                            bool IsUsecBaseLayer)>();
                        for (var i = 0; i < usecHorizontals.Count; i++)
                        {
                            var seg = usecHorizontals[i];
                            if (!DoesSegmentIntersectWindow(seg.A, seg.B, sectionTarget.Window))
                            {
                                continue;
                            }

                            var d = seg.B - seg.A;
                            var eastComp = Math.Abs(d.DotProduct(eastUnit));
                            var northComp = Math.Abs(d.DotProduct(northUnit));
                            if (eastComp < northComp)
                            {
                                continue;
                            }

                            var uA = ToU(seg.A);
                            var uB = ToU(seg.B);
                            var minU = Math.Min(uA, uB);
                            var maxU = Math.Max(uA, uB);
                            var vA = ToV(seg.A);
                            var vB = ToV(seg.B);
                            var vLine = 0.5 * (vA + vB);
                            if (Math.Abs(Math.Abs(vLine) - expectedSouthOffset) > southOffsetTol)
                            {
                                continue;
                            }

                            var spansBoundary = boundaryU >= (minU - 1.0) && boundaryU <= (maxU + 1.0);

                            var boundaryGap = 0.0;
                            if (boundaryU < minU)
                            {
                                boundaryGap = minU - boundaryU;
                            }
                            else if (boundaryU > maxU)
                            {
                                boundaryGap = boundaryU - maxU;
                            }

                            var apparentBoundarySpanTol = preferWestMostSeRaBoundary ? 45.0 : 22.0;
                            if (!spansBoundary && boundaryGap > apparentBoundarySpanTol)
                            {
                                skippedHorizontalNonSpanning++;
                                continue;
                            }

                            if (!TryIntersectInfiniteLines(seg.A, seg.B, boundaryCandidate.A, boundaryCandidate.B, out var targetPoint))
                            {
                                continue;
                            }

                            if (!IsPointInWindow(targetPoint, sectionTarget.Window))
                            {
                                continue;
                            }

                            if (DistancePointToSegment(targetPoint, seg.A, seg.B) > targetOnHorizontalTol)
                            {
                                skippedHorizontalNonSpanning++;
                                continue;
                            }

                            var tOnBoundary = (targetPoint - southPoint).DotProduct(boundaryDir);
                            var boundaryEndpointGap = 0.0;
                            if (tOnBoundary < -minExtend)
                            {
                                boundaryEndpointGap = -tOnBoundary;
                            }
                            else if (tOnBoundary > (boundaryLen + minExtend))
                            {
                                boundaryEndpointGap = tOnBoundary - (boundaryLen + minExtend);
                            }

                            var boundaryEndpointGapMax = preferWestMostSeRaBoundary ? 45.0 : 22.0;
                            if (boundaryEndpointGap > boundaryEndpointGapMax)
                            {
                                continue;
                            }

                            var horizontalMoveDist = Math.Min(
                                seg.A.GetDistanceTo(targetPoint),
                                seg.B.GetDistanceTo(targetPoint));
                            if (horizontalMoveDist <= endpointMoveTol || horizontalMoveDist > maxExtend)
                            {
                                continue;
                            }

                            var score = boundaryEndpointGap;
                            score += 0.20 * boundaryGap;
                            score += 0.10 * horizontalMoveDist;
                            if (!seg.IsGenerated)
                            {
                                score += 0.25;
                            }
                            if (sectionTarget.HasOriginalSeCorner)
                            {
                                score += 0.25 * DistancePointToSegment(sectionTarget.OriginalSeCorner, seg.A, seg.B);
                            }

                            candidatesForBoundary.Add((
                                seg.Id,
                                seg.A,
                                seg.B,
                                targetPoint,
                                Midpoint(seg.A, seg.B),
                                score,
                                seg.IsUsecTwentyLayer,
                                seg.IsUsecBaseLayer));
                        }

                        if (candidatesForBoundary.Count == 0)
                        {
                            continue;
                        }

                        selectedBoundary = boundaryCandidate;
                        selectedBoundaryFound = true;
                        horizontalCandidates = candidatesForBoundary;
                        break;
                    }

                    if (!selectedBoundaryFound)
                    {
                        continue;
                    }

                    candidatesEvaluated += horizontalCandidates.Count;
                    if (horizontalCandidates.Count == 0)
                    {
                        continue;
                    }

                    sectionsWithHorizontalCandidate++;
                    var orderedCandidates = horizontalCandidates
                        .OrderBy(c => c.Score)
                        .ToList();
                    var hasUsecTwentyCandidate = orderedCandidates.Any(c => c.IsUsecTwentyLayer);
                    var bestScore = orderedCandidates[0].Score;
                    var connectedThisSection = 0;
                    var maxConnectionsPerSection = trimHorizontalToBoundaryInSpecialSe ? 1 : 2;
                    const double additionalScoreTolerance = 8.0;
                    for (var ci = 0; ci < orderedCandidates.Count && connectedThisSection < maxConnectionsPerSection; ci++)
                    {
                        var best = orderedCandidates[ci];
                        if (best.Score > bestScore + additionalScoreTolerance)
                        {
                            break;
                        }

                        if (trimHorizontalToBoundaryInSpecialSe)
                        {
                            if (!best.IsUsecTwentyLayer)
                            {
                                if (!(best.IsUsecBaseLayer && !hasUsecTwentyCandidate))
                                {
                                    continue;
                                }
                            }

                            var bestVLine = 0.5 * (ToV(best.SegmentA) + ToV(best.SegmentB));
                            if (Math.Abs(Math.Abs(bestVLine) - expectedSouthOffset) > southBandMatchTol)
                            {
                                continue;
                            }

                            if (!(tr.GetObject(best.SegmentId, OpenMode.ForRead, false) is Entity horizontalEntity) ||
                                horizontalEntity.IsErased)
                            {
                                continue;
                            }

                            if (!TryReadOpenSegment(horizontalEntity, out var h0, out var h1) || !IsHorizontalLike(h0, h1))
                            {
                                rejectedNonHorizontalBoundary++;
                                continue;
                            }

                            bool TrySnapUsecZeroBoundaryToHorizontal(Point2d horizontalA, Point2d horizontalB)
                            {
                                var usecZeroBoundaryCandidates = eastBoundaryCandidates
                                    .Where(c => c.IsUsecZeroLayer)
                                    .OrderBy(c => usedVerticalBoundaries.Contains(c.Id) ? 1 : 0)
                                    .ThenByDescending(c => c.NearOriginalSe)
                                    .ThenBy(c => c.OriginalSeDistance)
                                    .ThenBy(c => c.SouthBandDistance)
                                    .ThenBy(c => Math.Abs(c.ULine - sectionTarget.EastEdgeU))
                                    .ToList();
                                for (var zi = 0; zi < usecZeroBoundaryCandidates.Count; zi++)
                                {
                                    var zeroBoundary = usecZeroBoundaryCandidates[zi];
                                    if (!(tr.GetObject(zeroBoundary.Id, OpenMode.ForWrite, false) is Entity writableBoundaryInSpecial) ||
                                        writableBoundaryInSpecial.IsErased)
                                    {
                                        continue;
                                    }

                                    if (!TryReadOpenSegment(writableBoundaryInSpecial, out var b0Special, out var b1Special) ||
                                        !IsVerticalLike(b0Special, b1Special))
                                    {
                                        continue;
                                    }

                                    if (!TryIntersectInfiniteLines(horizontalA, horizontalB, b0Special, b1Special, out var zeroTarget))
                                    {
                                        continue;
                                    }

                                    if (!IsPointInWindow(zeroTarget, sectionTarget.Window))
                                    {
                                        continue;
                                    }

                                    if (DistancePointToSegment(zeroTarget, horizontalA, horizontalB) > targetOnHorizontalTol)
                                    {
                                        continue;
                                    }

                                    var moveSouthStart = FirstPointIsSouth(b0Special, b1Special);
                                    var southEndpointSpecial = moveSouthStart ? b0Special : b1Special;
                                    var endpointMoveSpecial = southEndpointSpecial.GetDistanceTo(zeroTarget);
                                    if (endpointMoveSpecial <= endpointMoveTol || endpointMoveSpecial > maxExtend)
                                    {
                                        continue;
                                    }

                                    if (TryMoveEndpoint(writableBoundaryInSpecial, moveSouthStart, zeroTarget, endpointMoveTol))
                                    {
                                        movedVerticalBoundaryEndpoints++;
                                        usedVerticalBoundaries.Add(zeroBoundary.Id);
                                        return true;
                                    }
                                }

                                return false;
                            }

                            if (TrySnapUsecZeroBoundaryToHorizontal(h0, h1))
                            {
                                connected++;
                                connectedThisSection++;
                            }

                            continue;
                        }

                        // Directional fix for SE quarter bridge:
                        // move the N-S boundary endpoint (south end) to the apparent intersection,
                        // instead of extending the E-W horizontal segment.
                        if (!(tr.GetObject(selectedBoundary.Id, OpenMode.ForWrite, false) is Entity writableBoundary) || writableBoundary.IsErased)
                        {
                            continue;
                        }

                        if (!TryReadOpenSegment(writableBoundary, out var b0, out var b1) || !IsVerticalLike(b0, b1))
                        {
                            rejectedNonVerticalBoundary++;
                            continue;
                        }

                        var moveStart = FirstPointIsSouth(b0, b1); // move south endpoint only
                        var southEndpoint = moveStart ? b0 : b1;
                        var endpointMove = southEndpoint.GetDistanceTo(best.TargetPoint);
                        if (endpointMove <= endpointMoveTol || endpointMove > maxExtend)
                        {
                            continue;
                        }

                        if (!TryMoveEndpoint(writableBoundary, moveStart, best.TargetPoint, endpointMoveTol))
                        {
                            continue;
                        }

                        // Keep SE pass from pulling LSD endpoints until SE geometry is deterministic.
                        // (Historical source of bottom-township cross-through artifacts.)
                        // lsdTargetMidpoints.Add((sectionTarget.SectionId, Midpoint(westPoint, best.TargetPoint)));

                        connected++;
                        connectedThisSection++;
                        movedVerticalBoundaryEndpoints++;
                        usedVerticalBoundaries.Add(selectedBoundary.Id);
                    }
                }

                var lsdAdjusted = 0;
                if (lsdTargetMidpoints.Count > 0)
                {
                    var lsdSegments = new List<(ObjectId Id, Point2d A, Point2d B)>();
                    foreach (ObjectId id in ms)
                    {
                        if (!(tr.GetObject(id, OpenMode.ForRead, false) is Entity ent) || ent.IsErased)
                        {
                            continue;
                        }

                        if (!string.Equals(ent.Layer, "L-SECTION-LSD", StringComparison.OrdinalIgnoreCase))
                        {
                            continue;
                        }

                        if (!TryReadOpenSegment(ent, out var a, out var b))
                        {
                            continue;
                        }

                        if (!DoesSegmentIntersectAnyWindow(a, b))
                        {
                            continue;
                        }

                        if (!IsAdjustableLsdLineSegment(a, b))
                        {
                            continue;
                        }

                        lsdSegments.Add((id, a, b));
                    }

                    const double lsdMaxMove = 80.0;
                    const double southwardTol = 0.50;
                    const double maxSouthwardDelta = 70.0;
                    const double maxCenterlineOffset = 35.0;

                    bool TryGetOwningSectionIndex(Point2d a, Point2d b, out int sectionIndex)
                    {
                        const double ownershipUTol = 40.0;
                        sectionIndex = -1;
                        var mid = Midpoint(a, b);
                        var bestDistance = double.MaxValue;
                        for (var si = 0; si < sectionTargets.Count; si++)
                        {
                            var sectionTarget = sectionTargets[si];
                            if (!DoesSegmentIntersectWindow(a, b, sectionTarget.Window) &&
                                !IsPointInWindow(mid, sectionTarget.Window))
                            {
                                continue;
                            }

                            var midU = (mid - sectionTarget.SwCorner).DotProduct(sectionTarget.EastUnit);
                            if (midU < -ownershipUTol || midU > (sectionTarget.EastEdgeU + ownershipUTol))
                            {
                                continue;
                            }

                            var d = mid.GetDistanceTo(sectionTarget.SwCorner);
                            if (d < bestDistance)
                            {
                                bestDistance = d;
                                sectionIndex = si;
                            }
                        }

                        return sectionIndex >= 0;
                    }

                    bool TrySelectSouthTargetMidpoint(
                        Point2d southEndpoint,
                        int sectionIndex,
                        out Point2d targetMidpoint)
                    {
                        targetMidpoint = southEndpoint;
                        var sectionTarget = sectionTargets[sectionIndex];
                        var endpointU = (southEndpoint - sectionTarget.SwCorner).DotProduct(sectionTarget.EastUnit);
                        var endpointV = (southEndpoint - sectionTarget.SwCorner).DotProduct(sectionTarget.NorthUnit);

                        var found = false;
                        var bestCenterlineOffset = double.MaxValue;
                        var bestSouthDelta = double.MaxValue;
                        var bestMoveDistance = double.MaxValue;
                        for (var i = 0; i < lsdTargetMidpoints.Count; i++)
                        {
                            var adj = lsdTargetMidpoints[i];
                            if (adj.SectionId != sectionTarget.SectionId)
                            {
                                continue;
                            }

                            var targetU = (adj.Midpoint - sectionTarget.SwCorner).DotProduct(sectionTarget.EastUnit);
                            var centerlineOffset = Math.Abs(endpointU - targetU);
                            if (centerlineOffset > maxCenterlineOffset)
                            {
                                continue;
                            }

                            var targetV = (adj.Midpoint - sectionTarget.SwCorner).DotProduct(sectionTarget.NorthUnit);
                            var southDelta = endpointV - targetV;
                            if (southDelta < -southwardTol || southDelta > maxSouthwardDelta)
                            {
                                continue;
                            }

                            var move = southEndpoint.GetDistanceTo(adj.Midpoint);
                            if (move <= endpointMoveTol || move > lsdMaxMove)
                            {
                                continue;
                            }

                            var betterCenterline = centerlineOffset < (bestCenterlineOffset - 1e-6);
                            var tiedCenterline = Math.Abs(centerlineOffset - bestCenterlineOffset) <= 1e-6;
                            var betterSouth = tiedCenterline && southDelta < (bestSouthDelta - 1e-6);
                            var tiedSouth = tiedCenterline && Math.Abs(southDelta - bestSouthDelta) <= 1e-6;
                            var betterMove = tiedSouth && move < bestMoveDistance;
                            if (!betterCenterline && !betterSouth && !betterMove)
                            {
                                continue;
                            }

                            found = true;
                            bestCenterlineOffset = centerlineOffset;
                            bestSouthDelta = southDelta;
                            bestMoveDistance = move;
                            targetMidpoint = adj.Midpoint;
                        }

                        if (found)
                        {
                            return true;
                        }

                        // Strict: do not use neighboring-section nearest fallback.
                        return false;
                    }

                    for (var i = 0; i < lsdSegments.Count; i++)
                    {
                        var lsd = lsdSegments[i];
                        if (!(tr.GetObject(lsd.Id, OpenMode.ForWrite, false) is Entity writableLsd) || writableLsd.IsErased)
                        {
                            continue;
                        }

                        if (!TryReadOpenSegment(writableLsd, out var p0, out var p1))
                        {
                            continue;
                        }

                        if (!IsVerticalLike(p0, p1))
                        {
                            continue;
                        }

                        if (!TryGetOwningSectionIndex(p0, p1, out var sectionIndex))
                        {
                            continue;
                        }

                        var sectionTarget = sectionTargets[sectionIndex];
                        var v0 = (p0 - sectionTarget.SwCorner).DotProduct(sectionTarget.NorthUnit);
                        var v1 = (p1 - sectionTarget.SwCorner).DotProduct(sectionTarget.NorthUnit);
                        var moveStart = v0 <= v1;
                        var southEndpoint = moveStart ? p0 : p1;
                        if (!TrySelectSouthTargetMidpoint(southEndpoint, sectionIndex, out var targetMid))
                        {
                            continue;
                        }

                        if (writableLsd is Line lsdLine)
                        {
                            if (moveStart)
                            {
                                lsdLine.StartPoint = new Point3d(targetMid.X, targetMid.Y, lsdLine.StartPoint.Z);
                            }
                            else
                            {
                                lsdLine.EndPoint = new Point3d(targetMid.X, targetMid.Y, lsdLine.EndPoint.Z);
                            }
                        }
                        else if (writableLsd is Polyline lsdPoly && !lsdPoly.Closed && lsdPoly.NumberOfVertices >= 2)
                        {
                            var index = moveStart ? 0 : lsdPoly.NumberOfVertices - 1;
                            lsdPoly.SetPointAt(index, targetMid);
                        }
                        else
                        {
                            continue;
                        }

                        lsdAdjusted++;
                    }
                }

                tr.Commit();
                if (connected > 0)
                {
                    logger?.WriteLine($"Cleanup: connected {connected} SE L-USEC south 20.11 line(s) to west-most east RA original boundary.");
                    logger?.WriteLine($"Cleanup: SE directional bridge moves verticalEndpoints={movedVerticalBoundaryEndpoints}, horizontalEndpoints={movedHorizontalBoundaryEndpoints}, rejectedNonVerticalBoundary={rejectedNonVerticalBoundary}, rejectedNonHorizontalBoundary={rejectedNonHorizontalBoundary}.");
                    if (blockedByInterveningHorizontalRoad > 0)
                    {
                        logger?.WriteLine($"Cleanup: SE guard blocked {blockedByInterveningHorizontalRoad} candidate endpoint move(s) due to intervening horizontal road boundaries.");
                    }
                    if (skippedHorizontalNonSpanning > 0)
                    {
                        logger?.WriteLine($"Cleanup: SE guard skipped {skippedHorizontalNonSpanning} horizontal candidate(s) that did not span selected east boundary.");
                    }
                    if (lsdAdjusted > 0)
                    {
                        logger?.WriteLine($"Cleanup: adjusted {lsdAdjusted} L-SECTION-LSD endpoint(s) to midpoint of SE L-USEC south 20.11 connection(s).");
                    }
                }
                else
                {
                    logger?.WriteLine($"Cleanup: SE directional bridge moves verticalEndpoints={movedVerticalBoundaryEndpoints}, horizontalEndpoints={movedHorizontalBoundaryEndpoints}, rejectedNonVerticalBoundary={rejectedNonVerticalBoundary}, rejectedNonHorizontalBoundary={rejectedNonHorizontalBoundary}.");
                    if (blockedByInterveningHorizontalRoad > 0)
                    {
                        logger?.WriteLine($"Cleanup: SE guard blocked {blockedByInterveningHorizontalRoad} candidate endpoint move(s) due to intervening horizontal road boundaries.");
                    }
                    if (skippedHorizontalNonSpanning > 0)
                    {
                        logger?.WriteLine($"Cleanup: SE guard skipped {skippedHorizontalNonSpanning} horizontal candidate(s) that did not span selected east boundary.");
                    }
                    logger?.WriteLine(
                        $"Cleanup: SE L-USEC south 20.11 connect found no candidates " +
                        $"(sections={sectionTargets.Count}, withBoundary={sectionsWithOriginalBoundary}, withH={sectionsWithHorizontalCandidate}, candidates={candidatesEvaluated}).");
                }
            }

            // SE specific duplicate cleanup: equal-length blind-line twins can remain after SE connect.
            CleanupDuplicateBlindLineSegments(database, targetSectionIds, logger);
        }

private static List<Polyline> BuildBufferedQuarterOffsetPolylines(
            Database database,
            IEnumerable<ObjectId> quarterIds,
            double buffer,
            Logger? logger)
        {
            var result = new List<Polyline>();
            if (database == null || quarterIds == null || buffer <= 0.0)
            {
                return result;
            }

            var attempted = 0;
            var skippedInvalid = 0;
            var offsetFailed = 0;
            using (var tr = database.TransactionManager.StartTransaction())
            {
                foreach (var id in quarterIds.Distinct())
                {
                    if (id.IsNull || id.IsErased)
                    {
                        skippedInvalid++;
                        continue;
                    }

                    var quarter = tr.GetObject(id, OpenMode.ForRead, false) as Polyline;
                    if (quarter == null || !quarter.Closed || quarter.NumberOfVertices < 3)
                    {
                        skippedInvalid++;
                        continue;
                    }

                    attempted++;
                    if (TryCreateOutsideOffsetPolyline(quarter, buffer, out var outside, logger))
                    {
                        result.Add(outside);
                    }
                    else
                    {
                        offsetFailed++;
                        logger?.WriteLine($"DEFPOINTS BUFFER: offset failed for quarter id {id}.");
                    }
                }

                tr.Commit();
            }

            logger?.WriteLine($"DEFPOINTS BUFFER: attempted={attempted}, created={result.Count}, skippedInvalid={skippedInvalid}, failed={offsetFailed}");
            return result;
        }

        private static bool TryCreateOutsideOffsetPolyline(Polyline source, double distance, [NotNullWhen(true)] out Polyline? outside, Logger? logger)
        {
            outside = null;
            var candidates = new List<Polyline>();
            try
            {
                CollectOffsetCandidates(source, distance, candidates);
                CollectOffsetCandidates(source, -distance, candidates);
                if (candidates.Count == 0)
                {
                    logger?.WriteLine("DEFPOINTS BUFFER: no offset candidates produced by GetOffsetCurves.");
                    return false;
                }

                Polyline? best = null;
                var bestArea = double.MinValue;
                foreach (var c in candidates)
                {
                    double area;
                    try { area = Math.Abs(c.Area); }
                    catch { area = 0.0; }
                    if (area > bestArea)
                    {
                        bestArea = area;
                        best = c;
                    }
                }

                if (best == null)
                {
                    logger?.WriteLine("DEFPOINTS BUFFER: candidates existed but no best offset selected.");
                    return false;
                }

                outside = (Polyline)best.Clone();
                logger?.WriteLine($"DEFPOINTS BUFFER: selected offset area={bestArea:0.###}, candidates={candidates.Count}");
                return true;
            }
            finally
            {
                foreach (var c in candidates)
                {
                    c.Dispose();
                }
            }
        }

        private static void CollectOffsetCandidates(Polyline source, double distance, List<Polyline> destination)
        {
            DBObjectCollection? offsets = null;
            try
            {
                offsets = source.GetOffsetCurves(distance);
                if (offsets == null)
                {
                    return;
                }

                foreach (DBObject obj in offsets)
                {
                    if (obj is Polyline pl && pl.Closed && pl.NumberOfVertices >= 3)
                    {
                        destination.Add((Polyline)pl.Clone());
                    }
                }
            }
            catch
            {
            }
            finally
            {
                if (offsets != null)
                {
                    foreach (DBObject obj in offsets)
                    {
                        obj.Dispose();
                    }
                }
            }
        }

        private static List<Polyline> BuildUnionBoundaries(List<Polyline> polylines, Logger? logger)
        {
            var output = new List<Polyline>();
            if (polylines == null || polylines.Count == 0)
            {
                return output;
            }

            Region? union = null;
            try
            {
                logger?.WriteLine($"DEFPOINTS BUFFER: union input count={polylines.Count}");
                foreach (var poly in polylines)
                {
                    var region = CreateRegionFromPolyline(poly);
                    if (region == null)
                    {
                        logger?.WriteLine("DEFPOINTS BUFFER: CreateRegionFromPolyline returned null for one offset.");
                        continue;
                    }

                    if (union == null)
                    {
                        union = region;
                    }
                    else
                    {
                        try
                        {
                            union.BooleanOperation(BooleanOperationType.BoolUnite, region);
                        }
                        finally
                        {
                            region.Dispose();
                        }
                    }
                }

                if (union == null)
                {
                    return output;
                }

                var exploded = new DBObjectCollection();
                union.Explode(exploded);
                var explodedCurves = new List<Curve>();
                foreach (DBObject obj in exploded)
                {
                    if (obj is Polyline pl && pl.Closed && pl.NumberOfVertices >= 3)
                    {
                        output.Add((Polyline)pl.Clone());
                    }
                    else if (obj is Curve curve)
                    {
                        explodedCurves.Add((Curve)curve.Clone());
                    }
                    obj.Dispose();
                }

                if (output.Count == 0)
                {
                    if (TryBuildClosedPolylinesFromCurves(explodedCurves, output))
                    {
                        logger?.WriteLine("DEFPOINTS BUFFER: union explode yielded curves; rebuilt closed boundary loop(s).");
                    }
                }

                foreach (var curve in explodedCurves)
                {
                    curve.Dispose();
                }

                if (output.Count == 0)
                {
                    // Fallback: keep the per-quarter offsets instead of collapsing into one large
                    // rectangle. This avoids pulling in unrelated neighboring sections.
                    foreach (var poly in polylines)
                    {
                        if (poly == null || !poly.Closed || poly.NumberOfVertices < 3)
                        {
                            continue;
                        }

                        output.Add((Polyline)poly.Clone());
                    }

                    if (output.Count > 0)
                    {
                        logger?.WriteLine("DEFPOINTS BUFFER: union explode empty, used per-offset fallback (no convex hull).");
                    }
                }
                logger?.WriteLine($"DEFPOINTS BUFFER: union output boundaries={output.Count}");
            }
            catch (System.Exception ex)
            {
                logger?.WriteLine("DEFPOINTS offset-union failed: " + ex.Message);
            }
            finally
            {
                union?.Dispose();
            }

            return output;
        }

        private static bool TryBuildClosedPolylinesFromCurves(List<Curve> curves, List<Polyline> output)
        {
            if (curves == null || curves.Count == 0 || output == null)
            {
                return false;
            }

            const double tol = 0.01;
            var segments = new List<(Point2d A, Point2d B)>();
            foreach (var curve in curves)
            {
                if (!(curve is Line line))
                {
                    continue;
                }

                var a = new Point2d(line.StartPoint.X, line.StartPoint.Y);
                var b = new Point2d(line.EndPoint.X, line.EndPoint.Y);
                if (a.GetDistanceTo(b) <= tol)
                {
                    continue;
                }

                segments.Add((a, b));
            }

            if (segments.Count < 3)
            {
                return false;
            }

            var builtAny = false;
            while (segments.Count > 0)
            {
                var loop = new List<Point2d>();
                var first = segments[0];
                segments.RemoveAt(0);
                loop.Add(first.A);
                loop.Add(first.B);

                var closed = false;
                while (true)
                {
                    var current = loop[loop.Count - 1];
                    if (current.GetDistanceTo(loop[0]) <= tol)
                    {
                        closed = true;
                        break;
                    }

                    var foundIndex = -1;
                    var next = default(Point2d);
                    for (var i = 0; i < segments.Count; i++)
                    {
                        var seg = segments[i];
                        if (current.GetDistanceTo(seg.A) <= tol)
                        {
                            foundIndex = i;
                            next = seg.B;
                            break;
                        }

                        if (current.GetDistanceTo(seg.B) <= tol)
                        {
                            foundIndex = i;
                            next = seg.A;
                            break;
                        }
                    }

                    if (foundIndex < 0)
                    {
                        break;
                    }

                    segments.RemoveAt(foundIndex);
                    loop.Add(next);
                }

                if (!closed || loop.Count < 4)
                {
                    continue;
                }

                var poly = new Polyline(loop.Count - 1) { Closed = true };
                for (var i = 0; i < loop.Count - 1; i++)
                {
                    poly.AddVertexAt(i, loop[i], 0, 0, 0);
                }

                if (poly.NumberOfVertices >= 3)
                {
                    output.Add(poly);
                    builtAny = true;
                }
                else
                {
                    poly.Dispose();
                }
            }

            return builtAny;
        }

        private static Polyline? BuildConvexHullPolyline(List<Polyline> polylines)
        {
            if (polylines == null || polylines.Count == 0)
            {
                return null;
            }

            var points = new List<Point2d>();
            foreach (var poly in polylines)
            {
                if (poly == null || poly.NumberOfVertices < 3)
                {
                    continue;
                }

                for (var i = 0; i < poly.NumberOfVertices; i++)
                {
                    points.Add(poly.GetPoint2dAt(i));
                }
            }

            var hull = ComputeConvexHull(points);
            if (hull.Count < 3)
            {
                return null;
            }

            var result = new Polyline(hull.Count) { Closed = true };
            for (var i = 0; i < hull.Count; i++)
            {
                result.AddVertexAt(i, hull[i], 0, 0, 0);
            }

            return result;
        }

        private static List<Point2d> ComputeConvexHull(List<Point2d> input)
        {
            var points = input
                .Where(p => !double.IsNaN(p.X) && !double.IsNaN(p.Y) && !double.IsInfinity(p.X) && !double.IsInfinity(p.Y))
                .Distinct(new Point2dApproxComparer(1e-6))
                .OrderBy(p => p.X)
                .ThenBy(p => p.Y)
                .ToList();

            if (points.Count <= 1)
            {
                return points;
            }

            var lower = new List<Point2d>();
            foreach (var p in points)
            {
                while (lower.Count >= 2 && Cross(lower[lower.Count - 2], lower[lower.Count - 1], p) <= 0.0)
                {
                    lower.RemoveAt(lower.Count - 1);
                }
                lower.Add(p);
            }

            var upper = new List<Point2d>();
            for (var i = points.Count - 1; i >= 0; i--)
            {
                var p = points[i];
                while (upper.Count >= 2 && Cross(upper[upper.Count - 2], upper[upper.Count - 1], p) <= 0.0)
                {
                    upper.RemoveAt(upper.Count - 1);
                }
                upper.Add(p);
            }

            lower.RemoveAt(lower.Count - 1);
            upper.RemoveAt(upper.Count - 1);
            lower.AddRange(upper);
            return lower;
        }

        private static double Cross(Point2d a, Point2d b, Point2d c)
        {
            var ab = b - a;
            var ac = c - a;
            return (ab.X * ac.Y) - (ab.Y * ac.X);
        }

        private sealed class Point2dApproxComparer : IEqualityComparer<Point2d>
        {
            private readonly double _eps;

            public Point2dApproxComparer(double eps)
            {
                _eps = Math.Max(1e-9, eps);
            }

            public bool Equals(Point2d x, Point2d y)
            {
                return Math.Abs(x.X - y.X) <= _eps && Math.Abs(x.Y - y.Y) <= _eps;
            }

            public int GetHashCode(Point2d obj)
            {
                var qx = Math.Round(obj.X / _eps);
                var qy = Math.Round(obj.Y / _eps);
                return HashCode.Combine(qx, qy);
            }
        }

        private static Region? CreateRegionFromPolyline(Polyline polyline)
        {
            DBObjectCollection? curves = null;
            DBObjectCollection? regions = null;
            try
            {
                curves = new DBObjectCollection();
                curves.Add((Curve)polyline.Clone());
                regions = Region.CreateFromCurves(curves);
                if (regions == null || regions.Count == 0)
                {
                    return null;
                }

                var region = (Region)regions[0];
                for (var i = 1; i < regions.Count; i++)
                {
                    regions[i]?.Dispose();
                }
                return region;
            }
            catch
            {
                return null;
            }
            finally
            {
                if (curves != null)
                {
                    foreach (DBObject c in curves)
                    {
                        c.Dispose();
                    }
                }
            }
        }

        private static List<Extents2d> MergeIntersectingExtents(List<Extents2d> input)
        {
            var remaining = new List<Extents2d>(input);
            var merged = new List<Extents2d>();
            while (remaining.Count > 0)
            {
                var current = remaining[0];
                remaining.RemoveAt(0);
                var expanded = true;
                while (expanded)
                {
                    expanded = false;
                    for (var i = remaining.Count - 1; i >= 0; i--)
                    {
                        var other = remaining[i];
                        if (!Extents2dIntersects(current, other))
                        {
                            continue;
                        }

                        current = UnionExtents2d(current, other);
                        remaining.RemoveAt(i);
                        expanded = true;
                    }
                }

                merged.Add(current);
            }

            return merged;
        }

        private static bool Extents2dIntersects(Extents2d a, Extents2d b)
        {
            return !(a.MaxPoint.X < b.MinPoint.X ||
                     a.MinPoint.X > b.MaxPoint.X ||
                     a.MaxPoint.Y < b.MinPoint.Y ||
                     a.MinPoint.Y > b.MaxPoint.Y);
        }

        private static Extents2d UnionExtents2d(Extents2d a, Extents2d b)
        {
            return new Extents2d(
                new Point2d(Math.Min(a.MinPoint.X, b.MinPoint.X), Math.Min(a.MinPoint.Y, b.MinPoint.Y)),
                new Point2d(Math.Max(a.MaxPoint.X, b.MaxPoint.X), Math.Max(a.MaxPoint.Y, b.MaxPoint.Y)));
        }

        private static void EnsureDefpointsLayer(Database database, Transaction transaction)
        {
            var lt = (LayerTable)transaction.GetObject(database.LayerTableId, OpenMode.ForRead);
            if (lt.Has("DEFPOINTS"))
            {
                return;
            }

            lt.UpgradeOpen();
            var rec = new LayerTableRecord
            {
                Name = "DEFPOINTS",
                IsPlottable = false
            };
            lt.Add(rec);
            transaction.AddNewlyCreatedDBObject(rec, true);
        }

        private static string BuildTownshipKey(SectionKey key)
        {
            return $"{key.Zone}|{NormalizeNumberToken(key.Meridian)}|{NormalizeNumberToken(key.Range)}|{NormalizeNumberToken(key.Township)}";
        }

        private static bool TryParsePositiveToken(string token, out int value)
        {
            value = 0;
            var normalized = NormalizeNumberToken(token);
            return int.TryParse(normalized, NumberStyles.Integer, CultureInfo.InvariantCulture, out value) && value > 0;
        }

        private static HashSet<string> BuildContextTownshipKeys(IReadOnlyList<SectionRequest> requests)
        {
            var keys = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
            if (requests == null || requests.Count == 0)
            {
                return keys;
            }

            foreach (var request in requests)
            {
                if (!TryParsePositiveToken(request.Key.Range, out var rangeNum) ||
                    !TryParsePositiveToken(request.Key.Township, out var townshipNum))
                {
                    keys.Add(BuildTownshipKey(request.Key));
                    continue;
                }

                void AddTownship(int rangeCandidate, int townshipCandidate)
                {
                    if (rangeCandidate <= 0 || townshipCandidate <= 0)
                    {
                        return;
                    }

                    var key = new SectionKey(
                        request.Key.Zone,
                        "1",
                        townshipCandidate.ToString(CultureInfo.InvariantCulture),
                        rangeCandidate.ToString(CultureInfo.InvariantCulture),
                        request.Key.Meridian);
                    keys.Add(BuildTownshipKey(key));
                }

                // Always include the request's own township.
                AddTownship(rangeNum, townshipNum);

                var sectionNumber = ParseSectionNumber(request.Key.Section);
                if (!TryGetAtsSectionGridPosition(sectionNumber, out var row, out var col))
                {
                    // Unknown section token: preserve previous behavior (3x3 expansion).
                    for (var dRange = -1; dRange <= 1; dRange++)
                    {
                        for (var dTownship = -1; dTownship <= 1; dTownship++)
                        {
                            AddTownship(rangeNum + dRange, townshipNum + dTownship);
                        }
                    }
                    continue;
                }

                // Only expand to adjacent townships when a requested section touches a township edge.
                // Range increases westward in ATS, so west neighbor is range+1 and east neighbor is range-1.
                var touchesWest = col == 0;
                var touchesEast = col == 5;
                var touchesNorth = row == 0;
                var touchesSouth = row == 5;

                if (touchesWest) AddTownship(rangeNum + 1, townshipNum);
                if (touchesEast) AddTownship(rangeNum - 1, townshipNum);
                if (touchesNorth) AddTownship(rangeNum, townshipNum + 1);
                if (touchesSouth) AddTownship(rangeNum, townshipNum - 1);

                if (touchesWest && touchesNorth) AddTownship(rangeNum + 1, townshipNum + 1);
                if (touchesWest && touchesSouth) AddTownship(rangeNum + 1, townshipNum - 1);
                if (touchesEast && touchesNorth) AddTownship(rangeNum - 1, townshipNum + 1);
                if (touchesEast && touchesSouth) AddTownship(rangeNum - 1, townshipNum - 1);
                }

            return keys;
        }

        private static bool TryParseTownshipKey(
            string townshipKey,
            out int zone,
            out string meridian,
            out string range,
            out string township)
        {
            zone = 0;
            meridian = string.Empty;
            range = string.Empty;
            township = string.Empty;

            if (string.IsNullOrWhiteSpace(townshipKey))
            {
                return false;
            }

            var parts = townshipKey.Split('|');
            if (parts.Length != 4)
            {
                return false;
            }

            if (!int.TryParse(parts[0], NumberStyles.Integer, CultureInfo.InvariantCulture, out zone))
            {
                return false;
            }

            meridian = parts[1];
            range = parts[2];
            township = parts[3];
            return !string.IsNullOrWhiteSpace(meridian) &&
                   !string.IsNullOrWhiteSpace(range) &&
                   !string.IsNullOrWhiteSpace(township);
        }

        private static bool TryParseSectionNumberToken(string section, out int sectionNumber)
        {
            sectionNumber = 0;
            if (string.IsNullOrWhiteSpace(section))
            {
                return false;
            }

            var raw = section.Trim();
            var match = Regex.Match(raw, "\\d+");
            if (!match.Success)
            {
                return false;
            }

            return int.TryParse(match.Value, NumberStyles.Integer, CultureInfo.InvariantCulture, out sectionNumber);
        }

        private static bool IsUsecSeSouthSection(string section)
        {
            if (!TryParseSectionNumberToken(section, out var n))
            {
                return false;
            }

            return (n >= 1 && n <= 6) ||
                   (n >= 13 && n <= 18) ||
                   (n >= 25 && n <= 30);
        }

        private static bool IsUsecBlindSouthSection(string section)
        {
            if (!TryParseSectionNumberToken(section, out var n))
            {
                return false;
            }

            return (n >= 7 && n <= 12) ||
                   (n >= 19 && n <= 24) ||
                   (n >= 31 && n <= 36);
        }

        private static Vector2d GetUnitVector(Point2d from, Point2d to, Vector2d fallback)
        {
            var v = to - from;
            if (v.Length <= 1e-9)
            {
                return fallback;
            }

            return v / v.Length;
        }

        private static Point2d OffsetPoint(Point2d point, Vector2d directionUnit, double distance)
        {
            return point + (directionUnit * distance);
        }

        private static Point2d Midpoint(Point2d a, Point2d b)
        {
            return new Point2d((a.X + b.X) * 0.5, (a.Y + b.Y) * 0.5);
        }

        private static Point2d GetTrimmedNorthMidpoint(
            Polyline quarter,
            Vector2d eastUnit,
            Vector2d northUnit,
            double trimDistance,
            Point2d fallback)
        {
            if (!TryGetQuarterCorner(quarter, eastUnit, northUnit, QuarterCorner.NorthWest, out var nw) ||
                !TryGetQuarterCorner(quarter, eastUnit, northUnit, QuarterCorner.NorthEast, out var ne))
            {
                return fallback;
            }

            var edge = ne - nw;
            if (edge.Length <= (2.0 * trimDistance) + 1e-6)
            {
                return fallback;
            }

            var edgeUnit = edge / edge.Length;
            var start = nw + (edgeUnit * trimDistance);
            var end = ne - (edgeUnit * trimDistance);
            return new Point2d((start.X + end.X) * 0.5, (start.Y + end.Y) * 0.5);
        }

        private enum QuarterCorner
        {
            NorthWest,
            NorthEast,
            SouthWest,
            SouthEast
        }

        private static bool TryGetQuarterCorner(
            Polyline quarter,
            Vector2d eastUnit,
            Vector2d northUnit,
            QuarterCorner corner,
            out Point2d point)
        {
            point = default;
            if (quarter == null || quarter.NumberOfVertices <= 0)
            {
                return false;
            }

            double bestScore = double.MinValue;
            bool found = false;

            for (var i = 0; i < quarter.NumberOfVertices; i++)
            {
                var p = quarter.GetPoint2dAt(i);
                var e = (p.X * eastUnit.X) + (p.Y * eastUnit.Y);
                var n = (p.X * northUnit.X) + (p.Y * northUnit.Y);

                double score;
                switch (corner)
                {
                    case QuarterCorner.NorthWest:
                        score = n - e;
                        break;
                    case QuarterCorner.NorthEast:
                        score = n + e;
                        break;
                    case QuarterCorner.SouthWest:
                        score = -n - e;
                        break;
                    case QuarterCorner.SouthEast:
                        score = -n + e;
                        break;
                    default:
                        score = double.MinValue;
                        break;
                }

                if (!found || score > bestScore)
                {
                    bestScore = score;
                    point = p;
                    found = true;
                }
            }

            return found;
        }

        private static QuarterSelection PromptForQuarter(Editor editor)
        {
            var options = new PromptKeywordOptions("Select quarter")
            {
                AllowNone = false
            };
            options.Keywords.Add("NW");
            options.Keywords.Add("NE");
            options.Keywords.Add("SW");
            options.Keywords.Add("SE");
            options.Keywords.Add("N");
            options.Keywords.Add("S");
            options.Keywords.Add("E");
            options.Keywords.Add("W");
            options.Keywords.Add("ALL");

            var result = editor.GetKeywords(options);
            if (result.Status != PromptStatus.OK)
            {
                return QuarterSelection.None;
            }

            switch (result.StringResult.ToUpperInvariant())
            {
                case "NW":
                    return QuarterSelection.NorthWest;
                case "NE":
                    return QuarterSelection.NorthEast;
                case "SW":
                    return QuarterSelection.SouthWest;
                case "SE":
                    return QuarterSelection.SouthEast;
                case "N":
                    return QuarterSelection.NorthHalf;
                case "S":
                    return QuarterSelection.SouthHalf;
                case "E":
                    return QuarterSelection.EastHalf;
                case "W":
                    return QuarterSelection.WestHalf;
                case "ALL":
                    return QuarterSelection.All;
                default:
                    return QuarterSelection.None;
            }
        }

        private static bool TryPromptString(Editor editor, string message, out string value)
        {
            value = string.Empty;
            var options = new PromptStringOptions(message + ": ")
            {
                AllowSpaces = true
            };

            var result = editor.GetString(options);
            if (result.Status != PromptStatus.OK || string.IsNullOrWhiteSpace(result.StringResult))
            {
                return false;
            }

            value = result.StringResult;
            return true;
        }

        private static bool TryPromptInt(Editor editor, string message, out int value)
        {
            value = 0;
            var options = new PromptIntegerOptions(message + ": ")
            {
                AllowNone = false
            };

            var result = editor.GetInteger(options);
            if (result.Status != PromptStatus.OK)
            {
                return false;
            }

            value = result.Value;
            return true;
        }

        private static bool TryBuildQuarterMap(Polyline section, out Dictionary<QuarterSelection, Polyline> quarterMap, out QuarterAnchors anchors)
        {
            quarterMap = new Dictionary<QuarterSelection, Polyline>();

            if (!TryGetQuarterAnchors(section, out anchors))
            {
                anchors = GetFallbackAnchors(section);
            }

            var outline = GetPolylinePoints(section);
            if (outline.Count < 3)
            {
                return false;
            }

            if (TryBuildQuarterPolylines(outline, anchors, out quarterMap))
            {
                return true;
            }

            quarterMap = GenerateQuarterMapFromExtents(section);
            return quarterMap.Count > 0;
        }

        private static bool TryBuildQuarterPolylines(
            IReadOnlyList<Point2d> outline,
            QuarterAnchors anchors,
            out Dictionary<QuarterSelection, Polyline> quarterMap)
        {
            quarterMap = new Dictionary<QuarterSelection, Polyline>();

            var northLineStart = anchors.Left;
            var northLineEnd = anchors.Right;
            var westLineStart = anchors.Top;
            var westLineEnd = anchors.Bottom;

            var northSign = GetSideSign(northLineStart, northLineEnd, anchors.Top);
            if (northSign == 0)
            {
                northSign = GetSideSign(northLineStart, northLineEnd, anchors.Bottom);
            }

            var westSign = GetSideSign(westLineStart, westLineEnd, anchors.Left);
            if (westSign == 0)
            {
                westSign = GetSideSign(westLineStart, westLineEnd, anchors.Right);
            }

            if (northSign == 0 || westSign == 0)
            {
                return false;
            }

            var north = ClipPolygon(outline, northLineStart, northLineEnd, northSign);
            var south = ClipPolygon(outline, northLineStart, northLineEnd, -northSign);
            var northwest = ClipPolygon(north, westLineStart, westLineEnd, westSign);
            var northeast = ClipPolygon(north, westLineStart, westLineEnd, -westSign);
            var southwest = ClipPolygon(south, westLineStart, westLineEnd, westSign);
            var southeast = ClipPolygon(south, westLineStart, westLineEnd, -westSign);

            if (!TryAddQuarter(quarterMap, QuarterSelection.NorthWest, northwest) ||
                !TryAddQuarter(quarterMap, QuarterSelection.NorthEast, northeast) ||
                !TryAddQuarter(quarterMap, QuarterSelection.SouthWest, southwest) ||
                !TryAddQuarter(quarterMap, QuarterSelection.SouthEast, southeast))
            {
                return false;
            }

            return true;
        }

        private static bool TryAddQuarter(Dictionary<QuarterSelection, Polyline> quarterMap, QuarterSelection selection, List<Point2d> points)
        {
            var polyline = BuildPolylineFromPoints(points);
            if (polyline == null)
            {
                return false;
            }

            quarterMap[selection] = polyline;
            return true;
        }

        private static Dictionary<QuarterSelection, Polyline> GenerateQuarterMapFromExtents(Polyline section)
        {
            var extents = section.GeometricExtents;
            var minX = extents.MinPoint.X;
            var minY = extents.MinPoint.Y;
            var maxX = extents.MaxPoint.X;
            var maxY = extents.MaxPoint.Y;
            var midX = (minX + maxX) / 2.0;
            var midY = (minY + maxY) / 2.0;

            return new Dictionary<QuarterSelection, Polyline>
            {
                { QuarterSelection.SouthWest, CreateRectangle(minX, minY, midX, midY) },
                { QuarterSelection.SouthEast, CreateRectangle(midX, minY, maxX, midY) },
                { QuarterSelection.NorthWest, CreateRectangle(minX, midY, midX, maxY) },
                { QuarterSelection.NorthEast, CreateRectangle(midX, midY, maxX, maxY) }
            };
        }

        private static QuarterAnchors GetFallbackAnchors(Polyline section)
        {
            var extents = section.GeometricExtents;
            var minX = extents.MinPoint.X;
            var minY = extents.MinPoint.Y;
            var maxX = extents.MaxPoint.X;
            var maxY = extents.MaxPoint.Y;
            var midX = (minX + maxX) / 2.0;
            var midY = (minY + maxY) / 2.0;

            return new QuarterAnchors(
                new Point2d(midX, maxY),
                new Point2d(midX, minY),
                new Point2d(minX, midY),
                new Point2d(maxX, midY));
        }

        private static List<Point2d> GetPolylinePoints(Polyline section)
        {
            var points = new List<Point2d>(section.NumberOfVertices);
            for (var i = 0; i < section.NumberOfVertices; i++)
            {
                points.Add(section.GetPoint2dAt(i));
            }

            return points;
        }

        private static double GetSideSign(Point2d lineStart, Point2d lineEnd, Point2d point)
        {
            var lineDir = lineEnd - lineStart;
            var toPoint = point - lineStart;
            var cross = lineDir.X * toPoint.Y - lineDir.Y * toPoint.X;
            if (Math.Abs(cross) < 1e-9)
            {
                return 0;
            }

            return Math.Sign(cross);
        }

        private static List<Point2d> ClipPolygon(IReadOnlyList<Point2d> polygon, Point2d lineStart, Point2d lineEnd, double keepSign)
        {
            var output = new List<Point2d>();
            if (polygon.Count == 0)
            {
                return output;
            }

            var prev = polygon[polygon.Count - 1];
            var prevSide = SignedSide(lineStart, lineEnd, prev);
            var prevInside = IsInside(prevSide, keepSign);

            foreach (var current in polygon)
            {
                var currentSide = SignedSide(lineStart, lineEnd, current);
                var currentInside = IsInside(currentSide, keepSign);

                if (currentInside)
                {
                    if (!prevInside)
                    {
                        if (TryIntersectSegmentWithLine(prev, current, lineStart, lineEnd, out var intersection))
                        {
                            output.Add(intersection);
                        }
                    }

                    output.Add(current);
                }
                else if (prevInside)
                {
                    if (TryIntersectSegmentWithLine(prev, current, lineStart, lineEnd, out var intersection))
                    {
                        output.Add(intersection);
                    }
                }

                prev = current;
                prevSide = currentSide;
                prevInside = currentInside;
            }

            return output;
        }

        private static bool IsInside(double side, double keepSign)
        {
            if (keepSign > 0)
            {
                return side >= -1e-9;
            }

            return side <= 1e-9;
        }

        private static double SignedSide(Point2d lineStart, Point2d lineEnd, Point2d point)
        {
            var lineDir = lineEnd - lineStart;
            var toPoint = point - lineStart;
            return lineDir.X * toPoint.Y - lineDir.Y * toPoint.X;
        }

        private static bool TryIntersectSegmentWithLine(
            Point2d segmentStart,
            Point2d segmentEnd,
            Point2d lineStart,
            Point2d lineEnd,
            out Point2d intersection)
        {
            intersection = default;
            var p = segmentStart;
            var r = segmentEnd - segmentStart;
            var q = lineStart;
            var s = lineEnd - lineStart;

            var cross = r.X * s.Y - r.Y * s.X;
            if (Math.Abs(cross) < 1e-9)
            {
                return false;
            }

            var qmp = q - p;
            var t = (qmp.X * s.Y - qmp.Y * s.X) / cross;
            intersection = new Point2d(p.X + t * r.X, p.Y + t * r.Y);
            return true;
        }

        private static Polyline? BuildPolylineFromPoints(List<Point2d> points)
        {
            if (points.Count < 3)
            {
                return null;
            }

            var cleaned = new List<Point2d>();
            foreach (var point in points)
            {
                if (cleaned.Count == 0 || point.GetDistanceTo(cleaned[cleaned.Count - 1]) > 1e-6)
                {
                    cleaned.Add(point);
                }
            }

            if (cleaned.Count < 3)
            {
                return null;
            }

            if (cleaned[0].GetDistanceTo(cleaned[cleaned.Count - 1]) < 1e-6)
            {
                cleaned.RemoveAt(cleaned.Count - 1);
            }

            var polyline = new Polyline(cleaned.Count)
            {
                Closed = true
            };

            for (var i = 0; i < cleaned.Count; i++)
            {
                polyline.AddVertexAt(i, cleaned[i], 0, 0, 0);
            }

            return polyline;
        }

        private static bool TryGetQuarterAnchors(Polyline section, out QuarterAnchors anchors)
        {
            anchors = default;
            if (section.NumberOfVertices < 3)
            {
                return false;
            }

            var vertices = new List<Point3d>(section.NumberOfVertices);
            for (var i = 0; i < section.NumberOfVertices; i++)
            {
                var point = section.GetPoint2dAt(i);
                vertices.Add(new Point3d(point.X, point.Y, 0));
            }

            if (!TryGetQuarterAnchorsByEdgeMedianVertexChain(vertices, out var topV, out var bottomV, out var leftV, out var rightV))
            {
                return false;
            }

            anchors = new QuarterAnchors(
                new Point2d(topV.X, topV.Y),
                new Point2d(bottomV.X, bottomV.Y),
                new Point2d(leftV.X, leftV.Y),
                new Point2d(rightV.X, rightV.Y));
            return true;
        }

        private static bool TryGetQuarterAnchorsByEdgeMedianVertexChain(
            List<Point3d> verts,
            out Point3d topV,
            out Point3d bottomV,
            out Point3d leftV,
            out Point3d rightV)
        {
            topV = bottomV = leftV = rightV = Point3d.Origin;
            if (verts == null || verts.Count < 3)
            {
                return false;
            }

            var n = verts.Count;
            var edges = new List<EdgeInfo>(n);
            for (var i = 0; i < n; i++)
            {
                var a = verts[i];
                var b = verts[(i + 1) % n];
                var v = b - a;
                var len = v.Length;
                if (len <= 1e-9)
                {
                    continue;
                }

                var u = new Vector3d(v.X / len, v.Y / len, 0);
                var mid = new Point3d((a.X + b.X) * 0.5, (a.Y + b.Y) * 0.5, 0);
                edges.Add(new EdgeInfo { Index = i, A = a, B = b, U = u, Mid = mid, Len = len });
            }

            if (edges.Count == 0)
            {
                return false;
            }

            const double degTol = 12.0;
            var cosTol = Math.Cos(degTol * Math.PI / 180.0);
            var topEdge = default(EdgeInfo);
            var bestTopY = double.MinValue;
            foreach (var edge in edges)
            {
                var horiz = Math.Abs(edge.U.DotProduct(Vector3d.XAxis));
                var avgY = (edge.A.Y + edge.B.Y) * 0.5;
                if (horiz >= cosTol && avgY > bestTopY)
                {
                    bestTopY = avgY;
                    topEdge = edge;
                }
            }

            if (bestTopY == double.MinValue)
            {
                topEdge = edges.OrderByDescending(edge => edge.Len).First();
            }

            var east = topEdge.U.GetNormal();
            if (east.Length <= 1e-12)
            {
                return false;
            }

            var north = east.RotateBy(Math.PI / 2.0, Vector3d.ZAxis).GetNormal();

            var minE = double.MaxValue;
            var maxE = double.MinValue;
            var minN = double.MaxValue;
            var maxN = double.MinValue;
            for (var i = 0; i < n; i++)
            {
                var dp = verts[i] - Point3d.Origin;
                var pe = dp.DotProduct(east);
                var pn = dp.DotProduct(north);
                minE = Math.Min(minE, pe);
                maxE = Math.Max(maxE, pe);
                minN = Math.Min(minN, pn);
                maxN = Math.Max(maxN, pn);
            }

            var spanE = Math.Max(1e-6, maxE - minE);
            var spanN = Math.Max(1e-6, maxN - minN);
            var bandTol = Math.Max(5.0, 0.01 * Math.Max(spanE, spanN));

            var eChains = BuildChainsClosest(edges, east, north);
            var nChains = BuildChainsClosest(edges, north, east);
            if (eChains.Count == 0 || nChains.Count == 0)
            {
                return false;
            }

            bool TouchesTop(ChainInfo ch)
            {
                foreach (var idx in ChainVertexIndices(ch, n))
                {
                    if (maxN - AxisProj(verts[idx], north) <= bandTol)
                    {
                        return true;
                    }
                }

                return false;
            }

            bool TouchesBottom(ChainInfo ch)
            {
                foreach (var idx in ChainVertexIndices(ch, n))
                {
                    if (AxisProj(verts[idx], north) - minN <= bandTol)
                    {
                        return true;
                    }
                }

                return false;
            }

            bool TouchesLeft(ChainInfo ch)
            {
                foreach (var idx in ChainVertexIndices(ch, n))
                {
                    if (AxisProj(verts[idx], east) - minE <= bandTol)
                    {
                        return true;
                    }
                }

                return false;
            }

            bool TouchesRight(ChainInfo ch)
            {
                foreach (var idx in ChainVertexIndices(ch, n))
                {
                    if (maxE - AxisProj(verts[idx], east) <= bandTol)
                    {
                        return true;
                    }
                }

                return false;
            }

            var top = eChains.Where(TouchesTop).DefaultIfEmpty(eChains.OrderByDescending(c => c.Score).First()).First();
            var bottom = eChains.Where(TouchesBottom).DefaultIfEmpty(eChains.OrderBy(c => c.Score).First()).First();
            var left = nChains.Where(TouchesLeft).DefaultIfEmpty(nChains.OrderBy(c => c.Score).First()).First();
            var right = nChains.Where(TouchesRight).DefaultIfEmpty(nChains.OrderByDescending(c => c.Score).First()).First();

            var targetE = 0.5 * (minE + maxE);
            topV = ChainVertexNearestAxisValue(verts, top, east, targetE);
            bottomV = ChainVertexNearestAxisValue(verts, bottom, east, targetE);

            var targetN = 0.5 * (minN + maxN);
            leftV = ChainVertexNearestAxisValue(verts, left, north, targetN);
            rightV = ChainVertexNearestAxisValue(verts, right, north, targetN);

            var Emid = 0.5 * (AxisProj(leftV, east) + AxisProj(rightV, east));
            var Nmid = 0.5 * (AxisProj(topV, north) + AxisProj(bottomV, north));
            if (Math.Abs(Emid - 0.5 * (minE + maxE)) > 0.25 * spanE ||
                Math.Abs(Nmid - 0.5 * (minN + maxN)) > 0.25 * spanN)
            {
                Point3d FromEN(double e, double nCoord) =>
                    new Point3d(east.X * e + north.X * nCoord, east.Y * e + north.Y * nCoord, 0);

                topV = FromEN(0.5 * (minE + maxE), maxN);
                bottomV = FromEN(0.5 * (minE + maxE), minN);
                leftV = FromEN(minE, 0.5 * (minN + maxN));
                rightV = FromEN(maxE, 0.5 * (minN + maxN));
            }

            return true;
        }

        private static List<ChainInfo> BuildChainsClosest(List<EdgeInfo> edges, Vector3d primary, Vector3d other)
        {
            var chains = new List<ChainInfo>();
            var inChain = false;
            var start = -1;
            var sumProj = 0.0;
            var cnt = 0;
            var totLen = 0.0;

            for (var i = 0; i < edges.Count; i++)
            {
                var edge = edges[i];
                var de = Math.Abs(edge.U.DotProduct(primary));
                var dn = Math.Abs(edge.U.DotProduct(other));
                var isPrimary = de >= dn;

                if (isPrimary)
                {
                    if (!inChain)
                    {
                        inChain = true;
                        start = edge.Index;
                        sumProj = 0.0;
                        cnt = 0;
                        totLen = 0.0;
                    }

                    sumProj += (edge.Mid - Point3d.Origin).DotProduct(other);
                    cnt++;
                    totLen += edge.Len;
                }
                else if (inChain)
                {
                    chains.Add(new ChainInfo
                    {
                        Start = start,
                        SegCount = cnt,
                        Score = cnt > 0 ? sumProj / cnt : 0.0,
                        TotalLen = totLen
                    });
                    inChain = false;
                }
            }

            if (inChain)
            {
                chains.Add(new ChainInfo
                {
                    Start = start,
                    SegCount = cnt,
                    Score = cnt > 0 ? sumProj / cnt : 0.0,
                    TotalLen = totLen
                });
            }

            if (chains.Count >= 2)
            {
                var first = chains[0];
                var last = chains[chains.Count - 1];
                if (first.Start == 0 && (last.Start + last.SegCount == edges.Count))
                {
                    var totalSeg = last.SegCount + first.SegCount;
                    var totalLen = last.TotalLen + first.TotalLen;
                    var avgScore = totalSeg > 0
                        ? (last.Score * last.SegCount + first.Score * first.SegCount) / totalSeg
                        : 0.0;
                    var merged = new ChainInfo
                    {
                        Start = last.Start,
                        SegCount = totalSeg,
                        Score = avgScore,
                        TotalLen = totalLen
                    };
                    chains[0] = merged;
                    chains.RemoveAt(chains.Count - 1);
                }
            }

            return chains;
        }

        private static IEnumerable<int> ChainVertexIndices(ChainInfo chain, int vertexCount)
        {
            for (var k = 0; k <= chain.SegCount; k++)
            {
                yield return (chain.Start + k) % vertexCount;
            }
        }

        private static double AxisProj(Point3d point, Vector3d axis)
        {
            return (point - Point3d.Origin).DotProduct(axis);
        }

        private static Point3d ChainVertexNearestAxisValue(List<Point3d> verts, ChainInfo chain, Vector3d axis, double target)
        {
            var bestIdx = chain.Start % verts.Count;
            var best = double.MaxValue;

            foreach (var idx in ChainVertexIndices(chain, verts.Count))
            {
                var distance = Math.Abs(AxisProj(verts[idx], axis) - target);
                if (distance < best)
                {
                    best = distance;
                    bestIdx = idx;
                }
            }

            return verts[bestIdx];
        }

        private static IReadOnlyList<string> BuildSectionIndexSearchFolders(Config config)
        {
            var folders = new List<string>();
            AddFolder(folders, config.SectionIndexFolder);
            AddFolder(folders, new Config().SectionIndexFolder);
            AddFolder(folders, Path.GetDirectoryName(Assembly.GetExecutingAssembly().Location) ?? Environment.CurrentDirectory);
            return folders;
        }

        private static void AddFolder(List<string> folders, string? folder)
        {
            if (string.IsNullOrWhiteSpace(folder))
            {
                return;
            }

            if (!folders.Contains(folder, StringComparer.OrdinalIgnoreCase))
            {
                folders.Add(folder);
            }
        }

        private static bool TryLoadSectionOutline(
            IReadOnlyList<string> searchFolders,
            SectionKey key,
            Logger logger,
            [NotNullWhen(true)] out SectionOutline? outline)
        {
            outline = null;
            var cacheKey = BuildSectionOutlineCacheKey(searchFolders, key);
            lock (SectionOutlineCacheLock)
            {
                if (SectionOutlineCache.TryGetValue(cacheKey, out var cached))
                {
                    outline = cached == null
                        ? null
                        : new SectionOutline(new List<Point2d>(cached.Vertices), cached.Closed, cached.SourcePath);
                    return outline != null;
                }
            }

            var checkedAny = false;
            foreach (var folder in searchFolders)
            {
                if (!FolderHasSectionIndex(folder, key.Zone))
                {
                    continue;
                }

                checkedAny = true;
                if (SectionIndexReader.TryLoadSectionOutline(folder, key, logger, out outline))
                {
                    lock (SectionOutlineCacheLock)
                    {
                        SectionOutlineCache[cacheKey] = new SectionOutline(new List<Point2d>(outline.Vertices), outline.Closed, outline.SourcePath);
                    }
                    return true;
                }
            }

            if (!checkedAny)
            {
                logger.WriteLine($"No section index file found for zone {key.Zone}. Searched: {string.Join("; ", searchFolders)}");
            }

            lock (SectionOutlineCacheLock)
            {
                SectionOutlineCache[cacheKey] = null;
            }
            return false;
        }

        private static bool FolderHasSectionIndex(string folder, int zone)
        {
            if (string.IsNullOrWhiteSpace(folder))
            {
                return false;
            }

            var cacheKey = string.Format(CultureInfo.InvariantCulture, "{0}|{1}", folder, zone);
            lock (SectionOutlineCacheLock)
            {
                if (FolderIndexCache.TryGetValue(cacheKey, out var existsCached))
                {
                    return existsCached;
                }
            }

            var jsonl = Path.Combine(folder, $"Master_Sections.index_Z{zone}.jsonl");
            var csv = Path.Combine(folder, $"Master_Sections.index_Z{zone}.csv");
            var jsonlFallback = Path.Combine(folder, "Master_Sections.index.jsonl");
            var csvFallback = Path.Combine(folder, "Master_Sections.index.csv");
            var exists = File.Exists(jsonl) || File.Exists(csv) || File.Exists(jsonlFallback) || File.Exists(csvFallback);
            lock (SectionOutlineCacheLock)
            {
                FolderIndexCache[cacheKey] = exists;
            }

            return exists;
        }

        private static string BuildSectionOutlineCacheKey(IReadOnlyList<string> searchFolders, SectionKey key)
        {
            var foldersKey = searchFolders == null
                ? string.Empty
                : string.Join(";", searchFolders.Select(f => (f ?? string.Empty).Trim()).Where(f => f.Length > 0));

            return string.Format(
                CultureInfo.InvariantCulture,
                "{0}|{1}|{2}|{3}|{4}|{5}",
                key.Zone,
                NormalizeNumberToken(key.Meridian),
                NormalizeNumberToken(key.Range),
                NormalizeNumberToken(key.Township),
                NormalizeNumberToken(key.Section),
                foldersKey);
        }

        private struct P3ImportSummary
        {
            public int ImportedEntities;
            public int FilteredEntities;
            public int ImportFailures;
        }

        private static P3ImportSummary ImportP3Shapefiles(
            Database database,
            Editor editor,
            Logger logger,
            IReadOnlyList<ObjectId> sectionPolylineIds)
        {
            const string p3Folder = @"C:\AUTOCAD-SETUP CG\SHAPE FILES\P3";
            const string outputLayer = "T-WATER-P3";
            const double sectionBuffer = 100.0;
            var shapefiles = new[]
            {
                "BF_Hydro_Polygon.shp",
                "BF_SLNET_arc.shp"
            };

            var summary = new P3ImportSummary();
            var sectionExtents = BuildSectionExtents(database, sectionPolylineIds, sectionBuffer);
            if (sectionExtents.Count == 0)
            {
                logger?.WriteLine("P3 import skipped: no section extents.");
                return summary;
            }

            Importer? importer = null;
            try
            {
                importer = HostMapApplicationServices.Application?.Importer;
            }
            catch (System.Exception ex)
            {
                logger?.WriteLine("P3 importer unavailable: " + ex.Message);
            }

            if (importer == null)
            {
                summary.ImportFailures += shapefiles.Length;
                return summary;
            }

            foreach (var fileName in shapefiles)
            {
                var path = Path.Combine(p3Folder, fileName);
                if (!File.Exists(path))
                {
                    logger?.WriteLine("P3 shapefile missing: " + path);
                    summary.ImportFailures++;
                    continue;
                }

                var beforeIds = CaptureModelSpaceEntityIds(database);
                try
                {
                    importer.Init("SHP", path);
                    TrySetImporterLocationWindow(importer, sectionExtents, logger);
                    foreach (InputLayer layer in importer)
                    {
                        layer.ImportFromInputLayerOn = true;
                    }

                    importer.Import();
                }
                catch (System.Exception ex)
                {
                    logger?.WriteLine("P3 import failed for " + path + ": " + ex.Message);
                    summary.ImportFailures++;
                    continue;
                }

                var afterIds = CaptureModelSpaceEntityIds(database);
                var newIds = afterIds.Where(id => !beforeIds.Contains(id)).ToList();

                using (var tr = database.TransactionManager.StartTransaction())
                {
                    EnsureLayer(database, tr, outputLayer);

                    foreach (var id in newIds)
                    {
                        var ent = tr.GetObject(id, OpenMode.ForWrite, false) as Entity;
                        if (ent == null || ent.IsErased)
                        {
                            continue;
                        }

                        if (!IsEntityInsideAnySectionExtents(ent, sectionExtents))
                        {
                            ent.Erase(true);
                            summary.FilteredEntities++;
                            continue;
                        }

                        ent.Layer = outputLayer;
                        ent.ColorIndex = 256;
                        summary.ImportedEntities++;
                    }

                    tr.Commit();
                }
            }

            editor?.WriteMessage($"\nImported {summary.ImportedEntities} P3 entities.");
            return summary;
        }

        private static HashSet<ObjectId> CaptureModelSpaceEntityIds(Database database)
        {
            var ids = new HashSet<ObjectId>();
            using (var tr = database.TransactionManager.StartTransaction())
            {
                var blockTable = (BlockTable)tr.GetObject(database.BlockTableId, OpenMode.ForRead);
                var modelSpace = (BlockTableRecord)tr.GetObject(blockTable[BlockTableRecord.ModelSpace], OpenMode.ForRead);
                foreach (ObjectId id in modelSpace)
                {
                    ids.Add(id);
                }

                tr.Commit();
            }

            return ids;
        }

        private static List<Extents2d> BuildSectionExtents(
            Database database,
            IReadOnlyList<ObjectId> sectionPolylineIds,
            double buffer)
        {
            var extents = new List<Extents2d>();
            if (database == null || sectionPolylineIds == null || sectionPolylineIds.Count == 0)
            {
                return extents;
            }

            using (var tr = database.TransactionManager.StartTransaction())
            {
                foreach (var id in sectionPolylineIds)
                {
                    if (id.IsNull)
                    {
                        continue;
                    }

                    var ent = tr.GetObject(id, OpenMode.ForRead, false) as Entity;
                    if (ent == null)
                    {
                        continue;
                    }

                    try
                    {
                        var ge = ent.GeometricExtents;
                        extents.Add(new Extents2d(
                            ge.MinPoint.X - buffer,
                            ge.MinPoint.Y - buffer,
                            ge.MaxPoint.X + buffer,
                            ge.MaxPoint.Y + buffer));
                    }
                    catch
                    {
                        // ignore invalid extents
                    }
                }

                tr.Commit();
            }

            return extents;
        }

        private static bool IsEntityInsideAnySectionExtents(Entity ent, List<Extents2d> sectionExtents)
        {
            if (ent == null || sectionExtents == null || sectionExtents.Count == 0)
            {
                return false;
            }

            Extents3d ge;
            try
            {
                ge = ent.GeometricExtents;
            }
            catch
            {
                return false;
            }

            var e2d = new Extents2d(ge.MinPoint.X, ge.MinPoint.Y, ge.MaxPoint.X, ge.MaxPoint.Y);
            foreach (var sectionExtent in sectionExtents)
            {
                if (!(e2d.MaxPoint.X < sectionExtent.MinPoint.X ||
                      e2d.MinPoint.X > sectionExtent.MaxPoint.X ||
                      e2d.MaxPoint.Y < sectionExtent.MinPoint.Y ||
                      e2d.MinPoint.Y > sectionExtent.MaxPoint.Y))
                {
                    return true;
                }
            }

            return false;
        }

        private static void TrySetImporterLocationWindow(Importer importer, List<Extents2d> sectionExtents, Logger? logger)
        {
            if (importer == null || sectionExtents == null || sectionExtents.Count == 0)
            {
                return;
            }

            var union = UnionExtents(sectionExtents);
            try
            {
                var method = importer.GetType().GetMethod("SetLocationWindowAndOptions");
                if (method == null)
                {
                    return;
                }

                var parameters = method.GetParameters();
                if (parameters.Length != 5 || !parameters[4].ParameterType.IsEnum)
                {
                    return;
                }

                var option = GetEnumValue(parameters[4].ParameterType, 2, "kUseLocationWindow", "UseLocationWindow");
                method.Invoke(importer, new object[]
                {
                    union.MinPoint.X,
                    union.MaxPoint.X,
                    union.MinPoint.Y,
                    union.MaxPoint.Y,
                    option
                });
                logger?.WriteLine($"P3 importer location window set: X[{union.MinPoint.X:G},{union.MaxPoint.X:G}] Y[{union.MinPoint.Y:G},{union.MaxPoint.Y:G}]");
            }
            catch (System.Exception ex)
            {
                logger?.WriteLine("P3 location window setup failed: " + ex.Message);
            }
        }

        private static Extents2d UnionExtents(List<Extents2d> extents)
        {
            var minX = extents[0].MinPoint.X;
            var minY = extents[0].MinPoint.Y;
            var maxX = extents[0].MaxPoint.X;
            var maxY = extents[0].MaxPoint.Y;

            for (var i = 1; i < extents.Count; i++)
            {
                var e = extents[i];
                minX = Math.Min(minX, e.MinPoint.X);
                minY = Math.Min(minY, e.MinPoint.Y);
                maxX = Math.Max(maxX, e.MaxPoint.X);
                maxY = Math.Max(maxY, e.MaxPoint.Y);
            }

            return new Extents2d(minX, minY, maxX, maxY);
        }

        private static object GetEnumValue(Type enumType, int fallbackNumeric, params string[] names)
        {
            foreach (var name in names)
            {
                try
                {
                    return Enum.Parse(enumType, name, true);
                }
                catch
                {
                    // keep trying
                }
            }

            return Enum.ToObject(enumType, fallbackNumeric);
        }

        private static void EnsureLayer(Database database, Transaction transaction, string layerName)
        {
            var table = (LayerTable)transaction.GetObject(database.LayerTableId, OpenMode.ForRead);
            if (table.Has(layerName))
            {
                return;
            }

            table.UpgradeOpen();
            var record = new LayerTableRecord
            {
                Name = layerName
            };
            table.Add(record);
            transaction.AddNewlyCreatedDBObject(record, true);
        }

        private static bool IsUsecLayer(string layerName)
        {
            if (string.IsNullOrWhiteSpace(layerName))
            {
                return false;
            }

            if (string.Equals(layerName, LayerUsecBase, StringComparison.OrdinalIgnoreCase))
            {
                return true;
            }

            return string.Equals(layerName, LayerUsecZero, StringComparison.OrdinalIgnoreCase) ||
                   string.Equals(layerName, LayerUsecTwenty, StringComparison.OrdinalIgnoreCase) ||
                   string.Equals(layerName, LayerUsecThirty, StringComparison.OrdinalIgnoreCase);
        }

        private static short ResolveUsecLayerColorIndex(string layerName)
        {
            if (string.Equals(layerName, LayerUsecZero, StringComparison.OrdinalIgnoreCase))
            {
                return 1;
            }

            if (string.Equals(layerName, LayerUsecTwenty, StringComparison.OrdinalIgnoreCase))
            {
                return 3;
            }

            if (string.Equals(layerName, LayerUsecThirty, StringComparison.OrdinalIgnoreCase))
            {
                return 5;
            }

            return 7;
        }

        private static void EnsureLayerWithColor(Database database, Transaction transaction, string layerName, short colorIndex)
        {
            if (database == null || transaction == null || string.IsNullOrWhiteSpace(layerName))
            {
                return;
            }

            if (colorIndex < 1 || colorIndex > 255)
            {
                colorIndex = 7;
            }

            var table = (LayerTable)transaction.GetObject(database.LayerTableId, OpenMode.ForRead);
            if (table.Has(layerName))
            {
                var layerId = table[layerName];
                var layer = (LayerTableRecord)transaction.GetObject(layerId, OpenMode.ForWrite);
                var targetColor = Color.FromColorIndex(ColorMethod.ByAci, colorIndex);
                if (layer.Color != targetColor)
                {
                    layer.Color = targetColor;
                }

                return;
            }

            table.UpgradeOpen();
            var record = new LayerTableRecord
            {
                Name = layerName,
                Color = Color.FromColorIndex(ColorMethod.ByAci, colorIndex),
                IsOff = false
            };
            table.Add(record);
            transaction.AddNewlyCreatedDBObject(record, true);
        }

        private static void SetLayerVisibility(
            Database database,
            Transaction transaction,
            string layerName,
            bool isOff,
            bool isPlottable)
        {
            var table = (LayerTable)transaction.GetObject(database.LayerTableId, OpenMode.ForRead);
            if (!table.Has(layerName))
            {
                return;
            }

            var layerId = table[layerName];
            var layer = (LayerTableRecord)transaction.GetObject(layerId, OpenMode.ForWrite);
            layer.IsOff = isOff;
            layer.IsPlottable = isPlottable;
        }

        private static ObjectId InsertSectionLabelBlock(
            BlockTableRecord modelSpace,
            BlockTable blockTable,
            Transaction transaction,
            Editor editor,
            Point3d position,
            SectionKey key)
        {
            const string blockName = "L-SECLBL";

            if (!blockTable.Has(blockName))
            {
                editor?.WriteMessage($"\nBUILDSEC: Block '{blockName}' not found; skipped section label.");
                return ObjectId.Null;
            }

            var blockId = blockTable[blockName];
            var blockRef = new BlockReference(position, blockId)
            {
                ScaleFactors = new Scale3d(1.0)
            };
            var blockRefId = modelSpace.AppendEntity(blockRef);
            transaction.AddNewlyCreatedDBObject(blockRef, true);

            var blockDef = (BlockTableRecord)transaction.GetObject(blockId, OpenMode.ForRead);
            if (blockDef.HasAttributeDefinitions)
            {
                foreach (ObjectId id in blockDef)
                {
                    if (!(transaction.GetObject(id, OpenMode.ForRead) is AttributeDefinition definition))
                    {
                        continue;
                    }

                    if (definition.Constant)
                    {
                        continue;
                    }

                    var reference = new AttributeReference();
                    reference.SetAttributeFromBlock(definition, blockRef.BlockTransform);
                    blockRef.AttributeCollection.AppendAttribute(reference);
                    transaction.AddNewlyCreatedDBObject(reference, true);
                }
            }

            SetBlockAttribute(blockRef, transaction, "SEC", key.Section);
            SetBlockAttribute(blockRef, transaction, "TWP", key.Township);
            SetBlockAttribute(blockRef, transaction, "RGE", key.Range);
            SetBlockAttribute(blockRef, transaction, "MER", key.Meridian);

            return blockRefId;
        }

        private static void SetBlockAttribute(BlockReference blockRef, Transaction transaction, string tag, string value)
        {
            if (blockRef == null || string.IsNullOrWhiteSpace(tag))
            {
                return;
            }

            foreach (ObjectId id in blockRef.AttributeCollection)
            {
                if (!(transaction.GetObject(id, OpenMode.ForWrite) is AttributeReference attr))
                {
                    continue;
                }

                if (string.Equals(attr.Tag, tag, StringComparison.OrdinalIgnoreCase))
                {
                    attr.TextString = value ?? string.Empty;
                }
            }
        }

        private static Point2d ResolveSectionLabelPosition(
            Polyline sectionPolyline,
            Dictionary<QuarterSelection, Polyline> quarterMap,
            QuarterAnchors anchors,
            List<LineSegment2d> lineworkBarriers,
            BlockTable blockTable,
            Transaction transaction,
            bool drawLsds,
            Point2d sectionCenter)
        {
            if (sectionPolyline == null)
            {
                return sectionCenter;
            }

            if (!TryGetSectionLabelBlockFootprint(blockTable, transaction, out var labelWidth, out var labelHeight))
            {
                labelWidth = 130.0;
                labelHeight = 70.0;
            }

            var requiredClearance = Math.Sqrt((labelWidth * 0.5 * labelWidth * 0.5) + (labelHeight * 0.5 * labelHeight * 0.5)) + 2.0;

            bool Fits(Point2d p)
            {
                if (!IsLabelBoxInsideSection(sectionPolyline, p, labelWidth, labelHeight))
                    return false;

                return GetLineworkClearance(p, lineworkBarriers) >= requiredClearance;
            }

            if (!drawLsds)
            {
                if (Fits(sectionCenter))
                {
                    return sectionCenter;
                }

                if (TryFindNonOverlapSectionPosition(sectionPolyline, sectionCenter, labelWidth, labelHeight, requiredClearance, lineworkBarriers, out var candidate))
                {
                    return candidate;
                }

                return GetLeastCongestedQuarterCenter(quarterMap, sectionPolyline, lineworkBarriers, sectionCenter);
            }

            if (TryFindNonOverlapSectionPosition(sectionPolyline, sectionCenter, labelWidth, labelHeight, requiredClearance, lineworkBarriers, out var openArea))
            {
                return openArea;
            }

            return GetLeastCongestedLsdCenter(sectionPolyline, anchors, lineworkBarriers, sectionCenter);
        }

        private static bool TryGetSectionLabelBlockFootprint(
            BlockTable blockTable,
            Transaction transaction,
            out double width,
            out double height)
        {
            width = 0;
            height = 0;

            const string blockName = "L-SECLBL";
            if (blockTable == null || transaction == null || !blockTable.Has(blockName))
            {
                return false;
            }

            try
            {
                var blockId = blockTable[blockName];
                var blockDef = (BlockTableRecord)transaction.GetObject(blockId, OpenMode.ForRead);

                var found = false;
                var minX = 0.0;
                var minY = 0.0;
                var maxX = 0.0;
                var maxY = 0.0;

                foreach (ObjectId id in blockDef)
                {
                    if (!(transaction.GetObject(id, OpenMode.ForRead) is Entity entity))
                    {
                        continue;
                    }

                    Extents3d extents;
                    try
                    {
                        extents = entity.GeometricExtents;
                    }
                    catch
                    {
                        continue;
                    }

                    if (!found)
                    {
                        minX = extents.MinPoint.X;
                        minY = extents.MinPoint.Y;
                        maxX = extents.MaxPoint.X;
                        maxY = extents.MaxPoint.Y;
                        found = true;
                    }
                    else
                    {
                        minX = Math.Min(minX, extents.MinPoint.X);
                        minY = Math.Min(minY, extents.MinPoint.Y);
                        maxX = Math.Max(maxX, extents.MaxPoint.X);
                        maxY = Math.Max(maxY, extents.MaxPoint.Y);
                    }
                }

                if (!found)
                {
                    return false;
                }

                width = Math.Max(1.0, maxX - minX);
                height = Math.Max(1.0, maxY - minY);
                return true;
            }
            catch
            {
                return false;
            }
        }

        private static bool TryFindNonOverlapSectionPosition(
            Polyline sectionPolyline,
            Point2d preferredCenter,
            double labelWidth,
            double labelHeight,
            double requiredClearance,
            List<LineSegment2d> lineworkBarriers,
            out Point2d location)
        {
            location = preferredCenter;
            var step = Math.Max(5.0, Math.Min(labelWidth, labelHeight) * 0.6);
            foreach (var p in GeometryUtils.GetSpiralOffsets(preferredCenter, step, 400))
            {
                if (!IsLabelBoxInsideSection(sectionPolyline, p, labelWidth, labelHeight))
                {
                    continue;
                }

                if (GetLineworkClearance(p, lineworkBarriers) >= requiredClearance)
                {
                    location = p;
                    return true;
                }
            }

            return false;
        }

        private static Point2d GetLeastCongestedQuarterCenter(
            Dictionary<QuarterSelection, Polyline> quarterMap,
            Polyline sectionPolyline,
            List<LineSegment2d> lineworkBarriers,
            Point2d fallback)
        {
            if (quarterMap == null || quarterMap.Count == 0)
            {
                return fallback;
            }

            var bestPoint = fallback;
            var bestScore = double.NegativeInfinity;

            foreach (var quarter in quarterMap.Values)
            {
                if (quarter == null)
                {
                    continue;
                }

                var p = GeometryUtils.GetSafeInteriorPoint(quarter);
                if (!GeometryUtils.IsPointInsidePolyline(sectionPolyline, p))
                {
                    continue;
                }

                var score = GetLineworkClearance(p, lineworkBarriers);
                if (score > bestScore)
                {
                    bestScore = score;
                    bestPoint = p;
                }
            }

            return bestPoint;
        }

        private static Point2d GetLeastCongestedLsdCenter(
            Polyline sectionPolyline,
            QuarterAnchors anchors,
            List<LineSegment2d> lineworkBarriers,
            Point2d fallback)
        {
            var eastUnit = GetUnitVector(anchors.Left, anchors.Right, new Vector2d(1, 0));
            var northUnit = GetUnitVector(anchors.Bottom, anchors.Top, new Vector2d(0, 1));
            var width = anchors.Left.GetDistanceTo(anchors.Right);
            var height = anchors.Bottom.GetDistanceTo(anchors.Top);
            if (width <= 1e-6 || height <= 1e-6)
            {
                return fallback;
            }

            var southWest = fallback - (eastUnit * (width * 0.5)) - (northUnit * (height * 0.5));
            var bestPoint = fallback;
            var bestScore = double.NegativeInfinity;

            for (var row = 0; row < 4; row++)
            {
                for (var col = 0; col < 4; col++)
                {
                    var p = southWest +
                            (eastUnit * (width * ((col + 0.5) / 4.0))) +
                            (northUnit * (height * ((row + 0.5) / 4.0)));
                    if (!GeometryUtils.IsPointInsidePolyline(sectionPolyline, p))
                    {
                        continue;
                    }

                    var score = GetLineworkClearance(p, lineworkBarriers);
                    if (score > bestScore)
                    {
                        bestScore = score;
                        bestPoint = p;
                    }
                }
            }

            return bestPoint;
        }

        private static Point2d GetLeastCongestedPointInBoundary(
            Polyline boundary,
            List<LineSegment2d> lineworkBarriers,
            Point2d fallback)
        {
            if (boundary == null)
            {
                return fallback;
            }

            var seed = GeometryUtils.GetSafeInteriorPoint(boundary);
            var bestPoint = GeometryUtils.IsPointInsidePolyline(boundary, seed) ? seed : fallback;
            var bestScore = GetLineworkClearance(bestPoint, lineworkBarriers);

            var extents = boundary.GeometricExtents;
            var diag = extents.MaxPoint.DistanceTo(extents.MinPoint);
            var step = Math.Max(5.0, diag / 16.0);

            foreach (var p in GeometryUtils.GetSpiralOffsets(bestPoint, step, 220))
            {
                if (!GeometryUtils.IsPointInsidePolyline(boundary, p))
                {
                    continue;
                }

                var score = GetLineworkClearance(p, lineworkBarriers);
                if (score > bestScore)
                {
                    bestScore = score;
                    bestPoint = p;
                }
            }

            return bestPoint;
        }

        private static bool TryGetBestQuarterLsdCellCenter(
            Polyline quarterPolyline,
            Vector2d eastUnit,
            Vector2d northUnit,
            List<LineSegment2d> lineworkBarriers,
            Func<Point2d, bool> fitsPredicate,
            out Point2d bestCellCenter,
            out Point2d? bestFitCellCenter)
        {
            bestCellCenter = default;
            bestFitCellCenter = null;
            if (quarterPolyline == null)
            {
                return false;
            }

            var anchors = GetLsdAnchorsForQuarter(quarterPolyline, eastUnit, northUnit);
            var width = anchors.Left.GetDistanceTo(anchors.Right);
            var height = anchors.Bottom.GetDistanceTo(anchors.Top);
            if (width <= 1e-6 || height <= 1e-6)
            {
                return false;
            }

            var quarterCenter = new Point2d(
                0.5 * (anchors.Top.X + anchors.Bottom.X),
                0.5 * (anchors.Left.Y + anchors.Right.Y));
            var southWest = quarterCenter - (eastUnit * (width * 0.5)) - (northUnit * (height * 0.5));

            var haveAny = false;
            var bestAnyScore = double.NegativeInfinity;
            var bestFitScore = double.NegativeInfinity;

            for (var row = 0; row < 2; row++)
            {
                for (var col = 0; col < 2; col++)
                {
                    var p = southWest +
                            (eastUnit * (width * ((col + 0.5) / 2.0))) +
                            (northUnit * (height * ((row + 0.5) / 2.0)));
                    if (!GeometryUtils.IsPointInsidePolyline(quarterPolyline, p))
                    {
                        continue;
                    }

                    var score = GetLineworkClearance(p, lineworkBarriers);
                    if (!haveAny || score > bestAnyScore)
                    {
                        bestAnyScore = score;
                        bestCellCenter = p;
                        haveAny = true;
                    }

                    if (fitsPredicate != null && fitsPredicate(p) && score > bestFitScore)
                    {
                        bestFitScore = score;
                        bestFitCellCenter = p;
                    }
                }
            }

            return haveAny;
        }

        private static bool IsLabelBoxInsideSection(Polyline sectionPolyline, Point2d center, double width, double height)
        {
            var halfW = width * 0.5;
            var halfH = height * 0.5;
            var points = new[]
            {
                center,
                new Point2d(center.X - halfW, center.Y - halfH),
                new Point2d(center.X + halfW, center.Y - halfH),
                new Point2d(center.X - halfW, center.Y + halfH),
                new Point2d(center.X + halfW, center.Y + halfH),
                new Point2d(center.X, center.Y - halfH),
                new Point2d(center.X, center.Y + halfH),
                new Point2d(center.X - halfW, center.Y),
                new Point2d(center.X + halfW, center.Y)
            };

            foreach (var p in points)
            {
                if (!GeometryUtils.IsPointInsidePolyline(sectionPolyline, p))
                {
                    return false;
                }
            }

            return true;
        }

        private static double GetLineworkClearance(Point2d point, List<LineSegment2d> lineworkBarriers)
        {
            if (lineworkBarriers == null || lineworkBarriers.Count == 0)
            {
                return double.MaxValue;
            }

            var min = double.MaxValue;
            foreach (var segment in lineworkBarriers)
            {
                var d = DistancePointToSegment(point, segment.StartPoint, segment.EndPoint);
                if (d < min)
                {
                    min = d;
                }
            }

            return min;
        }

        private static double DistancePointToSegment(Point2d point, Point2d a, Point2d b)
        {
            var ab = b - a;
            var len2 = ab.DotProduct(ab);
            if (len2 <= 1e-12)
            {
                return point.GetDistanceTo(a);
            }

            var ap = point - a;
            var t = ap.DotProduct(ab) / len2;
            if (t < 0.0) t = 0.0;
            if (t > 1.0) t = 1.0;
            var nearest = new Point2d(a.X + ab.X * t, a.Y + ab.Y * t);
            return point.GetDistanceTo(nearest);
        }

        private static void AddPolylineSegments(List<LineSegment2d> destination, Polyline polyline)
        {
            if (destination == null || polyline == null || polyline.NumberOfVertices < 2)
            {
                return;
            }

            for (var i = 0; i < polyline.NumberOfVertices; i++)
            {
                var j = i + 1;
                if (j >= polyline.NumberOfVertices)
                {
                    if (!polyline.Closed)
                    {
                        break;
                    }

                    j = 0;
                }

                var a = polyline.GetPoint2dAt(i);
                var b = polyline.GetPoint2dAt(j);
                if (a.GetDistanceTo(b) > 1e-9)
                {
                    destination.Add(new LineSegment2d(a, b));
                }
            }
        }

        private struct QuarterAnchors
        {
            public QuarterAnchors(Point2d top, Point2d bottom, Point2d left, Point2d right)
            {
                Top = top;
                Bottom = bottom;
                Left = left;
                Right = right;
            }

            public Point2d Top { get; }
            public Point2d Bottom { get; }
            public Point2d Left { get; }
            public Point2d Right { get; }
        }

